// Multi-tradition mythological depth for animal guides.
// Layered ON TOP of Ayşe Nilgün Fırat's daily guidance — never replaces it.
// Each animal can be progressively enriched; missing fields render gracefully.

type Bilingual = { tr: string; en: string };
type BilingualTradition = { culture: Bilingual; meaning: Bilingual };

export interface AnimalLore {
  jung?: Bilingual;
  dream?: Bilingual;
  shadow?: Bilingual;
  traditions?: BilingualTradition[];
  myths?: Bilingual[];
  whenAppears?: Bilingual;
}

export interface Tradition {
  culture: string;
  meaning: string;
}

export const ANIMAL_LORE: Record<string, AnimalLore> = {
  // ─── a001 Bozkurt ───────────────────────────────────────────────────────
  a001: {
    jung: {
      tr: 'Bozkurt, kolektif bilinçaltında "Yol Gösteren Lider" arketipidir — kaybolmuş benliği eve döndüren içsel ses. Karanlık ormanda ışığı bulduran içgüdü.',
      en: 'The Grey Wolf is the "Guiding Leader" archetype within the Collective Unconscious — the inner voice that returns the lost Self home. The instinct that finds light in the dark forest.',
    },
    dream: {
      tr: 'Rüyada bozkurt — yolunu kaybettiğini ama içsel pusulanın hâlâ çalıştığını söyler. Sürünün sesi geliyor; dinle.',
      en: 'A wolf in dream — tells you that you have lost your way, but your inner compass still works. The call of the pack is coming; listen.',
    },
    shadow: {
      tr: 'Sürü zihniyetinde kaybolma. Bozkurt enerjisi kontrol edilemezse otoriter sertlik, kurt sürüsünün acımasızlığı çıkar.',
      en: 'Losing oneself in pack mentality. If the wolf energy goes unchecked, it manifests as authoritarian harshness and the ruthlessness of the wolf pack.',
    },
    whenAppears: {
      tr: 'Yalnız kaldığında, liderlik testinde, ailene/topluluğuna döndüğünde.',
      en: 'When you are alone, facing a test of leadership, returning to your family or community.',
    },
    traditions: [
      { culture: { tr: 'Türk Şamanizmi', en: 'Turkic Shamanism' }, meaning: { tr: 'Asena/Bozkurt — kutsal ata. Göktürk efsanesinde kaybolan halkı kurtaran ana. Devlet kurucu enerji.', en: 'Asena/Grey Wolf — the sacred ancestor. In the Göktürk legend, the mother who saved the lost people. State-founding energy.' } },
      { culture: { tr: 'Roma Mitolojisi', en: 'Roman Mythology' }, meaning: { tr: 'Lupa — Romulus ve Remus\'u emziren dişi kurt. Şehir kurucu, medeniyet besleyici.', en: 'Lupa — the she-wolf who suckled Romulus and Remus. City-founder, nurturer of civilization.' } },
      { culture: { tr: 'İskandinav', en: 'Norse' }, meaning: { tr: 'Fenrir — kontrol edilemeyen kozmik güç. Aynı zamanda Odin\'in iki yol arkadaşı Geri ve Freki.', en: 'Fenrir — uncontrollable cosmic force. Also Odin\'s two companions, Geri and Freki.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Lakota geleneğinde "öğretmen". Sürü, aile, sadakat dersleri verir.', en: 'In Lakota tradition, the "teacher". Imparts lessons of pack, family, and loyalty.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Cu Chulainn\'in koruyucusu. Ay\'ın bekçisi, geçişlerin habercisi.', en: 'Protector of Cú Chulainn. Guardian of the Moon, herald of transitions.' } },
    ],
    myths: [
      { tr: 'Göktürk Efsanesi: Düşman tarafından yok edilen Türk soyundan sağ kalan tek çocuğu Asena dişi kurdu kurtarır, mağarada büyütür. Türk halkı bu çocuğun soyundan türer.', en: 'Göktürk Legend: Asena, the she-wolf, rescues the sole surviving child of the Turkic lineage destroyed by enemies and raises him in a cave. The Turkic people descend from this child.' },
      { tr: 'Roma\'nın Kuruluşu: Romulus ve Remus\'u nehre bırakılınca dişi kurt Lupa bulup emzirir. Roma şehri bu çocuklar tarafından kurulur.', en: 'The Founding of Rome: When Romulus and Remus were left by the river, the she-wolf Lupa found and suckled them. The city of Rome was founded by these children.' },
    ],
  },

  // ─── a002 Kartal ────────────────────────────────────────────────────────
  a002: {
    jung: { tr: 'Kartal, "Yüksek Benlik" arketipidir. Egodan kopup ruhsal perspektife geçişin sembolü. Üçüncü gözün hayvan formu.', en: 'The Eagle is the "Higher Self" archetype. A symbol of detaching from ego into spiritual perspective. The animal form of the third eye.' },
    dream: { tr: 'Kartalın uçtuğunu görmek — düşüncenin yükseldiğine, sorunun küçüldüğüne işaret. Kartal seni avlıyorsa: yüksek bir gerçek aşağıdan seni yakalamaya geliyor.', en: 'Seeing an eagle in flight — indicates that thought is rising and the problem is shrinking. If the eagle is hunting you: a higher truth is coming from above to catch you.' },
    shadow: { tr: 'Soğuk uzaklık. Toprağa bağlanmamış zihinsellik. Mesafeden bakmak insandan kopmaya dönüşürse — kartal düşer.', en: 'Cold distance. Mentality unrooted from the earth. When viewing from afar turns into disconnection from humanity — the eagle falls.' },
    whenAppears: { tr: 'Büyük kararlar öncesi, perspektif kaybettiğinde, hayalle gerçek arasında köprü kurarken.', en: 'Before major decisions, when you have lost perspective, while bridging dream and reality.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Zeus\'un kuşu. Tanrının iradesini taşıyan haberci. Ganimedes\'i Olympos\'a taşıyan ruhsal yükselici.', en: 'Zeus\'s bird. The messenger carrying the god\'s will. The spiritual ascender who carried Ganymede to Olympus.' } },
      { culture: { tr: 'Hitit', en: 'Hittite' }, meaning: { tr: 'Çift başlı kartal — gökle yerin birleşim noktası. Anadolu\'nun en kadim devlet sembolü.', en: 'The double-headed eagle — the meeting point of sky and earth. Anatolia\'s most ancient symbol of statehood.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Wakan Tanka\'nın (Büyük Ruh) habercisi. Tüy en kutsal hediye.', en: 'Messenger of Wakan Tanka (the Great Spirit). The feather is the most sacred gift.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Aziz Yuhanna\'nın sembolü. Diriliş ve ilahi vahiy.', en: 'Symbol of Saint John. Resurrection and divine revelation.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Garuda — Vishnu\'nun bineği. Yılan-bilgisini taşıyan ruhsal güç.', en: 'Garuda — Vishnu\'s mount. The spiritual force bearing serpent-wisdom.' } },
    ],
    myths: [
      { tr: 'Prometheus: Tanrılardan ateşi çalan Prometheus\'u her gün kartal yer. Burada kartal — ego cezalandırıcı, ama aynı zamanda yenilenme döngüsünün taşıyıcısı.', en: 'Prometheus: The eagle daily devours Prometheus, who stole fire from the gods. Here the eagle is the ego-punisher, yet also the bearer of the cycle of renewal.' },
      { tr: 'Hitit Çifte Kartalı: Selçuklu\'dan modern Türk devletine kadar — iki yöne bakan tek kartal. Geçmiş ve gelecek.', en: 'The Hittite Double Eagle: From the Seljuks to the modern Turkish state — a single eagle gazing in two directions. Past and future.' },
    ],
  },

  // ─── a003 At ────────────────────────────────────────────────────────────
  a003: {
    jung: { tr: '"Yaşam Gücü/Libido" arketipi. At, içsel enerjinin sembolüdür — eyerlenmiş hâli irade, vahşi hâli içgüdü. Animanın bineği.', en: 'The "Life Force/Libido" archetype. The horse symbolizes inner energy — saddled it is will, wild it is instinct. The Anima\'s mount.' },
    dream: { tr: 'Rüyada at — özgürlük çağrısı. Beyaz at: yükselen ruhsallık. Siyah at: bastırılmış arzu. At dizginsizse: hayatın seni sürüklüyor.', en: 'A horse in dream — a call to freedom. White horse: rising spirituality. Black horse: repressed desire. If the horse is unbridled: life is dragging you along.' },
    shadow: { tr: 'Kontrolsüz tutku. Atın gemini bırakmak — disiplinsiz tutkuyla harcanan ömür. Ya da: hep eyerli kalmak, asla koşamamak.', en: 'Uncontrolled passion. To let go of the reins — a life spent on undisciplined passion. Or: always staying saddled, never being able to run.' },
    whenAppears: { tr: 'Bir yola çıkma anında, büyük göç/seyahat öncesi, içsel bir tutkunun uyanışında, özgürleşme zamanı.', en: 'At the moment of setting out, before a great migration or journey, at the awakening of an inner passion, in time of liberation.' },
    traditions: [
      { culture: { tr: 'Türk Mitolojisi', en: 'Turkic Mythology' }, meaning: { tr: 'At "yiğidin kanadı" — Dede Korkut destanlarında ayrılmaz yoldaş. Tulpar — uçan kanatlı at, Tanrı bineği.', en: 'The horse is "the hero\'s wing" — the inseparable companion in the Dede Korkut epics. Tulpar — the flying winged horse, the divine mount.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Pegasus — Medusa\'nın kanından doğan kanatlı at. İlham perilerinin bineği. Şair-savaşçı sembolü.', en: 'Pegasus — the winged horse born of Medusa\'s blood. Mount of the Muses. Symbol of the poet-warrior.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Epona — at tanrıçası. Ölülerin ruhlarını öteye taşıyan rehber.', en: 'Epona — the horse goddess. The guide who carries the souls of the dead to the beyond.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Ashvamedha — at kurbanı kralın kozmik egemenliği için. Vishnu\'nun Kalki avatarı beyaz at üstündedir.', en: 'Ashvamedha — the horse sacrifice for the king\'s cosmic sovereignty. Vishnu\'s Kalki avatar rides a white horse.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Vahiy kitabında dört atlı — fetih, savaş, kıtlık, ölüm. Apokaliptik haberci.', en: 'The four horsemen of Revelation — conquest, war, famine, death. Apocalyptic messengers.' } },
    ],
    myths: [
      { tr: 'Pegasus ve Bellerophon: Bellerophon kanatlı Pegasus\'u ehlileştirir, Khimera canavarını öldürür. Ama Olympos\'a çıkmaya kalkınca Zeus onu düşürür — kibrin cezası.', en: 'Pegasus and Bellerophon: Bellerophon tames the winged Pegasus and slays the Chimera. But when he tries to ascend to Olympus, Zeus throws him down — the punishment of hubris.' },
      { tr: 'Dede Korkut\'ta At: "Yiğidin başı omuzun üstünde, yiğidin atı yanı başında." Anadolu kahramanı ile atı arasındaki kardeşlik.', en: 'The Horse in Dede Korkut: "The hero\'s head upon his shoulders, the hero\'s horse at his side." The brotherhood between the Anatolian hero and his horse.' },
    ],
  },

  // ─── a004 Turna ─────────────────────────────────────────────────────────
  a004: {
    jung: { tr: '"Sadık Hac Yolcusu" arketipi. Turna, döngüsel uzun yolculuğun, kararlılığın ve sadakatin sembolü. Aşk için göç eden kalp.', en: 'The "Faithful Pilgrim" archetype. The crane is a symbol of the cyclical long journey, determination, and loyalty. The heart that migrates for love.' },
    dream: { tr: 'Turna rüyada — uzun bekleyişlerin meyvesinin yaklaştığını söyler. Sürü hâlinde uçuyorsa: dostluk/topluluk bir şey kuruyor. Yalnızsa: sevdiğine yöneliş.', en: 'A crane in dream — tells you the fruit of long waiting is near. Flying in a flock: friendship/community is building something. Alone: turning toward your beloved.' },
    shadow: { tr: 'Bir ümitle ömür boyu beklemek. Turna döngüsü kararlılık olabilir, ama gerçeklikten kaçışsa — donmuş hayat.', en: 'Waiting a lifetime on a single hope. The crane\'s cycle may be determination, but if it is flight from reality — a frozen life.' },
    whenAppears: { tr: 'Uzun ayrılık sonrası kavuşmada, evlilik/sözleşme öncesinde, sabırla beklenmiş bir habere yakın.', en: 'At a reunion after long separation, before marriage or covenant, near news patiently awaited.' },
    traditions: [
      { culture: { tr: 'Alevi-Bektaşi', en: 'Alevi-Bektashi' }, meaning: { tr: 'Hz. Ali\'nin kutsal kuşu. Semah\'ta turna duruşu — kanatların aşk için açılışı. Cemde rehber kuş.', en: 'The sacred bird of Imam Ali. The crane posture in the Semah — wings opening for love. The guide-bird of the cem ceremony.' } },
      { culture: { tr: 'Türk Halk', en: 'Turkish Folk' }, meaning: { tr: '"Turnalar geldi" ezgisi — sevdiğine haber, gurbet kavuşması. Anadolu\'nun en içli kuşu.', en: 'The "Cranes have come" song — news to the beloved, reunion from exile. Anatolia\'s most soulful bird.' } },
      { culture: { tr: 'Japonya', en: 'Japanese' }, meaning: { tr: 'Tsuru — 1000 yıl yaşar, uzun ömür sembolü. 1000 turna katlamak (senbazuru) — bir dileğin kabulü.', en: 'Tsuru — lives 1,000 years, symbol of longevity. Folding 1,000 cranes (senbazuru) — the granting of a wish.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Taoist ölümsüzlerin bineği. Erdem ve bilgelik sembolü.', en: 'Mount of the Taoist immortals. Symbol of virtue and wisdom.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Hermes\'in alfabesi turnaların uçuş dizilişinden. Yazının habercisi.', en: 'Hermes\'s alphabet came from the flight formations of cranes. Herald of writing.' } },
    ],
    myths: [
      { tr: 'Pir Sultan ve Turnalar: "Yürü bre Hızır Paşa / Senin de çarkın kırılır" — Anadolu\'da turnalar Pir Sultan\'a haber taşıyan, sözü ileten kuşlar.', en: 'Pir Sultan and the Cranes: "Go forth, Hızır Pasha / Your wheel too shall break" — in Anatolia, cranes are the birds that bear news and carry the word to Pir Sultan.' },
      { tr: 'Senbazuru: Hiroshima\'da bombadan etkilenen Sadako adlı kız iyileşmek için 1000 turna katlamaya başlar. Hikayesi dünyada barış sembolü olur.', en: 'Senbazuru: Sadako, a girl affected by the Hiroshima bombing, begins folding 1,000 cranes to heal. Her story becomes a worldwide symbol of peace.' },
    ],
  },

  // ─── a005 Hüma Kuşu ─────────────────────────────────────────────────────
  a005: {
    jung: { tr: '"Kutsal Kader" arketipi. Hüma, kişiyi seçen ilahi mukadderatın sembolü — gölgesi başına düşene saltanat veren mitik kuş.', en: 'The "Sacred Destiny" archetype. Huma is the symbol of divine fate that chooses a person — the mythic bird that bestows sovereignty upon whoever its shadow falls on.' },
    dream: { tr: 'Hüma rüyada — bir lütfun, beklenmedik bir nimetin yaklaştığını söyler. Üstüne konuyorsa: kaderin sana yöneliyor. Yüksekten geçiyorsa: izle, takip et.', en: 'Huma in dream — tells you a grace, an unexpected blessing, is near. If it lands on you: destiny turns toward you. If it passes overhead: watch, follow.' },
    shadow: { tr: 'Kaderi beklemek için hareket etmemek. "Hüma kuşum nerede?" diye oturup hayatı kaçırmak. Mistik bir bahane.', en: 'Not acting while waiting for fate. Sitting and asking "Where is my Huma?" while missing life. A mystical excuse.' },
    whenAppears: { tr: 'Beklenmedik bir fırsat çıkmadan önce, hak ettiğin tanınma anında, kader anlarında.', en: 'Before an unexpected opportunity arises, at the moment of the recognition you deserve, in moments of destiny.' },
    traditions: [
      { culture: { tr: 'Pers/İran', en: 'Persian/Iranian' }, meaning: { tr: 'Hümay-i Saadet — saadet kuşu. Asla yere konmaz, hep havadadır. Gölgesi başa düşene padişahlık nasip olur.', en: 'Humay-i Saadet — the bird of felicity. Never lands, ever airborne. Whoever its shadow falls upon is destined for kingship.' } },
      { culture: { tr: 'Türk-İslam', en: 'Turco-Islamic' }, meaning: { tr: 'Osmanlı sarayında "Hüma" bahtın simgesi. Tahta çıkacak şehzadeyi belirleyen kutsal kuş.', en: 'In the Ottoman court, Huma was the symbol of fortune. The sacred bird that designated which prince would ascend the throne.' } },
      { culture: { tr: 'Sufi', en: 'Sufi' }, meaning: { tr: 'Yüksekte uçar, asla durmaz — "tarikat-ı seyr" sembolü. Aşkın kuşu hep yolda.', en: 'Flies high, never stopping — the symbol of "the path of wayfaring". The bird of love is ever on the road.' } },
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Garuda\'nın akrabası — gökyüzü tanrılarının habercisi.', en: 'A kin of Garuda — herald of the sky gods.' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: '"Hüma kuşunun gölgesi başına düşsün" duası — büyük kısmet temennisi.', en: '"May the shadow of the Huma fall upon you" — a blessing wishing great fortune.' } },
    ],
    myths: [
      { tr: 'Hüma ve Sultan: Anadolu efsanesinde tahta çıkacak şehzadeyi seçmek için Hüma kuşu salınır. Kimin başına gölgesi düşerse o sultan olur — kader önceden bellidir, ama kuşun seçimine güven gerekir.', en: 'Huma and the Sultan: In Anatolian legend, the Huma bird is released to choose which prince will ascend the throne. Whoever its shadow falls upon becomes sultan — destiny is foreordained, yet one must trust the bird\'s choice.' },
      { tr: 'Attar\'ın Hüması: "Mantık-üt Tayr"da Hüma ölümsüzlüğün ve göklerin kuşudur — Simurg\'a ulaşmaya çalışan otuz kuşun rehberlerinden.', en: 'Attar\'s Huma: In "The Conference of the Birds," Huma is the bird of immortality and the heavens — one of the guides for the thirty birds seeking the Simurgh.' },
    ],
  },

  // ─── a006 Anka ──────────────────────────────────────────────────────────
  a006: {
    jung: { tr: '"Ölüm-Diriliş" arketipi. En radikal dönüşüm sembolü. Eski benlik ölmeden yeni doğamaz — ateş hem yıkıcı hem yaratıcı.', en: 'The "Death-Rebirth" archetype. The most radical symbol of transformation. The new cannot be born until the old Self dies — fire is both destroyer and creator.' },
    dream: { tr: 'Anka rüyada — bir döngünün sona ermesi gerekiyor. Yanıyorsa: dirilişin eşiğindesin. Küllerden çıkıyorsa: çoktan dönüştün, sadece bunu kabul et.', en: 'Phoenix in dream — a cycle must end. If it burns: you are on the threshold of resurrection. If it rises from ashes: you have already transformed, only accept it.' },
    shadow: { tr: 'Sürekli kriz yaratma. "Kendini yakıp yeniden doğmak" bir yaşam biçimi olursa — stabilite kaybedilir. Drama bağımlılığı.', en: 'Constantly creating crisis. If "burning oneself and being reborn" becomes a way of life — stability is lost. Addiction to drama.' },
    whenAppears: { tr: 'Ciddi bir kayıp sonrası, mesleki çöküşte, kimlik krizinde, "bu kadar yeter" dediğin anda.', en: 'After a serious loss, in professional collapse, in identity crisis, at the moment you say "enough".' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Phoenix — 500 yılda bir kendini yakıp küllerinden doğan kuş. Helios\'a adanmış.', en: 'Phoenix — the bird that immolates itself and is reborn from its ashes every 500 years. Dedicated to Helios.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Bennu — Ra\'nın kuşu. Heliopolis tapınağında her gün yeniden doğan güneş ruhu.', en: 'Bennu — Ra\'s bird. The solar spirit reborn each day in the temple of Heliopolis.' } },
      { culture: { tr: 'İslam-Sufi', en: 'Islamic-Sufi' }, meaning: { tr: 'Simurg — Attar\'ın eserinde 30 kuş Simurg\'u arar. Sonunda fark ederler ki: 30 kuş kendileridir (Si=30, Murg=kuş).', en: 'Simurgh — in Attar\'s work, thirty birds seek the Simurgh. In the end they realize: the thirty birds are themselves (Si = thirty, Murgh = bird).' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Fenghuang — uyum, erdem ve barış sembolü. İmparatoriçenin kuşu.', en: 'Fenghuang — symbol of harmony, virtue, and peace. The empress\'s bird.' } },
      { culture: { tr: 'Türk Mitolojisi', en: 'Turkic Mythology' }, meaning: { tr: 'Tuğrul/Anka — Türk hanedanlarının amblemi. Saltanatın ölümsüzlüğü.', en: 'Tuğrul/Anka — emblem of the Turkic dynasties. The immortality of sovereignty.' } },
    ],
    myths: [
      { tr: 'Attar\'ın Simurg\'u: Dünyanın bütün kuşları kralları Simurg\'u bulmak için yolculuğa çıkar. Tehlikeli vadileri geçerler, çoğu ölür. Sonunda 30 kuş kalır ve aynaya bakarlar — Simurg kendileridir. Sufi\'de "kendini bulma"nın en güçlü metaforu.', en: 'Attar\'s Simurgh: All the world\'s birds set out to find their king, the Simurgh. They cross perilous valleys; most perish. In the end, thirty birds remain and look into a mirror — the Simurgh is themselves. In Sufism, the most powerful metaphor for self-realization.' },
      { tr: 'Mısır Bennu Kuşu: Her sabah Heliopolis tapınağında güneşle birlikte doğan, akşam ölüp tekrar dirilen kutsal kuş. Tanrı Ra\'nın ruhu.', en: 'The Egyptian Bennu Bird: The sacred bird reborn each morning with the sun in the temple of Heliopolis, dying each evening only to rise again. The soul of the god Ra.' },
    ],
  },

  // ─── a007 Geyik ─────────────────────────────────────────────────────────
  a007: {
    jung: { tr: '"Kalbin Habercisi" arketipi. Geyik anima/animus köprüsü — vahşi olduğu kadar nazik, kaçtığı kadar yaklaşan. Maskülen-feminen dengesinin sembolü.', en: 'The "Herald of the Heart" archetype. The deer is the Anima/Animus bridge — as wild as it is gentle, as fleeing as it is approaching. Symbol of the masculine-feminine balance.' },
    dream: { tr: 'Geyik rüyada görünürse — kalp meselesi açılıyor demektir. Geyiği takip ediyorsan, ruhun bir sevgiye yönlendiriliyor. Kaçıyorsa, korkuyorsun.', en: 'If a deer appears in dream — a matter of the heart is opening. If you follow the deer, your soul is being guided toward a love. If it flees, you are afraid.' },
    shadow: { tr: 'Aşırı hassasiyet. Hep tetikte yaşamak. Sürekli kaçış halinde olmak savunma değil, hapis olur.', en: 'Excessive sensitivity. Living always on edge. Being in constant flight becomes not defense but imprisonment.' },
    whenAppears: { tr: 'Şefkat sınavında, vahşi ile nazik arasında seçim yaparken, sürpriz bir aşk veya kalp açılışında.', en: 'In a test of tenderness, while choosing between wild and gentle, at a surprise love or opening of the heart.' },
    traditions: [
      { culture: { tr: 'Türk Mitolojisi', en: 'Turkic Mythology' }, meaning: { tr: 'Hakan Oğuz Han\'a yol gösteren kutsal ak geyik. Devleti kuran rehber.', en: 'The sacred white deer that guided Oğuz Khan. The guide who founded the state.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Cernunnos — boynuzlu geyik tanrısı. Vahşi doğanın kralı, döngüsel ölüm-doğum.', en: 'Cernunnos — the horned stag god. King of wild nature, cyclical death and birth.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Aziz Eustace\'in görmesi — boynuzları arasında haç taşıyan geyik. İlahi çağrı.', en: 'The vision of Saint Eustace — a stag bearing a cross between its antlers. The divine summons.' } },
      { culture: { tr: 'Şamanik', en: 'Shamanic' }, meaning: { tr: 'Sibirya şamanları ruhlar alemine geyikle yolculuk eder. Üç dünya arasında köprü.', en: 'Siberian shamans journey to the spirit realm on the deer. A bridge between the three worlds.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Artemis\'in kutsal hayvanı. Bakire avcı tanrıçanın bineği ve simgesi.', en: 'Artemis\'s sacred animal. Mount and emblem of the virgin huntress goddess.' } },
    ],
    myths: [
      { tr: 'Oğuz Han Destanı: Oğuz Han avlanırken karşısına bir ak geyik çıkar, onu izleyerek yeni topraklara ulaşır ve devletini kurar.', en: 'The Oğuz Khan Epic: While hunting, Oğuz Khan encounters a white deer; following it, he reaches new lands and founds his state.' },
      { tr: 'Aziz Eustace: Romalı bir general avlanırken bir geyikle karşılaşır, boynuzları arasında haç görür — bu görüntüyle Hristiyanlığa geçer.', en: 'Saint Eustace: While hunting, a Roman general encounters a stag and sees a cross between its antlers — by this vision he converts to Christianity.' },
    ],
  },

  // ─── a008 Baykuş ────────────────────────────────────────────────────────
  a008: {
    jung: { tr: '"Bilge Yaşlı" arketipi — Senex. Karanlıkta görme yeteneği; bilinçaltını okuma kapasitesi. Gece zekası.', en: 'The "Wise Elder" archetype — Senex. The ability to see in darkness; the capacity to read the unconscious. Nocturnal intelligence.' },
    dream: { tr: 'Baykuş rüyada — bir sırrın çözülmek üzere olduğunu söyler. Ya da bir aldatma fark ediliyor. Baykuşun bakışı: gerçeği görme zamanı geldi.', en: 'Owl in dream — says a secret is about to be unraveled. Or a deception is being noticed. The owl\'s gaze: the time to see the truth has come.' },
    shadow: { tr: 'Kötümser bilgelik. Her şeyi "görmek" insanı yalnızlaştırırsa baykuş — küskün münzeviye dönüşür. Bilgi acıya dönüşür.', en: 'Pessimistic wisdom. If "seeing everything" isolates a person, the owl turns into a resentful hermit. Knowledge becomes pain.' },
    whenAppears: { tr: 'Aldatıldığında, gizli bir gerçek hissettiğinde, içe çekilme döneminde, sezgin keskinleştiğinde.', en: 'When you are deceived, when you sense a hidden truth, in a period of withdrawal, when your intuition sharpens.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Athena\'nın kuşu. Bilgelik tanrıçasının zeka simgesi. Atina sikkelerinde basılı.', en: 'Athena\'s bird. Symbol of the wisdom goddess\'s intellect. Stamped on Athenian coins.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Ölüler diyarının bekçisi. Geçişin ve gece âleminin hayvanı.', en: 'Guardian of the land of the dead. Animal of transition and the nocturnal realm.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Hopi geleneğinde uyarıcı — kötü haberi taşıyan ama doğruyu söyleyen.', en: 'In Hopi tradition, the warner — bearer of bad news yet speaker of truth.' } },
      { culture: { tr: 'Türk Halk İnancı', en: 'Turkish Folk Belief' }, meaning: { tr: 'Anadolu\'da uğursuz sayılan ama gerçekte kadim bilgeliği taşıyan. Atalardan miras zihinsel direnç.', en: 'In Anatolia regarded as ill-omened, yet truly the bearer of ancient wisdom. Mental endurance inherited from the ancestors.' } },
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Lakshmi\'nin bineği. Bolluk tanrıçasının gözleri — karanlıkta bile bereketi görür.', en: 'Lakshmi\'s mount. The eyes of the goddess of abundance — sees prosperity even in darkness.' } },
    ],
    myths: [
      { tr: 'Athena ve Baykuş: Bilgelik tanrıçası Athena\'nın omzunda taşıdığı baykuş, sahibinin sezgilerini ve görüsünü taşır. Atina\'nın sembolü.', en: 'Athena and the Owl: The owl carried on the shoulder of Athena, goddess of wisdom, bears its mistress\'s intuition and vision. Symbol of Athens.' },
      { tr: 'Anadolu\'da Baykuş: "Baykuş öttü, kötü oldu" inanışı yüzyıllar boyu sürmüş — ama gerçek şaman geleneğinde baykuş atadan haberdir.', en: 'The Owl in Anatolia: The belief "the owl hooted, ill has come" lasted centuries — but in true shamanic tradition the owl is a message from the ancestors.' },
    ],
  },

  // ─── a009 Aslan ─────────────────────────────────────────────────────────
  a009: {
    jung: { tr: '"Kral" arketipi. Sezar, Pir, Hükümdar. İçsel otoritenin sembolü. Egoyu hizmete dönüştürme gücü.', en: 'The "King" archetype. Caesar, Pir, Sovereign. Symbol of inner authority. The power to transform ego into service.' },
    dream: { tr: 'Aslan rüyada — içindeki kral uyanıyor. Üzerine atıyor mu? Bastırdığın bir gücün geri istiyor. Yanında yatıyor mu? Otoritene barıştın.', en: 'Lion in dream — the king within you awakens. Does it pounce? A force you have suppressed wants itself back. Does it lie beside you? You have made peace with your authority.' },
    shadow: { tr: 'Kibir ve narsisizm. Kral arketipi denetlenmezse — tiranlık, açlık doymayan ego, gösteriş için var olma.', en: 'Arrogance and narcissism. When the King archetype goes unchecked — tyranny, an ego whose hunger is never sated, existing for display.' },
    whenAppears: { tr: 'Otorite sınavında, lider olarak çıkma zamanında, haksızlığa uğradığında, sesini yükseltmen gerekirken.', en: 'In a test of authority, when it is time to rise as a leader, when you have been wronged, when you must raise your voice.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Sekhmet — aslan başlı tanrıça. Şiddetli iyileştirici. Sahmet adaletin koruyucusu.', en: 'Sekhmet — the lion-headed goddess. Fierce healer. Sekhmet, guardian of justice.' } },
      { culture: { tr: 'Hitit', en: 'Hittite' }, meaning: { tr: 'Tapınak bekçisi. Anadolu\'da Hattuşa kapılarında taş aslanlar — sınırın koruyucuları.', en: 'Temple guardian. In Anatolia, the stone lions at the gates of Hattusa — protectors of the threshold.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Aziz Markos\'un sembolü. Diriliş ve İsa\'nın krallığı. "Yahuda\'nın aslanı".', en: 'Symbol of Saint Mark. Resurrection and the kingship of Christ. The "Lion of Judah".' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Narasimha — Vishnu\'nun aslan-insan avatarı. Adaletsizliği yıkıcı kutsal öfke.', en: 'Narasimha — Vishnu\'s lion-man avatar. Holy wrath destructive of injustice.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Nemea aslanı — Herakles\'in ilk işi. Bastırılması gereken vahşi güç.', en: 'The Nemean Lion — Heracles\'s first labor. The wild force that must be subdued.' } },
    ],
    myths: [
      { tr: 'Sekhmet: Mısır mitolojisinde insanları kötülüklerinden temizlemek için gönderilen aslan başlı tanrıça. Hem yıkıcı hem de şifa veren güç.', en: 'Sekhmet: In Egyptian mythology, the lion-headed goddess sent to purge humanity of its evils. A force both destructive and healing.' },
      { tr: 'Hitit Aslan Kapısı: Bu aslanlar 3500 yıldır şehri korumaya devam ediyor — Anadolu\'nun ilk kralları aslanı sınırın bekçisi yaptı.', en: 'The Hittite Lion Gate: These lions have guarded the city for 3,500 years — the first kings of Anatolia made the lion the keeper of the threshold.' },
    ],
  },

  // ─── a010 Ayı ──────────────────────────────────────────────────────────
  a010: {
    jung: { tr: '"Büyük Ana" arketipi — kollayıcı, besleyici, ama sınırını çiğnemeye gelen olursa yıkıcı. İçsel kaynaklara çekilme.', en: 'The "Great Mother" archetype — protective, nourishing, yet destructive if her boundary is crossed. Withdrawal into inner resources.' },
    dream: { tr: 'Ayı rüyada — uyku, dinlenme, içe dönüşe çağrı. Saldırıyorsa: bir sınırın çiğneniyor. Yavrularını koruyorsa: kendine ait olanı savunmalısın.', en: 'Bear in dream — a call to sleep, rest, turning inward. If attacking: a boundary of yours is being crossed. If protecting cubs: you must defend what is yours.' },
    shadow: { tr: 'Aşırı içekapanma, depresyon, hibernasyonun bitmemesi. Ayı uyandığında çıkmazsa — soğukta donar.', en: 'Excessive withdrawal, depression, hibernation that never ends. If the bear does not emerge when it wakes — it freezes in the cold.' },
    whenAppears: { tr: 'Sosyal yorgunlukta, bir krizden sonra şifaya çekildiğinde, koruyucu enerjini bulman gerekirken.', en: 'In social exhaustion, when withdrawing to heal after a crisis, when you must find your protective energy.' },
    traditions: [
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Şifa hayvanı. Tıp adamları "Ayı Tıbbı" toplar. Mağaraya çekilip rüyada öğrenme.', en: 'The healing animal. Medicine people gather "Bear Medicine". Withdrawing into the cave to learn in dream.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Artos — savaşçı kraliçenin sembolü. Kral Arthur\'un adı buradan gelir.', en: 'Artos — symbol of the warrior queen. The name of King Arthur derives from this.' } },
      { culture: { tr: 'Sibirya/Şamanik', en: 'Siberian/Shamanic' }, meaning: { tr: 'Ayı törenleri — avlandıktan sonra ruhuna saygı duruşu. Atalar ayıdan türemiş kabul edilir.', en: 'Bear ceremonies — a salute to the bear\'s spirit after the hunt. Ancestors are held to descend from the bear.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Artemis\'in formu. Kalypso\'nun mağarası — ayı annenin sığınağı.', en: 'A form of Artemis. Calypso\'s cave — the sanctuary of the bear-mother.' } },
      { culture: { tr: 'İskandinav', en: 'Norse' }, meaning: { tr: 'Berserkir — savaşçılar ayı postu giyerek savaş çılgınlığına girer. Vahşi koruyucu güç.', en: 'Berserkir — warriors entering battle-frenzy by donning bear skins. Wild protective power.' } },
    ],
    myths: [
      { tr: 'Kallisto: Yunan mitolojisinde Artemis\'in nymph\'i. Zeus\'la birleştiği için ayıya dönüştürülüp gökyüzüne fırlatılır — Büyük Ayı takımyıldızı olur.', en: 'Callisto: In Greek mythology, a nymph of Artemis. For uniting with Zeus, she is transformed into a bear and cast into the sky — becoming the constellation Ursa Major.' },
      { tr: 'Şamanik Ayı Töreni: Sibirya\'da avlanan ayının ruhuna özür dilenir, eti törensel paylaşılır. Ayı atadır, kabul edilir.', en: 'The Shamanic Bear Ceremony: In Siberia, apology is offered to the soul of the hunted bear, and its meat is shared ceremonially. The bear is acknowledged as ancestor.' },
    ],
  },

  // ─── a011 Tilki ─────────────────────────────────────────────────────────
  a011: {
    jung: { tr: '"Hilebaz/Trickster" arketipi. Kuralları sorgulayan, beklenmedik yoldan çözüm bulan zeka. Logosa karşı mythos.', en: 'The "Trickster" archetype. An intelligence that questions rules and finds solutions on unexpected paths. Mythos against Logos.' },
    dream: { tr: 'Tilki rüyada — bir durumda dolambaçlı yola gitmeni söylüyor. Direkt yaklaşma çözmüyor. Ya da: biri seni kandırıyor, gözünü aç.', en: 'Fox in dream — tells you to take the indirect path in a situation. The direct approach is not working. Or: someone is deceiving you — open your eyes.' },
    shadow: { tr: 'Manipülasyon ve sahtekarlık. Zeka etik olmaksızın kullanılırsa tilki — yolsuz politikacı, dolandırıcı.', en: 'Manipulation and dishonesty. Intelligence used without ethics turns the fox into the corrupt politician, the swindler.' },
    whenAppears: { tr: 'Doğrudan yaklaşımın işe yaramadığı bir durumda, yaratıcı stratejiye ihtiyaç duyduğunda, oyunun kurallarını yeniden yazman gereken anda.', en: 'In a situation where the direct approach fails, when you need creative strategy, when you must rewrite the rules of the game.' },
    traditions: [
      { culture: { tr: 'Japonya', en: 'Japanese' }, meaning: { tr: 'Kitsune — dokuz kuyruklu tilki ruhu. Şekil değiştirir, ya yardım eder ya tuzak kurar. İnari tanrıçanın habercisi.', en: 'Kitsune — the nine-tailed fox spirit. A shapeshifter who either aids or sets traps. Messenger of the goddess Inari.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Coyote (kuzen ruh) — yaratıcı ve yıkıcı. Dünyaya hem akıl hem kaos getiren.', en: 'Coyote (kin-spirit) — creator and destroyer. The one who brought both reason and chaos to the world.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Diplomasi ve sezginin sembolü. Druidler tilki tüyüyle rüya gönderir.', en: 'Symbol of diplomacy and intuition. The Druids sent dreams using fox fur.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Halk masallarında daima kazanan zeki kahraman. "Aklını kullanan tilki, zorlukları aşar."', en: 'In folk tales, the clever hero who always wins. "The fox who uses its wits overcomes hardship."' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Hu jing — bin yaşına ulaşan tilki insana dönüşür. Şehvet ve hile sembolü.', en: 'Hu jing — a fox that reaches a thousand years turns into a human. Symbol of lust and deceit.' } },
    ],
    myths: [
      { tr: 'Kitsune Efsaneleri: Japonya\'da bir tilkinin 100 yaşına gelince beyaz olduğu, 1000 yaşına gelince 9 kuyruk açtığı ve tanrısallaştığı söylenir.', en: 'Kitsune Legends: In Japan it is said that at 100 years a fox turns white, and at 1,000 years it unfurls nine tails and becomes divine.' },
      { tr: 'Aesop\'un Tilkisi: "Üzümlere ulaşamayınca ekşi olduğunu söyleyen tilki" — Batı medeniyetinin en eski hilebaz hikayesi.', en: 'Aesop\'s Fox: "The fox who, unable to reach the grapes, calls them sour" — Western civilization\'s oldest trickster tale.' },
    ],
  },

  // ─── a012 Yunus ─────────────────────────────────────────────────────────
  a012: {
    jung: { tr: '"Sevinç Rehberi" arketipi. Yunus, duygu denizinde özgürce yüzen bilinç — neşeyle bilgelik aynı bedende.', en: 'The "Joy-Guide" archetype. The dolphin is consciousness swimming freely in the sea of feeling — joy and wisdom in one body.' },
    dream: { tr: 'Yunus rüyada — duygusal akış geri geldi. Suyun üzerinden atlıyorsa: kalbin neşeleniyor. Sana eşlik ediyorsa: yalnız değilsin, ruh dostları yakın.', en: 'Dolphin in dream — emotional flow has returned. Leaping above the water: your heart is rejoicing. Accompanying you: you are not alone, soul friends are near.' },
    shadow: { tr: 'Hep iyimser görünme baskısı. Her şeyi "neşeyle" karşılamaya çalışmak, gerçek acıyı bastırırsa — yunus boğulur.', en: 'The pressure to always appear optimistic. If meeting everything "with joy" suppresses real pain — the dolphin drowns.' },
    whenAppears: { tr: 'Uzun bir hüzünden sonra, çocuksu sevincini geri istediğinde, suyla/denizle iletişiminin açıldığı anda.', en: 'After a long sorrow, when you want your childlike joy back, at the moment communion with water or sea opens.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Apollon\'un kutsal hayvanı. Boğulanları kurtaran rehber. Delphi tapınağının habercisi.', en: 'Apollo\'s sacred animal. The guide who rescues the drowning. Herald of the temple of Delphi.' } },
      { culture: { tr: 'Sumer', en: 'Sumerian' }, meaning: { tr: 'Enki — bilgelik tanrısı yunusla yolculuk eder. Tatlı su ve bilgeliğin kuşağı.', en: 'Enki — the god of wisdom travels with the dolphin. The companion of fresh water and wisdom.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Mesih sembolü — denizden insanı çıkaran kurtarıcı. Erken katakomblarda sık çizilen motif.', en: 'Symbol of the Messiah — the savior who draws humanity from the sea. A frequent motif in the early catacombs.' } },
      { culture: { tr: 'Maori', en: 'Maori' }, meaning: { tr: 'Taniwha — denizin ruhu, kabilenin koruyucusu. Yardım çağrısına gelir.', en: 'Taniwha — spirit of the sea, protector of the tribe. Comes when called for aid.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Akdeniz halklarının dost ruhu. Balıkçılara yol gösteren akrabası.', en: 'Friend-spirit of Mediterranean peoples. A kin who guides fishermen.' } },
    ],
    myths: [
      { tr: 'Arion ve Yunus: Yunan şairi Arion gemiciler tarafından denize atılır, bir yunus onu sırtında alıp kıyıya götürür. Sanat ve doğa arasındaki kardeşliğin sembolü.', en: 'Arion and the Dolphin: The Greek poet Arion is thrown into the sea by sailors; a dolphin takes him on its back to shore. A symbol of the kinship between art and nature.' },
      { tr: 'Yunus Emre ve Adı: Bir rivayete göre Yunus Emre adını, Yunus peygamberin balıktan çıkışı gibi içsel bir dirilişten alır — derinden yüzeye gelen aşk.', en: 'Yunus Emre and His Name: According to one tradition, the Sufi poet Yunus Emre takes his name from an inner resurrection like the prophet Jonah\'s emergence from the fish — love rising from the depths to the surface.' },
    ],
  },

  // ─── a013 Kaplumbağa ────────────────────────────────────────────────────
  a013: {
    jung: { tr: '"Kadim Bilge" arketipi. Yavaş, sabırlı, uzun ömürlü. Kabuğunu evine taşıyan — içsel istikrarın sembolü.', en: 'The "Ancient Sage" archetype. Slow, patient, long-lived. The one who carries its home as its shell — symbol of inner stability.' },
    dream: { tr: 'Kaplumbağa rüyada — acele etmemen gerekiyor. Kabuğuna çekiliyorsa: korunma zamanı. Yumurtluyorsa: uzun vadeli tohumlar atıyorsun.', en: 'Turtle in dream — you must not rush. Withdrawing into its shell: time for protection. Laying eggs: you are planting long-term seeds.' },
    shadow: { tr: 'Aşırı temkin. "Sonra"ya erteleyerek ömrü tamamlamak. Kaplumbağa hızlıdır kendi yolunda — ama hiç çıkmazsa hapse dönüşür.', en: 'Excessive caution. Completing a lifetime by postponing to "later". The turtle is swift on its own path — but if it never emerges, the shell becomes a prison.' },
    whenAppears: { tr: 'Acele kararlardan vazgeçmen gerektiğinde, uzun soluklu projelerde, yaşlılık bilgeliğine açıldığında.', en: 'When you must renounce hasty decisions, in long-haul projects, when opening to the wisdom of age.' },
    traditions: [
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Dört kutsal hayvandan biri (Xuanwu). Kuzey, kış, su ve uzun ömrün koruyucusu. Yaratılışın temeli.', en: 'One of the Four Sacred Animals (Xuanwu). Guardian of the north, winter, water, and longevity. The foundation of creation.' } },
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Vishnu\'nun Kurma avatarı — okyanus çalkalanırken dünyayı sırtında taşıyan kaplumbağa.', en: 'Vishnu\'s Kurma avatar — the turtle bearing the world on its back during the churning of the ocean.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: '"Kaplumbağa Adası" — Kuzey Amerika kıtasının atası. Dünyanın kendisi onun sırtında.', en: '"Turtle Island" — the ancestor of the North American continent. The world itself rests on its back.' } },
      { culture: { tr: 'Afrika', en: 'African' }, meaning: { tr: 'Anansi masallarında zeki kahraman. Yavaşlığın altında gizli akıl.', en: 'In Anansi tales, the clever hero. Hidden cunning beneath slowness.' } },
      { culture: { tr: 'Japonya', en: 'Japanese' }, meaning: { tr: '"Minogame" — 10000 yıl yaşayan kaplumbağa. Uzun ömür ve şansın simgesi.', en: '"Minogame" — the turtle that lives 10,000 years. Symbol of longevity and luck.' } },
    ],
    myths: [
      { tr: 'Kurma Avatarı: Hint mitolojisinde tanrılar ve şeytanlar ölümsüzlük iksiri için okyanusu çalkalar. Vishnu kaplumbağa olur, dağı sırtında destekler — yaratılışın sabit ekseni.', en: 'The Kurma Avatar: In Hindu mythology, gods and demons churn the ocean for the elixir of immortality. Vishnu becomes a turtle and supports the mountain on his back — the steady axis of creation.' },
      { tr: 'Kaplumbağa Adası: Kızılderili kozmolojisinde dünya sular üzerinde yüzen bir kaplumbağanın sırtında durur. Toprak — onun zırhının üstünde toplanmış çamur.', en: 'Turtle Island: In Native American cosmology, the world rests on the back of a turtle floating upon the waters. The earth is mud gathered atop its shell.' },
    ],
  },

  // ─── a014 Yılan ─────────────────────────────────────────────────────────
  a014: {
    jung: { tr: '"Dönüşüm" arketipi. Ouroboros — kuyruğunu yiyen yılan. Ölüm ve doğum aynı ağzın iki ucu. Kundalini enerjisinin omurga boyunca yükseliş hayvanı.', en: 'The "Transformation" archetype. Ouroboros — the serpent devouring its own tail. Death and birth are two ends of the same mouth. The animal of Kundalini energy rising along the spine.' },
    dream: { tr: 'Yılan rüyada — derin bir dönüşüm sürecindesin. Isırıyorsa: bastırdığın bir gerçek seni uyandırıyor. Deri değiştiriyorsa: eski sen ölüyor.', en: 'Serpent in dream — you are in a profound process of transformation. If it bites: a truth you have suppressed is waking you. If it sheds skin: the old self is dying.' },
    shadow: { tr: 'Aldatma, manipülasyon, zehir. Yılan enerjisi dönüştürülmezse — pasif-agresif kontrol, gizli sokuş.', en: 'Deception, manipulation, venom. If serpent energy is not transmuted — passive-aggressive control, hidden striking.' },
    whenAppears: { tr: 'Kimlik değişiminde, eski bir kalıbı bırakırken, derin şifa sürecinde, cinsel uyanışta, ölüm-yas süreçlerinde.', en: 'In identity change, when releasing an old pattern, in deep healing, in sexual awakening, in death-grief processes.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Asklepios\'un asası — şifa tanrısının iki yılanı. Modern tıp sembolü.', en: 'The staff of Asclepius — the two serpents of the god of healing. The modern symbol of medicine.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Wadjet — kobra tanrıça. Firavunların alın koruyucusu. Bilgeliğin gözü.', en: 'Wadjet — the cobra goddess. Protector of the pharaohs\' brow. The eye of wisdom.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Kundalini — omurganın dibinde uyuyan ilahi enerji. Yedi çakra boyunca yükseliş.', en: 'Kundalini — the divine energy asleep at the base of the spine. Ascent through the seven chakras.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Cennetten kovulma — bilginin acı meyvesi. Aynı zamanda Musa\'nın tunç yılanı: şifa.', en: 'Expulsion from Eden — the bitter fruit of knowledge. Yet also Moses\'s bronze serpent: healing.' } },
      { culture: { tr: 'Türk Mitolojisi', en: 'Turkic Mythology' }, meaning: { tr: 'Şahmeran — yılan kraliçesi. Bilgelik, şifa, ölümsüzlük sırrını bilen kadın-yılan.', en: 'Shahmaran — the serpent queen. The woman-serpent who knows the secrets of wisdom, healing, and immortality.' } },
      { culture: { tr: 'Aztek', en: 'Aztec' }, meaning: { tr: 'Quetzalcoatl — tüylü yılan tanrı. Bilgelik, kültür, dönüşümün getiricisi.', en: 'Quetzalcoatl — the feathered serpent god. Bringer of wisdom, culture, and transformation.' } },
    ],
    myths: [
      { tr: 'Şahmeran Efsanesi: Anadolu\'nun en kadim mitlerinden. Mağarada yaşayan, yarı kadın yarı yılan bilgelik kraliçesi. İhanetle ölür, ama suyunu içen kişi büyük bir şifacı olur.', en: 'The Shahmaran Legend: One of Anatolia\'s most ancient myths. The half-woman half-serpent queen of wisdom who lives in a cave. She dies by betrayal, yet whoever drinks her water becomes a great healer.' },
      { tr: 'Kundalini: Hint geleneğinde insanın kuyruk sokumunda uyuyan yılan. Meditasyon ve nefesle uyandırılır, omurga boyunca yükselip taç çakrada aydınlanmaya ulaştırır.', en: 'Kundalini: In Hindu tradition, the serpent asleep at the base of the human spine. Awakened through meditation and breath, it ascends along the spine and brings enlightenment at the crown chakra.' },
    ],
  },

  // ─── a015 Kelebek ───────────────────────────────────────────────────────
  a015: {
    jung: { tr: '"Yeniden Doğan Ruh" arketipi. Psyche — Yunanca hem "ruh" hem "kelebek" anlamına gelir. Bilincin metamorfozu.', en: 'The "Reborn Soul" archetype. Psyche — in Greek means both "soul" and "butterfly". The metamorphosis of consciousness.' },
    dream: { tr: 'Kelebek rüyada — bir dönüşümün tamamlandığını söyler. Yumurtadan tırtıla, krizalitten kelebeğe — şu an hangi aşamadasın?', en: 'Butterfly in dream — tells you a transformation is being completed. Egg to caterpillar, chrysalis to butterfly — which stage are you in now?' },
    shadow: { tr: 'Hafiflik kaçıngana dönüşmek. "Sadece güzelin tarafını al" tutumu — derinliği kaçırma. Kelebek kanat çırpar ama yer çekimini unutur.', en: 'Lightness turning into avoidance. The "only take the beautiful side" stance — missing depth. The butterfly flutters but forgets gravity.' },
    whenAppears: { tr: 'Bir kişilik dönemini bitirip yenisine geçerken, depresyon sonrası uyanışta, yaratıcılığın yeniden açılışında.', en: 'When ending one phase of personality and crossing into another, in awakening after depression, at the reopening of creativity.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Psyche — ruhun bizzat kendisi. Eros\'la aşkı: ruhun aşkı arayışı.', en: 'Psyche — the soul itself. Her love with Eros: the soul\'s search for love.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'İki kelebek — Zhuangzi\'nin meşhur rüyası: "Ben kelebek mi olduğumu rüyada gören insanım, yoksa insan olduğunu rüyada gören kelebek miyim?"', en: 'Two butterflies — Zhuangzi\'s famous dream: "Am I a man who dreamed of being a butterfly, or a butterfly dreaming of being a man?"' } },
      { culture: { tr: 'Aztek', en: 'Aztec' }, meaning: { tr: 'Itzpapalotl — obsidyen kelebek tanrıça. Savaşçı ruhların eşlikçisi.', en: 'Itzpapalotl — the obsidian butterfly goddess. Companion of warrior souls.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Ölmüş yakının ruhunun ziyareti. Mezarlıkta kelebek görmek — atalar konuşuyor.', en: 'The visit of a deceased loved one\'s soul. To see a butterfly in a cemetery — the ancestors are speaking.' } },
      { culture: { tr: 'Japonya', en: 'Japanese' }, meaning: { tr: 'Aşkın simgesi. İki kelebek bir arada — sadık eşler.', en: 'Symbol of love. Two butterflies together — faithful spouses.' } },
    ],
    myths: [
      { tr: 'Eros ve Psyche: Aşk tanrısı Eros\'a aşık olan ölümlü kız Psyche\'nin sınavları. Aşk ruhu arıyor, ruh aşkı arıyor — sonunda Olympos\'a yükseliyor.', en: 'Eros and Psyche: The trials of the mortal girl Psyche, in love with the god of love Eros. Love seeks the soul, the soul seeks love — at last she ascends to Olympus.' },
      { tr: 'Zhuangzi\'nin Rüyası: Çinli Taocu filozofun en ünlü hikayesi — rüyada kelebek olur, uyandığında hangisinin gerçek olduğundan emin olamaz.', en: 'Zhuangzi\'s Dream: The most famous story of the Chinese Taoist philosopher — he becomes a butterfly in dream, and upon waking cannot be sure which is real.' },
    ],
  },

  // ─── a016 Tavus ─────────────────────────────────────────────────────────
  a016: {
    jung: { tr: '"Görkemli Benlik" arketipi. Tavus kuşu — ifşa edilmiş güzellik, görünmeye cesaret eden ego.', en: 'The "Magnificent Self" archetype. The peacock — beauty unveiled, the ego that dares to be seen.' },
    dream: { tr: 'Tavus rüyada — kendini göstermek için izin alıyorsun. Kuyruğunu açıyorsa: sahip olduğun değeri kabul et. Kapalıysa: gücünü saklıyorsun.', en: 'Peacock in dream — you are seeking permission to show yourself. Spreading its tail: accept the worth you possess. Closed: you are hiding your power.' },
    shadow: { tr: 'Kibir, gösteriş, sahte parlaklık. Tavus enerjisi savunmasızlığını kaybederse — yalnız gösterişin içinde donar.', en: 'Vanity, display, false brilliance. If peacock energy loses its vulnerability — it freezes within mere show.' },
    whenAppears: { tr: 'Sahneye çıkma anında, görünür olma fırsatında, içsel güzelliğin tanınma talebinde.', en: 'At the moment of stepping onto the stage, at the chance to become visible, in the demand for inner beauty to be recognized.' },
    traditions: [
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Sarasvati\'nin bineği — sanat ve bilgi tanrıçası. Kartikeya\'nın da kuşu.', en: 'Mount of Saraswati — goddess of arts and knowledge. Also the bird of Kartikeya.' } },
      { culture: { tr: 'Yezidi', en: 'Yazidi' }, meaning: { tr: 'Melek Tavus — Yezidiliğin merkezi figürü. Tanrı\'nın yeryüzündeki yansıması.', en: 'Melek Taus — the central figure of Yazidism. The reflection of God upon earth.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Hera\'nın kuşu. Argos\'un yüz gözünü tüylerine işler — uyanıklık ve sadakat.', en: 'Hera\'s bird. She weaves Argus\'s hundred eyes into its feathers — vigilance and loyalty.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Ölümsüzlük ve diriliş. Bizans mozaiklerinde sık görülür — kanatlarındaki "gözler" ilahi bakış.', en: 'Immortality and resurrection. Often seen in Byzantine mosaics — the "eyes" in its feathers are the divine gaze.' } },
      { culture: { tr: 'Türk-İslam', en: 'Turco-Islamic' }, meaning: { tr: 'Cennet kuşu. Sufi metinlerinde "tavus-i ervah" — ruhların gösterişli formu.', en: 'Bird of paradise. In Sufi texts, "tavus-i ervah" — the splendid form of souls.' } },
    ],
    myths: [
      { tr: 'Hera ve Argos: Hera, sadık dev bekçisi Argos öldürülünce yüz gözünü tavusun kuyruğuna işler. O günden beri tavus, sadakatin ve uyanıklığın taşıyıcısıdır.', en: 'Hera and Argus: When her faithful giant watchman Argus is slain, Hera weaves his hundred eyes into the peacock\'s tail. Since that day, the peacock has been the bearer of loyalty and vigilance.' },
      { tr: 'Melek Tavus: Yezidi geleneğinde Melek Tavus, Tanrı\'nın yedi meleğinden en büyüğüdür. Diğer dinlerde "düşmüş melek" olarak yorumlanmış ama Yezidilerce yücedir — perspektif meselesi.', en: 'Melek Taus: In Yazidi tradition, Melek Taus is the greatest of God\'s seven angels. Interpreted as a "fallen angel" in other religions but exalted by Yazidis — a matter of perspective.' },
    ],
  },

  // ─── a017 Leylek ────────────────────────────────────────────────────────
  a017: {
    jung: { tr: '"Doğum/Yeni Başlangıç" arketipi. Leylek, eski döngünün bitimi ve yeni ruhun gelişinin habercisi.', en: 'The "Birth/New Beginning" archetype. The stork is the herald of the old cycle\'s end and the new soul\'s arrival.' },
    dream: { tr: 'Leylek rüyada — yeni bir başlangıç doğuyor. Üzerinde bebek varsa: yaratıcı bir doğuma hazırsın. Uçuyorsa: göç ve değişim zamanı.', en: 'Stork in dream — a new beginning is being born. With a baby upon it: you are ready for a creative birth. Flying: time of migration and change.' },
    shadow: { tr: '"Bir şeyler getirsin" diye pasif beklemek. Leylek getirir ama tohumu sen ekmelisin. Beklemek doğurmak değildir.', en: 'Waiting passively "for something to be brought". The stork delivers, but you must plant the seed. Waiting is not giving birth.' },
    whenAppears: { tr: 'Hamilelik/doğum (gerçek ya da yaratıcı) öncesinde, ev kuruşunda, yeni bir döneme geçişte.', en: 'Before pregnancy/birth (literal or creative), in establishing a home, in transition to a new period.' },
    traditions: [
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: '"Hacı leylek" — kutsal yolcunun, hacca giden ruhun adı. Çatıya leylek yuvası: o ev bereketli.', en: '"Hacı leylek" — the name of the sacred pilgrim, the soul that goes on hajj. A stork\'s nest on the roof: that house is blessed.' } },
      { culture: { tr: 'Slav-Alman', en: 'Slavic-Germanic' }, meaning: { tr: 'Bebekleri getiren kuş. Doğum hediyesi olarak çocukları evlere taşır.', en: 'The bird that brings babies. It carries children to homes as a birth-gift.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Ba — insanın ruhu leylek/lekleğe benzer kuş formunda gösterilir. Bedenden ayrılan ruh.', en: 'Ba — the human soul depicted as a stork-like bird. The soul departing the body.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Hera\'nın koruyuculuk simgesi. Anneler için kutsanmış kuş.', en: 'Symbol of Hera\'s protection. A bird blessed for mothers.' } },
      { culture: { tr: 'İslam Halk', en: 'Islamic Folk' }, meaning: { tr: 'Hacca gidip dönen kuş olduğuna inanılır. "Hacı leylek" duası — yolculuğun bereketi.', en: 'Believed to be the bird that travels to Mecca and returns. The "Hacı leylek" blessing — the journey\'s benediction.' } },
    ],
    myths: [
      { tr: 'Hacı Leylek: Anadolu inanışına göre leylekler her yıl hacca gider, dönerler. Onlara zarar veren bu kutsal yolculuğu bozmuş sayılır — büyük günah.', en: 'The Pilgrim Stork: According to Anatolian belief, storks go on hajj every year and return. To harm them is to disrupt this sacred journey — a great sin.' },
      { tr: 'Babylonia\'da Leylek: Eski Mezopotamya tabletlerinde leylekler tanrı Marduk\'un haberci kuşlarıdır — kuraklığa rağmen suyu bulan rehber.', en: 'The Stork in Babylonia: In ancient Mesopotamian tablets, storks are the messenger birds of the god Marduk — the guide that finds water despite drought.' },
    ],
  },

  // ─── a018 Şahin ─────────────────────────────────────────────────────────
  a018: {
    jung: { tr: '"Odaklanmış İrade" arketipi. Şahin — net görüş, isabetli karar, hedeflenmiş eylem. Kartal kadar yüksek değil ama daha keskin.', en: 'The "Focused Will" archetype. The falcon — clear sight, precise decision, targeted action. Not as high as the eagle, but sharper.' },
    dream: { tr: 'Şahin rüyada — bir şeye keskinleşmen gerekiyor. Avlanıyorsa: hedefini bul. Eline konuyorsa: gücün geri geliyor, ehlileşmiş halde.', en: 'Falcon in dream — you must sharpen toward something. Hunting: find your target. Landing on your hand: your power is returning, tamed.' },
    shadow: { tr: 'Acımasız odak. Hedefe ulaşmak için her şeyi feda etmek. Şahin keskindir ama ısırırsa zalimleşir.', en: 'Ruthless focus. Sacrificing everything to reach the goal. The falcon is sharp, but if it bites, it becomes cruel.' },
    whenAppears: { tr: 'Bir kararın netleşmesi gerektiğinde, dağılmış enerjini toplaman gerekirken, bir sözünü tutman gereken anda.', en: 'When a decision must become clear, when you must gather your scattered energy, at the moment you must keep your word.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Horus — şahin başlı tanrı. Krallığın, göğün ve adaletin sembolü. Firavunun ruhsal protokolü.', en: 'Horus — the falcon-headed god. Symbol of kingship, sky, and justice. The pharaoh\'s spiritual protocol.' } },
      { culture: { tr: 'Türk Şamanizmi', en: 'Turkic Shamanism' }, meaning: { tr: 'Şamanlar şahin formunda göğe yükselir. Sungar (sungur) — av kuşu, hanın gözü.', en: 'Shamans ascend to the sky in falcon form. Sungar — the hunting bird, the khan\'s eye.' } },
      { culture: { tr: 'Arap', en: 'Arabic' }, meaning: { tr: 'Bedevi geleneğinde en değerli av yoldaşı. Avcılığın sanatı: şahinciliğin (şahincilik) UNESCO\'ya kayıtlı miras.', en: 'In Bedouin tradition, the most prized hunting companion. The art of falconry is UNESCO-listed heritage.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Garuda\'nın akrabası. Soma\'yı (kutsal içecek) tanrılara taşıyan kuş.', en: 'A kin of Garuda. The bird that carries Soma (the sacred draught) to the gods.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Yiğit padişahların kolundaki şahin — irade ve sadakatin sembolü. Doğan ve şahinli sancaklar.', en: 'The falcon on the arm of valiant sultans — symbol of will and loyalty. Banners bearing falcons and hawks.' } },
    ],
    myths: [
      { tr: 'Horus ve Set: Mısır mitolojisinde şahin başlı Horus, babası Osiris\'i öldüren amcası Set ile uzun savaşa girer. Horus\'un kaybettiği göz — sonradan "Uçat" şifa sembolü olur.', en: 'Horus and Set: In Egyptian mythology, the falcon-headed Horus wages a long war against his uncle Set, who killed his father Osiris. The eye Horus loses — later becomes the "Udjat" symbol of healing.' },
      { tr: 'Selçuklu Şahincibaşılığı: Selçuklu sarayında "Emir-i Şikar" — şahincibaşı en yüksek makamlardan biriydi. Padişahın şahini onun gözüdür.', en: 'The Seljuk Master of Falcons: In the Seljuk court, the "Emir-i Şikar" — master of falcons — was one of the highest offices. The sultan\'s falcon is his eye.' },
    ],
  },

  // ─── a019 Pars ──────────────────────────────────────────────────────────
  a019: {
    jung: { tr: '"Sessiz Avcı" arketipi. Pars — sessizlikte güç, beklemekte zafer. İçsel disiplinin sembolü.', en: 'The "Silent Hunter" archetype. The leopard — power in silence, victory in waiting. Symbol of inner discipline.' },
    dream: { tr: 'Pars rüyada — sabır ve doğru zamanlama hakkında ders. Pusuda yatıyorsa: harekete geçme anı yaklaşıyor. Avlanıyorsa: kararlılıkla ilerle.', en: 'Leopard in dream — a lesson in patience and right timing. Lying in ambush: the moment to act draws near. Hunting: advance with resolve.' },
    shadow: { tr: 'Aşırı kontrol. Her hamleyi ölçmek, kendiliğindenliği öldürür. Pars hep hesaplıdır, ama insan değildir.', en: 'Excessive control. Measuring every move kills spontaneity. The leopard is always calculating — but it is not human.' },
    whenAppears: { tr: 'Stratejik bir bekleyişte, çabuk hareket etmek yerine sezgiyi beklemen gerekirken, yalnız savaşırken.', en: 'In a strategic wait, when you must await intuition rather than act quickly, when fighting alone.' },
    traditions: [
      { culture: { tr: 'Pers/Türk', en: 'Persian/Turkic' }, meaning: { tr: '"Pars" Eski Türkçe ve Farsça\'da kaplan/leoparddan ayrı bir hayvan — bağımsız ve yalnız savaşçı.', en: 'In Old Turkic and Persian, "pars" is an animal distinct from the tiger/leopard — the independent, solitary warrior.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Dionysos\'un bineği — coşku ve vahşi bilgeliğin birleşimi. Şarap tanrısı parsın sırtında.', en: 'Dionysus\'s mount — the union of ecstasy and wild wisdom. The wine god rides upon the leopard.' } },
      { culture: { tr: 'Afrika', en: 'African' }, meaning: { tr: 'Maasai geleneğinde — yalnız avcının onuru. Genç savaşçının olgunluk sınavı.', en: 'In Maasai tradition — the honor of the solitary hunter. The young warrior\'s test of maturity.' } },
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Durga\'nın bineği — kötülüğü mahveden tanrıçanın bir formu.', en: 'Durga\'s mount — a form of the goddess who destroys evil.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Beş zehrin kovucusu. Tılsım hayvanı — gizli kötülüğü görür ve avlar.', en: 'The repeller of the five poisons. A talismanic animal — sees and hunts hidden evil.' } },
    ],
    myths: [
      { tr: 'Dionysos ve Pars: Yunan mitolojisinde şarap ve coşku tanrısı Dionysos parsın sırtında gezer. Pars\'ın bakışında hem ölüm hem zevk var — yaşam paradoksunun bineği.', en: 'Dionysus and the Leopard: In Greek mythology, the god of wine and ecstasy rides upon the leopard. In the leopard\'s gaze are both death and delight — the mount of life\'s paradox.' },
      { tr: 'Anadolu Parsı: Antik kaynaklarda Toros Dağları\'nda yaşayan Anadolu parsı yiğitliğin simgesiydi. Bugün neredeyse soyu tükenmiş — kaybedilen bilgeliğin sessiz işareti.', en: 'The Anatolian Leopard: In ancient sources, the Anatolian leopard of the Taurus Mountains was the symbol of valor. Today nearly extinct — the silent sign of lost wisdom.' },
    ],
  },

  // ─── a020 Arı ───────────────────────────────────────────────────────────
  a020: {
    jung: { tr: '"Hizmetkâr Yaratıcı" arketipi. Arı — birey ve kolektif aynı bedende. İlhamı tatlıya dönüştüren çalışkanlık.', en: 'The "Servant-Creator" archetype. The bee — individual and collective in one body. The diligence that turns inspiration into sweetness.' },
    dream: { tr: 'Arı rüyada — verimli yaratıcılık çağrısı. Sokuyorsa: bastırdığın bir görev seni uyandırıyor. Bal yapıyorsa: emeklerin meyvesini verecek.', en: 'Bee in dream — a call to fruitful creativity. If it stings: a duty you have suppressed is waking you. Making honey: your labors will bear fruit.' },
    shadow: { tr: 'Aşırı çalışkanlık. "Ben olmasam kovan çöker" sanrısı. Arı kolektifin parçasıdır, ama tükenmek de mümkündür.', en: 'Excessive industriousness. The delusion "without me the hive collapses". The bee is part of the collective, yet burnout is possible too.' },
    whenAppears: { tr: 'Verimli bir döneme girerken, ortak bir projede yer alırken, ilham balına çevirmen gerektiğinde.', en: 'When entering a fertile period, while joining a shared project, when you must turn inspiration into honey.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Ra\'nın gözyaşlarından doğan arılar — güneş tanrısının yeryüzü habercileri. Bal, tanrı kanı.', en: 'Bees born from Ra\'s tears — earthly messengers of the sun god. Honey is the gods\' blood.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Melissa — Zeus\'u arılarla emziren nympha. Şair Pythagoras\'ın gizemli arı sembolü.', en: 'Melissa — the nymph who suckled Zeus with bees. The mystic bee-symbol of the poet Pythagoras.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Bilgi ve ilhamın taşıyıcısı. Bardlar (şairler) "arı dilini" konuşur.', en: 'Bearer of knowledge and inspiration. The bards (poets) speak "the language of the bee".' } },
      { culture: { tr: 'İslam', en: 'Islamic' }, meaning: { tr: 'Kuran\'da Nahl Suresi — arıya kendine ev yapması, çiçeklerden yemesi vahyedilir. Tanrı\'nın doğrudan rehberlik ettiği yaratık.', en: 'In the Qur\'an, Surah An-Nahl — it is revealed to the bee to build its house and feed on flowers. A creature directly guided by God.' } },
      { culture: { tr: 'Türk Halk', en: 'Turkish Folk' }, meaning: { tr: 'Anadolu\'da "arı tutmak" — bereketin simgesi. Kovanı olan ailenin ocağı tüter.', en: 'In Anatolia, to "keep bees" — a symbol of abundance. The hearth of the family with a hive smokes well.' } },
    ],
    myths: [
      { tr: 'Melissa ve Zeus: Bebek Zeus dağda saklanmışken nympha Melissa onu arı balıyla besler. Bu yüzden arılar "Melissa\'nın kızları" olur — kutsal şifa taşıyıcıları.', en: 'Melissa and Zeus: While the infant Zeus is hidden on the mountain, the nymph Melissa feeds him with honey from the bees. Thus bees become "Melissa\'s daughters" — bearers of sacred healing.' },
      { tr: 'Nahl Suresi: Kuran\'da Allah arıya doğrudan ilham eder: "Dağlardan, ağaçlardan ev edin... çiçeklerden ye." Arı, vahiy alabilecek bilince yakın bir varlık olarak konumlanır.', en: 'Surah An-Nahl: In the Qur\'an, God directly inspires the bee: "Take houses in the mountains, in the trees... eat of the flowers." The bee is positioned as a being near to a consciousness capable of receiving revelation.' },
    ],
  },

  // ─── a021 Kırlangıç ─────────────────────────────────────────────────────
  a021: {
    jung: { tr: '"Bahar Müjdecisi" arketipi. Kırlangıç — yeniden başlayan döngünün, eve dönüşün sembolü.', en: 'The "Herald of Spring" archetype. The swallow — symbol of the cycle that begins anew, of homecoming.' },
    dream: { tr: 'Kırlangıç rüyada — uzun bir kıştan sonra ısınma. Yuva yapıyorsa: bir şey kuruyorsun. Uçuyorsa: göç ve serbestlik.', en: 'Swallow in dream — warming after a long winter. Building a nest: you are establishing something. In flight: migration and freedom.' },
    shadow: { tr: 'Sürekli göç, asla yerleşememek. Kırlangıç döner ama her yerde misafir kalırsa — kök yok olur.', en: 'Constant migration, never able to settle. The swallow returns, but if it remains a guest everywhere — its roots vanish.' },
    whenAppears: { tr: 'Uzun bir bekleyiş sonrası başlangıçta, eve dönüş yolunda, mevsimsel/içsel bir geçişte.', en: 'At a beginning after long waiting, on the way home, in a seasonal or inner transition.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Aphrodite\'nin kuşu. Aşkın ve baharın habercisi. "İlk kırlangıç yaz getirmez" deyişi — sabır.', en: 'Aphrodite\'s bird. Herald of love and spring. The saying "one swallow does not make a summer" — patience.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Sadakatin kuşu. Bir kez eşleşince yıllarca aynı yuvaya döner.', en: 'The bird of loyalty. Once paired, it returns to the same nest for years.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Çatıya kırlangıç yuva yaparsa o ev kutsanmıştır. Yuvayı bozan uğursuz sayılır.', en: 'If a swallow nests on a roof, that house is blessed. Whoever destroys the nest is deemed ill-fortuned.' } },
      { culture: { tr: 'Roma', en: 'Roman' }, meaning: { tr: 'Penates\'in (ev tanrıları) kuşu — ailenin koruyucusu.', en: 'The bird of the Penates (household gods) — protector of the family.' } },
      { culture: { tr: 'Japonya', en: 'Japanese' }, meaning: { tr: 'Tsubame — bahar, gençlik ve bereketin simgesi. Çiftçinin dostu.', en: 'Tsubame — symbol of spring, youth, and abundance. The farmer\'s friend.' } },
    ],
    myths: [
      { tr: 'Prokne ve Philomela: Yunan mitolojisinde iki kız kardeş, zulümden kurtulmak için kuşa dönüşür — biri kırlangıç, diğeri bülbül olur. Acının kanatlanması.', en: 'Procne and Philomela: In Greek mythology, two sisters transform into birds to escape cruelty — one becomes a swallow, the other a nightingale. The wing-taking of pain.' },
      { tr: 'Çatı Kırlangıcı: Anadolu\'da "ocağına kırlangıç konsun" duası — en güzel bereket dileği. O yuva yıkılırsa bereket kaybolur.', en: 'The Roof Swallow: In Anatolia, the blessing "may a swallow alight on your hearth" — the finest wish of abundance. If that nest falls, the blessing departs.' },
    ],
  },

  // ─── a022 Güvercin ──────────────────────────────────────────────────────
  a022: {
    jung: { tr: '"Kutsal Ruh/Sulh" arketipi. Güvercin — masum sevgi, barış, ilahi yumuşaklık.', en: 'The "Holy Spirit/Peace" archetype. The dove — innocent love, peace, divine gentleness.' },
    dream: { tr: 'Güvercin rüyada — bir affediş veya barışın yaklaştığını söyler. Beyaz güvercin: kutsal mesaj. Eline konuyorsa: lütuf seni buldu.', en: 'Dove in dream — tells you a forgiveness or peace is near. White dove: sacred message. Landing on your hand: grace has found you.' },
    shadow: { tr: '"Hep barışçıl olmak" baskısı. Güvercin masum ama saf değildir — sınırlarını koruyamamak, kurban moduna kayma.', en: 'The pressure of "always being peaceful". The dove is innocent but not naive — failure to defend boundaries slides into victim mode.' },
    whenAppears: { tr: 'Bir çatışmanın bitiminde, affediş anında, kalbinin yumuşadığı ya da yumuşaması gerektiği zamanda.', en: 'At the end of a conflict, in the moment of forgiveness, when your heart softens or must soften.' },
    traditions: [
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Kutsal Ruh\'un simgesi. Vaftiz sırasında İsa\'nın üzerine inen güvercin. Mesajın saflığı.', en: 'Symbol of the Holy Spirit. The dove descending upon Christ at his baptism. The purity of the message.' } },
      { culture: { tr: 'Yahudilik', en: 'Judaism' }, meaning: { tr: 'Nuh\'un gemisinden salınan güvercin zeytin dalıyla döner — tufanın bitimi, barış.', en: 'The dove released from Noah\'s ark returns with an olive branch — the end of the flood, peace.' } },
      { culture: { tr: 'İslam', en: 'Islamic' }, meaning: { tr: 'Hacerü\'l-Esved\'i taşıyan kuş efsanelerinde geçer. Mevlana\'da "aşk güvercini".', en: 'Appears in legends as the bird that carried the Black Stone. In Rumi, "the dove of love".' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Afrodit\'in kuşu. Aşkın ve şehvetin temsilcisi — sertlik ve yumuşaklığı bir arada.', en: 'Aphrodite\'s bird. Representative of love and desire — firmness and gentleness together.' } },
      { culture: { tr: 'Sumer', en: 'Sumerian' }, meaning: { tr: 'İnanna\'nın kuşu — aşk ve savaş tanrıçası. Güvercin paradoksu: hem yumuşak hem kararlı.', en: 'Inanna\'s bird — the goddess of love and war. The dove\'s paradox: both soft and resolute.' } },
    ],
    myths: [
      { tr: 'Nuh\'un Güvercini: Tufan sonrası gemiden salınan güvercin geri döner — kara yok. Bir hafta sonra tekrar salınır, ağzında zeytin dalıyla döner. Tufan bitti. İnsanlığın yeniden başlangıcı.', en: 'Noah\'s Dove: After the flood, the dove released from the ark returns — no land. A week later released again, it returns with an olive branch in its beak. The flood is over. Humanity\'s new beginning.' },
      { tr: 'Afrodit\'in Güvercinleri: Kıbrıs\'ta Afrodit tapınağında yüzlerce güvercin yetiştirilirdi. Şiddetli aşk ile yumuşak barışın aynı tanrıçada birleşmesi.', en: 'Aphrodite\'s Doves: Hundreds of doves were raised in Aphrodite\'s temple on Cyprus. Fierce love and gentle peace united in one goddess.' },
    ],
  },

  // ─── a023 Bülbül ────────────────────────────────────────────────────────
  a023: {
    jung: { tr: '"Aşık Sanatçı" arketipi. Bülbül — acıdan beslenen güzellik. Kalbi yaralı olduğu için en güzel öten kuş.', en: 'The "Lover-Artist" archetype. The nightingale — beauty nourished by pain. The bird that sings most beautifully because its heart is wounded.' },
    dream: { tr: 'Bülbül rüyada — kalbin bir sözü var, söylenmek istiyor. Gül diken üzerinde ötüyorsa: aşkın acısı yaratıcılığa dönüşüyor.', en: 'Nightingale in dream — your heart has a word that wants to be said. Singing upon a rose-thorn: the pain of love is turning into creativity.' },
    shadow: { tr: 'Acı romantizmi. Mutsuzluğu sanat için kutsallaştırmak. Bülbül acıdan öter — ama hep yaralı kalmak gerekmez.', en: 'The romanticism of pain. Sacralizing unhappiness for the sake of art. The nightingale sings from pain — but one need not remain forever wounded.' },
    whenAppears: { tr: 'Aşk acısında, sanata dökülmesi gereken bir hisde, yas ile şarkı arasında köprüde.', en: 'In the pain of love, in a feeling that must be poured into art, on the bridge between grief and song.' },
    traditions: [
      { culture: { tr: 'Sufi-Fars', en: 'Sufi-Persian' }, meaning: { tr: '"Bülbül ve Gül" — mistik aşkın en kadim metaforu. Bülbül âşık, gül maşuk. Aşk hep yaralayan ama hep çağıran.', en: '"The Nightingale and the Rose" — the most ancient metaphor of mystical love. The nightingale is the lover, the rose the beloved. Love always wounds, yet always calls.' } },
      { culture: { tr: 'Türk Divan Şiiri', en: 'Turkish Divan Poetry' }, meaning: { tr: 'Fuzuli\'den Nedim\'e — bülbül şairin kendisi. "Aşk derdiyle hoşem el çek ilacımdan tabib."', en: 'From Fuzuli to Nedim — the nightingale is the poet himself. "I am content with love\'s ailment; physician, withhold your cure."' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Philomela — kızını kaybeden anneye dönüşen bülbül. Acının sesi.', en: 'Philomela — the nightingale into which a mother who lost her daughter is transformed. The voice of pain.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Saraylarda bülbül beslemek — saray edebinin işareti. Şiirin müzikal hâli.', en: 'Keeping nightingales in palaces — a sign of courtly refinement. The musical form of poetry.' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: 'Halk türküleri "bülbül kondu dalına" — sevdiğine sözü taşıyan elçi.', en: 'Folk songs of "the nightingale alighting on the branch" — the envoy who carries word to the beloved.' } },
    ],
    myths: [
      { tr: 'Bülbül ve Gül: Fars-Türk edebiyatının en derin sembolü. Bülbül her gece güle âşık öter, gül ise dikenleriyle yanıt verir. Aşk — istemek değil, oluş hâli; ulaşmak değil, var olmak.', en: 'The Nightingale and the Rose: The deepest symbol of Persian-Turkish literature. Each night the nightingale sings to the rose; the rose replies with its thorns. Love is not desiring but being; not arriving but existing.' },
      { tr: 'Philomela\'nın Dilsizleşmesi: Yunan mitolojisinde tecavüze uğrayan Philomela\'nın dili kesilir. Sessizliğini dokumalara işler, sonra bülbüle dönüşür. Dilsiz acının sese kavuşması.', en: 'The Silencing of Philomela: In Greek mythology, Philomela, after being raped, has her tongue cut out. She weaves her silence into a tapestry and is then transformed into a nightingale. The voiceless pain finding its voice.' },
    ],
  },

  // ─── a024 Kaplan ────────────────────────────────────────────────────────
  a024: {
    jung: { tr: '"İlkel Güç" arketipi. Kaplan — bastırılamayan tutku, vahşi yaratıcılık. Aslan kraldır, kaplan tanrıdır.', en: 'The "Primal Power" archetype. The tiger — irrepressible passion, wild creativity. The lion is king; the tiger is god.' },
    dream: { tr: 'Kaplan rüyada — büyük bir güç uyanıyor. Saldırıyorsa: bastırdığın bir tutku patlamak üzere. Yanında yürüyorsa: vahşi tarafınla barıştın.', en: 'Tiger in dream — a great power is awakening. Attacking: a passion you have suppressed is about to erupt. Walking beside you: you have made peace with your wild side.' },
    shadow: { tr: 'Kontrolsüz öfke, yıkıcı tutku. Kaplan ehlileşmezse evi yakar. Ama ehlileştirilemez de — sadece saygı duyulur.', en: 'Uncontrolled rage, destructive passion. Untamed, the tiger burns the house. Yet it cannot be tamed — only respected.' },
    whenAppears: { tr: 'Büyük bir tutkunun uyandığı, sınır koymak için kükremek gerektiğinde, yaratıcı bir çağrının dirilişinde.', en: 'When a great passion awakens, when you must roar to set a boundary, at the resurrection of a creative summons.' },
    traditions: [
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Dört kutsal hayvandan biri (Bai Hu — Ak Kaplan). Batı, sonbahar, metal ve cesaretin koruyucusu.', en: 'One of the Four Sacred Animals (Bai Hu — White Tiger). Guardian of the west, autumn, metal, and courage.' } },
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Durga\'nın bineği. Tanrıça kötülüğe karşı kaplanın sırtında savaşır.', en: 'Durga\'s mount. The goddess battles evil from the tiger\'s back.' } },
      { culture: { tr: 'Kore', en: 'Korean' }, meaning: { tr: 'Kore mitolojisinin en kutsal hayvanı. Dağların ruhu, kahramanların rehberi.', en: 'The most sacred animal of Korean mythology. Spirit of the mountains, guide of heroes.' } },
      { culture: { tr: 'Türk Mitolojisi', en: 'Turkic Mythology' }, meaning: { tr: 'Anadolu\'da yok ama Orta Asya kökenli Türklerde "Bars" — savaşçı sembolü, hakanlık alameti.', en: 'Absent in Anatolia, but among the Central Asian Turks "Bars" — symbol of the warrior, emblem of the khanate.' } },
      { culture: { tr: 'Şamanik', en: 'Shamanic' }, meaning: { tr: 'Tibetan Bön\'da kaplan dağın koruyucusu — yıkıcı kutsallık.', en: 'In Tibetan Bön, the tiger is the guardian of the mountain — destructive holiness.' } },
    ],
    myths: [
      { tr: 'Bai Hu — Ak Kaplan: Çin kozmolojisinde batının koruyucu hayvanı. Kahramanların yetişmesini gözetler. Ölümsüzlük arayan kahraman ondan onay almalıdır.', en: 'Bai Hu — the White Tiger: In Chinese cosmology, the western guardian. He watches over heroes\' maturation. The hero seeking immortality must have his approval.' },
      { tr: 'Durga ve Kaplan: Hint mitolojisinde tanrıça Durga, hiçbir tanrının yenemediği şeytan Mahishasura\'yı kaplan sırtında öldürür. Vahşi gücün adaletle birleşmesi.', en: 'Durga and the Tiger: In Hindu mythology, the goddess Durga slays the demon Mahishasura, whom no god could defeat, from the back of the tiger. The union of wild power with justice.' },
    ],
  },

  // ─── a025 Köpek ─────────────────────────────────────────────────────────
  a025: {
    jung: { tr: '"Sadık Yoldaş" arketipi. Köpek — koşulsuz bağlılık, ehlileştirilmiş içgüdü. İnsanın yanındaki vahşi.', en: 'The "Faithful Companion" archetype. The dog — unconditional bond, tamed instinct. The wild one beside the human.' },
    dream: { tr: 'Köpek rüyada — sadakatin testi. Sana saldırıyorsa: hayatında biri sınır çiğniyor. Yanında yürüyorsa: rehberin yakın, içgüdüne güven.', en: 'Dog in dream — a test of loyalty. Attacking you: someone in your life is crossing a boundary. Walking beside you: your guide is near, trust your instinct.' },
    shadow: { tr: 'Aşırı sadakat — kendini kaybetme pahasına bağlılık. Köpek sahibine bağlıdır ama köle değildir; sevgi ile teslimiyet farkı.', en: 'Excessive loyalty — devotion at the cost of self-loss. The dog is bonded to its master but is not a slave; the difference between love and submission.' },
    whenAppears: { tr: 'Bir dostluğun derinleşmesinde, koşulsuz sevgi sınavında, ölüm ya da kayıp eşiklerinde (köpek geçişe eşlik eder).', en: 'In the deepening of a friendship, in a test of unconditional love, on the thresholds of death or loss (the dog accompanies the passage).' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Anubis — çakal başlı tanrı, ölüleri öbür dünyaya taşır. Geçişin koruyucusu.', en: 'Anubis — the jackal-headed god who carries the dead to the otherworld. Guardian of the passage.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Kerberos — Hades\'in üç başlı bekçi köpeği. Ölüler diyarının kapısı.', en: 'Cerberus — Hades\'s three-headed watchdog. The gate of the land of the dead.' } },
      { culture: { tr: 'Türk-İslam', en: 'Turco-Islamic' }, meaning: { tr: 'Eshab-ı Kehf (Mağara Arkadaşları) ile birlikte 309 yıl uyuyan Kıtmir — Kuran\'da geçen tek köpek. Sadakatin kutsallaşması.', en: 'Qitmir, who slept 309 years with the Companions of the Cave (Ashab al-Kahf) — the only dog mentioned in the Qur\'an. The sanctification of loyalty.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Cu Sith — peri köpekleri. Hem rehber hem haberci. Ölümün habercisi.', en: 'Cù-sìth — fairy dogs. Both guide and messenger. Herald of death.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Yama\'nın (ölüm tanrısı) iki dört gözlü köpeği — ruhun yolculuğunda eşlikçi.', en: 'The two four-eyed dogs of Yama (the god of death) — companions on the soul\'s journey.' } },
    ],
    myths: [
      { tr: 'Ashab-ı Kehf ve Kıtmir: Kuran\'da geçen mağara arkadaşları zulümden kaçar, mağarada uyurlar. Yanlarında bir köpek de uyur. Üç yüz yıl sonra uyanırlar. Köpeğin adı: Kıtmir. Sadakatin ödüllendirilmesi.', en: 'The Companions of the Cave and Qitmir: The Cave Companions in the Qur\'an flee persecution and sleep in a cave. A dog sleeps with them. They wake after three hundred years. The dog\'s name: Qitmir. The reward of loyalty.' },
      { tr: 'Anubis ve Ölüm: Mısır mitolojisinde Anubis öleninin kalbini Maat tüyüyle tartar. Eğer kalp tüyden hafifse — cennet. Ağırsa — yokluk. Köpek başlı tanrı: adil terazi.', en: 'Anubis and Death: In Egyptian mythology, Anubis weighs the deceased\'s heart against the feather of Maat. If the heart is lighter than the feather — paradise. Heavier — oblivion. The dog-headed god: the just scale.' },
    ],
  },

  // ─── a026 Çita ──────────────────────────────────────────────────────────
  a026: {
    jung: { tr: '"Şimşek Eylem" arketipi. Çita — fırsatı görüp anında harekete geçme. Hız, ama kısa süreli; tüm enerjiyi bir hamlede kullanma.', en: 'The "Lightning Action" archetype. The cheetah — seeing an opportunity and acting at once. Speed, but brief; spending all energy in a single move.' },
    dream: { tr: 'Çita rüyada — bir fırsat çok kısa sürede gelip geçecek. Koşuyorsa: harekete geç, beklersen kaçar. Yorgunsa: aşırı acele ediyorsun, dinlen.', en: 'Cheetah in dream — an opportunity will come and go quickly. Running: act, if you wait it escapes. Tired: you are rushing too much, rest.' },
    shadow: { tr: 'Sprint yaşamak. Her şeyi bir patlamada yapma takıntısı — sonrasında çöküş. Çita uzun mesafede kazanmaz, yıldız anlarda kazanır.', en: 'Living in sprints. The compulsion to do everything in one burst — followed by collapse. The cheetah does not win the long distance; it wins the star moments.' },
    whenAppears: { tr: 'Anlık kararlar gerektiğinde, fırsat penceresinin daraldığında, hızlı tepki ya da yenilenme arasında bir seçim anında.', en: 'When instant decisions are required, when the window of opportunity narrows, at a moment of choice between swift response and renewal.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Mafdet — çita başlı tanrıça. Zehirden ve yılandan koruyan. Hızlı adaletin temsilcisi.', en: 'Mafdet — the cheetah-headed goddess. Protector from venom and serpents. Representative of swift justice.' } },
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Hızın ve dikkatin sembolü. Maharaja\'ların av eşlikçisi — kraliyet hızı.', en: 'Symbol of speed and attention. Hunting companion of the maharajas — royal velocity.' } },
      { culture: { tr: 'Afrika', en: 'African' }, meaning: { tr: 'Maasai geleneğinde — annenin yavruları için yaptığı fedakârlığın simgesi. Yalnız savaşan dişi.', en: 'In Maasai tradition — symbol of the mother\'s sacrifice for her cubs. The lone-fighting female.' } },
      { culture: { tr: 'Pers', en: 'Persian' }, meaning: { tr: 'Yuyutsu — çitaların yetiştirildiği eski av kuralları. Hızın imparatorluğu.', en: 'Yuyutsu — the ancient hunting codes by which cheetahs were raised. The empire of speed.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Rüzgârın hayvanı. Beş elementten hızla geçen.', en: 'The animal of the wind. The one that passes swiftly through the five elements.' } },
    ],
    myths: [
      { tr: 'Mafdet: Mısır mitolojisinde Firavun\'un yatağını yılanlardan koruyan çita-tanrıça. Hıza atfedilen kutsallık: hız ölümden önce davranabilir.', en: 'Mafdet: In Egyptian mythology, the cheetah-goddess who guarded the pharaoh\'s bed from serpents. The holiness attributed to speed: speed can act before death.' },
      { tr: 'Çita Anneleri: Afrika halk hikâyelerinde çita anne yavruları için aslandan kaçarak ölümü göze alır. Hız, sevginin hizmetinde olduğunda kutsaldır.', en: 'Cheetah Mothers: In African folk tales, the cheetah mother risks death fleeing from the lion for her cubs. Speed is sacred when it serves love.' },
    ],
  },

  // ─── a027 Ejderha ───────────────────────────────────────────────────────
  a027: {
    jung: { tr: '"Kozmik Bilinç" arketipi. Ejderha — yıkıcı ve yaratıcı en büyük güç. İçsel hazinenin bekçisi.', en: 'The "Cosmic Consciousness" archetype. The dragon — the greatest power, destructive and creative. Guardian of the inner treasure.' },
    dream: { tr: 'Ejderha rüyada — büyük bir güçle yüzleşiyorsun. Saldırıyorsa: ego seni sınıyor. Üstüne biniyorsan: derin bir gücü taşımayı öğrendin.', en: 'Dragon in dream — you are confronting a great power. Attacking: the ego is testing you. Riding it: you have learned to carry a deep force.' },
    shadow: { tr: 'Hazineyi koruma takıntısı. Ejderha sahip olduklarının üstüne yatar — paylaşmak yerine biriktirir. Egoizmin kozmik formu.', en: 'The compulsion to guard the hoard. The dragon lies upon what it owns — hoarding rather than sharing. The cosmic form of egoism.' },
    whenAppears: { tr: 'Devasa bir dönüşümün eşiğinde, kendi gücünle yüzleşmen gereken anda, içsel hazineye inişte.', en: 'On the threshold of a vast transformation, at the moment you must face your own power, in the descent to the inner treasure.' },
    traditions: [
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Long — imparatorun simgesi, su, yağmur, bereket. Dört yön ejderhası dünyayı kuşatır.', en: 'Long — emblem of the emperor, water, rain, abundance. The four-direction dragons encircle the world.' } },
      { culture: { tr: 'Türk Mitolojisi', en: 'Turkic Mythology' }, meaning: { tr: 'Evren — Türk-Moğol mitolojisinde gökyüzü ejderhası. Bayraklarda, kalkanlarda. Ölümsüzlüğün taşıyıcısı.', en: 'Evren — the sky dragon of Turco-Mongol mythology. On banners and shields. Bearer of immortality.' } },
      { culture: { tr: 'Avrupa Hristiyan', en: 'European Christian' }, meaning: { tr: 'Aziz Yorgi\'nin (St. George) öldürdüğü canavar — bastırılması gereken pagan gücü.', en: 'The beast slain by Saint George — the pagan power that must be subdued.' } },
      { culture: { tr: 'İskandinav', en: 'Norse' }, meaning: { tr: 'Jörmungandr — dünyayı saran kuyruğunu yiyen ejderha. Sonun başlangıcı.', en: 'Jörmungandr — the dragon encircling the world, devouring its own tail. The beginning of the end.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Vritra — kuraklığın ejderhası. İndra tarafından öldürülünce sular akar — yaratıcı yıkım.', en: 'Vritra — the dragon of drought. When slain by Indra, the waters flow — creative destruction.' } },
    ],
    myths: [
      { tr: 'Çin Ejderhası ve Yağmur: Çin mitolojisinde ejderhalar nehir ve göllerde yaşar. Yağmur getirir, bereket yağdırır. Kuraklık — ejderhanın kızgınlığıdır, sevgisini geri kazanmak gerek.', en: 'The Chinese Dragon and Rain: In Chinese mythology, dragons dwell in rivers and lakes. They bring rain and pour abundance. Drought is the dragon\'s anger — one must win back its love.' },
      { tr: 'St. George ve Ejderha: Hristiyan ikonografisinde Aziz Yorgi, prensesi kurtarmak için ejderhayı öldürür. Doğu\'nun kutsadığı, Batı\'nın bastırdığı — perspektif tartışması.', en: 'St. George and the Dragon: In Christian iconography, Saint George slays the dragon to save the princess. What the East sanctifies, the West subdues — a question of perspective.' },
    ],
  },

  // ─── a028 Karakulak ─────────────────────────────────────────────────────
  a028: {
    jung: { tr: '"Sessiz Sezgi" arketipi. Karakulak — kulağıyla görür, görünmeyeni duyur. Görünmeden gözlemleyen yargıç.', en: 'The "Silent Intuition" archetype. The caracal — sees with its ears, hears the unseen. The judge who observes without being seen.' },
    dream: { tr: 'Karakulak rüyada — duyamadığın bir şeye dikkat çekiyor. Gizli bir mesaj, fısıltı, sezgi. Birinin söylemediği var.', en: 'Caracal in dream — draws attention to what you cannot hear. A hidden message, whisper, intuition. Someone has something they are not saying.' },
    shadow: { tr: 'Sürekli kuşku. Her şeyin altında bir komplo aramak. Karakulak duyar ama yorumda yanılırsa paranoya doğar.', en: 'Constant suspicion. Searching for a conspiracy beneath everything. The caracal hears, but errors in interpretation give birth to paranoia.' },
    whenAppears: { tr: 'Kelimelerin gerçeği örttüğü konuşmalarda, bir hissin doğrulanmasını beklerken, gizli niyetleri okuman gerekirken.', en: 'In conversations where words conceal the truth, while awaiting confirmation of a feeling, when you must read hidden intentions.' },
    traditions: [
      { culture: { tr: 'Anadolu Vahşi Yaşam', en: 'Anatolian Wildlife' }, meaning: { tr: 'Anadolu\'nun saklı avcısı. Toroslar\'da, çöllerinde gizlice yaşar. Sessiz biliciliğin sembolü.', en: 'Anatolia\'s hidden hunter. Lives secretly in the Taurus mountains and the deserts. Symbol of silent knowing.' } },
      { culture: { tr: 'Pers/Arap', en: 'Persian/Arabic' }, meaning: { tr: 'Çöl çakallarının kuzeni. Bedevi geleneğinde "uzak haberi getiren" kabul edilir.', en: 'Cousin to the desert jackals. In Bedouin tradition, regarded as "the one who brings news from afar".' } },
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Şiva\'nın gözünden saklananları gören — gizli adaletin habercisi.', en: 'The one who sees what is hidden from Shiva\'s eye — herald of hidden justice.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Anubis\'in çakal akrabası. Yer altı dünyasının habercisi.', en: 'Jackal-kin to Anubis. Messenger of the underworld.' } },
      { culture: { tr: 'Bedevi', en: 'Bedouin' }, meaning: { tr: 'Avcılık geleneğinde "sultanın kulağı". Padişaha en yakın av hayvanı.', en: 'In the hunting tradition, "the sultan\'s ear". The hunting animal closest to the ruler.' } },
    ],
    myths: [
      { tr: 'Karakulak ve Tilki: Anadolu masallarında karakulak tilkiden daha sessiz, daha sezgisel hayvan olarak resmedilir. Tilki konuşurken kandırır, karakulak susarak kandırılır mı diye bakar.', en: 'The Caracal and the Fox: In Anatolian tales, the caracal is depicted as quieter, more intuitive than the fox. The fox deceives by speaking; the caracal, by being silent, watches to see if it is being deceived.' },
      { tr: 'Sultan\'ın Karakulağı: Osmanlı sarayında padişaha "duyduklarını gizlice anlatan" yakın adamlara "karakulak" denirdi. Hayvanın saklı kulağı — politikanın metaforu.', en: 'The Sultan\'s Caracal: In the Ottoman court, close attendants who "secretly conveyed what they heard" to the sultan were called "karakulak". The animal\'s hidden ear — a metaphor for politics.' },
    ],
  },

  // ─── a029 Maral ─────────────────────────────────────────────────────────
  a029: {
    jung: { tr: '"Sevda Çağrısı" arketipi. Maral — kederin ve şefkatin birleşimi. Yaralı kalbin sesi.', en: 'The "Call of Longing" archetype. The doe — union of sorrow and tenderness. The voice of the wounded heart.' },
    dream: { tr: 'Maral rüyada — bir özlemin, bir sevdanın çağrısı. Kaçıyorsa: sevdiğine yetişemiyorsun. Sana yaklaşıyorsa: kalp açılıyor.', en: 'Doe in dream — the call of a longing, a love. Fleeing: you cannot catch up to your beloved. Approaching you: the heart is opening.' },
    shadow: { tr: '"Yaralı ceylan" rolü. Korunmaya muhtaç pozisyonu hayat tarzı yapmak — şefkat dilenmek.', en: 'The "wounded gazelle" role. Making the posture of needing protection a way of life — begging for tenderness.' },
    whenAppears: { tr: 'Bir sevgilinin uzaklığında, ana-yavru bağında, hayatın yumuşaklığa çağırdığı anda.', en: 'In a beloved\'s distance, in the mother-child bond, at the moment life calls you to gentleness.' },
    traditions: [
      { culture: { tr: 'Türk Halk Şiiri', en: 'Turkish Folk Poetry' }, meaning: { tr: '"Karac\'oğlan\'ın Maralı" — Anadolu aşk şiirinin merkez sembolü. Sevgilinin gözleri, boynunun zarafeti.', en: '"Karacaoğlan\'s Doe" — the central symbol of Anatolian love poetry. The beloved\'s eyes, the grace of her neck.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Aktaion mitinde — avcı Artemis\'i çıplak görür, ceza olarak geyiğe (maral) dönüştürülür ve kendi köpeklerince parçalanır.', en: 'In the Actaeon myth — the hunter sees Artemis naked; in punishment he is turned into a stag and torn apart by his own hounds.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Beyaz maral — ruhlar âleminden gelen mesajcı. Kralı seçen kutsal.', en: 'The white doe — messenger from the spirit realm. The sacred one who chooses the king.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Sarama — tanrıların habercisi. Saf ruhun yer üstündeki formu.', en: 'Sarama — messenger of the gods. The earthly form of the pure soul.' } },
      { culture: { tr: 'Şamanik', en: 'Shamanic' }, meaning: { tr: 'Sibirya geleneğinde — bedensiz aşk ruhunun temsilcisi.', en: 'In Siberian tradition — representative of the bodiless spirit of love.' } },
    ],
    myths: [
      { tr: 'Karac\'oğlan ve Maralı: Anadolu\'nun en lirik halk şiirinde, Karac\'oğlan sevdiğini "marala" benzetir. Maral kaçar, şair kovalar — sevda, yetişilemeyen güzelliktir.', en: 'Karacaoğlan and His Doe: In Anatolia\'s most lyric folk poetry, Karacaoğlan likens his beloved to a doe. The doe flees, the poet pursues — love is the unattainable beauty.' },
      { tr: 'Aktaion\'un Cezası: Yunan mitolojisinde avcı Aktaion, su perisi formundaki Artemis\'i görür. Tanrıça onu cezalandırmak için marala dönüştürür — kendi köpekleri tarafından parçalanır. Görenin görülmesi.', en: 'Actaeon\'s Punishment: In Greek mythology, the hunter Actaeon sees Artemis in her water-nymph form. To punish him, the goddess transforms him into a stag — he is torn apart by his own hounds. The seer is seen.' },
    ],
  },

  // ─── a030 Timsah ────────────────────────────────────────────────────────
  a030: {
    jung: { tr: '"İlkel Bilinçaltı" arketipi. Timsah — sürüngen beynin dipteki sesi. Korkunun bedenleşmiş hâli, ama aynı zamanda hayatta kalmanın koruyucusu.', en: 'The "Primal Unconscious" archetype. The crocodile — the deep voice of the reptilian brain. The embodied form of fear, yet also the guardian of survival.' },
    dream: { tr: 'Timsah rüyada — bilinçaltında bekleyen bir tehlikenin veya gücün var. Suyun altındaysa: gölge taraf hareketsiz bekliyor. Karaya çıkıyorsa: yüzleşmen gereken bir şey ortaya çıktı.', en: 'Crocodile in dream — a danger or a power lies waiting in your unconscious. Underwater: the shadow side waits motionless. Coming ashore: something you must face has surfaced.' },
    shadow: { tr: 'Soğuk zalimlik. Timsah enerjisi bilinçsizleşirse — duygusuz hayatta kalma, başkalarını yutarak yaşama.', en: 'Cold cruelty. When crocodile energy turns unconscious — emotionless survival, living by devouring others.' },
    whenAppears: { tr: 'Derin korkularla yüzleşirken, gölge çalışmasında, bilinçaltına dalman gerektiğinde.', en: 'While confronting deep fears, in shadow work, when you must descend into the unconscious.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Sobek — timsah başlı tanrı. Nil\'in gücü, doğurganlık, ama aynı zamanda korkunun tanrısı. Firavunun yıkıcı yönü.', en: 'Sobek — the crocodile-headed god. The Nile\'s force, fertility, yet also the god of fear. The pharaoh\'s destructive aspect.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Makara — Varuna\'nın (su tanrısı) bineği. Suyun bilinçaltı bilgeliği.', en: 'Makara — the mount of Varuna (god of waters). The unconscious wisdom of the waters.' } },
      { culture: { tr: 'Maya/Aztek', en: 'Mayan/Aztec' }, meaning: { tr: 'Cipactli — dünyanın üzerinde yaratıldığı dev timsah. Yaratılışın platformu.', en: 'Cipactli — the giant crocodile upon which the world was created. The platform of creation.' } },
      { culture: { tr: 'Afrika', en: 'African' }, meaning: { tr: 'Yoruba geleneğinde — adaletin ve nehir tanrılarının habercisi.', en: 'In Yoruba tradition — herald of justice and the river gods.' } },
      { culture: { tr: 'Avustralya', en: 'Australian' }, meaning: { tr: 'Aborjin rüya zamanında — toprak ve suyun kararlılığını koruyan ata varlık.', en: 'In Aboriginal Dreamtime — the ancestral being who guards the steadiness of earth and water.' } },
    ],
    myths: [
      { tr: 'Sobek ve Nil: Mısırlılar Nil\'in taşmasını Sobek\'in iradesi sayardı. Tanrıyı memnun etmek için timsahlara altın takılır, tapınaklarda bakılırdı — korkulan ama saygı duyulan güç.', en: 'Sobek and the Nile: The Egyptians considered the Nile\'s flooding to be Sobek\'s will. To please the god, crocodiles were adorned with gold and tended in temples — a power feared yet revered.' },
      { tr: 'Cipactli\'nin Yaratılışı: Aztek mitolojisinde Quetzalcoatl ve Tezcatlipoca, devasa timsah Cipactli\'yi parçalayarak dünyayı yaratır. Gökyüzü onun sırtı, yer onun karnı — yaratılış parçalanmadır.', en: 'Cipactli\'s Creation: In Aztec mythology, Quetzalcoatl and Tezcatlipoca create the world by dismembering the giant crocodile Cipactli. The sky is its back, the earth its belly — creation is dismemberment.' },
    ],
  },

  // ─── a031 Kartal Baykuşu ────────────────────────────────────────────────
  a031: {
    jung: { tr: '"Karanlık Bilgelik" arketipi. Kartal baykuşu — gece kralı. Baykuşun sezgisi ve kartalın gücü birleşmiş.', en: 'The "Dark Wisdom" archetype. The eagle owl — king of the night. The owl\'s intuition and the eagle\'s power united.' },
    dream: { tr: 'Kartal baykuşu rüyada — derin bir gece bilgisi sana açılıyor. Hem otorite hem sezgi taşıyor. Karanlıkta görü kazanıyorsun.', en: 'Eagle owl in dream — a deep nocturnal knowledge is opening to you. It carries both authority and intuition. You are gaining vision in darkness.' },
    shadow: { tr: 'Yargılayıcı bilgelik. "Ben gördüm, sen göremedin" üstünlüğü. Bilgi otoriteye dönüşürse — yalnız kalır.', en: 'Judgmental wisdom. The superiority of "I saw, you could not". When knowledge turns to authority — it ends alone.' },
    whenAppears: { tr: 'Hem güç hem sezgi gerektiğinde, geceleyin alınması gereken kararlarda, derinlerden gelen liderlik anlarında.', en: 'When both power and intuition are required, in decisions that must be made at night, in moments of leadership rising from the depths.' },
    traditions: [
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Toroslar\'ın gece kralı. En büyük baykuş türü — dağ bilgeliğinin somut hâli.', en: 'King of the Taurus night. The largest of the owl species — the embodied form of mountain wisdom.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Athena\'nın baykuşunun büyük akrabası. Gerçek bilgeliğin gece görüsü.', en: 'Larger kin to Athena\'s owl. The nocturnal vision of true wisdom.' } },
      { culture: { tr: 'Türk Şamanizmi', en: 'Turkic Shamanism' }, meaning: { tr: 'Şaman gecesinde göğe yükselen baykuş ruhu — en üst saviyenin sembolü.', en: 'The owl-spirit ascending to the sky in the shaman\'s night — symbol of the highest realm.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Cailleach\'in kuşu — yaşlı tanrıçanın gece habercisi.', en: 'The Cailleach\'s bird — the night-messenger of the old goddess.' } },
      { culture: { tr: 'Sibirya', en: 'Siberian' }, meaning: { tr: 'Tundranın bekçisi. Yalnız avcının atası kabul edilir.', en: 'Guardian of the tundra. Held to be the ancestor of the solitary hunter.' } },
    ],
    myths: [
      { tr: 'Kartal Baykuşu ve Avcı: Sibirya halk hikâyelerinde genç bir avcı yıllarca kartal baykuşundan ders alır — gece görüsü, sessiz hareket, doğru zamanlama. Sonunda kendisi gece kralı olur.', en: 'The Eagle Owl and the Hunter: In Siberian folk tales, a young hunter studies for years under the eagle owl — night vision, silent movement, right timing. At last he himself becomes king of the night.' },
      { tr: 'Toros Dağları: Anadolu\'da bu kuşa rastlamak çok nadirdir. Onu gören kişinin "ata bilgeliğinden" haber aldığı söylenir. Kayboluşu — kaybedilen sezginin işareti.', en: 'The Taurus Mountains: To encounter this bird in Anatolia is very rare. Those who see it are said to receive word from "ancestral wisdom". Its disappearance — a sign of lost intuition.' },
    ],
  },

  // ─── a032 Boğa ──────────────────────────────────────────────────────────
  a032: {
    jung: { tr: '"Bedenlenmiş Güç" arketipi. Boğa — toprağa kök salmış erkek/dişil güç. Şehvet, bereket, ama aynı zamanda kontrol edilmesi gereken vahşilik.', en: 'The "Embodied Power" archetype. The bull — masculine/feminine force rooted in the earth. Lust, fertility, yet also a wildness that must be controlled.' },
    dream: { tr: 'Boğa rüyada — bedenin ve içgüdülerinin sesi. Saldırıyorsa: bastırılmış arzu/öfke patlıyor. Otluyorsa: doyumlu bir döneme giriyorsun.', en: 'Bull in dream — the voice of body and instinct. Charging: a repressed desire or anger is exploding. Grazing: you are entering a period of contentment.' },
    shadow: { tr: 'Şiddet ve baskı. Boğa enerjisi kontrol edilmezse — zorbalığa, kıskançlığa, yıkıma dönüşür.', en: 'Violence and dominance. Uncontrolled, bull energy turns into bullying, jealousy, destruction.' },
    whenAppears: { tr: 'Bedensel gücünle bağlandığında, cinsel/yaratıcı enerjini doğru yöne çevirmen gerekirken, kararını "ayakta dur" haline getirmen lazımken.', en: 'When you connect with your bodily power, when you must direct sexual/creative energy rightly, when you must turn your decision into a "stand your ground".' },
    traditions: [
      { culture: { tr: 'Hitit/Anadolu', en: 'Hittite/Anatolian' }, meaning: { tr: 'Hattuşa\'da boğa tapınağı. Fırtına tanrısının (Teşup) kutsal bineği. Anadolu medeniyetinin ekseni.', en: 'The bull temple at Hattusa. Sacred mount of the storm god (Teshub). The axis of Anatolian civilization.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Apis — Memphis\'te yaşatılan kutsal boğa. Yeryüzünde Osiris\'in bedenleşmiş hâli.', en: 'Apis — the sacred bull kept at Memphis. The earthly incarnation of Osiris.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Minotaur — yarı insan yarı boğa. Knossos\'taki labirentin ortasındaki bastırılmış doğa.', en: 'Minotaur — half man, half bull. The repressed nature at the center of the labyrinth at Knossos.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Nandi — Şiva\'nın bineği. Tapınakların önünde otururken karşı tarafa, ilahi tarafa bakar.', en: 'Nandi — Shiva\'s mount. Seated before temples, he gazes across to the divine side.' } },
      { culture: { tr: 'Mitra Kültü', en: 'Mithraic Cult' }, meaning: { tr: 'Mitra\'nın boğayı boğazlaması — kozmik yenilenme ayini. Roma askerinin sırı.', en: 'Mithras\'s slaying of the bull — the cosmic renewal rite. The secret of the Roman soldier.' } },
    ],
    myths: [
      { tr: 'Minotaur ve Labirent: Yunan mitolojisinde Kral Minos\'un karısı Pasiphae bir boğaya âşık olur. Doğan çocuk Minotaur — yarı insan yarı boğa. Daedalos\'un labirentinde tutulur — bastırılan şehvetin merkezde saklanması.', en: 'The Minotaur and the Labyrinth: In Greek mythology, Pasiphae, wife of King Minos, falls in love with a bull. The child born is the Minotaur — half man, half bull. He is kept in Daedalus\'s labyrinth — the repressed desire concealed at the center.' },
      { tr: 'Apis ve Memphis: Mısır\'da Apis adlı boğa Osiris\'in dünyadaki vücudu sayılırdı. Doğal ölünce büyük matem tutulur, yeni Apis doğana kadar Mısır yas içinde kalırdı.', en: 'Apis and Memphis: In Egypt, the bull called Apis was considered the earthly body of Osiris. Upon his natural death, great mourning was held, and Egypt remained in grief until a new Apis was born.' },
    ],
  },

  // ─── a033 Karınca ───────────────────────────────────────────────────────
  a033: {
    jung: { tr: '"Kolektif Sabır" arketipi. Karınca — küçük çabaların toplamı, görünmez emeğin sembolü. Disiplin ve toplumsallık.', en: 'The "Collective Patience" archetype. The ant — the sum of small efforts, symbol of invisible labor. Discipline and sociality.' },
    dream: { tr: 'Karınca rüyada — küçük adımların büyük bir yapı kurduğunu söyler. Yığın hâlinde: kolektif yaratım. Sana tırmanıyorsa: sıkıntılar birikiyor, ele al.', en: 'Ant in dream — tells you that small steps are building a great structure. In great numbers: collective creation. Climbing on you: troubles are accumulating — address them.' },
    shadow: { tr: 'Robot gibi yaşamak. Bireyselliğini kaybedip sadece "iş" haline gelmek. Karınca büyük bir parça, ama tek başına anlamlıdır.', en: 'Living like a robot. Losing individuality and becoming only "work". The ant is part of a great whole, yet meaningful in itself.' },
    whenAppears: { tr: 'Uzun vadeli projelerde, küçük katkıların önemini fark ettiğinde, toplulukta görünmez ama vazgeçilmez rolde olduğun anda.', en: 'In long-term projects, when you grasp the importance of small contributions, at the moment you hold an invisible yet indispensable role in a community.' },
    traditions: [
      { culture: { tr: 'Süleyman ve Karınca', en: 'Solomon and the Ant' }, meaning: { tr: 'Kuran\'da Neml Suresi — Süleyman peygamber karıncaların lideriyle konuşur. Karıncanın sesi: "Yuvalarınıza girin ki Süleyman ordusu sizi çiğnemesin."', en: 'In the Qur\'an, Surah An-Naml — the prophet Solomon speaks with the leader of the ants. The ant\'s voice: "Enter your dwellings, lest Solomon and his hosts crush you."' } },
      { culture: { tr: 'Afrika', en: 'African' }, meaning: { tr: 'Anansi masallarında — kolektif aklın sembolü. Tek bireyin yapamadığını topluluk yapar.', en: 'In Anansi tales — symbol of the collective mind. What no single being can do, the community accomplishes.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Hopi geleneğinde karınca-insanlar yer altından geldi. Sabır ve birlik öğretmeni.', en: 'In Hopi tradition, the Ant People came from below the earth. Teacher of patience and unity.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Konfüçyüsçü gelenekte erdem örneği — disiplin, sadakat, hiyerarşi.', en: 'In the Confucian tradition, an example of virtue — discipline, loyalty, hierarchy.' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: '"Karınca kararınca" deyişi — herkes payına düşeni yapsın.', en: 'The saying "ant by ant\'s measure" — let each do their share.' } },
    ],
    myths: [
      { tr: 'Süleyman ve Karınca Vadisi: Kuran\'da Süleyman ordusu karıncalar vadisinden geçerken bir karınca diğerlerini uyarır. Süleyman gülümser ve şükreder. En küçük yaratığın sözünü duyabilmek — gerçek liderliktir.', en: 'Solomon and the Valley of the Ants: In the Qur\'an, as Solomon\'s army passes through the valley of the ants, one ant warns the others. Solomon smiles and gives thanks. To hear the speech of the smallest creature — that is true leadership.' },
      { tr: 'Hopi Karınca-İnsanları: Hopi yaratılış mitinde, dünyanın yüzeyi bozulunca insanlar yer altına çekilir. Karınca-insanlar onları besler, korur, sonunda yeniden yüzeye taşır — kolektif şifa.', en: 'The Hopi Ant People: In the Hopi creation myth, when the surface of the world is corrupted, humans retreat underground. The Ant People feed and protect them, and finally bring them back to the surface — collective healing.' },
    ],
  },

  // ─── a034 Hac Leyleği ───────────────────────────────────────────────────
  a034: {
    jung: { tr: '"Yolcu Hac\'ı" arketipi. Hac leyleği — ömrü yolculuğa adamış. Her yıl aynı kutsal yolu yenilemek.', en: 'The "Pilgrim Wayfarer" archetype. The pilgrim stork — a life devoted to journey. Renewing the same sacred path each year.' },
    dream: { tr: 'Hac leyleği rüyada — ruhsal bir göç yaklaşıyor. Aynı yere her yıl giden bir döngünün parçasısın. Yola çıkmanın zamanı geldi.', en: 'Pilgrim stork in dream — a spiritual migration approaches. You are part of a cycle returning to the same place each year. The time has come to set out.' },
    shadow: { tr: 'Sürekli "yolda" olmak ama hiç varmamak. Hac sembolik bir yolculuktur — eğer asla dönmüyorsan, kaçışa dönüşür.', en: 'Always being "on the way" but never arriving. The pilgrimage is a symbolic journey — if you never return, it becomes flight.' },
    whenAppears: { tr: 'Uzun, döngüsel bir göç döneminde, ruhsal bir hac niyetinde, "her yıl bu zamanda hep aynı" hissinde.', en: 'In a long, cyclical period of migration, in the intention of a spiritual pilgrimage, in the feeling "every year at this time, the same again".' },
    traditions: [
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: '"Hacı leylek" — hacca gidip dönen kuş. Çatıdaki yuvası — kutsanmış ev.', en: '"Hacı leylek" — the bird that goes on pilgrimage and returns. Its rooftop nest — a blessed home.' } },
      { culture: { tr: 'İslam Halk', en: 'Islamic Folk' }, meaning: { tr: 'Yıllık göçü hac olarak yorumlanır. Mekke\'ye gidip dönen ruh.', en: 'Its yearly migration is interpreted as pilgrimage. The soul that travels to Mecca and returns.' } },
      { culture: { tr: 'Slav', en: 'Slavic' }, meaning: { tr: 'Dolu Çar tanrısının habercisi. Bahar getiren kuş.', en: 'Messenger of the god Tsar of Hail. The bird that brings spring.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Ba ruhunun kuş hâli — bedenden ayrılıp seyahat eden öz.', en: 'The bird-form of the Ba soul — the essence that leaves the body and travels.' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: '"Leylek bahar getirir" — döngüsel umut sembolü.', en: '"The stork brings spring" — symbol of cyclical hope.' } },
    ],
    myths: [
      { tr: 'Hacca Giden Leylek: Anadolu inanışına göre leylekler her yıl Mekke yönüne göç eder, dönerler. Bu nedenle "hacı leylek" denir. Onlara zarar veren bir kutsalı bozmuş sayılır.', en: 'The Stork that Goes on Hajj: According to Anatolian belief, storks migrate each year toward Mecca and return. For this reason they are called "hacı leylek". To harm them is to break a sacred thing.' },
      { tr: 'Leyleğin Yuvası: Bir Anadolu hikâyesi: Bir köylü çatısındaki leylek yuvasını yıkar. O yıl yağmur yağmaz, mahsul kurur. Köylü yuvayı tekrar yapana kadar bereket dönmez.', en: 'The Stork\'s Nest: An Anatolian tale: a peasant destroys the stork\'s nest on his roof. That year no rain falls and the crop withers. Abundance does not return until the peasant rebuilds the nest.' },
    ],
  },

  // ─── a035 Ördek ─────────────────────────────────────────────────────────
  a035: {
    jung: { tr: '"Akış İçinde Durulluk" arketipi. Ördek — suda yüzer, yağmurda ıslanmaz. Etrafından geçen kaosa karışmayan iç huzur.', en: 'The "Stillness Within Flow" archetype. The duck — swims on water, untouched by rain. The inner peace that does not mingle with the chaos passing through.' },
    dream: { tr: 'Ördek rüyada — duygusal akıştan etkilenmeden durabilmen gerektiğini söyler. Yüzüyorsa: huzur içinde ilerliyorsun. Uçuyorsa: bir döngüden çıkış zamanı.', en: 'Duck in dream — tells you that you must remain unaffected by emotional currents. Swimming: you are moving forward in peace. Flying: time to exit a cycle.' },
    shadow: { tr: 'Aşırı ayrılık. "Etkilenmemek" duyarsızlığa dönüşürse — ördek su kuşu olur ama "kalp" kalmaz.', en: 'Excessive detachment. If "not being affected" turns into insensitivity — the duck remains a water bird, but the heart is gone.' },
    whenAppears: { tr: 'Kaotik bir ortamda merkezde kalman gerekirken, başkalarının dramından çıkmak istediğinde, suyun seni temizlediği bir anda.', en: 'When you must stay centered in a chaotic environment, when you wish to exit another\'s drama, in a moment when water cleanses you.' },
    traditions: [
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Mandarin ördekleri — sadık eşler. Düğün hediyesi olarak çift verilir.', en: 'Mandarin ducks — faithful spouses. Given in pairs as wedding gifts.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Su ile gök arasında köprü. Hem yüzer hem uçar — iki dünya hayvanı.', en: 'A bridge between water and sky. It swims and flies — a two-world animal.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Akhenaten döneminde — basitliğin ve halkın hayvanı. Tapınak motiflerinde aile sahnesi.', en: 'In the Akhenaten period — the animal of simplicity and the people. A family scene in temple motifs.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Göl köylerinde rızkın simgesi. "Ördek bolsa, ev tok" deyişi.', en: 'In lakeside villages, the symbol of sustenance. The saying "where ducks are plenty, the home is fed".' } },
      { culture: { tr: 'Slav', en: 'Slavic' }, meaning: { tr: 'Yumurtasında dünyanın saklandığı kuş — yaratılışın annesi.', en: 'The bird whose egg conceals the world — the mother of creation.' } },
    ],
    myths: [
      { tr: 'Mandarin Ördekleri: Çin geleneğinde mandarin ördekleri eşlerini ömür boyu değiştirmez. Eşi ölünce diğeri de bekler. Bu yüzden düğünlerde çift mandarin ördeği hediye edilir — sadakat duası.', en: 'Mandarin Ducks: In Chinese tradition, mandarin ducks never change partners. When one dies, the other waits. For this reason a pair of mandarin ducks is given at weddings — a prayer of faithfulness.' },
      { tr: 'Slav Yaratılış Ördekleri: Slav mitolojisinde dünya, suların üstünde yüzen iki ördeğin yumurtaladığı sarı yumurtadan doğdu. Akış üstünde yaratım.', en: 'The Slavic Creation Ducks: In Slavic mythology, the world was born from the yellow egg laid by two ducks floating on the waters. Creation upon flow.' },
    ],
  },

  // ─── a036 Kuzgun ────────────────────────────────────────────────────────
  a036: {
    jung: { tr: '"Trickster Bilge" arketipi. Kuzgun — kâhin ile soytarı bir bedende. Karanlığın zekası, ölümün haberi, ama aynı zamanda yaratıcılık.', en: 'The "Trickster Sage" archetype. The raven — seer and jester in one body. The intelligence of darkness, the news of death, yet also creativity.' },
    dream: { tr: 'Kuzgun rüyada — bir uyarı geliyor. Ya da: zekanı saklamayı bırak. Konuşuyorsa: gizli bir bilgi açılıyor.', en: 'Raven in dream — a warning is coming. Or: stop hiding your intelligence. Speaking: a hidden knowledge is opening.' },
    shadow: { tr: 'Kara mizah ve alaycılık. Kuzgun her şeyi bilir gibi davranırsa — siniklik. Her şeyin "boş" olduğunu söyleyen ses.', en: 'Black humor and mockery. If the raven acts as though it knows everything — cynicism. The voice saying that all is "empty".' },
    whenAppears: { tr: 'Uyarı işaretlerini görmen gerekirken, zekanın kara mizahla beslendiği anlarda, ölüm-yas süreçlerinde rehber gibi.', en: 'When you must see the warning signs, in moments when intelligence is fed by dark humor, as a guide in death-grief processes.' },
    traditions: [
      { culture: { tr: 'İskandinav', en: 'Norse' }, meaning: { tr: 'Odin\'in iki kuzgunu Huginn (düşünce) ve Muninn (hafıza). Her gün dünyayı dolaşır, hanlarına bilgi getirir.', en: 'Odin\'s two ravens, Huginn (thought) and Muninn (memory). Every day they fly across the world and bring news back to their lord.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Morrigan — savaş tanrıçası kuzgun formunda görünür. Ölüme yakın olanları işaretler.', en: 'The Morrigan — the war goddess appears in raven form. She marks those near to death.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Haida ve Tlingit geleneğinde — yaratıcı trickster. Güneşi çalan, dünyayı şekillendiren.', en: 'In Haida and Tlingit tradition — the creative trickster. The one who stole the sun and shaped the world.' } },
      { culture: { tr: 'Türk-Moğol', en: 'Turco-Mongol' }, meaning: { tr: 'Karakuş — şamanın yardımcısı. Atalardan haber getiren kara haberci.', en: 'Karakuş — the shaman\'s helper. The dark messenger who brings word from the ancestors.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Nuh\'un gemisinden ilk salınan kuş — geri dönmemiş. Sadakatsizliğin simgesi olarak yorumlanmış, ama bağımsızlık olarak da.', en: 'The first bird released from Noah\'s ark — it did not return. Interpreted as a symbol of disloyalty, yet also of independence.' } },
    ],
    myths: [
      { tr: 'Odin\'in Kuzgunları: İskandinav baş tanrı Odin\'in omuzlarında iki kuzgun durur — Huginn (düşünce) ve Muninn (hafıza). Her gün dünyayı dolaşır, akşam Odin\'in kulağına haber fısıldarlar. Bilgelik — gözlemleyebilmektir.', en: 'Odin\'s Ravens: Two ravens perch on the shoulders of the Norse high god Odin — Huginn (thought) and Muninn (memory). Each day they roam the world and at evening whisper news in Odin\'s ear. Wisdom is the capacity to observe.' },
      { tr: 'Haida Kuzgunu: Haida mitolojisinde kuzgun, kutucu tanrıdan güneşi, ayı ve yıldızları çalar ve dünyaya dağıtır. Yaratıcı hilebaz — kuralı bozarak hayatı veren.', en: 'The Haida Raven: In Haida mythology, the raven steals the sun, moon, and stars from the hoarder-god and distributes them to the world. The creative trickster — the one who gives life by breaking the rule.' },
    ],
  },

  // ─── a037 Ak Kelebek ────────────────────────────────────────────────────
  a037: {
    jung: { tr: '"Saf Ruh" arketipi. Ak kelebek — kelebeklerin en hassas, en geçici formu. Ruhun beyaz ışığı.', en: 'The "Pure Soul" archetype. The white butterfly — the most delicate, most fleeting form of butterflies. The white light of the soul.' },
    dream: { tr: 'Ak kelebek rüyada — bir saflık, bir aydınlık geri geliyor. Ölmüş yakının ruhu, ya da çocuksu özün ziyareti.', en: 'White butterfly in dream — a purity, a clarity is returning. The soul of a deceased loved one, or a visit from your childlike essence.' },
    shadow: { tr: 'Aşırı maneviyat — bedeni inkâr. Ak kelebek hep "yüksek titreşim"de yaşamaya çalışırsa, dünya işlerini ihmal eder.', en: 'Excessive spirituality — denial of the body. If the white butterfly tries to live always at "high vibration", it neglects worldly matters.' },
    whenAppears: { tr: 'Bir hafızanın berraklaştığı anda, atalarınla bağlantı kurmak istediğinde, çocuksu temiz neşeyi geri istediğin günlerde.', en: 'At the moment a memory clarifies, when you wish to connect with your ancestors, in the days you want your pure childlike joy back.' },
    traditions: [
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: '"Ak kelebek atadan haber" — yas evine giren ak kelebek, gidenden mesaj.', en: '"The white butterfly is news from the ancestor" — a white butterfly entering a house in mourning is a message from the departed.' } },
      { culture: { tr: 'Japonya', en: 'Japanese' }, meaning: { tr: 'Hakuchō — ölmüş kişinin ruhunun ziyareti. Aile yıldönümlerinde gelir.', en: 'Hakuchō — the visit of a deceased person\'s soul. It comes on family anniversaries.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Ölmüş çocukların ruhu beyaz kelebek formunda dönermiş. Anneye teselli.', en: 'The souls of deceased children were said to return in the form of white butterflies. A consolation to the mother.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Diriliş sembolü. Mezar taşlarında işlenir — ruhun bedeni terk edip yükselişi.', en: 'Symbol of resurrection. Carved on tombstones — the soul leaving the body to ascend.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Saf aşkın simgesi. Sevdiğine söz vermenin işareti.', en: 'Symbol of pure love. The sign of pledging oneself to the beloved.' } },
    ],
    myths: [
      { tr: 'Atadan Haber: Anadolu\'da ölmüş bir yakının yas haftalarında eve giren ak kelebek, onun ruhunun ziyareti sayılır. "Hoş geldin" denir, kovulmaz. Kelebek çıkana kadar dua edilir.', en: 'Word from the Ancestor: In Anatolia, a white butterfly entering the home during the mourning weeks of a deceased loved one is considered a visit from their soul. It is greeted with "welcome" and not driven away. Prayers are offered until the butterfly leaves.' },
      { tr: 'Hakuchō Geleneği: Japon ailelerinde ölüm yıldönümlerinde evin etrafında dolaşan beyaz kelebekler, atayı temsil eder. Tütsü yakılır, isim anılır — kelebek gelmeden gidemez.', en: 'The Hakuchō Tradition: In Japanese families, white butterflies circling the home on death anniversaries represent the ancestor. Incense is lit, the name is spoken — the butterfly cannot depart until it has come.' },
    ],
  },

  // ─── a038 Deve ──────────────────────────────────────────────────────────
  a038: {
    jung: { tr: '"Çöl Yolcusu" arketipi. Deve — uzun yola dayanıklılık, kurak dönemleri içsel kaynakla geçme.', en: 'The "Desert Wayfarer" archetype. The camel — endurance on the long road, traversing dry seasons by inner resource.' },
    dream: { tr: 'Deve rüyada — uzun bir dayanıklılık testi var. Yük taşıyorsa: sorumluluk artıyor. Çölde yürüyorsa: ruhsal kuraklıkta da yolunu bulacaksın.', en: 'Camel in dream — a long test of endurance lies ahead. Bearing a load: responsibility is growing. Walking in the desert: you will find your way even through spiritual drought.' },
    shadow: { tr: 'Her yükü taşıma takıntısı. Deve "hayır" demeyi bilmeli — sınırsız fedakârlık çöküştür.', en: 'The compulsion to carry every burden. The camel must know how to say "no" — limitless sacrifice is collapse.' },
    whenAppears: { tr: 'Uzun süreli bir yüke girerken, kıt kaynakla dayanman gerektiğinde, ruhsal çölde içsel kaynakları bulman lazımken.', en: 'When taking on a long-lasting burden, when you must endure with scarce resources, when you must find inner reserves in the spiritual desert.' },
    traditions: [
      { culture: { tr: 'Arap-İslam', en: 'Arab-Islamic' }, meaning: { tr: 'Hz. Salih\'in mucize devesi — Kuran\'da Naka. Kavmin sınanması; deveyi öldüren toplum cezalandırılır.', en: 'The miracle she-camel of the prophet Salih — Naqah in the Qur\'an. The trial of his people; the community that slays the camel is punished.' } },
      { culture: { tr: 'Sufi', en: 'Sufi' }, meaning: { tr: 'Mevlana\'nın Mesnevi\'sinde — sabır ve teslimiyetin sembolü.', en: 'In Rumi\'s Masnavi — symbol of patience and surrender.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Yörük kültüründe yaşam hattının kendisi. Deve kervansız Anadolu olmaz.', en: 'In Yörük culture, the very line of life. Anatolia is unthinkable without the camel caravan.' } },
      { culture: { tr: 'İbrahimi', en: 'Abrahamic' }, meaning: { tr: 'İbrahim\'in deve kervanı — peygamberlerin yolunun bineği.', en: 'Abraham\'s camel caravan — the mount of the prophets\' way.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Çölün kapısı — yaşam ve ölüm arasında köprü.', en: 'The gate of the desert — bridge between life and death.' } },
    ],
    myths: [
      { tr: 'Salih\'in Devesi: Kuran\'da Hz. Salih\'in kavmine mucize olarak bir deve verilir. Onu öldürmemeleri ve suyu paylaşmaları istenir. Kavim deveyi öldürür — kavim helak olur. Kutsal yüke saygı testi.', en: 'Salih\'s She-Camel: In the Qur\'an, a she-camel is given as a miracle to the people of the prophet Salih. They are commanded not to slay her and to share the water. The people kill the camel — the people are destroyed. A test of respect for the sacred burden.' },
      { tr: 'Yörük Devesi: Anadolu Yörüklerinde deve sadece bir hayvan değil, ailenin parçasıdır. İsim verilir, yas tutulur. Devesini kaybeden ev, evladını kaybetmiş kabul edilir.', en: 'The Yörük Camel: Among Anatolian Yörüks, the camel is not merely an animal but part of the family. It is named, mourned. A household that loses its camel is held to have lost a child.' },
    ],
  },

  // ─── a039 Balık ─────────────────────────────────────────────────────────
  a039: {
    jung: { tr: '"Bilinçaltı Akış" arketipi. Balık — suyun derinindeki bilgelik. Sezgi, doğurganlık, geçişlerin habercisi.', en: 'The "Unconscious Flow" archetype. The fish — the wisdom in the depths of water. Intuition, fertility, herald of transitions.' },
    dream: { tr: 'Balık rüyada — derin bir bilgi yüzeye çıkıyor. Çok balık görüyorsan: bolluk yakın. Yakalıyorsan: bir hakikati avlıyorsun.', en: 'Fish in dream — a deep knowledge is surfacing. Seeing many fish: abundance is near. Catching them: you are hunting a truth.' },
    shadow: { tr: 'Soğukluk, kayganlık. Balık tutulmaz — sezginin bedeni yok olur, eline geçmez.', en: 'Coldness, slipperiness. The fish cannot be held — intuition has no body, never quite reaches your hand.' },
    whenAppears: { tr: 'Hamilelik (gerçek/yaratıcı), sezginin keskinleştiği, dünyanın altında bir akıntının seni taşıdığı anda.', en: 'In pregnancy (literal/creative), when intuition sharpens, at the moment an underground current is carrying you.' },
    traditions: [
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'İsa\'nın sembolü. "İkhthys" — Yunanca balık, İsa\'nın adının ilk harfleri. Erken Hristiyanların gizli sembolü.', en: 'Symbol of Christ. "Ichthys" — Greek for fish, an acronym of Christ\'s name. The secret symbol of the early Christians.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Matsya — Vishnu\'nun balık avatarı. Tufandan insanlığı kurtarır.', en: 'Matsya — Vishnu\'s fish avatar. He saves humanity from the flood.' } },
      { culture: { tr: 'Sumer', en: 'Sumerian' }, meaning: { tr: 'Oannes — balık-insan tanrı, sudan çıkıp insanlara medeniyet öğretti.', en: 'Oannes — the fish-man god who emerged from the waters to teach civilization to humanity.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Bolluğun sembolü. Yeni yılda balık yenir — "yıllar boyu fazlalık" duası.', en: 'Symbol of abundance. Fish is eaten at New Year — the wish "surplus through the years".' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: 'Bereket sembolü. Düğünlerde balık motifi — doğurganlık duası.', en: 'Symbol of abundance. The fish motif at weddings — a blessing of fertility.' } },
    ],
    myths: [
      { tr: 'Matsya Avatarı: Hint mitolojisinde tufan yaklaşırken Vishnu küçük bir balık olarak Manu\'ya görünür. Büyür, devleşir, gemiyi çekerek insanlığı kurtarır. Sular bilinçaltı, balık o bilinçaltından çıkan kurtuluş.', en: 'The Matsya Avatar: In Hindu mythology, as the flood nears, Vishnu appears to Manu as a small fish. He grows immense and tows the ship, saving humanity. The waters are the unconscious; the fish is the salvation emerging from it.' },
      { tr: 'İkhthys: Roma\'da Hristiyanlar zulüm altındayken birbirini tanımak için balık sembolünü kumda çizerdi. "Iesous Khristos Theou Yios Soter" baş harfleri — İsa, Tanrının Oğlu, Kurtarıcı.', en: 'Ichthys: While Christians were persecuted in Rome, they drew the fish symbol in the sand to recognize one another. The initials of "Iesous Khristos Theou Yios Soter" — Jesus Christ, Son of God, Savior.' },
    ],
  },

  // ─── a040 Horoz ─────────────────────────────────────────────────────────
  a040: {
    jung: { tr: '"Şafak Habercisi" arketipi. Horoz — uyanışı ilan eden, karanlığı yarıp ışığı çağıran ses.', en: 'The "Herald of Dawn" archetype. The rooster — the voice that announces awakening, that splits darkness and summons light.' },
    dream: { tr: 'Horoz rüyada — uyanma vakti! Bilinçaltında gördüğün bir şey gün ışığına çıkmak istiyor. Ötüyorsa: ilan zamanı, sus durmak günah.', en: 'Rooster in dream — time to wake! Something you have seen in your unconscious wants to come to daylight. Crowing: time to declare; staying silent is sin.' },
    shadow: { tr: 'Kibirli gösteriş. Horoz sabahları ilan eder ama "ben olmasam güneş doğmaz" sanrısı — egonun çiçeklenmesi.', en: 'Conceited display. The rooster heralds the mornings, but the delusion "without me the sun would not rise" — the ego in bloom.' },
    whenAppears: { tr: 'Uyanmak, ilan etmek, sözünü yüksek sesle söylemek gerektiğinde, karanlık dönem bittiğinde.', en: 'When you must wake, declare, speak your word aloud, when a dark period has ended.' },
    traditions: [
      { culture: { tr: 'Türk Halk', en: 'Turkish Folk' }, meaning: { tr: 'Sabahın müjdecisi — ezandan önce öten kuş. Anadolu köyünün saatçisi.', en: 'Herald of the morning — the bird that crows before the call to prayer. The clockkeeper of the Anatolian village.' } },
      { culture: { tr: 'Pers', en: 'Persian' }, meaning: { tr: 'Zerdüştlükte — kötülüğü kovan, ışığı çağıran kutsal kuş.', en: 'In Zoroastrianism — the sacred bird that drives off evil and summons light.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Petrus\'un üç kez İsa\'yı inkâr etmesi horozun ötüşüyle bağlı — vicdanın sesi.', en: 'Peter\'s threefold denial of Christ is bound to the rooster\'s crow — the voice of conscience.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'On iki burç hayvanından biri. Dürüstlük, sadakat, çalışkanlığın sembolü.', en: 'One of the twelve zodiac animals. Symbol of honesty, loyalty, and diligence.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Yer altı dünyasının uyarıcısı — ruhların uyanış saatini bildirir.', en: 'The warner of the underworld — announcer of the hour the souls awaken.' } },
    ],
    myths: [
      { tr: 'Petrus ve Horoz: Hristiyan İncil\'inde Petrus, İsa\'yı korkudan üç kez inkâr eder. Horoz öttüğünde fark eder ve ağlar. Horoz — vicdanın geri dönüş sesi.', en: 'Peter and the Rooster: In the Christian Gospel, Peter denies Christ three times out of fear. When the rooster crows, he realizes and weeps. The rooster — the voice of conscience\'s return.' },
      { tr: 'Zerdüşt Horozu: Eski Pers geleneğinde horozun ötüşüyle birlikte gece şeytanları kovulurdu. Şafak — kötülüğün geri çekilmesi. Horoz tanrısal düzenin müjdecisi.', en: 'The Zoroastrian Rooster: In ancient Persian tradition, the night demons were driven out at the rooster\'s crow. The dawn — the retreat of evil. The rooster, herald of divine order.' },
    ],
  },

  // ─── a041 Tavşan ────────────────────────────────────────────────────────
  a041: {
    jung: { tr: '"Ay Çocuğu / Trickster" arketipi. Tavşan — sezgiyle hareket eden çevik akıl. Hızla kaybolup hızla geri gelen.', en: 'The "Moon Child / Trickster" archetype. The rabbit — the agile intellect moving by intuition. The one who vanishes swiftly and returns swiftly.' },
    dream: { tr: 'Tavşan rüyada — bir fırsat hızla geçiyor, dikkatli ol. Kaçıyorsa: korkudan değil, sezgiden hareket et. Çoğalıyorsa: bereket geliyor.', en: 'Rabbit in dream — an opportunity is passing quickly, be alert. Fleeing: move by intuition, not by fear. Multiplying: abundance is coming.' },
    shadow: { tr: 'Aşırı korku. Her gölgeden ürkmek, hayatı kaçırmak. Tavşan hızlıdır ama gizlenmek hep çözüm değildir.', en: 'Excessive fear. Startling at every shadow, missing life. The rabbit is swift, but hiding is not always the answer.' },
    whenAppears: { tr: 'Hızlı bir karar gerektiğinde, doğurgan bir döneme girerken, ay döngüsünün başlangıcında.', en: 'When a swift decision is needed, when entering a fertile period, at the start of a lunar cycle.' },
    traditions: [
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Ay\'da ölümsüzlük iksiri döven yeşim tavşan. Mid-Autumn Festival\'ın sembolü.', en: 'The jade rabbit pounding the elixir of immortality on the moon. Symbol of the Mid-Autumn Festival.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Cerridwen\'in kazanından doğan dönüşüm sembolü. Bereket tanrıçasının yoldaşı.', en: 'A symbol of transformation born from Cerridwen\'s cauldron. Companion of the goddess of abundance.' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: '"Tavşan masalı" — zekasıyla kurttan ve tilkiden kurtulan küçük kahraman.', en: '"The Rabbit\'s Tale" — the small hero who, by his wits, escapes the wolf and the fox.' } },
      { culture: { tr: 'Aztek', en: 'Aztec' }, meaning: { tr: 'Centzon Totochtin — 400 tavşan tanrı. Pulque (içki) ve coşkunun habercisi.', en: 'Centzon Totochtin — the four hundred rabbit gods. Heralds of pulque (drink) and ecstasy.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Paskalya tavşanı — dirilişin ve baharın simgesi. Yumurta dağıtan haberci.', en: 'The Easter Bunny — symbol of resurrection and spring. The herald who distributes eggs.' } },
    ],
    myths: [
      { tr: 'Ay Tavşanı: Çin mitolojisinde Ay\'da bir tavşan yaşar ve ölümsüzlük iksiri döver. Mid-Autumn Festival\'da çocuklar onun şerefine ay kekleri yer — kozmik bereket.', en: 'The Moon Rabbit: In Chinese mythology, a rabbit lives on the moon and pounds the elixir of immortality. At the Mid-Autumn Festival, children eat mooncakes in its honor — cosmic abundance.' },
      { tr: 'Tavşan ve Kaplumbağa: Aesop\'un en bilinen fablında hızlı tavşan, yavaş kaplumbağaya yarışta kaybeder. Hız her zaman kazanmaz — sebat kazanır.', en: 'The Hare and the Tortoise: In Aesop\'s best-known fable, the swift hare loses the race to the slow tortoise. Speed does not always win — perseverance does.' },
    ],
  },

  // ─── a042 Akrep ─────────────────────────────────────────────────────────
  a042: {
    jung: { tr: '"Yıkıcı Dönüştürücü" arketipi. Akrep — Yılan ile aynı boyda, hatta daha derin. Yas ile yenilenmeyi bir ısırışta birleştiren.', en: 'The "Destructive Transformer" archetype. The scorpion — equal to or deeper than the serpent. The one who unites mourning and renewal in a single sting.' },
    dream: { tr: 'Akrep rüyada — bastırılan bir konu yüzeye çıkıyor. Sokuyorsa: bir gerçek seni dönüştürecek. Sırtında taşıyorsan: zor bir bilgiyi taşıyorsun.', en: 'Scorpion in dream — a suppressed matter is surfacing. Stinging: a truth will transform you. Carrying it on your back: you are bearing a difficult knowledge.' },
    shadow: { tr: 'Zehir saçmak. Akrep yaralandığında çevresine kuyruğunu sallar — yaralı kişi başkalarını yaralar. İçsel acı tedavi edilmezse zehirleyici olur.', en: 'Spreading venom. Wounded, the scorpion swings its tail at all around — the wounded one wounds others. Inner pain untreated becomes toxic.' },
    whenAppears: { tr: 'Yas, yıkım, kıskançlık veya ihanet gibi derin duygu süreçlerinde, dönüştürücü acıyla yüzleşmen gerektiğinde.', en: 'In deep emotional processes such as grief, destruction, jealousy, or betrayal, when you must face transformative pain.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Serqet — akrep tanrıça. Ölüleri öbür dünyada koruyan. Zehiri tedaviye dönüştüren.', en: 'Serqet — the scorpion goddess. Protector of the dead in the otherworld. The one who turns venom into cure.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Orion\'u öldüren akrep — Artemis tarafından gönderilen kozmik adalet. Yıldız takımı oldular.', en: 'The scorpion that killed Orion — cosmic justice sent by Artemis. They became constellations.' } },
      { culture: { tr: 'Astroloji', en: 'Astrology' }, meaning: { tr: 'Akrep burcu — ölüm ve diriliş, tabu, gizli bilgi. Pluto\'nun ev sahibi.', en: 'The sign of Scorpio — death and resurrection, taboo, hidden knowledge. The house of Pluto.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Köy efsanelerinde akrebin yuvasını bozan başına iş alır. Sınırlı varlığın saygısı.', en: 'In village legends, whoever disturbs the scorpion\'s nest brings trouble upon themselves. The reverence due to bounded being.' } },
      { culture: { tr: 'İslam', en: 'Islamic' }, meaning: { tr: 'Hadis-i şerifte cennette zararı olmayan, dünyada koruyucu sayılır — kötülük yalnız kendine değer.', en: 'In hadith, harmless in paradise and a protector in this world — evil reaches only itself.' } },
    ],
    myths: [
      { tr: 'Serqet ve Mumya: Mısır firavunları mumyalanırken karaciğer kavanozunu akrep tanrıça Serqet korurdu. Zehrin antiseptik gücü — ölümle yenilenmenin birleşmesi.', en: 'Serqet and the Mummy: When Egyptian pharaohs were mummified, the jar of the liver was guarded by the scorpion goddess Serqet. The antiseptic power of venom — the union of death and renewal.' },
      { tr: 'Orion ve Akrep: Yunan mitolojisinde dev avcı Orion kibirinden cezalandırılır — küçük bir akrep onu öldürür. İkisi de gökyüzüne yerleşir, biri doğarken diğeri batar — sonsuz kovalama.', en: 'Orion and the Scorpion: In Greek mythology, the giant hunter Orion is punished for his arrogance — a small scorpion kills him. Both are placed in the sky, one rising as the other sets — eternal pursuit.' },
    ],
  },

  // ─── a043 Kurbağa ───────────────────────────────────────────────────────
  a043: {
    jung: { tr: '"Eşiğin Habercisi" arketipi. Kurbağa — sudan karaya, çocukluktan yetişkinliğe geçen. Metamorfozun en görünür hâli.', en: 'The "Herald of the Threshold" archetype. The frog — the one who passes from water to land, from childhood to adulthood. The most visible form of metamorphosis.' },
    dream: { tr: 'Kurbağa rüyada — bir geçiş tamamlanıyor. Yağmurda görünüyorsa: temizlenme yaklaşıyor. Vıraklıyorsa: sesini bul, söyle.', en: 'Frog in dream — a transition is being completed. Appearing in rain: cleansing approaches. Croaking: find your voice and speak.' },
    shadow: { tr: 'Yarı-dönüşüm. Bir hayatta hep iribaş kalmak — büyüyemeyen, sudan çıkamayan. Konfor geçişi engeller.', en: 'Half-transformation. Remaining a tadpole all one\'s life — unable to grow, unable to leave the water. Comfort prevents passage.' },
    whenAppears: { tr: 'Bir eşikte (taşınma, evlilik, ayrılık), ruhsal/duygusal temizlenmede, sesini kullanma çağrısında.', en: 'At a threshold (moving, marriage, separation), in spiritual/emotional cleansing, at the call to use your voice.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Heqet — kurbağa başlı tanrıça. Doğumun ve yenilenmenin koruyucusu. Nil taşkınının habercisi.', en: 'Heqet — the frog-headed goddess. Protector of birth and renewal. Herald of the Nile flood.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Üç ayaklı kurbağa Jin Chan — ay ve zenginlik sembolü. Para getiren tılsım.', en: 'The three-legged frog Jin Chan — symbol of the moon and wealth. A talisman that draws money.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: '"Kurbağa öttü, yağmur yağdı" — bereketin habercisi. Köy ekonomisinde belirleyici sayılırdı.', en: '"The frog croaked, the rain came" — herald of abundance. Considered decisive in the village economy.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Şifa kuyularının koruyucusu. Toprak ile suyun birleştiği yerin bekçisi.', en: 'Guardian of healing wells. Keeper of the place where earth and water meet.' } },
      { culture: { tr: 'Aztek', en: 'Aztec' }, meaning: { tr: 'Tlaltecuhtli — yer tanrıça, kurbağa formunda. Yaratılışın bedeni.', en: 'Tlaltecuhtli — the earth goddess in frog form. The body of creation.' } },
    ],
    myths: [
      { tr: 'Heqet ve Doğum: Mısır mitolojisinde kadın doğum yaparken kurbağa tanrıça Heqet\'in tılsımı bedeninin üzerinde taşınırdı. Suyun ve toprağın doğurgan birleşmesi.', en: 'Heqet and Birth: In Egyptian mythology, while a woman gave birth, the talisman of the frog goddess Heqet was worn on her body. The fertile union of water and earth.' },
      { tr: 'Prens Kurbağa: Grimm masalında prensesin öptüğü kurbağa prense dönüşür. Aşk ve kabul — gerçek kimliği ortaya çıkarır. Görünenin altındakini görmek.', en: 'The Frog Prince: In the Grimm tale, the frog the princess kisses turns into a prince. Love and acceptance — reveal the true identity. To see beneath what appears.' },
    ],
  },

  // ─── a044 Karga ─────────────────────────────────────────────────────────
  a044: {
    jung: { tr: '"Kolektif Bilge" arketipi. Karga — Kuzgun\'un sürü hâli. Bireysel zekanın paylaşıma açıldığı yer.', en: 'The "Collective Sage" archetype. The crow — the raven in its flock form. The place where individual intelligence opens to sharing.' },
    dream: { tr: 'Karga rüyada — kalabalığın akıllıca seçilmiş bir parçası olmaya çağrılıyorsun. Konuşuyorsa: bir mesaj iletmen lazım. Sürü hâlinde: kolektif karar zamanı.', en: 'Crow in dream — you are being called to become a wisely chosen part of the crowd. Speaking: you must convey a message. In flock: time for a collective decision.' },
    shadow: { tr: '"Toplum baskısı" — kalabalık zihne kapılma. Karga sürüsü güçlüdür ama tek tek özgün kalmak da gerekir.', en: '"Social pressure" — being swept by the crowd mind. The murder of crows is strong, yet each must remain its own.' },
    whenAppears: { tr: 'Bir gruba katılırken, fikrini kalabalığa açıkça söylemen gerektiğinde, kolektif bir karara dahil olduğunda.', en: 'While joining a group, when you must speak your view openly to the crowd, when you are included in a collective decision.' },
    traditions: [
      { culture: { tr: 'Tibet', en: 'Tibetan' }, meaning: { tr: 'Mahakala\'nın haberci kuşu. Yıkıcı bilgeliğin habercisi.', en: 'The messenger bird of Mahakala. Herald of destructive wisdom.' } },
      { culture: { tr: 'Türk Halk', en: 'Turkish Folk' }, meaning: { tr: 'Karga zekası ile bilinir — bir kayalığa ceviz düşürerek kırması Anadolu masallarında geçer.', en: 'Known for the crow\'s wit — breaking a walnut by dropping it on a rock is told in Anatolian tales.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Apollon\'un kuşu. Önce beyazdı, kötü haber getirdiği için tanrı tarafından siyaha boyandı.', en: 'Apollo\'s bird. Once white, painted black by the god for bringing bad news.' } },
      { culture: { tr: 'Avustralya Aborjin', en: 'Australian Aboriginal' }, meaning: { tr: 'Waa — yaratıcı ata. Ateşi insanlığa getiren trickster.', en: 'Waa — the creator ancestor. The trickster who brought fire to humanity.' } },
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Şani (Satürn) tanrısının bineği. Karma ve adaletin habercisi.', en: 'The mount of the god Shani (Saturn). Herald of karma and justice.' } },
    ],
    myths: [
      { tr: 'Apollon\'un Beyaz Kargası: Yunan mitolojisinde karga eskiden beyazdı. Apollon\'a sevgilisi Koronis\'in sadakatsizliğini söyleyince, tanrı haberin acısını kuşa yansıttı — karganın rengi siyah oldu, sesi cızırdadı.', en: 'Apollo\'s White Crow: In Greek mythology, the crow was once white. When it told Apollo of his beloved Coronis\'s unfaithfulness, the god transferred the pain of the news onto the bird — the crow\'s color became black and its voice grew harsh.' },
      { tr: 'Waa ve Ateş: Avustralya Aborjin mitolojisinde karga Waa, kadınların gizlediği ateşi çalar ve insanlığa getirir. Trickster yaratıcı — kuralı bozarak hayatı kolaylaştıran.', en: 'Waa and Fire: In Australian Aboriginal mythology, the crow Waa steals the fire hidden by the women and brings it to humanity. The trickster-creator — the one who eases life by breaking the rule.' },
    ],
  },

  // ─── a045 Sincap ────────────────────────────────────────────────────────
  a045: {
    jung: { tr: '"Mütevazı Hazırlayıcı" arketipi. Sincap — küçük olduğunu bilen, ama planını yapan. Kollektif değil, bireysel hazırlığın sembolü.', en: 'The "Humble Preparer" archetype. The squirrel — knowing it is small, yet making its plan. Symbol of individual, not collective, preparation.' },
    dream: { tr: 'Sincap rüyada — geleceğe hazırlık zamanı. Yiyecek saklıyorsa: ekonomik/duygusal güvenlik için tedbir al. Atlıyorsa: çevik bir hamle gerekiyor.', en: 'Squirrel in dream — time to prepare for the future. Hoarding food: take measures for economic/emotional security. Leaping: an agile move is needed.' },
    shadow: { tr: 'Kaygılı biriktiricilik. "Yetmez" duygusuyla durmadan istiflemek — neşeyi kaçırır. Sincap aynı zamanda oynar; sadece çalışmaz.', en: 'Anxious hoarding. Stockpiling endlessly out of the feeling of "not enough" — joy is missed. The squirrel also plays; it does not only work.' },
    whenAppears: { tr: 'Bir kış dönemine girmeden önce, tasarruf veya enerji birikimine ihtiyaç duyulurken, hayatın size çeviklik gösterdiği anlarda.', en: 'Before entering a winter season, when savings or energy reserves are needed, in moments when life shows you agility.' },
    traditions: [
      { culture: { tr: 'İskandinav', en: 'Norse' }, meaning: { tr: 'Ratatoskr — dünya ağacı Yggdrasil\'de yukarı aşağı koşan haberci sincap. Tanrılar ile devler arasında mesaj taşır.', en: 'Ratatoskr — the messenger squirrel running up and down the world-tree Yggdrasil. Carries messages between the gods and the giants.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Hazırlık ve ileri görüşün sembolü. Druidlerin doğa öğretmenlerinden.', en: 'Symbol of preparation and foresight. One of the nature-teachers of the Druids.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Cherokee geleneğinde — küçüklüğünüze rağmen büyük katkı yapabilirsiniz mesajının habercisi.', en: 'In Cherokee tradition — the herald of the message that you can make a great contribution despite your smallness.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Karadeniz ormanlarında sevimli yoldaş. Çocuk masallarının küçük zeki kahramanı.', en: 'A beloved companion in the Black Sea forests. The small clever hero of children\'s tales.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Rama\'nın köprü inşasına yardım eden küçük sincap — büyük işlerde küçük katkılar.', en: 'The small squirrel that helps Rama build the bridge — small contributions to great works.' } },
    ],
    myths: [
      { tr: 'Ratatoskr ve Yggdrasil: İskandinav mitolojisinde dünya ağacı Yggdrasil\'in tepesindeki kartal ile köklerindeki ejderha arasında mesaj taşıyan haberci sincap. Çatışmayı körükler — söylenti yayıcı kötülük mü, gerekli aracı mı?', en: 'Ratatoskr and Yggdrasil: In Norse mythology, the messenger squirrel that carries messages between the eagle atop the world-tree Yggdrasil and the dragon at its roots. He stirs conflict — is he a gossip-spreading evil, or a necessary intermediary?' },
      { tr: 'Rama\'nın Sincabı: Hint destanı Ramayana\'da Rama köprü inşa ederken küçük bir sincap kuma bulanıp suya atlayarak yardım eder. Rama parmaklarıyla sırtını okşar — sincapların sırtındaki üç çizgi o izden gelir. Büyük işte küçük katkı.', en: 'Rama\'s Squirrel: In the Hindu epic Ramayana, while Rama is building the bridge, a small squirrel helps by rolling in sand and leaping into the water. Rama strokes its back with his fingers — the three stripes on squirrels\' backs come from that touch. A small contribution to a great work.' },
    ],
  },

  // ─── a046 Yarasa ────────────────────────────────────────────────────────
  a046: {
    jung: { tr: '"Eşik Bekçisi" arketipi. Yarasa — gece ile gündüz, yer ile gök, ölüm ile hayat arasında. Liminal varlık.', en: 'The "Threshold Keeper" archetype. The bat — between night and day, earth and sky, death and life. A liminal being.' },
    dream: { tr: 'Yarasa rüyada — bir geçiş eşiğindesin, eski sen ölüyor. Mağaradan çıkıyorsa: gölge çalışmandan dönüyorsun. Sana yaklaşıyorsa: sezgi mesajı taşıyor.', en: 'Bat in dream — you are at a threshold of passage, the old self is dying. Coming out of the cave: you are returning from shadow work. Approaching you: it carries an intuitive message.' },
    shadow: { tr: 'Yapışkan korkular. Yarasalardan korkanlar genelde dönüşümden korkar. Yarasa fobisi — eski kimliği bırakmaktan kaçınma.', en: 'Clinging fears. Those who fear bats generally fear transformation. Bat-phobia — avoidance of releasing the old identity.' },
    whenAppears: { tr: 'Karanlık dönemlerde, ölüm-yas süreçlerinde, sezgini körlemesine kullanman gerekirken (ekolokasyon — görmeden duyma).', en: 'In dark periods, in death-grief processes, when you must use your intuition blindly (echolocation — hearing without seeing).' },
    traditions: [
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Fu — "yarasa" ve "şans" aynı sesle telaffuz edilir. Beş yarasa = beş kutsama (uzun ömür, zenginlik, sağlık, erdem, doğal ölüm).', en: 'Fu — "bat" and "fortune" are pronounced alike. Five bats = the five blessings (longevity, wealth, health, virtue, a natural death).' } },
      { culture: { tr: 'Maya/Aztek', en: 'Mayan/Aztec' }, meaning: { tr: 'Camazotz — yarasa tanrı. Geçişin ve gece âleminin habercisi.', en: 'Camazotz — the bat god. Herald of passage and the nocturnal realm.' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: 'Uğursuz sayılır ama eski Şaman geleneğinde — ata ruhların habercisi.', en: 'Considered ill-omened, yet in the old shamanic tradition — the messenger of ancestral spirits.' } },
      { culture: { tr: 'Hristiyan', en: 'Christian' }, meaning: { tr: 'Orta Çağ\'da şeytanın kuşu sayıldı — gece ve karanlıkla özdeşleştirildi.', en: 'In the Middle Ages, considered the devil\'s bird — identified with night and darkness.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Bazı kabilelerde — eski kişinin ölüp yeni kişinin doğuşu için rehber.', en: 'In some tribes — the guide for the death of the old self and the birth of the new.' } },
    ],
    myths: [
      { tr: 'Çin\'in Beş Yarasası: Çin geleneğinde beş yarasa motifi (wufu) — şans, zenginlik, uzun ömür, erdem, doğal ölüm. Düğün ve yılbaşı süslemelerinde çok kullanılır. Korkulan hayvan kutsama olur.', en: 'China\'s Five Bats: In Chinese tradition, the motif of five bats (wufu) — fortune, wealth, longevity, virtue, a natural death. Widely used in wedding and New Year decorations. The feared animal becomes a blessing.' },
      { tr: 'Camazotz Mağarası: Maya mitolojisinde kahramanlar ölüler diyarı Xibalba\'da Yarasa Mağarası\'ndan geçmek zorundadır. Yarasalar onları sınar — bilgeliği almak için ölüme yaklaşmak gerek.', en: 'The Cave of Camazotz: In Mayan mythology, heroes must pass through the Bat Cave in Xibalba, the land of the dead. The bats test them — to receive wisdom, one must draw near to death.' },
    ],
  },

  // ─── a047 Yengeç ────────────────────────────────────────────────────────
  a047: {
    jung: { tr: '"Ana-Kabuk" arketipi. Yengeç — evi bedeninde taşır. Duygusal güvenliğin, içe çekilmenin, sınırın sembolü.', en: 'The "Mother-Shell" archetype. The crab — carrying its home on its body. Symbol of emotional safety, withdrawal, and boundary.' },
    dream: { tr: 'Yengeç rüyada — bir savunma ihtiyacın var. Kabuğunun içine girmen meşru. Pençeleriyle bir şey tutuyorsa: bırakmıyorsun, bırak mı bırakma mı bir bak.', en: 'Crab in dream — you have a need for defense. To withdraw into your shell is legitimate. Holding something in its claws: you are not letting go — look at whether you should release it or not.' },
    shadow: { tr: 'Kabuğa kapanma takıntısı. Yengeç hep içe çekilirse — duygusal hareketsizlik. Pençeler de bir şeyi hiç bırakmamak da olabilir.', en: 'The compulsion to close into the shell. If the crab always withdraws — emotional paralysis. The claws may also mean never letting anything go.' },
    whenAppears: { tr: 'Sınır koymak gerektiğinde, eve dönmek istediğinde, ay döngüsünün etkili olduğu duygusal anlarda, geri çekilme zamanında.', en: 'When you must set a boundary, when you wish to return home, in emotional moments under the moon\'s influence, in a time of withdrawal.' },
    traditions: [
      { culture: { tr: 'Astroloji', en: 'Astrology' }, meaning: { tr: 'Yengeç burcu — Ay ile yönetilen ev, anne, duygusal kök. Suyun ilk burcu.', en: 'The sign of Cancer — moon-ruled home, mother, emotional root. The first water sign.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Hera, Herakles\'i öldürmek için bir yengeç gönderir. Yengeç ezilir — Hera onu gökyüzüne, Yengeç takımyıldızına koyar.', en: 'Hera sends a crab to kill Heracles. The crab is crushed — Hera places it in the sky as the constellation Cancer.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Sonbahar ve hasat sembolü. Mooncake döneminde yenir.', en: 'Symbol of autumn and harvest. Eaten in the mooncake season.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Karkata rashi — Ay\'ın evi. Anneliğin ve emosyonel zeminin yıldız evi.', en: 'Karkata rashi — the Moon\'s house. The stellar house of motherhood and emotional ground.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Akdeniz balıkçı köylerinde "kara yengeç" — uğurlu sayılır, asla öldürülmez sadece yakalandığı yere bırakılır.', en: 'In Mediterranean fishing villages, the "black crab" — considered fortunate; never killed, only returned to where it was caught.' } },
    ],
    myths: [
      { tr: 'Herakles ve Yengeç: Hera yengeci Herakles\'in topuğunu ısırması için gönderir. Kahraman ezer, ama Hera kuşun sadakatine değer verir ve onu gökyüzüne yerleştirir — Yengeç (Cancer) takımyıldızı. Küçük sadakat bile kutsanır.', en: 'Heracles and the Crab: Hera sends the crab to bite Heracles\'s heel. The hero crushes it, but Hera values the creature\'s loyalty and places it in the sky — the constellation Cancer. Even small loyalty is blessed.' },
      { tr: 'Yengeç Hareketi: "Yengeç yürüyüşü" deyimi — geri geri gitmek, dolambaçlı yol. Ama yengeç boş yere geri gitmez; tehlikeyi kabuğuyla geriye iter. Sezgisel savunma.', en: 'The Crab\'s Movement: The expression "crab walk" — moving backward, on a winding path. Yet the crab does not retreat in vain; it pushes danger back with its shell. Intuitive defense.' },
    ],
  },

  // ─── a048 Fil ───────────────────────────────────────────────────────────
  a048: {
    jung: { tr: '"Büyük Hafıza" arketipi. Fil — yıllar boyu hatırlar, ama hatırlamayla yaşamaz. Yargısız bellek.', en: 'The "Great Memory" archetype. The elephant — remembers across years, yet does not live by remembering. Memory without judgment.' },
    dream: { tr: 'Fil rüyada — geçmişten gelen bir bilgi/duygu yüzeye çıkıyor. Aileyle: kolektif bellek. Yalnız: kişisel ağırlık.', en: 'Elephant in dream — a knowledge or feeling from the past is surfacing. With family: collective memory. Alone: personal weight.' },
    shadow: { tr: '"Hiçbir şeyi unutmama" yükü. Affediş olmadan bellek hapse dönüşür. Fil hatırlar — ama bilge fil yara izini hayata değil tarihe bırakır.', en: 'The burden of "forgetting nothing". Without forgiveness, memory becomes a prison. The elephant remembers — but the wise elephant leaves the scar to history, not to life.' },
    whenAppears: { tr: 'Geçmişle yüzleşme zamanlarında, atalardan miras gelen yükleri taşırken, büyük ailedeki rolünü kabul ettiğinde.', en: 'In times of facing the past, while carrying burdens inherited from the ancestors, when you accept your role in the larger family.' },
    traditions: [
      { culture: { tr: 'Hint', en: 'Hindu' }, meaning: { tr: 'Ganeşa — fil başlı tanrı. Engellerin kaldırıcısı, başlangıçların koruyucusu.', en: 'Ganesha — the elephant-headed god. Remover of obstacles, protector of beginnings.' } },
      { culture: { tr: 'Budist', en: 'Buddhist' }, meaning: { tr: 'Buddha\'nın annesi Maya, hamile kalırken rüyasında beyaz bir fil görür — kutsal doğumun habercisi.', en: 'Buddha\'s mother Maya, while conceiving, dreams of a white elephant — herald of the sacred birth.' } },
      { culture: { tr: 'Vedik', en: 'Vedic' }, meaning: { tr: 'Airavata — Indra\'nın beyaz fil bineği. Yağmur ve bereketin getiricisi.', en: 'Airavata — Indra\'s white elephant mount. Bringer of rain and abundance.' } },
      { culture: { tr: 'Sufi-İslam', en: 'Sufi-Islamic' }, meaning: { tr: 'Mevlana\'nın "Karanlıkta Fil" hikayesi — herkes filin farklı parçasına dokunur, farklı şeyler tarif eder. Gerçek — bütünündedir.', en: 'Rumi\'s story "The Elephant in the Dark" — each touches a different part of the elephant and describes different things. The truth lies in the whole.' } },
      { culture: { tr: 'Afrika', en: 'African' }, meaning: { tr: 'Maasai\'de — kabilenin liderliğinin sembolü. Filin yürüyüşü "aile yürüyüşü"dür.', en: 'Among the Maasai — symbol of tribal leadership. The elephant\'s walk is the "family walk".' } },
    ],
    myths: [
      { tr: 'Ganeşa\'nın Başı: Hint mitolojisinde Parvati oğlu Ganeşa\'yı yaratır. Şiva, oğlunu tanımayıp başını keser. Pişman olunca ilk gördüğü canlının başını takar — fil. Ganeşa böyle doğar: engellerin kaldırıcısı, başlangıçların tanrısı.', en: 'Ganesha\'s Head: In Hindu mythology, Parvati creates her son Ganesha. Not recognizing his son, Shiva severs his head. Repenting, he attaches the head of the first creature he sees — an elephant. Thus Ganesha is born: remover of obstacles, god of beginnings.' },
      { tr: 'Mevlana\'nın Fili: "Bir karanlık odada filin yanına farklı insanlar girer. Biri hortumuna dokunur, yılan sanır. Biri kulağına, yelpaze. Biri ayağına, sütun." Mevlana\'da: hakikat bir parçayla değil, bütünle bilinir.', en: 'Rumi\'s Elephant: "Different people enter a dark room where an elephant stands. One touches its trunk and takes it for a snake. Another, its ear, and calls it a fan. Another, its leg, and calls it a pillar." For Rumi: truth is known not by a part but by the whole.' },
    ],
  },

  // ─── a049 Vaşak ─────────────────────────────────────────────────────────
  a049: {
    jung: { tr: '"Sırların Bekçisi" arketipi. Vaşak — gördüklerini söylemeyen, ama hakikati en derinden bilen.', en: 'The "Keeper of Secrets" archetype. The lynx — the one who does not tell what it sees, yet knows the truth most deeply.' },
    dream: { tr: 'Vaşak rüyada — bir gerçeği biliyorsun ama henüz söylenmemeli. Gizli gözlemiyorsa: aksiyon zamanı yaklaşıyor. Yaklaşırsa: derin bir bilgi sana açılıyor.', en: 'Lynx in dream — you know a truth, but it must not yet be told. Watching in secret: the time of action approaches. Drawing near: a deep knowledge is opening to you.' },
    shadow: { tr: 'Soğuk gizem. Sırrın hayat tarzı olursa — yalnızlık. Vaşak yalnızdır ama küskün değildir; ayrım var.', en: 'Cold mystery. If the secret becomes a way of life — loneliness. The lynx is solitary but not resentful; there is a distinction.' },
    whenAppears: { tr: 'Bir sırrı taşıman/saklamian gerektiğinde, derin gözlem zamanında, kalabalıktan çekilip görüye girdiğinde.', en: 'When you must carry or keep a secret, in a time of deep observation, when withdrawing from the crowd into vision.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Lynx — adından geliyor "lynx eyed" deyimi: keskin bakış. Görünmeyeni gören.', en: 'Lynx — from its name comes the expression "lynx-eyed": piercing sight. The one who sees the unseen.' } },
      { culture: { tr: 'Kuzey Avrupa', en: 'Northern European' }, meaning: { tr: 'İskandinav, Finlandiya geleneğinde — orman ruhlarının habercisi.', en: 'In Scandinavian and Finnish tradition — messenger of the forest spirits.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Sırların hayvanı. Vaşak bilenlere bilgi verir, bilmeyenlere görünmez.', en: 'The animal of secrets. The lynx gives knowledge to those who know; to those who do not, it remains invisible.' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: 'Toroslar\'ın gölgesi. Görenin görüldüğü ama söyleyemediği hayvan — saygı sınırı.', en: 'The shadow of the Taurus. An animal whose sighter is seen but cannot tell — the boundary of reverence.' } },
      { culture: { tr: 'Roma', en: 'Roman' }, meaning: { tr: 'Vaşak ışığın tüm renklerini görür sanılırdı — gizli olanı bile parça parça çözer.', en: 'The lynx was thought to see all the colors of light — unraveling even the hidden, piece by piece.' } },
    ],
    myths: [
      { tr: 'Lynx\'in Bakışı: Antik kaynaklara göre vaşağın bakışı taşları bile delerdi. Onun ışıltısı kıymetli taşların oluşumunu açıklarmış — gizli kırılmanın görüsü.', en: 'The Lynx\'s Gaze: According to ancient sources, the lynx\'s gaze could pierce even stones. Its luster was said to explain the formation of precious gems — the vision of hidden refraction.' },
      { tr: 'Anadolu Toros Vaşağı: Modern zamanlarda neredeyse soyu tükenmiş. Onu son görenler "bakışı seni durdurur" dermiş — biliyor olma duygusunun katlanılmaz ağırlığı.', en: 'The Anatolian Taurus Lynx: Nearly extinct in modern times. Those who last saw it said "its gaze stops you" — the unbearable weight of being known.' },
    ],
  },

  // ─── a050 Örümcek ───────────────────────────────────────────────────────
  a050: {
    jung: { tr: '"Yaratıcı Dokumacı" arketipi. Örümcek — kaderini kendi dokuyan. Hem yaratıcı hem avcı; sabırlı sanatçı.', en: 'The "Creative Weaver" archetype. The spider — the one who weaves her own fate. Both creator and hunter; the patient artist.' },
    dream: { tr: 'Örümcek rüyada — yaratım sürecinde dikkatli olmalısın. Ağ kuruyorsa: planlı bir yaratımdasın. Sana yaklaşıyorsa: bir tuzak ya da fırsat — ayırt et.', en: 'Spider in dream — you must be careful in your creative process. Spinning a web: you are in a planned creation. Approaching you: a trap or an opportunity — discern between them.' },
    shadow: { tr: 'Ağına başkalarını dolama. Manipülatif kontrol. Örümcek yaratır ama bağımlılaştırırsa — kendi ağında boğulur.', en: 'Entangling others in your web. Manipulative control. The spider creates, but if she fosters dependence — she drowns in her own web.' },
    whenAppears: { tr: 'Yaratıcı projelere başlarken, kaderini yeniden örmek istediğinde, sabırla iplik iplik kurman gereken bir hayatta.', en: 'When beginning creative projects, when you wish to reweave your fate, in a life you must build thread by thread with patience.' },
    traditions: [
      { culture: { tr: 'İslam', en: 'Islamic' }, meaning: { tr: 'Sevr Mağarası — Hz. Muhammed ve Ebubekir kaçarken mağaranın ağzında bir örümcek ağ örer, düşmanlar geçer ama kimsenin orada saklanmadığını sanır.', en: 'The Cave of Thawr — as the Prophet Muhammad and Abu Bakr flee, a spider weaves a web at the cave\'s mouth; the enemies pass by, thinking no one could be hiding there.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Arakhne — dokumada Athena\'yı yenince tanrıça onu örümceğe çevirir. İlk dokumacı.', en: 'Arachne — when she surpasses Athena at weaving, the goddess turns her into a spider. The first weaver.' } },
      { culture: { tr: 'Afrika', en: 'African' }, meaning: { tr: 'Anansi — örümcek-trickster tanrı. Hikayelerin kralı. Akıllı zayıfın gücü.', en: 'Anansi — the spider-trickster god. King of stories. The power of the clever underdog.' } },
      { culture: { tr: 'Kızılderili', en: 'Native American' }, meaning: { tr: 'Spider Grandmother — yaratıcı ana. Dünyayı dokuyan ve yıldız haritasını gönderen.', en: 'Spider Grandmother — the creator mother. The one who weaves the world and sends the star map.' } },
      { culture: { tr: 'Anadolu Halk', en: 'Anatolian Folk' }, meaning: { tr: '"Örümcek ağı bozulmuş" — terkedilmişliği ifade eder. Ama aynı zamanda örümcek sebatıyla yeniden örer.', en: '"The spider\'s web is broken" — expresses abandonment. Yet the spider, with perseverance, weaves it again.' } },
    ],
    myths: [
      { tr: 'Sevr Mağarası: İslam tarihinde Hz. Muhammed Mekke\'den Medine\'ye hicret ederken Ebubekir ile Sevr Mağarası\'na sığınır. Bir örümcek mağaranın ağzında hızla ağ örer, bir güvercin yuva yapar. Mekkeli düşmanlar gelir, ağ ve yuva el değmemiş görünür — kimse orada olamaz sanırlar. En küçük yaratık peygamberi korur.', en: 'The Cave of Thawr: In Islamic history, as the Prophet Muhammad emigrates from Mecca to Medina with Abu Bakr, he takes refuge in the Cave of Thawr. A spider swiftly weaves a web at the cave\'s mouth, and a dove builds a nest. The Meccan pursuers arrive; the web and nest appear untouched — they think no one could be inside. The smallest creature protects the prophet.' },
      { tr: 'Anansi\'nin Hikayeleri: Batı Afrika geleneğinde dünyanın bütün hikayeleri başlangıçta gök tanrısının elindedir. Örümcek Anansi onları zekasıyla alır ve insanlığa dağıtır — hikaye anlatmanın atası.', en: 'Anansi\'s Stories: In West African tradition, all the world\'s stories were originally in the hands of the sky god. The spider Anansi takes them by his cleverness and gives them to humanity — the ancestor of storytelling.' },
    ],
  },

  // ─── a051 Kuğu ──────────────────────────────────────────────────────────
  a051: {
    jung: { tr: '"Saflık ve Dönüşüm" arketipi. Kuğu, bilinçdışında ham güzelliğin en olgun biçimine geçişi temsil eder — çirkin ördek yavrusundan beyaz Kuğu\'ya uzanan yol, ruhun öz gerçekliğini bulmasıdır. Zarif yüzeyin altında güçlü, yorulmaz ayaklar yüzer: görünen ile görünmeyen arasındaki bu sırrı taşır.', en: 'The "Purity and Transformation" archetype. The Swan represents the transition to the most mature form of raw beauty in the unconscious — the path from ugly duckling to white Swan is the soul\'s discovery of its true nature. Beneath the graceful surface, powerful tireless legs paddle: it carries this secret between the visible and the invisible.' },
    dream: { tr: 'Kuğu rüyada görünürse — güzelliğini henüz tanımadığın bir yönün sana seslenmesi. Uçuyorsa: ruhsal yükseliş ve özgürleşme eşiğinde. Suda süzülüyorsa: duygusal derinlikle barış içindesin, ama yüzeyi korumayı unutma.', en: 'If Swan appears in a dream — a facet of your beauty not yet recognized is calling to you. If it flies: you are on the threshold of spiritual ascent and liberation. If it glides on water: you are at peace with emotional depth, but do not forget to maintain the surface.' },
    shadow: { tr: 'Zarafet takıntısına dönüşebilir — her şeyin "güzel" görünmesi uğruna gerçeği örtbas etmek. Kuğu gölgesi: kibir ve soğukluk, "benim seviyemde değil" duygusuyla sağlıklı bağlardan kopmak.', en: 'Can turn into an obsession with grace — concealing truth for the sake of everything appearing "beautiful". The Swan shadow: pride and coldness, severing healthy bonds with the feeling of "not at my level".' },
    whenAppears: { tr: 'Kendinizi çirkin ya da yetersiz hissettiğinizde, bir dönüşümün tam ortasında olduğunuzda veya sanatsal/estetik bir yolculuğun başında.', en: 'When you feel ugly or inadequate, when you are in the midst of a transformation, or at the beginning of an artistic or aesthetic journey.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Zeus Kuğu kılığına girerek Leda ile birleşti — böylece ilahi ile beşeri arasındaki geçişkenliği simgeler. Ayrıca Apollo\'nun kuşudur: kehanet ve müziğin taşıyıcısı.', en: 'Zeus transformed into a Swan to unite with Leda — symbolizing the permeability between the divine and the human. It is also Apollo\'s bird: carrier of prophecy and music.' } },
      { culture: { tr: 'Kelt Geleneği', en: 'Celtic Tradition' }, meaning: { tr: 'Kuğular öteki dünyayla bağlantılı kutsal varlıklardır. Öldürülmeleri lanet getirir. Çoğunlukla büyülenmiş insan ruhlarını taşırlar.', en: 'Swans are sacred beings connected to the otherworld. Killing them brings a curse. They often carry enchanted human souls.' } },
      { culture: { tr: 'Hint Mitolojisi', en: 'Hindu Mythology' }, meaning: { tr: 'Hamsa — Brahma\'nın bineği, ruh ile maddeyi ayırt etme yetisinin simgesi. "Ham-sa" nefes mantrası ile özdeşleştirilir: "Ben O\'yum".', en: 'Hamsa — Brahma\'s vehicle, symbol of the ability to discern spirit from matter. Identified with the breath mantra "Ham-sa": "I am That".' } },
      { culture: { tr: 'Fin-Ugor Geleneği', en: 'Finno-Ugric Tradition' }, meaning: { tr: 'Kalevala destanında Kuğu, ölüler nehri Tuonela\'nın sularında süzülür — ölüm ile yaşam arasındaki sessiz bekçi.', en: 'In the Kalevala epic, the Swan glides upon the waters of Tuonela, the river of the dead — the silent guardian between death and life.' } },
      { culture: { tr: 'Anadolu Halk Geleneği', en: 'Anatolian Folk Tradition' }, meaning: { tr: 'Kuğu, gelin kuşudur — düğün türkülerinde saflığın ve soyun simgesidir. "Kuğu boyunlu" deyimi en güzel övgüdür.', en: 'The Swan is the bride\'s bird — in wedding songs it is the symbol of purity and lineage. "Swan-necked" is the highest compliment.' } },
    ],
    myths: [
      { tr: 'Lohengrin efsanesi: Kutsal Kase\'nin şövalyesi Lohengrin, bir Kuğu\'nun çektiği kayıkla belirsiz bir yerden gelir ve bir prensesi kurtarır. Tek şartı: kimliğini sormaması. Sorulduğu an, kuğu-kayık onu alıp götürür — koşulsuz güvenin olmadığı yerde ilahi armağan da durmaz.', en: 'The legend of Lohengrin: The knight of the Holy Grail, Lohengrin, arrives from an unknown place in a boat drawn by a Swan and rescues a princess. His only condition: she must not ask his identity. The moment she does, the swan-boat takes him away — where unconditional trust is absent, the divine gift cannot remain.' },
      { tr: 'Hint efsanesinde Hamsa Kuşu, süt ile suyu birbirinden ayırt edebilme özelliğine sahiptir. Bu yüzden bilge kişiye "Paramahamsa" — büyük Hamsa — denir. Gerçeği yanlıştan ayırt etmek, ruhun en yüce erdemidir.', en: 'In Hindu legend, the Hamsa Bird has the ability to separate milk from water. This is why the wise person is called "Paramahamsa" — the great Swan. Discerning truth from falsehood is the soul\'s highest virtue.' },
    ],
  },

  // ─── a052 Kondor ─────────────────────────────────────────────────────────
  a052: {
    jung: { tr: '"Üst Dünya Elçisi" arketipi. Kondor, bilinçdışının en yüksek katmanını — kolektif atalar belleğini — temsil eder. Ölü etin üzerinde süzülmesi, dönüşümün vahşi ama zorunlu yüzünü gösterir: yaşam ancak ölümün işini kabul ederek sürebilir.', en: 'The "Upper World Emissary" archetype. The Condor represents the highest layer of the unconscious — the collective ancestral memory. Its gliding over carrion reveals the wild yet necessary face of transformation: life can only continue by accepting the work of death.' },
    dream: { tr: 'Kondor rüyada görünürse — ata ruhları bir mesaj taşıyor; geçmişten gelen bilgelik seni bekliyor. Başının üzerinde daireler çiziyorsa: yüksek perspektiften bak, şu an içinde kaybolduğun sorun küçüktür. Yere konuyorsa: toprağa, köke, bedene dön.', en: 'If Condor appears in a dream — ancestral spirits carry a message; wisdom from the past awaits you. If it circles above your head: look from a high perspective, the problem you are lost in right now is small. If it lands: return to the earth, the root, the body.' },
    shadow: { tr: 'Ölüme ve yıkıma fazla yakınlık — melankoliye, nihilizme kayma. "Her şey geçici zaten" düşüncesinin yaşam sevincini yok etmesi. Ya da tam tersi: ölümden patolojik kaçış, dönüşümü reddeden donukluk.', en: 'Too much proximity to death and destruction — sliding into melancholy and nihilism. The thought "everything is transient anyway" destroying joy in life. Or the opposite: pathological flight from death, the rigidity that refuses transformation.' },
    whenAppears: { tr: 'Bir yakının ölümü sonrasında, kuşaktan kuşağa geçen bir örüntüyü kırmaya çalışırken ya da köklü bir karar arifesinde.', en: 'After the death of a loved one, when trying to break a pattern passed down through generations, or on the eve of a pivotal decision.' },
    traditions: [
      { culture: { tr: 'And Uygarlıkları (Quechua)', en: 'Andean Civilizations (Quechua)' }, meaning: { tr: 'Kondor üst dünyayı (Hanan Pacha) temsil eder. Üçlü And kozmolojisinde Jaguar yeryüzü, Yılan yeraltı, Kondor ise gök-alem arasındaki köprüdür.', en: 'The Condor represents the upper world (Hanan Pacha). In the triple Andean cosmology, the Jaguar is the earth, the Serpent the underworld, and the Condor is the bridge to the sky-realm.' } },
      { culture: { tr: 'İnka İmparatorluğu', en: 'Inca Empire' }, meaning: { tr: 'İnka\'da güneş tanrısı İnti\'nin temsilcisi. Ölmüş İnka imparatorlarının ruhu Kondor biçimini alırdı ve halkını gökyüzünden izlerdi.', en: 'In the Inca Empire, representative of the sun god Inti. The spirits of deceased Inca emperors took the form of the Condor and watched over their people from the sky.' } },
      { culture: { tr: 'Mapuche Geleneği', en: 'Mapuche Tradition' }, meaning: { tr: 'Kondor ölümün habercisi değil, ruhun taşıyıcısıdır. Şaman (Machi) ruhunu Kondor\'a binerek öteki dünyaya taşıyabilir.', en: 'The Condor is not a harbinger of death but a carrier of the soul. The shaman (Machi) can carry their spirit to the other world by riding the Condor.' } },
      { culture: { tr: 'Navajo Geleneği (Kuzey Amerika)', en: 'Navajo Tradition (North America)' }, meaning: { tr: 'Büyük Kondor benzeri kuşlar yaratılış destanlarında dünyanın ilk temizleyicileri olarak görülür — yeryüzünü ilk insanlar için hazırlarlar.', en: 'Great Condor-like birds in creation epics are seen as the world\'s first purifiers — they prepare the earth for the first humans.' } },
      { culture: { tr: 'Kolomb Öncesi Sanatı', en: 'Pre-Columbian Art' }, meaning: { tr: 'Nazca çizgilerindeki dev Kondor figürü, gökyüzü tanrılarına yapılan mesaj olarak yorumlanmaktadır — yeryüzünden göğe açılan bir dua.', en: 'The giant Condor figure in the Nazca lines is interpreted as a message to sky gods — a prayer opening from earth to heaven.' } },
    ],
    myths: [
      { tr: 'And efsanesinde Kondor bir zamanlar yerden çok alçak uçarmış ve günde üç öğün yemek yermiş. Bir gün gökyüzüne çıkmaya karar vermiş, açlık ve rüzgara katlanmayı öğrenmiş. Artık haftalar boyunca yemeden uçabiliyormuş. Feragat, özgürlüğün bedelidir.', en: 'In Andean legend, the Condor once flew very close to the ground and ate three meals a day. One day it decided to ascend to the sky, and learned to endure hunger and wind. It could now fly for weeks without eating. Renunciation is the price of freedom.' },
      { tr: 'Quechua geleneğinde "Kondor ile Kartal Dansı" kehaneti: Batı\'nın Kartalı ile Doğu\'nun Kondoru her 500 yılda bir bir araya gelir ve insan bilincinde yeni bir çağ açılır. Son buluşma 1990\'larda gerçekleşmiş — zihin ile kalbin birleşme çağıdır.', en: 'In Quechua tradition, the prophecy of the "Dance of the Condor and Eagle": the Eagle of the West and the Condor of the East meet every 500 years, opening a new era in human consciousness. The last meeting occurred in the 1990s — it is the age of the union of mind and heart.' },
    ],
  },

  // ─── a053 Somon ──────────────────────────────────────────────────────────
  a053: {
    jung: { tr: '"Köke Dönüş" arketipi. Somon, kolektif bilinçdışında en derin özlem dürtüsünü taşır — kaynağa dönme, doğduğun yerde ölme, tamamlanma iştiyakı. Nehre karşı yüzme imgesi, bilinçdışı direncin bilinçli azimle aşılmasını simgeler.', en: 'The "Return to the Root" archetype. The Salmon carries the deepest longing impulse in the collective unconscious — returning to the source, dying where you were born, the yearning for completion. The image of swimming against the river symbolizes overcoming unconscious resistance with conscious determination.' },
    dream: { tr: 'Somon rüyada görünürse — köküne, ailenle ya da özünle olan bağına dikkat çekiliyor. Nehre karşı yüzüyorsa: zorlu ama doğru bir yoldayısın, bırakma. Ölüp nehre düşüyorsa: bir misyonun tamamlandı, verdiğin şey senden çok daha büyük bir hayatı besleyecek.', en: 'If Salmon appears in a dream — attention is drawn to your root, your bond with family or your core self. If it swims upstream: you are on a difficult but right path, do not quit. If it dies and falls into the river: a mission has been completed, what you have given will nourish a life far greater than yourself.' },
    shadow: { tr: '"Geri dönmek zorundayım" takıntısı nostaljiye, gerçek anlamda ilerlemeyi reddeden bir geçmiş hapsolmasına dönüşebilir. Ya da tam tersi: köksüzlük, kaynaktan tamamen kopuş, hafıza yoksunluğu.', en: 'The obsession with "I must return" can turn into nostalgia, imprisonment in the past that truly refuses forward movement. Or the opposite: rootlessness, complete severance from the source, deprivation of memory.' },
    whenAppears: { tr: 'Göç sonrası özlem dönemlerinde, aile kökenlerinizi araştırırken ya da büyük bir projeyi tamamlamak için son güçlerinizi toplarken.', en: 'During periods of longing after migration, while researching your family origins, or when gathering your final strength to complete a great project.' },
    traditions: [
      { culture: { tr: 'Kelt Geleneği', en: 'Celtic Tradition' }, meaning: { tr: 'Fionn\'un efsanevi Bilgelik Somonu — kim yerse evrenin tüm bilgisini kazanır. Druid geleneğinde Somon, akarsularda yaşayan en eski bilge varlıktır.', en: 'The legendary Salmon of Wisdom of Fionn — whoever eats it gains all the knowledge of the universe. In Druid tradition, the Salmon is the oldest wise being living in watercourses.' } },
      { culture: { tr: 'Kuzeybatı Amerika Yerlileri', en: 'Pacific Northwest Indigenous Peoples' }, meaning: { tr: 'Somon kutsal bir armağandır — nehre geri döner ve ölümüyle ormanı besler. "Somon Halkı" kozmolojisinde Somon ruhları gönüllü olarak kurban olur.', en: 'Salmon is a sacred gift — it returns to the river and with its death nourishes the forest. In the "Salmon People" cosmology, Salmon spirits sacrifice themselves voluntarily.' } },
      { culture: { tr: 'Japon Geleneği', en: 'Japanese Tradition' }, meaning: { tr: 'Sake (Somon) döngüsü, Japon Shinto geleneğinde doğanın mükemmel çemberi olarak anlatılır. Tanrı Watatsumi\'nin hediyesidir.', en: 'The salmon (sake) cycle is described in Japanese Shinto tradition as the perfect circle of nature. It is the gift of the god Watatsumi.' } },
      { culture: { tr: 'İskandinav Mitolojisi', en: 'Norse Mythology' }, meaning: { tr: 'Hileci Loki Somon kılığına girerek tanrılardan kaçtı. Ağlara takılınca tanrılar onu yakaladı. Somon burada dönüşüm ve tespit edilemeyen zekânın simgesidir.', en: 'The trickster Loki disguised himself as a Salmon to escape the gods. When caught in nets, the gods captured him. Here the Salmon is a symbol of transformation and undetectable intelligence.' } },
      { culture: { tr: 'Anadolu Su Kültleri', en: 'Anatolian Water Cults' }, meaning: { tr: 'Kutsal su kaynakları çevresinde yaşayan büyük balıklar, Anadolu halk inancında dile getirilmez — onlara dokunmak kehaneti bozmak demektir.', en: 'Large fish living around sacred springs cannot be touched in Anatolian folk belief — to touch them is to break the prophecy.' } },
    ],
    myths: [
      { tr: 'İrlanda\'da Fionn mac Cumhaill efsanesi: Yaşlı şair Finnegas yıllarca Boyne Nehri\'nde Bilgelik Somonu\'nu avlamaya çalışır. Sonunda yakalar ve pişirmesi için genç Fionn\'a verir. Fionn yanlışlıkla başparmağını yakar, emer — tüm bilgelik ona geçer. Bilgelik her zaman hazırlanana değil, hazır olana gelir.', en: 'The legend of Fionn mac Cumhaill in Ireland: The old poet Finnegas tries for years to catch the Salmon of Wisdom in the River Boyne. He finally catches it and gives it to young Fionn to cook. Fionn accidentally burns his thumb, sucks it — all wisdom passes to him. Wisdom always comes not to the one who is prepared, but to the one who is ready.' },
      { tr: 'Kuzey Amerika\'nın Haida geleneğinde Somon Halkı, okyanus dibinde insan biçiminde yaşar. Her yıl insanlara armağan olmak için Somon kılığına girer ve nehirlere çıkar. Kemikleri özenle suya iade edilirse, bir sonraki yıl yeniden gelirler. Bu efsane, minnetle karşılanan her armağanın yenileneceğini anlatır.', en: 'In the Haida tradition of North America, the Salmon People live in human form at the ocean floor. Each year they take the form of Salmon to be a gift to humans and ascend the rivers. If their bones are returned carefully to the water, they come again the following year. This legend tells that every gift received with gratitude will be renewed.' },
    ],
  },

  // ─── a054 Sinek Kuşu ─────────────────────────────────────────────────────
  a054: {
    jung: { tr: '"Ebedi Neşe ve Savaşçı Hafiflik" arketipi. Sinek Kuşu, bilinçdışında paradoksu taşır: en küçük beden, en büyük enerji. Saniyede yüz kez kanat çırpmak — bu, varoluşun tam yoğunluğuyla yaşanmasının imgesidir. Tatlılığa yönelim (çiçekten çiçeğe) ise ruhun yaşamın özünü aramasını simgeler.', en: 'The "Eternal Joy and Warrior Lightness" archetype. The Hummingbird carries the paradox in the unconscious: the smallest body, the greatest energy. Beating wings a hundred times per second — this is the image of life lived at full intensity. The orientation toward sweetness (flower to flower) symbolizes the soul\'s search for life\'s essence.' },
    dream: { tr: 'Sinek Kuşu rüyada — baskı altında bile neşeyi korumanın mümkün olduğuna dair bir hatırlatma. Çiçeğe konuyorsa: en küçük zevklerden beslen. Kaçıp gidiyorsa: güzelliği yakalamanın yolu onu kovalamak değil, kendini güzelliğe açmaktır.', en: 'Hummingbird in a dream — a reminder that it is possible to maintain joy even under pressure. If it lands on a flower: nourish yourself from the smallest pleasures. If it flies away: the way to capture beauty is not to chase it but to open yourself to beauty.' },
    shadow: { tr: 'Aşırı hız ve enerjinin tükenmişliğe dönüşmesi — sürekli hareket halinde olmak derinleşmeyi engeller. Sinek Kuşu gölgesi: yüzeysellik, bir şeyde uzun süre kalmamak, doyumsuzluk.', en: 'Excessive speed and energy turning into burnout — being in constant motion prevents deepening. The Hummingbird shadow: superficiality, not staying in one thing for long, insatiability.' },
    whenAppears: { tr: 'Hayatın ağırlaştığı dönemlerde, neşeyi unuttuğunuzda ya da küçük anlardaki güzelliği göremez hale geldiğinizde.', en: 'During periods when life has grown heavy, when you have forgotten joy, or when you can no longer see the beauty in small moments.' },
    traditions: [
      { culture: { tr: 'Aztek Mitolojisi', en: 'Aztec Mythology' }, meaning: { tr: 'Huitzilopochtli — Azteklerin güneş ve savaş tanrısı, Sinek Kuşu anlamına gelir. Savaşta ölen savaşçıların ruhları Sinek Kuşu olarak yeniden doğar ve güneşe refakat ederdi.', en: 'Huitzilopochtli — the Aztec god of sun and war, means Hummingbird. The souls of warriors who died in battle were reborn as Hummingbirds and accompanied the sun.' } },
      { culture: { tr: 'Kızılderili Taíno Geleneği', en: 'Taíno Indigenous Tradition' }, meaning: { tr: 'Zunzuncito — barışın ve sevginin elçisi. İki düşman kabilenin aşk hikâyesini birbirine taşıyan kutsal haberci.', en: 'Zunzuncito — messenger of peace and love. The sacred herald carrying love stories between two enemy tribes.' } },
      { culture: { tr: 'Hopi Geleneği', en: 'Hopi Tradition' }, meaning: { tr: 'Sinek Kuşu kuraklık zamanlarında yağmur tanrıları için araya girer. Çiçek poleni taşıdığı için bereketin simgesidir.', en: 'The Hummingbird intercedes with the rain gods in times of drought. Because it carries flower pollen, it is a symbol of abundance.' } },
      { culture: { tr: 'Kolombiya Yerlileri', en: 'Colombian Indigenous Peoples' }, meaning: { tr: 'Sinek Kuşu\'nun tüyleri aşk tılsımlarında kullanılır. Onu rüyada görmek, uzak bir sevgilinin özlemini taşıdığına işaret eder.', en: 'Hummingbird feathers are used in love talismans. To see it in a dream indicates that a distant beloved carries longing for you.' } },
      { culture: { tr: 'Jamaika Halk Geleneği', en: 'Jamaican Folk Tradition' }, meaning: { tr: '"Doctor Bird" olarak bilinir — şifa ve dönüşümün simgesi. Uğurlu sayılır, yakalanmaya çalışılmaz; yalnızca izlenir.', en: 'Known as "Doctor Bird" — symbol of healing and transformation. Considered lucky, not to be captured; only observed.' } },
    ],
    myths: [
      { tr: 'Aztek yaratılış destanında Huitzilopochtli annesi Coatlicue\'nin rahminde Sinek Kuşu tüyünden doğar. Kardeşlerinin saldırısına karşı doğar doğmaz silahlanıp savaşa girer. Bu destan, küçük ama tam donanımlı doğanın — savunmaya hazır neşenin — imgesidir.', en: 'In the Aztec creation epic, Huitzilopochtli is born in his mother Coatlicue\'s womb from a hummingbird feather. Against the attack of his siblings he arms himself and enters battle the moment he is born. This epic is the image of one born small but fully equipped — joy ready to defend itself.' },
      { tr: 'Güney Amerika\'nın Quechua anlatısında, dünya henüz çok karanlıkken ve çiçekler açmayı bilmezken, Sinek Kuşu tanrıya gidip yalvarmış: "Bize renk ver." Tanrı Sinek Kuşu\'nun gagasını çiçeğin içine batırmış — ilk nektar böyle doğmuş, çiçekler de o gün renk kazanmış.', en: 'In a Quechua narrative from South America, when the world was still very dark and flowers did not know how to bloom, the Hummingbird went to the god and pleaded: "Give us color." The god dipped the Hummingbird\'s beak inside a flower — the first nectar was thus born, and that day flowers gained their color.' },
    ],
  },

  // ─── a055 Yaban Domuzu ───────────────────────────────────────────────────
  a055: {
    jung: { tr: '"Ham Güç ve Savaşçı Yürek" arketipi. Yaban Domuzu, bilinçdışındaki dizginlenmemiş yaşam enerjisini — id\'in en ham biçimini — temsil eder. Cesareti korkuyu yokmuş gibi hareket etmek değil, korku içinde yine de ilerlemektir. Dişleri hem silah hem de toprağı kazan araç: bu, yıkıcılık ile verimliliğin aynı kökten çıkmasıdır.', en: 'The "Raw Power and Warrior Heart" archetype. The Wild Boar represents the untamed life energy in the unconscious — the rawest form of the id. Its courage is not acting as if fear does not exist, but moving forward despite fear. Its tusks are both weapon and tool for digging the earth: this is destructiveness and fertility arising from the same root.' },
    dream: { tr: 'Yaban Domuzu rüyada saldırıyorsa — bastırılmış öfke ya da savunma ihtiyacı yüzeye çıkıyor; bu enerjiyle yüzleş. Orman içinde sakin yürüyorsa: ham gücünle barışıksın, onu yönlendirme vakti. Sürüyle görünürse: klanına, kolektif güce yaslan.', en: 'If Wild Boar attacks in a dream — suppressed anger or a need for defense is surfacing; confront this energy. If it walks calmly in the forest: you are at peace with your raw power, it is time to channel it. If it appears with a herd: lean on your clan, on collective strength.' },
    shadow: { tr: 'Kontrolsüz saldırganlık — her şeyi kafa kafaya çözme ısrarı, müzakere ve incelik yetisinin körelmesi. Yaban Domuzu gölgesi: kör öfke, etrafındakilere zarar veren savunmacılık, "ben haklıyım" katılığı.', en: 'Uncontrolled aggression — insisting on solving everything head-on, dulling the ability for negotiation and subtlety. The Wild Boar shadow: blind rage, defensiveness that harms those around you, the rigidity of "I am right".' },
    whenAppears: { tr: 'Kendi sınırlarını korumakta zorlandığınızda, cesaret gerektiren bir karar arifesinde ya da uzun süre bastırdığınız öfkenin nihayet sizi harekete geçirdiğinde.', en: 'When you struggle to protect your own boundaries, on the eve of a decision requiring courage, or when anger long suppressed finally moves you to action.' },
    traditions: [
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Ares ve Artemis\'in kutsal hayvanı. Kaledonia Domuzu, Yunanistan\'ın en büyük kahramanlarını bir araya getiren efsanevi av. Herakles\'in dokuzuncu görevi: Erymanthia Domuzu\'nu canlı yakalamak.', en: 'Sacred animal of Ares and Artemis. The Calydonian Boar, the legendary hunt that brought together Greece\'s greatest heroes. Heracles\' ninth labor: to capture the Erymanthian Boar alive.' } },
      { culture: { tr: 'Kelt Geleneği', en: 'Celtic Tradition' }, meaning: { tr: 'Yaban Domuzu Kelt savaşçısının simgesidir — miğferler, kalkanlar ve bayraklarda görülür. Öteki dünyanın kapısını da bekler: kutsal bir yaban domuzu avı çoğunlukla kahramanı öteki âleme taşır.', en: 'The Wild Boar is the symbol of the Celtic warrior — seen on helmets, shields, and banners. It also guards the gateway to the otherworld: a sacred boar hunt often carries the hero to the other realm.' } },
      { culture: { tr: 'Japon Shinto', en: 'Japanese Shinto' }, meaning: { tr: 'İnoshishi (Yaban Domuzu) Bishamonten\'in — savaş ve servet tanrısının — bineğidir. Korkmadan ilerlemek ve sezgiyle hareket etmek anlamına gelir.', en: 'Inoshishi (Wild Boar) is the mount of Bishamonten — the god of war and wealth. It means advancing without fear and acting with intuition.' } },
      { culture: { tr: 'İskandinav Mitolojisi', en: 'Norse Mythology' }, meaning: { tr: 'Freyr\'in altın yaban domuzu Gullinbursti geceyi aydınlatırdı. Freya\'nın domuzu Hildisvíni ise bilgeliğin ve savaşın birleşimiydi.', en: 'Freyr\'s golden boar Gullinbursti illuminated the night. Freya\'s boar Hildisvíni was the union of wisdom and war.' } },
      { culture: { tr: 'Anadolu ve Mezopotamya', en: 'Anatolia and Mesopotamia' }, meaning: { tr: 'Çatal Höyük buluntularında Yaban Domuzu avı ritüeli, erkeğin doğayla hesaplaşmasının simgesidir. Ham gücü dönüştürmek uygarlığın temeli sayılmıştır.', en: 'In the finds of Çatal Höyük, the Wild Boar hunt ritual is the symbol of man\'s reckoning with nature. Transforming raw power has been considered the foundation of civilization.' } },
    ],
    myths: [
      { tr: 'Kaledonia Domuzu Avı: Tanrıça Artemis, Kaledonia Kralı\'nın kendisine sunağı ihmal etmesi üzerine kocaman bir yaban domuzu gönderir. Tüm Yunan kahramanları — Jason, Theseus, Peleus — bir araya gelip onu avlamak için bu topraklara koşar. İlk yaralayanın ödülü, Atalanta adlı bir kadın avcıdır. Güç, zafer hakkını herkese eşit açar.', en: 'The Calydonian Boar Hunt: The goddess Artemis sends a massive wild boar when the King of Calydon neglects her altar. All the Greek heroes — Jason, Theseus, Peleus — rush to these lands to hunt it together. The reward for the first to wound it goes to a female hunter named Atalanta. Power opens the right to victory equally to everyone.' },
      { tr: 'İrlanda destanında Diarmuid, büyülü bir yaban domuzu tarafından öldürülmek üzere doğmuştur — bu kader değiştirilemez. Kahraman bunu bildiği halde domuzun izine çıkar. Bilinen sona rağmen cesaretle yürümek, Kelt kahramanlık anlayışının özüdür.', en: 'In an Irish epic, Diarmuid is fated to be killed by an enchanted wild boar — this fate cannot be changed. Knowing this, the hero still sets out on the boar\'s trail. Walking with courage despite a known ending is the essence of Celtic heroism.' },
    ],
  },

  // ─── a056 Kedi ───────────────────────────────────────────────────────────
  a056: {
    jung: { tr: '"Bağımsız Benlik ve Gece Sezgisi" arketipi. Kedi, bilinçdışında sahiplenilemeyen, evcilleştirilemeyen özün simgesidir — sevgi verir ama teslim olmaz. Gece görme yetisi, bilinçdışının karanlık katmanlarına erişimi; pençesini çekip uzatabilmek ise saldırganlık ile zarafeti aynı anda taşıyabilmeyi simgeler.', en: 'The "Independent Self and Nocturnal Intuition" archetype. The Cat is the symbol of an essence that cannot be possessed or domesticated in the unconscious — it gives love but does not surrender. The ability to see at night symbolizes access to the dark layers of the unconscious; the ability to retract and extend claws symbolizes carrying both aggression and grace simultaneously.' },
    dream: { tr: 'Kedi rüyada görünürse — sezgin, fısıltılı bir bilgi sana ulaşmaya çalışıyor; acele etme, bekle. Saldırıyorsa: bağımsızlığına ya da sezgine saygı gösterilmiyor. Kucağına kuruluyorsa: içindeki vahşi olanla barış kuruldu, güvendesin.', en: 'If Cat appears in a dream — an intuitive, whispered knowledge is trying to reach you; do not rush, wait. If it attacks: your independence or intuition is not being respected. If it settles in your lap: peace has been made with what is wild inside you, you are safe.' },
    shadow: { tr: 'Kontrolsüz bağımsızlık — gerçek bağ kurmaktan kaçınma, duygusal mesafeyi hep koruma. Kedi gölgesi: manipülatif sevgi (sadece işine gelince yakınlaşmak), soğukluk, narsisizm.', en: 'Uncontrolled independence — avoiding forming real bonds, always maintaining emotional distance. The Cat shadow: manipulative love (approaching only when convenient), coldness, narcissism.' },
    whenAppears: { tr: 'Sınırlarınızı kaybettiğinizde, birinin baskısı altında kendinizden uzaklaştığınızda ya da sezgilerinize kulak vermeyi bıraktığınızda.', en: 'When you have lost your boundaries, when you have drifted from yourself under someone\'s pressure, or when you have stopped listening to your intuitions.' },
    traditions: [
      { culture: { tr: 'Mısır Medeniyeti', en: 'Egyptian Civilization' }, meaning: { tr: 'Bastet — kedi başlı tanrıça. Evin, doğurganlığın ve güneşin koruyucusu. Kedilere zarar vermek ölümle cezalandırılırdı. Mumyalanmış kediler Bastet tapınaklarına sunulurdu.', en: 'Bastet — the cat-headed goddess. Protector of home, fertility, and the sun. Harming cats was punishable by death. Mummified cats were offered at the temples of Bastet.' } },
      { culture: { tr: 'İslam Geleneği', en: 'Islamic Tradition' }, meaning: { tr: 'Hz. Muhammed\'in kedisi Müezza\'yı çok severdi; namaz vakti uyuyan Müezza\'yı uyandırmamak için cüppesinin kolunu kestiği rivayet edilir. Kedi İslam\'da temiz ve mübarek bir hayvandır.', en: 'The Prophet Muhammad loved his cat Muezza greatly; it is narrated that he cut the sleeve of his robe rather than wake sleeping Muezza when it was time for prayer. The cat is a clean and blessed animal in Islam.' } },
      { culture: { tr: 'Japon Geleneği', en: 'Japanese Tradition' }, meaning: { tr: 'Maneki-neko (çağıran kedi) — bir pençesini kaldırmış kedi figürü bolluk ve şans getirir. Kara kedi ise bazı bölgelerde koruyucu, bazılarında tehlikeli sayılır.', en: 'Maneki-neko (beckoning cat) — the cat figurine with one paw raised brings abundance and luck. A black cat is considered protective in some regions, dangerous in others.' } },
      { culture: { tr: 'Kuzey Avrupa / Vik Geleneği', en: 'Northern Europe / Norse Tradition' }, meaning: { tr: 'Tanrıça Freya\'nın arabası iki büyük kedi tarafından çekilir. Kedi, Freya\'nın özgürlük, sihir ve tutku enerjisini taşır.', en: 'The goddess Freya\'s chariot is pulled by two large cats. The Cat carries Freya\'s energy of freedom, magic, and passion.' } },
      { culture: { tr: 'Anadolu Halk İnancı', en: 'Anatolian Folk Belief' }, meaning: { tr: 'Kedi eve girdiğinde o evi "seçmiş" sayılır — kovulmaz, misafir edilir. Yedi can imgesi, kedinin ölüm ve diriliş arasındaki sınırda yaşadığına dair yaygın bir Anadolu inancını yansıtır.', en: 'When a cat enters a home it is considered to have "chosen" that house — it is not driven away, it is welcomed. The image of nine lives reflects a widespread Anatolian belief that the cat lives on the border between death and resurrection.' } },
    ],
    myths: [
      { tr: 'Mısır\'da Ra her gece Apep yılanıyla savaşır ve sabah galip çıkar — bu savaşta Ra\'ya yardım eden Büyük Kedi\'dir. Heliopolis\'teki kutsal ağacın dibinde Apep\'i her gece yenen kedi, güneşin doğmasını sağlar. Sezgi ve sabır, kaosun üstesinden gelir.', en: 'In Egypt, Ra battles the serpent Apep each night and emerges victorious in the morning — the Great Cat helps Ra in this battle. The cat that defeats Apep each night at the foot of the sacred tree in Heliopolis enables the sun to rise. Intuition and patience overcome chaos.' },
      { tr: 'Japon\'un Gotokuji Tapınağı efsanesi: Yoksul bir rahip kedisini paylaştığı az yemeği bile verir. Bir gün büyük bir savaş lordu tapınağın önünden geçerken kedi pençesini kaldırır ve lordu içeri davet eder. Lord içeri girer; dışarıda fırtına kopar. Minnettar lord tapınağa servet bağışlar. Şükranla karşılanan küçük sevgiler, büyük dönüşümleri doğurur.', en: 'The legend of Japan\'s Gotokuji Temple: A poor monk gives his cat even from the little food he shares. One day as a great warlord passes before the temple, the cat raises its paw and invites the lord inside. The lord enters; outside a storm breaks. The grateful lord donates his wealth to the temple. Small loves received with gratitude give birth to great transformations.' },
    ],
  },

  // ─── a057 Yusufçuk ───────────────────────────────────────────────────────
  a057: {
    jung: { tr: '"İllüzyon ve Işık Dönüşümü" arketipi. Yusufçuk, bilinçdışında yanılsamanın ve ardından gelen aydınlanmanın simgesidir — görüneni değil, görünmeyeni görmek. Renk değiştiren kanatları, gerçekliğin algıya göre değiştiğini anlatır; hayatının büyük bölümünü su altında (bilinçdışında) geçirip sonunda havalanmak ise köklü dönüşümü simgeler.', en: 'The "Illusion and Light Transformation" archetype. The Dragonfly is the symbol of illusion and subsequent illumination in the unconscious — seeing not what is visible but what is invisible. Its color-shifting wings tell that reality changes according to perception; spending most of its life underwater (in the unconscious) and finally taking flight symbolizes profound transformation.' },
    dream: { tr: 'Yusufçuk rüyada görünürse — algılarını sorgula; gördüğün şey gerçekliğin tamamı değil. Üzerine konuyorsa: bu an, bu nefes yeterli — sadeliğe dön. Birden çok yönde uçuyorsa: çevik düşünme yetisi açılıyor, farklı perspektifleri dene.', en: 'If Dragonfly appears in a dream — question your perceptions; what you see is not the whole of reality. If it lands on you: this moment, this breath is enough — return to simplicity. If it flies in multiple directions: the ability for agile thinking is opening, try different perspectives.' },
    shadow: { tr: 'Gerçeklikten kaçış için illüzyona sığınma — hayal ile gerçeği ayırt edememe. Yusufçuk gölgesi: kararsızlık, sürekli fikir değiştirme, derinlik yerine parlaklığa kapılma.', en: 'Taking refuge in illusion to escape reality — inability to distinguish dream from reality. The Dragonfly shadow: indecision, constantly changing one\'s mind, being captivated by brilliance rather than depth.' },
    whenAppears: { tr: 'Bir durumu olduğundan farklı gördüğünüzde, büyük bir dönüşümün eşiğinde olduğunuzda ya da hayata daha hafif bir gözle bakma ihtiyacı duyduğunuzda.', en: 'When you see a situation differently from what it is, when you are on the threshold of a great transformation, or when you feel the need to look at life with a lighter eye.' },
    traditions: [
      { culture: { tr: 'Japon Kültürü', en: 'Japanese Culture' }, meaning: { tr: 'Akitsu-shima — "Yusufçuk Adası" — Japonya\'nın eski adı. Yusufçuk zafer ve güç sembolüdür; Japon savaşçıları zırhlarına yusufçuk motifi işlerdi. Ayrıca sonbaharın ve gelip geçiciliğin imgesidir.', en: 'Akitsu-shima — "Island of the Dragonfly" — the ancient name of Japan. The Dragonfly is a symbol of victory and power; Japanese warriors embroidered dragonfly motifs onto their armor. It is also the image of autumn and transience.' } },
      { culture: { tr: 'Lakota Yerlileri', en: 'Lakota Indigenous People' }, meaning: { tr: 'Yusufçuk aldatıcı düşmanlara karşı koruma sağlar. Savaşçılar atlarına ve kalkanlarına yusufçuk çizerdi — hızlı ve öngörülemeyen olmak için.', en: 'The Dragonfly provides protection against deceptive enemies. Warriors drew dragonflies on their horses and shields — to be swift and unpredictable.' } },
      { culture: { tr: 'Kelt Geleneği', en: 'Celtic Tradition' }, meaning: { tr: 'Peri dünyasının habercisi. Yusufçuğun göründüğü yerde peri kapısı açılmış demektir — dikkatli ol, yanılabilirsin.', en: 'Messenger of the fairy world. Where a dragonfly appears, a fairy gate has opened — be careful, you may be deceived.' } },
      { culture: { tr: 'İsveç Halk İnancı', en: 'Swedish Folk Belief' }, meaning: { tr: 'Yusufçuk iblislerin gözü olarak düşünülmüş, ruhları tartmaya gelir. Ama aynı zamanda ev tanrılarının koruyucu habercisi de sayılmıştır.', en: 'The Dragonfly has been thought of as the eye of demons, coming to weigh souls. But it has also been considered the protective messenger of household gods.' } },
      { culture: { tr: 'Çin Geleneği', en: 'Chinese Tradition' }, meaning: { tr: 'Yusufçuk uyum ve başarının simgesidir. Suyun üzerinde uçması — iki dünya arasında; görünen ile görünmeyenin kesişim noktasında yaşamak.', en: 'The Dragonfly is a symbol of harmony and success. Flying over water — living between two worlds; at the intersection of the visible and the invisible.' } },
    ],
    myths: [
      { tr: 'Japon efsanesinde ilk Yusufçuk, tanrı İzanagi\'nin gözyaşından doğmuştur. Kayıp sevgilisi İzanami için yas tutarken döktüğü gözyaşı suya düşmüş, o damla kanat takınmış ve uçmuş. Acı dönüşümle güzelliğe kavuştuğunda, en kırılgan an en güzel yaratığı doğurur.', en: 'In Japanese legend, the first Dragonfly was born from the tear of the god Izanagi. The tear he shed while mourning for his lost beloved Izanami fell to the water, that drop took wings and flew. When pain meets transformation and becomes beauty, the most fragile moment gives birth to the most beautiful creature.' },
      { tr: 'Navajo yaratılış anlatısında Yusufçuk, eski dünyadaki halkın yeni dünyaya geçerken arkasında bıraktığı bilinç kıvılcımıdır. İki dünya arasında asılı kalmış, ne tam öteki âlemde ne de bu dünyada — o yüzden hem gerçek hem yanılsama taşır.', en: 'In the Navajo creation narrative, the Dragonfly is the spark of consciousness left behind by the people of the old world as they crossed into the new. It remained suspended between two worlds, neither fully in the other realm nor in this one — that is why it carries both reality and illusion.' },
    ],
  },

  // ─── a058 Hüdhüd ─────────────────────────────────────────────────────────
  a058: {
    jung: { tr: '"İlahi Rehber ve Ruhsal Mesaj" arketipi. Hüdhüd, bilinçdışında Öz\'ün (Self) sesi olarak belirir — yüksekten görür, derinliği sezar ve ikisi arasında köprü kurar. Tepesindeki taç, bilgeliğin tacını taşıyan kişinin özel bir görev üstlendiğini anlatır; üst dünyayla alt dünya arasındaki haberciliği ise ego ile ruhun diyaloğunu simgeler.', en: 'The "Divine Guide and Spiritual Message" archetype. The Hoopoe appears as the voice of the Self in the unconscious — it sees from above, senses depth, and bridges the two. The crown on its head tells that one who carries the crown of wisdom has taken on a special mission; its role as messenger between the upper and lower worlds symbolizes the dialogue between ego and soul.' },
    dream: { tr: 'Hüdhüd rüyada görünürse — bir rehberlik geliyor; dikkatlice dinle. Sana yaklaşıyorsa: içindeki bilge sesin önünü tıkama, konuşmasına izin ver. Uzaklaşıyorsa: görmezden geldiğin bir ilahi işareti kaçırdın — ama henüz geç değil.', en: 'If Hoopoe appears in a dream — guidance is coming; listen carefully. If it approaches you: do not block the wise voice within you, allow it to speak. If it moves away: you missed a divine sign you ignored — but it is not yet too late.' },
    shadow: { tr: '"Ben seçilmiş rehberim" kibrinin tuzağı. Hüdhüd gölgesi: manevi üstünlük iddiası, gerçek rehberliği sahte peygamberlikle karıştırmak, herkese danışılmadan öğüt vermek.', en: 'The trap of the arrogance "I am the chosen guide". The Hoopoe shadow: claiming spiritual superiority, confusing genuine guidance with false prophecy, giving advice to everyone without being asked.' },
    whenAppears: { tr: 'Önemli bir kararın arifesinde ruhsal yönlendirmeye ihtiyaç duyduğunuzda, bir öğretmen ya da lider rolü üstlenmeniz gerektiğinde ya da kayıp hissedip pusulaya baktığınızda.', en: 'When you need spiritual guidance on the eve of an important decision, when you need to assume a role as teacher or leader, or when you feel lost and look to your compass.' },
    traditions: [
      { culture: { tr: 'İslam-Sufi Geleneği', en: 'Islamic-Sufi Tradition' }, meaning: { tr: 'Feridüddin Attar\'ın Mantıku\'t-Tayr\'ında (Kuşların Dili) Hüdhüd, ruhsal yolculuğa çıkan kuşların rehberi ve sözcüsüdür. Simurg\'u arayan kuşları yönetir — bilgeliğin önderi.', en: 'In Fariduddin Attar\'s Mantiq ut-Tayr (The Conference of the Birds), the Hoopoe is the guide and spokesperson of the birds who set out on the spiritual journey. It leads the birds seeking the Simurgh — the forerunner of wisdom.' } },
      { culture: { tr: 'Kuran\'ı Kerim', en: 'The Quran' }, meaning: { tr: 'Neml Suresi\'nde Hüdhüd, Hz. Süleyman\'ın habercisi olarak Sebe Kraliçesi Belkıs\'ın haberini getirir. İlahi bilgi ile dünyevi iktidar arasındaki köprüdür.', en: 'In Surah An-Naml, the Hoopoe brings the news of Queen Bilqis of Sheba as the messenger of the Prophet Solomon. It is the bridge between divine knowledge and earthly power.' } },
      { culture: { tr: 'Mısır Hiyeroglifleri', en: 'Egyptian Hieroglyphs' }, meaning: { tr: 'Hüdhüd hiyeroglifi "şükran" ve "babanı onurlandır" anlamına gelir. Ebeveynlere bakmanın kutsal hayvanı olarak bilinir.', en: 'The Hoopoe hieroglyph means "gratitude" and "honor your father". It is known as the sacred animal of caring for parents.' } },
      { culture: { tr: 'İran Edebiyatı', en: 'Persian Literature' }, meaning: { tr: 'Hüdhüd Hafız ve Rumi şiirlerinde sıkça anılır. Mürşidin sesi, içsel rehberin sembolü. "Hüdhüd gibi haber getir" — doğru zamanı, doğru sözü bil.', en: 'The Hoopoe is frequently referenced in the poetry of Hafez and Rumi. The voice of the guide, the symbol of the inner guide. "Bring news like the Hoopoe" — know the right time, know the right word.' } },
      { culture: { tr: 'İsrail Geleneği', en: 'Israelite Tradition' }, meaning: { tr: 'Hz. Süleyman\'ın kuşu. Talmud\'da hüdhüd Hz. Süleyman\'a çölde gölge yapar — yönetici ile korunan arasındaki karşılıklı hizmetin simgesi.', en: 'The bird of King Solomon. In the Talmud, the Hoopoe shades King Solomon in the desert — symbol of mutual service between ruler and protected.' } },
    ],
    myths: [
      { tr: 'Attar\'ın Mantıku\'t-Tayr\'ında tüm kuşlar Simurg\'u bulmak için yola çıkar. Rehberleri Hüdhüd\'dür. Yedi derin vadiden geçerler: Aşk, Sezgi, Bilgi, İsteksizlik, Tevhid, Şaşkınlık ve son olarak Yokluğun Vadisi. Yolculuk sona erdiğinde geriye 30 kuş kalmıştır ve aynaya bakarlar — Simurg onlardır. Hüdhüd\'ün rehberliği, rehberi gereksiz kılan bilgeliğe ulaştırır.', en: 'In Attar\'s Mantiq ut-Tayr, all the birds set out to find the Simurgh. Their guide is the Hoopoe. They pass through seven deep valleys: Love, Intuition, Knowledge, Detachment, Unity, Bewilderment, and finally the Valley of Nothingness. When the journey ends, thirty birds remain and look into a mirror — they are the Simurgh. The Hoopoe\'s guidance leads to the wisdom that makes the guide unnecessary.' },
      { tr: 'Hz. Süleyman\'ın Hüdhüdü: Kuşların sultanı Süleyman, Hüdhüd\'ün yokluğunu fark eder ve öfkelenir. Hüdhüd döner ve der ki: "Senin bilmediğin bir şeyi öğrendim — Yemen\'de güneşe tapan bir kraliçe var." Bu haberle Belkıs İslam\'a girer. Küçük bir haberci, büyük bir uyanışı başlatabilir.', en: 'The Hoopoe of King Solomon: Solomon, sultan of birds, notices the Hoopoe\'s absence and grows angry. The Hoopoe returns and says: "I have learned something you do not know — there is a queen in Yemen who worships the sun." With this news, Bilqis accepts the faith of Solomon. A small messenger can initiate a great awakening.' },
    ],
  },

  // ─── a059 Akbaba ─────────────────────────────────────────────────────────
  a059: {
    jung: { tr: '"Arınma ve Ölümü Kucaklama" arketipi. Akbaba, kolektif bilinçdışında en derin tabu ile yüzleşmeyi — ölümle barışmayı — temsil eder. Pisliği yiyen ama kendisi temiz kalan bu kuş, gölge materyalini sindirerek onu dönüştürmenin simgesidir. Onu itici bulmak, kendi ölümlülüğümüzle yüzleşmekten kaçışın bir yansımasıdır.', en: 'The "Purification and Embracing Death" archetype. The Vulture represents confronting the deepest taboo in the collective unconscious — making peace with death. This bird that eats filth yet remains clean itself is the symbol of transforming shadow material by digesting it. Finding it repulsive is a reflection of our flight from confronting our own mortality.' },
    dream: { tr: 'Akbaba rüyada görünürse — bir şeyin gerçekten bittiğini kabul etme vakti; yas tutmayı erteledin. Yemek yiyorsa: dönüşüm sürüyor, bekle. Başının üzerinde dönüyorsa: bir durumu senin yerine çözmeye çalışmıyorlar, sadece zamanı geldiğinde temizlenecek.', en: 'If Vulture appears in a dream — it is time to accept that something has truly ended; you have been postponing mourning. If it is eating: transformation is ongoing, wait. If it circles above your head: they are not trying to solve a situation in your place, only what will be cleansed when the time comes.' },
    shadow: { tr: 'Ölümle sağlıklı temas yerine ölüme büyülenme — katastrof beklentisi, başkalarının çöküşünden beslenme. Akbaba gölgesi: fırsatçılık, başkasının zayıflığından kazanç sağlama, kötümserlik.', en: 'Instead of healthy contact with death, fascination with death — catastrophic expectation, feeding on the collapse of others. The Vulture shadow: opportunism, profiting from the weakness of others, pessimism.' },
    whenAppears: { tr: 'Uzun süre bitmesi gereken bir şeyi tutunmaya devam ettiğinizde, derin bir kaybı sindirmeniz gerektiğinde ya da eskiyi temizleyip yeniye alan açmanız gereken dönemlerde.', en: 'When you continue to hold on to something that should have ended long ago, when you need to digest a deep loss, or during periods when you need to cleanse the old and make room for the new.' },
    traditions: [
      { culture: { tr: 'Mısır Medeniyeti', en: 'Egyptian Civilization' }, meaning: { tr: 'Nekhbet — akbaba başlı tanrıça, Yukarı Mısır\'ın koruyucusu. Anne ve kraliçe sembolü. Firavunlar tacının üzerinde Nekhbet akbabası taşırdı. Ölümü ve yeniden doğumu yöneten kutsal varlık.', en: 'Nekhbet — the vulture-headed goddess, protector of Upper Egypt. Symbol of mother and queen. Pharaohs bore the vulture of Nekhbet on their crown. The sacred being governing death and rebirth.' } },
      { culture: { tr: 'Tibet Budizmi', en: 'Tibetan Buddhism' }, meaning: { tr: 'Gökyüzü Gömüsü (Jhator) ritüelinde Akbabalar kutsal temizleyicilerdir. Ölen kişinin bedenini yiyen Akbabalar ruhu gökyüzüne taşır. Ölüm korkulacak değil, döngünün bir halkasıdır.', en: 'In the Sky Burial (Jhator) ritual, Vultures are sacred purifiers. Vultures that consume the body of the deceased carry the soul to the sky. Death is not to be feared, it is a link in the cycle.' } },
      { culture: { tr: 'Zerdüşt Geleneği', en: 'Zoroastrian Tradition' }, meaning: { tr: 'Ateşin ve toprağın kirlenmemesi için cesetler Sessizlik Kulesi\'nde Akbabalara bırakılır. Akbaba, maddeyi spiritüele dönüştüren kutsal araçtır.', en: 'So that fire and earth are not defiled, corpses are left to Vultures in the Tower of Silence. The Vulture is the sacred instrument transforming matter into the spiritual.' } },
      { culture: { tr: 'Maya Takvimi', en: 'Maya Calendar' }, meaning: { tr: 'Kibich (Akbaba) — Maya takvimine göre güneşin yeniden doğuşuyla ilişkilendirilir. Şaman ölümünü ve ruhsal yeniden doğumunu sembolize eder.', en: 'Kibich (Vulture) — associated with the rebirth of the sun according to the Maya calendar. Symbolizes the shaman\'s death and spiritual rebirth.' } },
      { culture: { tr: 'Yunan-Anadolu Geleneği', en: 'Greco-Anatolian Tradition' }, meaning: { tr: 'Prometheus\'u karaciğerinden her gün yiyen kartal değil, bazı anlatılarda akbabadır. Süregelen acının içinde bile yenileme ve arınma döngüsü işler.', en: 'In some narratives it is not the eagle but the vulture that eats from Prometheus\'s liver each day. Even within enduring pain, the cycle of renewal and purification works.' } },
    ],
    myths: [
      { tr: 'Tibet\'in Jhator (Gökyüzü Gömüsü) ritüeli: Lama bedeni 108 parçaya böler, Akbabalara sunar. Akbabalar yedikçe ruh bedenin ağırlığından kurtulur ve Bardo\'ya — ölüm ile yeniden doğuş arası berzah — geçer. "Beden zaten ödünç alınmıştı; şimdi geri veriyoruz" — Budist ölüm felsefesinin özü.', en: 'Tibet\'s Jhator (Sky Burial) ritual: The Lama divides the body into 108 pieces and offers them to the Vultures. As the Vultures eat, the soul is freed from the weight of the body and passes to Bardo — the intermediate state between death and rebirth. "The body was borrowed to begin with; now we return it" — the essence of Buddhist death philosophy.' },
      { tr: 'Mısır yaratılış mitinde Nekhbet ve Wadjet — Akbaba ve Kobra — birlikte Firavun\'un tacını oluştururlar. Biri Güney\'i, biri Kuzey\'i temsil eder; biri ölümü, biri yaşamı. Taç bu iki gücü birleştirir. Gerçek egemenlik, zıtları bir arada tutabilmektir.', en: 'In the Egyptian creation myth, Nekhbet and Wadjet — Vulture and Cobra — together form the Pharaoh\'s crown. One represents the South, the other the North; one death, the other life. The crown unites these two forces. True sovereignty is the ability to hold opposites together.' },
    ],
  },

  // ─── a060 Jaguar ─────────────────────────────────────────────────────────
  a060: {
    jung: { tr: '"Gece Güneşi ve Şaman Dönüşümü" arketipi. Jaguar, bilinçdışının en derin katmanını — Gölge\'nin tahtını — temsil eder. Geceleri parlayan gözleri, karanlığın içinde bilinçle görmeyi simgeler. Dönüştürücü güç: Jaguar şaman yalnızca hayvanı çağırmaz, kendisi Jaguar olur — ego sınırlarının tamamen eridiği birleşme hali.', en: 'The "Night Sun and Shamanic Transformation" archetype. The Jaguar represents the deepest layer of the unconscious — the throne of the Shadow. Its eyes that shine in the night symbolize seeing with consciousness inside the darkness. The transformative power: the Jaguar shaman does not merely summon the animal, he becomes the Jaguar — the state of union where ego boundaries completely dissolve.' },
    dream: { tr: 'Jaguar rüyada görünürse — bilinçdışının en derin mesajı yüzeye çıkıyor; korkma, bak. Seni kovalıyorsa: yüzleşmekten kaçtığın güçlü bir içsel güç var. Yanında sessizce yürüyorsa: gücünle barışıksın, şaman yolculuğuna hazırsın.', en: 'If Jaguar appears in a dream — the deepest message of the unconscious is surfacing; do not be afraid, look. If it chases you: there is a powerful inner force you are running from confronting. If it walks silently beside you: you are at peace with your power, you are ready for the shamanic journey.' },
    shadow: { tr: 'Karanlığa çekilme, toplumdan kopuş ve yıkıcı yalnızlık. Jaguar gölgesi: zalimlik, güç üzerinden kurulmuş ilişkiler, merhametsizlik. Ya da güçten tamamen kopma — kendi Jaguarından kaçış.', en: 'Being drawn to the darkness, withdrawal from society, and destructive solitude. The Jaguar shadow: cruelty, relationships built on power, mercilessness. Or complete disconnection from power — fleeing from one\'s own Jaguar.' },
    whenAppears: { tr: 'Derinliklerle — bilinçdışınızla, ölümle, seksüalite ya da güçle — yüzleşmeniz gereken dönemlerde; şamanistik ya da spiritüel bir dönüşüm sürecinin içindeyken.', en: 'During periods when you must confront the depths — your unconscious, death, sexuality or power; when you are within a shamanistic or spiritual transformation process.' },
    traditions: [
      { culture: { tr: 'Olmek Medeniyeti', en: 'Olmec Civilization' }, meaning: { tr: 'Olmek sanatının merkezinde İnsan-Jaguar melezi figürü vardır — şaman ile kutsal hayvanın birleşimi. Jaguar dönüşümü, ilk Amerikan uygarlığının temel ruhsal pratiğidir.', en: 'At the center of Olmec art is the human-jaguar hybrid figure — the union of the shaman and the sacred animal. Jaguar transformation is the fundamental spiritual practice of the first American civilization.' } },
      { culture: { tr: 'Maya Uygarlığı', en: 'Maya Civilization' }, meaning: { tr: 'Ix\'Chel — Maya\'nın ay tanrıçası, Jaguar\'ın gücünü taşır. Yöneticiler "Jaguar" unvanı alırdı. Alt dünya yöneticisi Ah Puch\'un tapınağında Jaguar derisi kutsal örtüdür.', en: 'Ix\'Chel — the Maya moon goddess, carries the power of the Jaguar. Rulers received the title "Jaguar". In the temple of the underworld ruler Ah Puch, jaguar skin is the sacred covering.' } },
      { culture: { tr: 'Aztek Uygarlığı', en: 'Aztec Civilization' }, meaning: { tr: 'Jaguar Savaşçıları — Ocēlōtl — Aztek\'in seçkin askeri sınıfı. Jaguarın gücünü içselleştirmiş savaşçılar. Güneş tanrısı Tezcatlipoca gece gökyüzünde Jaguar biçimine girer.', en: 'Jaguar Warriors — Ocēlōtl — the elite military class of the Aztecs. Warriors who have internalized the power of the Jaguar. The sun god Tezcatlipoca takes the form of the Jaguar in the night sky.' } },
      { culture: { tr: 'And Şamanizmi', en: 'Andean Shamanism' }, meaning: { tr: 'Ayahuasca seremonilerinde Jaguar ruhunun görülmesi şamanın olgunlaştığının işaretidir. Jaguar alt dünyayla iletişimi sağlar; karanlığı taşıyabilmek ruhsal güç gerektirir.', en: 'Seeing the spirit of the Jaguar in ayahuasca ceremonies is a sign that the shaman has matured. The Jaguar enables communication with the underworld; being able to carry darkness requires spiritual strength.' } },
      { culture: { tr: 'Toltec Bilgeliği', en: 'Toltec Wisdom' }, meaning: { tr: 'Don Miguel Ruiz\'in aktardığı Toltec geleneğinde Jaguar, rüyanın efendisidir — hem bireysel rüyalar hem de toplumsal yanılsamalar üzerinde hakimiyet anlamında. Gerçek savaşçı kendi zihnine hükmeder.', en: 'In the Toltec tradition as conveyed by Don Miguel Ruiz, the Jaguar is the master of the dream — in the sense of mastery over both individual dreams and collective illusions. The true warrior rules their own mind.' } },
    ],
    myths: [
      { tr: 'Aztek yaratılış mitinde Tezcatlipoca ve Quetzalcoatl dünyanın yaratıcılarıdır ve sürekli mücadele halindedir. Tezcatlipoca, Quetzalcoatl tarafından devrilen her güneş döngüsünde Jaguar biçimine girerek geceyi yönetir. Gece güneşi, gündüz güneşi kadar güçlüdür — karanlık yalnızca yokluğun değil, gizli gücün adıdır.', en: 'In the Aztec creation myth, Tezcatlipoca and Quetzalcoatl are the creators of the world and are in perpetual struggle. In each solar cycle overthrown by Quetzalcoatl, Tezcatlipoca takes the form of the Jaguar to rule the night. The night sun is as powerful as the day sun — darkness is not merely the name of absence, but of hidden power.' },
      { tr: 'Amazon şamanizmi: Büyük bir şaman ilk kez Jaguar ruhunu çağırdığında, ruh onu sınar — o gece şaman hem avlanır hem avdır. Sabah güneşiyle birlikte ayağa kalkarsa, artık iki dünyada birden yürüyebilir demektir. İlk dönüşüm her zaman ölümcül görünür; hayatta kalanlar şaman olur.', en: 'Amazon shamanism: When a great shaman calls the Jaguar spirit for the first time, the spirit tests them — that night the shaman is both hunter and hunted. If they rise with the morning sun, it means they can now walk in both worlds simultaneously. The first transformation always appears lethal; those who survive become shamans.' },
    ],
  },

  // ─── a061 Kobra ─────────────────────────────────────────────────────────
  a061: {
    jung: { tr: '"İlahi Koruyucu" ve "Kundalini Enerjisi" arketipi. Kobra, bilinçaltının en derin katmanlarında yatan dönüştürücü gücü temsil eder — uyandırıldığında ne iyileştirir ne de yıkım getirir, ikisini birden yapar. Kral işareti olarak taç giyen yılan, ego\'nun aşılıp evrensel bilince erişmenin simgesidir.', en: 'The "Divine Protector" and "Kundalini Energy" archetype. The cobra represents the transformative power coiled in the deepest layers of the unconscious — when awakened it neither heals nor destroys alone, it does both at once. The serpent crowned as a royal mark is the symbol of transcending ego to access universal consciousness.' },
    dream: { tr: 'Kobra rüyada dikilip sana bakıyorsa — içindeki uyuyan güç uyanmak üzere. Saldırıyorsa: bastırılmış hayat enerjisi dışa çıkmak istiyor, artık kaçmak mümkün değil. Başında taç varsa ya da dans ediyorsa: kutsal bir koruma altındasın, içgüdülerine güven.', en: 'If a cobra stands and watches you in a dream — the sleeping power within is about to awaken. If it strikes: suppressed life energy wants to emerge, escape is no longer possible. If it wears a crown or dances: you are under sacred protection, trust your instincts.' },
    shadow: { tr: 'Kobra gölgesi — zehri dışarı değil içe sıkıştırmak. Baskılanmış öfke, ifade edilemeyen güç kimliği çürütür. Öteki uçta: gücünü başkalarını felç etmek için kullanmak, gözdağı ve manipülasyon.', en: 'The cobra\'s shadow — injecting venom inward rather than outward. Suppressed rage, unexpressed power corrodes identity. At the other extreme: using power to paralyze others, through intimidation and manipulation.' },
    whenAppears: { tr: 'Kundalini deneyimi eşiğinde, ruhsal bir uyanışın tam öncesinde, iyileşme krizi anında ya da liderliğin kaçınılmaz hale geldiği dönemeçlerde.', en: 'On the threshold of kundalini experience, in the moment just before spiritual awakening, during a healing crisis, or at crossroads where leadership becomes unavoidable.' },
    traditions: [
      { culture: { tr: 'Hindu', en: 'Hindu' }, meaning: { tr: 'Şiva\'nın boynundaki kobra — Kundalini Shakti\'nin sembolü. Omurga boyunca yükselen ilahi enerjiyi temsil eder.', en: 'The cobra around Shiva\'s neck — symbol of Kundalini Shakti. Represents the divine energy rising along the spine.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Uraeus — firavunların taçlarında kobra. İlahi otorite, koruyucu ateş ve Ra\'nın gücünün simgesi.', en: 'Uraeus — the cobra on pharaohs\' crowns. Symbol of divine authority, protective fire, and the power of Ra.' } },
      { culture: { tr: 'Budizm', en: 'Buddhism' }, meaning: { tr: 'Mucalinda yılanı — meditasyon eden Buda\'yı yağmurdan korumak için başının üstünde açılan dev kobra. İlahi koruma imgesi.', en: 'Mucalinda serpent — the great cobra that spread its hood over the meditating Buddha to shield him from rain. An image of divine protection.' } },
      { culture: { tr: 'Yunan', en: 'Greek' }, meaning: { tr: 'Asklepios\'un asasındaki yılan — iyileştirici bilgelik ve dönüşümün simgesi. Zehir hem öldürür hem de şifalandırır.', en: 'The serpent on the staff of Asclepius — symbol of healing wisdom and transformation. Venom both kills and cures.' } },
      { culture: { tr: 'Anadolu / Hitit', en: 'Anatolian / Hittite' }, meaning: { tr: 'Tarkan yılanı — tanrıların haberini taşıyan kutsal sürüngen. Kayalara kazınan yılan figürleri koruyucu ruh olarak kabul edilirdi.', en: 'The sacred serpent of Hittite tradition — the reptile that carried the gods\' messages. Serpent figures carved into rock were regarded as protective spirits.' } },
    ],
    myths: [
      { tr: 'Hint mitolojisinde Adi Şesha, evrenin yükünü sırtında taşıyan bin başlı kobradır; Vişnu onun üzerinde uyur. Yaratılış ve yıkım arasındaki denge, bu yılanın nefesiyle tutulur.', en: 'In Hindu mythology, Adi Shesha is the thousand-headed cobra who bears the weight of the universe; Vishnu sleeps upon him. The balance between creation and destruction is held by this serpent\'s breath.' },
      { tr: 'Mısır\'da İsis, kobra biçimine bürünerek Osiris\'i ölüler diyarından geri çekmiştir. Yılanın yeniden doğuşu — her yıl derisini dökmesi — sonsuzluğun döngüsel simgesi olarak tapınıldı.', en: 'In Egypt, Isis took the form of a cobra to draw Osiris back from the realm of the dead. The serpent\'s renewal — shedding its skin every year — was venerated as a cyclical symbol of eternity.' },
    ],
  },

  // ─── a062 Puma ───────────────────────────────────────────────────────────
  a062: {
    jung: { tr: '"Sessiz Lider" ve "Gizli Güç" arketipi. Puma gürlemez — varlığıyla yönetir. Jung\'un gölge çalışmasında puma, ego\'nun sessizliğe çekilip gerçek gücünü keşfettiği o kristal ana karşılık gelir. Yalnızlık burada zayıflık değil, özgünlüğün koşuludur.', en: 'The "Silent Leader" and "Hidden Power" archetype. The puma does not roar — it leads with presence. In Jungian shadow work, the puma corresponds to that crystalline moment when ego withdraws into silence and discovers its true power. Solitude here is not weakness — it is the condition for authenticity.' },
    dream: { tr: 'Puma rüyanda seni izliyorsa — içindeki liderlik seni takip ediyor, henüz kabul etmedin. Peşinden geliyorsa: liderlikten kaçma, o güç zaten senin. Hareketsiz duruyorsa: karar zamanı, çevrenin gürültüsüne değil içindeki sessizliğe kulak ver.', en: 'If the puma watches you in a dream — the leadership within is following you, you have not yet accepted it. If it comes after you: do not flee from leadership, that power is already yours. If it stands motionless: it is time to decide, listen to the silence within rather than the noise around you.' },
    shadow: { tr: 'Gücünü gizlemeyi bir silaha dönüştürmek — manipülatif sessizlik, soğuk mesafe. Aşırı uçta: dünyanın geri kalanını küçümseyerek tam yalnızlığa çekilmek ve gerçek bağlantıdan kopuş.', en: 'Turning the concealment of power into a weapon — manipulative silence, cold distance. At the extreme: withdrawing into total isolation while contemning the rest of the world, severing genuine connection.' },
    whenAppears: { tr: 'Liderlik rolünü üstlenmekte tereddüt ettiğinde, başkalarının sesi altında kendi sesini kaybettiğinde ya da yalnız bir karar almanın tam eşiğinde.', en: 'When you hesitate to take on a leadership role, when your own voice is lost under the voices of others, or on the precise threshold of making a solitary decision.' },
    traditions: [
      { culture: { tr: 'İnka / And Medeniyeti', en: 'Inca / Andean' }, meaning: { tr: 'Puma — Inca kozmolojisinin üç dünyasından biri olan Kay Pacha\'nın (bu dünya) simgesi. Cuzco şehri puma biçiminde inşa edilmiştir.', en: 'Puma — symbol of Kay Pacha (this world), one of the three realms of Inca cosmology. The city of Cuzco was built in the shape of a puma.' } },
      { culture: { tr: 'Kuzey Amerika Yerlileri (Quechua)', en: 'Native North American (Quechua)' }, meaning: { tr: 'Dağ aslanı — hem avcı hem de adil yargıç. Liderlik gücünü sessiz ve dengeli kullananların totemine sahip çıkar.', en: 'Mountain lion — both hunter and fair judge. Claims the totem of those who wield leadership power silently and in balance.' } },
      { culture: { tr: 'Aztec', en: 'Aztec' }, meaning: { tr: 'Ocelotl savaşçıları — puma ve jaguar derisi giyen seçkin savaş birliği. Karanlıkta görme ve gizli güç sembolü.', en: 'Ocelotl warriors — the elite combat unit wearing puma and jaguar skins. Symbol of seeing in the dark and concealed power.' } },
      { culture: { tr: 'Mapuche (Şili)', en: 'Mapuche (Chile)' }, meaning: { tr: 'Puma, atalardan gelen koruyucu ruh. Şamanlar puma biçimine bürünerek ata dünyasıyla iletişim kurduğuna inanılır.', en: 'The puma is the ancestral protective spirit. Shamans are believed to take puma form to communicate with the world of ancestors.' } },
      { culture: { tr: 'Anadolu / Halk İnancı', en: 'Anatolian / Folk Belief' }, meaning: { tr: 'Yırtıcı kediler Anadolu\'da "dağ sultanı" sayılır; gücü sessiz taşıyan ve haksızlığa uğramış ruhları koruyan kutsal varlıklar olarak anılır.', en: 'Large wild cats are considered "mountain sultans" in Anatolia; they are revered as sacred beings who silently carry power and protect souls that have been wronged.' } },
    ],
    myths: [
      { tr: 'İnka söylencesine göre Viracocha tanrı, dünyanın ilk insanlarını puma biçiminde yarattı; sonra onları insan yaptı ama puma ruhu içlerinde kaldı. Her büyük lider bu gizli puma ruhunu taşır.', en: 'According to Inca legend, the god Viracocha first created the world\'s first humans in the form of a puma; then he made them human, but the puma spirit remained within them. Every great leader carries this hidden puma spirit.' },
      { tr: 'And şamanizminde puma, ölüler ve yaşayanlar arasındaki sınırda yürür. Geçiş törenlerinde genç savaşçı yalnız dağa gönderilir — pumayı görürse ruhsal olgunluğa erişmiş sayılır, çünkü puma yalnızca hazıra görünür.', en: 'In Andean shamanism, the puma walks the boundary between the dead and the living. In initiation rites a young warrior is sent alone to the mountain — if he sees the puma he is deemed to have attained spiritual maturity, for the puma appears only to those who are ready.' },
    ],
  },

  // ─── a063 Su Samuru ──────────────────────────────────────────────────────
  a063: {
    jung: { tr: '"Oyuncu Kadın Bilgeliği" ve "Akan Şans" arketipi. Su samuru, Jungian anima figürünün en hafif ve en özgür tezahürüdür — ağırlığı yoktur, her şeyin üzerinden kayar. Bilgeliği oyunun içinde taşır; ciddiyet gerektiren yerlerde bile şakasını yapar, çünkü gerçek anlayış kasılmadan gelir.', en: 'The "Playful Feminine Wisdom" and "Flowing Luck" archetype. The otter is the lightest and most liberated expression of the Jungian anima — it carries no weight, gliding over everything. It holds wisdom inside play; it jokes even where seriousness is expected, because true understanding comes without tension.' },
    dream: { tr: 'Su samuru rüyanda suyun üstünde kayarak geçiyorsa — hayatın daha hafif tutulması gerekiyor, zorla değil akışla. Seninle oynuyorsa: içindeki çocuk özgürlük istiyor. Suya dalıp kayboluyorsa: bilinçdışının derinliklerine mutlu bir yolculuk yapıyorsun.', en: 'If the otter slides across water in your dream — life needs to be held more lightly, through flow not force. If it plays with you: the child within wants freedom. If it dives and disappears: you are making a joyful journey into the depths of the unconscious.' },
    shadow: { tr: 'Hiçbir şeyi ciddiye almamak, sorumluluktan kaçmak için oyunu kalkan olarak kullanmak. Öte yanda: kaygıdan doğan aşırı kontrol — suyun akışını durdurmaya çalışmak, şansı zorlamak.', en: 'Taking nothing seriously, using play as a shield to escape responsibility. On the other side: excessive control born of anxiety — trying to stop the flow of water, forcing luck.' },
    whenAppears: { tr: 'Hayatın ağırlığı altında ezilirken, yaratıcılığını kaybettiğini hissedince ya da bir ilişkide ya da işte sevinci yeniden bulmak gerektiğinde.', en: 'When crushed under the weight of life, when you feel you have lost your creativity, or when joy needs to be rediscovered in a relationship or vocation.' },
    traditions: [
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Su samuru Kelt efsanelerinde kutsal nehirlerin koruyucusudur. İrlanda geleneğinde "dobhar-chú" — nehir tanrıçasının elçisi.', en: 'In Celtic legend the otter is the guardian of sacred rivers. In Irish tradition "dobhar-chú" — the messenger of the river goddess.' } },
      { culture: { tr: 'Japon', en: 'Japanese' }, meaning: { tr: 'Kawa-uso — nehirlerde yaşayan dönüşebilen ruh. Şansı beraberinde getirir ama kandırılmayı da sever.', en: 'Kawa-uso — a shape-shifting spirit living in rivers. It brings luck but also enjoys trickery.' } },
      { culture: { tr: 'Kuzey Amerika Yerlileri (Haida)', en: 'Native North American (Haida)' }, meaning: { tr: 'Su samuru dişil ruhun simgesi; aile bağını, neşeyi ve topluluk içindeki kadın bilgeliğini temsil eder.', en: 'The otter is a symbol of the feminine spirit; it represents family bonds, joy, and feminine wisdom within the community.' } },
      { culture: { tr: 'İran / Fars', en: 'Iranian / Persian' }, meaning: { tr: 'Avesta\'da su samuru kutsal sayılır — Ahura Mazda\'nın yaratığı. Onu öldürmek günahtır, nehrin bereketini keser.', en: 'In the Avesta the otter is considered sacred — a creature of Ahura Mazda. Killing one is a sin that cuts off the river\'s abundance.' } },
      { culture: { tr: 'Anadolu / Halk İnancı', en: 'Anatolian / Folk Belief' }, meaning: { tr: 'Nehir kenarlarında görülen su samuru, "suların şans getiren beyi" olarak bilinir; balıkçılar onu görürse o gün ağ dolacağına inanır.', en: 'The otter seen along riverbanks is known as "the luck-bringing lord of the waters"; fishermen believe that seeing one means the net will be full that day.' } },
    ],
    myths: [
      { tr: 'İrlanda efsanesinde Fionn mac Cumhaill\'in dostu, nehir tanrıçasının gönderdiği bir su samurudur. Samur, kahramana görünmez bir zırh giyer ve su altındaki hazineyi gösterir — bilgelik her zaman oyunun içinde gizlidir.', en: 'In Irish legend, the companion of Fionn mac Cumhaill is an otter sent by the river goddess. The otter clothes the hero in invisible armor and reveals the treasure beneath the water — wisdom is always hidden inside play.' },
      { tr: 'Zerdüştlükte anlatılır: Bir samur öldürüldüğünde rüzgarlar durur, mahsul kurur, çocuklar hastalanır. Yeniden dirilmesi için yüzlerce kurban gerekir. Su samurunun şansı tüm topluluğu taşır.', en: 'It is told in Zoroastrianism: when an otter is killed the winds stop, crops wither, children fall ill. Hundreds of offerings are required for its resurrection. The otter\'s luck carries the whole community.' },
    ],
  },

  // ─── a064 Balıkçıl ──────────────────────────────────────────────────────
  a064: {
    jung: { tr: '"Öz-Belirlenim" ve "Temaşa Bilgeliği" arketipi. Balıkçıl, saatlerce kıpırdamadan durabilir — dışarıdan hareketsizlik, içeride mutlak farkındalık. Jung\'un "individuasyon" sürecinde bu kuş, egonun gürültüsü sustuğunda ortaya çıkan derin öz-bilgiyi simgeler. Sabır burada pasiflik değil, zamanın doğru biçimde kullanılmasıdır.', en: 'The "Self-Determination" and "Contemplative Wisdom" archetype. The heron can stand motionless for hours — outwardly stillness, inwardly absolute awareness. In Jung\'s process of individuation this bird symbolizes the deep self-knowledge that emerges when the ego\'s noise falls silent. Patience here is not passivity — it is the proper use of time.' },
    dream: { tr: 'Balıkçıl rüyanda suda hareketsiz duruyorsa — bekle, henüz doğru an gelmedin. Uçuyorsa: yalnız bir karar almanın vakti geldi, kimseye danışma. Su içinden balık tutuyorsa: bilinçdışından net bir cevap geliyor, dikkat et.', en: 'If the heron stands motionless in water in your dream — wait, the right moment has not yet arrived. If it flies: the time has come to make a solitary decision, consult no one. If it catches a fish from the water: a clear answer is coming from the unconscious, pay attention.' },
    shadow: { tr: 'Bekleyişi sonsuza uzatmak — fırsatları hareketsizliğin arkasına saklanarak kaçırmak. Öte yanda: izolasyonu erdem saymak, yardımı reddetmek ve başkalardan üstün bir yalnızlık içinde donup kalmak.', en: 'Extending the wait into infinity — missing opportunities by hiding behind stillness. On the other side: mistaking isolation for virtue, refusing help, and freezing in a solitude that considers itself superior to others.' },
    whenAppears: { tr: 'Aceleci kararların bedel ödettirdiği bir dönemde, meditasyon ya da inzivayı düşünürken ya da kendi içsel bilgeliğine güvenmeyi öğrenmen gereken anda.', en: 'In a period when hasty decisions have exacted a price, when you are thinking of meditation or retreat, or at the moment you must learn to trust your own inner wisdom.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Bennu kuşu (balıkçıl tabanlı) — yaratılışın ilk anında Nun\'un sularından yükselen güneş ruhu. Zaman ve yeniden doğuşun efendisi.', en: 'The Bennu bird (heron-based) — the solar spirit rising from the waters of Nun at the first moment of creation. Master of time and rebirth.' } },
      { culture: { tr: 'Japon', en: 'Japanese' }, meaning: { tr: 'Sagi — Shinto geleneğinde saflık ve öz-denetim sembolü. Beyaz balıkçıl, ruhun arınmasının habercisidir.', en: 'Sagi — in Shinto tradition a symbol of purity and self-discipline. The white heron heralds the purification of the spirit.' } },
      { culture: { tr: 'Kelt', en: 'Celtic' }, meaning: { tr: 'Corr — kelt mitinde balıkçıl, yalnız bilge ve öteki dünyanın sınırında duran bekçidir. Druidlerin kutsal kuşu sayılır.', en: 'Corr — in Celtic myth the heron is the solitary sage and guardian standing at the boundary of the otherworld. It is considered the sacred bird of the Druids.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Cangbai — sabır ve uzun ömür sembolü. Balıkçıl tüyleri üst düzey yetkililerin tacını süslüyordu; öz-denetimin sosyal statü getirdiği inancıyla.', en: 'Cangbai — symbol of patience and longevity. Heron feathers adorned the crowns of high-ranking officials, reflecting the belief that self-discipline brings social standing.' } },
      { culture: { tr: 'Anadolu / Halk Şiiri', en: 'Anatolian / Folk Poetry' }, meaning: { tr: 'Türk halk şiirinde "balıkçıl" sabırlı aşkın simgesidir — yıllar boyunca aynı kıyıda bekleyen âşık imgesi.', en: 'In Turkish folk poetry the heron is a symbol of patient love — the image of a lover waiting years on the same shore.' } },
    ],
    myths: [
      { tr: 'Mısır yaratılış anlatısında Bennu kuşu, var olmayan bir zamanda, karanlık sulardan yükselen tek kayaya kondu ve ilk sesi çıkardı. O ses yaratılışı başlattı. Balıkçıl hareketsizliği kaos öncesindeki sonsuz potansiyeli taşır.', en: 'In the Egyptian creation narrative, the Bennu bird alighted on the single rock rising from dark waters at a time before time, and uttered the first cry. That cry initiated creation. The heron\'s stillness carries the infinite potential that precedes chaos.' },
      { tr: 'İrlanda efsanesinde Fionnuala adlı kız üvey annesi tarafından balıkçıla dönüştürülür; dokuz yüz yıl boyunca üç göl arasında uçar. Her kış soğuğunda bile şarkı söylemeyi bırakmaz — çünkü sabır ve öz-belirlenim, büyüyü çözen tek anahtardır.', en: 'In Irish legend a girl named Fionnuala is turned into a heron by her stepmother; for nine hundred years she flies among three lakes. Even through every winter\'s cold she never stops singing — because patience and self-determination are the only key that breaks the enchantment.' },
    ],
  },

  // ─── a065 Çakal ─────────────────────────────────────────────────────────
  a065: {
    jung: { tr: '"Trickster Öğretici" ve "Geçiş Rehberi" arketipi. Çakal, Jung\'un en derin trickster figürüdür — saçma görünen davranışların ardında evrenin işleyişini anlatır. Sınırda yürür: ne tam yaşam ne tam ölüm, ne tam bilge ne tam aptal. Anubis geleneğinde olduğu gibi, ölü ruhları karanlıkta yol göstermeksizin kaybedeceği labirentin içinden çıkarır.', en: 'The "Trickster Teacher" and "Guide of Passage" archetype. The jackal is Jung\'s deepest trickster figure — behind seemingly absurd behavior it narrates the workings of the universe. It walks the boundary: not quite life, not quite death, not quite wise, not quite fool. As in the Anubis tradition, it leads dead souls out of the labyrinth where they would be lost in the dark without guidance.' },
    dream: { tr: 'Çakal rüyanda gülerken görülüyorsa — dikkat et, şu an anlamadığın bir ders veriliyor. Geceleri uluryorsa: bir geçiş döneminin ortasındasın, yönünü bil. Seni rehberliğinde götürüyorsa: bilinçdışı seni daha derin bir hakikate doğru çekiyor.', en: 'If you see the jackal laughing in a dream — pay attention, a lesson you do not yet understand is being given. If it howls at night: you are in the middle of a transition, know your direction. If it leads you in guidance: the unconscious is drawing you toward a deeper truth.' },
    shadow: { tr: 'Trickster enerjisinin karanlık yüzü: aldatma, istismar, kaosu amaç haline getirmek. Çakalın gölgesi her şeyle alay eden, hiçbir şeyi kutsal saymayan sinik zihindir.', en: 'The dark face of trickster energy: deception, exploitation, making chaos an end in itself. The jackal\'s shadow is the cynical mind that mocks everything and holds nothing sacred.' },
    whenAppears: { tr: 'Bir dönem kapanıp yenisi başlamak üzereyken, yasın ortasında anlam arayışında ya da başkasının öğretemediği bir dersi hayat sana verirken.', en: 'When one chapter is closing and another is about to begin, in the midst of grief searching for meaning, or when life itself is giving you a lesson no one else could teach.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Anubis — çakal başlı ölüler tanrısı. Ölünün kalbini tüy ile tartar; ruhları Duat\'tan geçirir. Adil yargı ve geçiş rehberliğinin efendisi.', en: 'Anubis — the jackal-headed god of the dead. He weighs the heart of the deceased against the feather; he guides souls through the Duat. Master of just judgment and guidance through passage.' } },
      { culture: { tr: 'Afrika / Yoruba', en: 'African / Yoruba' }, meaning: { tr: 'Çakal benzeri hilekâr hayvan figürleri, bilgeliğin gülünç görünen kılığa büründüğü anlatıları temsil eder.', en: 'Jackal-like trickster animal figures represent narratives where wisdom takes on a ridiculous disguise.' } },
      { culture: { tr: 'Kuzey Amerika Yerlileri (Navajo)', en: 'Native North American (Navajo)' }, meaning: { tr: 'Coyote (çakalla özdeşleşir) — dünyayı yaratan ve bozan trickster. Her düzeni bozuşu yeni bir denge doğurur.', en: 'Coyote (identified with the jackal) — the trickster who creates and undoes the world. Each disruption of order gives birth to a new balance.' } },
      { culture: { tr: 'Hint', en: 'Indian' }, meaning: { tr: 'Panchatantra masallarında çakal — kurnaz ancak adil rehber. Gücü olmayanın zekâsıyla zafere ulaşmasını anlatan hikayelerin kahramanı.', en: 'In the Panchatantra the jackal is the cunning yet just guide. The hero of stories where one without power achieves victory through intelligence.' } },
      { culture: { tr: 'Anadolu / Halk Geleneği', en:  'Anatolian / Folk Tradition' }, meaning: { tr: '"Çakal derisi" deyimi Anadolu\'da gerçeği örtbas edenleri anlatır; ama halk anlatısında çakal aynı zamanda zayıfı güçlüden koruyan kurnaz adil figürdür.', en: 'The phrase "jackal skin" in Anatolia refers to those who cover up truth; but in folk narrative the jackal is also the cunningly just figure that protects the weak from the powerful.' } },
    ],
    myths: [
      { tr: 'Mısır\'da Osiris\'in parçalanmış bedeni toplandığında Anubis, cesedi ilk mumyalayan tanrıdır. Ölümden diriliş mümkündür — ama yalnızca doğru geçiş rehberi eşliğinde. Çakal olmadan ruh çorak çölde kaybolur.', en: 'In Egypt, when the dismembered body of Osiris was gathered, Anubis was the god who performed the first mummification. Resurrection from death is possible — but only in the company of the right guide of passage. Without the jackal the soul is lost in barren desert.' },
      { tr: 'Hint masalında üç çakal bir aslanı kandırarak güçlü olmadan nasıl hayatta kalınacağını öğretir. Sonunda aslan tuzağa düşer, çakallar serbest kalır. Trickster öğretisinin özü: güç değil, farkındalık kazandırır.', en: 'In an Indian tale three jackals trick a lion and teach how to survive without power. In the end the lion falls into the trap and the jackals go free. The essence of trickster teaching: it is not strength but awareness that wins.' },
    ],
  },

  // ─── a066 Ketsal Kuşu ────────────────────────────────────────────────────
  a066: {
    jung: { tr: '"Kutsal Güzellik" ve "Özgür Ruh" arketipi. Ketsal, Jung\'un "Özbenlik" kavramının en görünür kılığıdır — varlığı salt bir tezahür, bir anlık mükemmellik parlaması. Esarette ölür: gerçek öz de baskı altında solar. Özgürlük burada bir hak değil, varoluşun kendisidir.', en: 'The "Sacred Beauty" and "Free Spirit" archetype. The quetzal is the most visible guise of Jung\'s concept of the "Self" — its existence is pure manifestation, a momentary flash of perfection. It dies in captivity: the true self also fades under oppression. Freedom here is not a right — it is existence itself.' },
    dream: { tr: 'Ketsal rüyanda uçuyorsa — ruhun en özgür hali seni çağırıyor, takip et. Kafeste görülüyorsa: hangi konfor alanı seni kısıtlıyor, farkında mısın? Kanatlarını açıp size bakıyorsa: kutsal bir güzelliği görme zamanı, belki de kendin.', en: 'If the quetzal flies in your dream — your soul\'s most liberated state is calling you, follow it. If it appears in a cage: which comfort zone is constraining you, are you aware? If it spreads its wings and looks at you: it is time to see a sacred beauty, perhaps yourself.' },
    shadow: { tr: 'Güzelliği sadece kendisinde görmek — kibir, estetik tiranlık. Öte yanda: güzelliği yaşamaktan korkmak, sıradanlığa saklanmak, kendini dünyaya açmayı reddeden çekingenlik.', en: 'Seeing beauty only in oneself — arrogance, aesthetic tyranny. On the other side: fearing to live beauty, hiding in ordinariness, a timidity that refuses to open oneself to the world.' },
    whenAppears: { tr: 'Yaratıcı ifadeni bastırdığında, özgünlüğünden taviz verdiğinde ya da başkalarının gözünde kaybolmak pahasına da olsa kendin olman gerektiği anda.', en: 'When you suppress your creative expression, when you compromise your authenticity, or at the moment you must be yourself even at the cost of disappearing in the eyes of others.' },
    traditions: [
      { culture: { tr: 'Maya', en: 'Maya' }, meaning: { tr: 'Kukulkan — tüylü yılan tanrısı, ketsal tüyleri ve yılan bedeninden oluşur. Gökle yerin, özgürlükle gücün birleşimi.', en: 'Kukulcan — the feathered serpent deity, composed of quetzal feathers and a serpent body. The union of sky and earth, of freedom and power.' } },
      { culture: { tr: 'Aztek', en: 'Aztec' }, meaning: { tr: 'Quetzalcoatl — tüylü yılan. Ketsal tüyleri yalnızca tanrılar ve kral sınıfına aitti; kuşu öldürmek ölümle cezalandırılırdı.', en: 'Quetzalcoatl — the feathered serpent. Quetzal feathers belonged only to the gods and the royal class; killing the bird was punishable by death.' } },
      { culture: { tr: 'Guatemala Yerlileri (Kiche Maya)', en: 'Guatemalan Indigenous (Kiche Maya)' }, meaning: { tr: 'Ketsal, ulusal kuş ve özgürlük simgesi. "Özgür doğarım ya da ölürüm" prensibiyle özdeşleşmiştir; para birimi bile ketsal adını taşır.', en: 'The quetzal is the national bird and symbol of freedom. It is identified with the principle "I am born free or I die"; even the currency bears the name quetzal.' } },
      { culture: { tr: 'Sufi / İslam', en: 'Sufi / Islamic' }, meaning: { tr: 'Anka ve Hüma gibi efsanevi kuşlar Sufi geleneğinde özgür ruhun sembolüdür; ketsal da bu kutsallığı taşır — görülmesi şans, dokunulması kutsanmak demektir.', en: 'Legendary birds like the Phoenix and Huma are symbols of the free spirit in Sufi tradition; the quetzal also carries this sanctity — to see it is luck, to touch it is to be blessed.' } },
      { culture: { tr: 'Anadolu / Alevi-Bektaşi', en: 'Anatolian / Alevi-Bektashi' }, meaning: { tr: 'Hüma kuşu — Anadolu\'da özgürlüğün ve kutsal güzelliğin simgesi. Gölgesi üzerine düşen kişi sultan olur. Ketsal\'ın Anadolu yankısı.', en: 'The Huma bird — symbol of freedom and sacred beauty in Anatolia. Whoever its shadow falls upon becomes a sultan. The Anatolian echo of the quetzal.' } },
    ],
    myths: [
      { tr: 'Maya efsanesine göre savaşçı Tecun Uman İspanyol fatihi Alvarado\'ya karşı savaşırken ketsal onun saç süsüydü. Savaşçı öldüğünde ketsal göğsüne kondu ve kırmızıya boyandı — o günden beri ketsal\'ın göğsü kırmızıdır, özgürlük şehitlerinin kanıyla.', en: 'According to Maya legend, when the warrior Tecun Uman fought the Spanish conquistador Alvarado, the quetzal was his headdress. When the warrior died the quetzal alighted on his chest and was stained red — since that day the quetzal\'s breast has been red, with the blood of martyrs of freedom.' },
      { tr: 'Aztek mitinde Quetzalcoatl\'ın yaratılış anında ketsal tüylerinden dünyanın ilk insanları yapılmıştır. Güzellik ve özgürlük, insanın en köklü özüdür — kaybedildiğinde insan olmaktan çıkılır.', en: 'In Aztec myth, at the moment of Quetzalcoatl\'s creation, the world\'s first humans were fashioned from quetzal feathers. Beauty and freedom are the most fundamental essence of the human being — when lost, one ceases to be human.' },
    ],
  },

  // ─── a067 Maymun ────────────────────────────────────────────────────────
  a067: {
    jung: { tr: '"Oyuncu Zihin" ve "Yaratıcı Zekâ" arketipi. Maymun, Jung\'un "trickster" ve "puer aeternus" figürlerinin birleşimidir — sonsuz merak, sonsuz enerji, ancak odak sorunu. Evrimsel olarak en yakın akrabamız olduğu için maymunda aynı zamanda kendi hayvani doğamızın aynasını görürüz: ne kadar insanız, ne kadar içgüdüsel.', en: 'The "Playful Mind" and "Creative Intelligence" archetype. The monkey is the union of Jung\'s "trickster" and "puer aeternus" figures — infinite curiosity, infinite energy, but a problem of focus. As our evolutionarily closest relative, in the monkey we also see the mirror of our own animal nature: how human we are, how instinctual.' },
    dream: { tr: 'Maymun rüyanda sıçrayıp duruyorsa — zihnin bir yerden bir yere atlamasını durduramıyorsun, meditasyon yardımcı olur. Seninle oynuyorsa: yaratıcılığını özgürce ifade et, bu dönem bunun için. Aynaya bakıyorsa: kendini daha derin gör, yüzeyselliğin ötesine geç.', en: 'If the monkey keeps leaping in a dream — you cannot stop your mind jumping from place to place, meditation would help. If it plays with you: express your creativity freely, this period is for that. If it looks in a mirror: see yourself more deeply, move beyond the surface.' },
    shadow: { tr: 'Dağıtıcı zekâ — her şeyle ilgilenen ama hiçbirini tamamlamayan, sabırsız, dikkat süresi kısa bir zihin. Öte yanda: zekâyı manipülasyon için kullanmak, başkalarını küçümsemek ve alaycı üstünlük.', en: 'Dispersive intelligence — a mind interested in everything but completing nothing, impatient, with a short attention span. On the other side: using intelligence for manipulation, belittling others, and sarcastic superiority.' },
    whenAppears: { tr: 'Yaratıcı bir projeye başlarken, zihni sakinleştirmenin gereği ortaya çıktığında ya da oyundan ve eğlenceden hayatı uzaklaştırdığın dönemlerde.', en: 'When beginning a creative project, when the need to calm the mind arises, or in periods when you have driven play and joy away from life.' },
    traditions: [
      { culture: { tr: 'Hint / Hindu', en: 'Indian / Hindu' }, meaning: { tr: 'Hanuman — rüzgar tanrısının oğlu, sonsuz güç ve bağlılığın maymun tanrısı. Rama\'ya olan sevgisi, onu tanrısal güce kavuşturur.', en: 'Hanuman — son of the wind god, the monkey deity of infinite strength and devotion. His love for Rama elevates him to divine power.' } },
      { culture: { tr: 'Çin / Budizm', en: 'Chinese / Buddhism' }, meaning: { tr: 'Sun Wukong — Taş Maymun. Kendi kendine doğan, ölümsüzlük kazanan ve cennet ordusuyla savaşan trickster kahraman. Ego\'nun yolculuğu.', en: 'Sun Wukong — the Monkey King. A trickster hero born of stone, who wins immortality and battles the armies of heaven. The journey of the ego.' } },
      { culture: { tr: 'Maya', en: 'Maya' }, meaning: { tr: 'Hunahpu — Maya ikiz kahramanlarından biri maymuna dönüştürülür. Yaratıcılık ve sanat tanrısı olur. Dönüşüm bilgeliği taşır.', en: 'Hunahpu — one of the Maya twin heroes is transformed into a monkey. He becomes a deity of creativity and art. He carries the wisdom of transformation.' } },
      { culture: { tr: 'Afrika / Yoruba', en: 'African / Yoruba' }, meaning: { tr: 'Maymun figürü bilgeliğin naif ama derin taşıyıcısıdır; öğretileri doğrudan değil, göstererek anlatır.', en: 'The monkey figure is the naive but profound carrier of wisdom; it teaches not directly but by showing.' } },
      { culture: { tr: 'Anadolu / Osmanlı Minyatürü', en: 'Anatolian / Ottoman Miniature' }, meaning: { tr: 'Osmanlı minyatürlerinde maymun zaman zaman insanın karikatürü olarak çizilir — toplumsal eleştirinin zarif kılığı.', en: 'In Ottoman miniatures the monkey is sometimes drawn as a caricature of the human — the elegant guise of social criticism.' } },
    ],
    myths: [
      { tr: 'Ramayana\'da Hanuman Sita\'yı aramak için Lanka\'ya geçer. Okyanusu tek sıçramada aşar — çünkü gerçek inanç, fiziksel sınırları aşar. Maymunun zekâsı ile kalbin bağlılığı birleşince mucize doğar.', en: 'In the Ramayana, Hanuman crosses to Lanka to seek Sita. He leaps across the ocean in a single bound — because true faith transcends physical limits. When the monkey\'s intelligence unites with the heart\'s devotion, miracle is born.' },
      { tr: 'Çin\'de Taş Maymun\'un Batı\'ya Yolculuğu destanında Sun Wukong Buda\'nın elinden kaçamayacağını anlar. Kendi gücünün sınırını öğrenmek, gerçek zekânın başlangıcıdır. Tüm bilgelik yolculukları bir gurur sınavıyla başlar.', en: 'In China\'s "Journey to the West" epic, Sun Wukong learns that he cannot escape the hand of the Buddha. Learning the limits of one\'s own power is the beginning of true intelligence. All journeys of wisdom begin with a test of pride.' },
    ],
  },

  // ─── a068 Papağan ────────────────────────────────────────────────────────
  a068: {
    jung: { tr: '"İletişim Aynası" ve "Öğretici Ses" arketipi. Papağan, Jung\'un persona kavramıyla derin bir ilişki içindedir — duyduğunu yansıtır, ama bu yansıtma bazen gerçeği ortaya çıkarır. Hafıza ve ses, bilincin en kadim araçlarıdır; papağan bu araçları sahiplenerek ritüel bir öğretici olur.', en: 'The "Communication Mirror" and "Teaching Voice" archetype. The parrot bears a deep relationship with Jung\'s concept of the persona — it reflects what it hears, but that reflection sometimes reveals truth. Memory and voice are the most ancient instruments of consciousness; the parrot, by claiming these instruments, becomes a ritual teacher.' },
    dream: { tr: 'Papağan rüyanda senin sözlerini tekrarlıyorsa — söylediklerini duyuyor musun, gerçekten? Konuşamıyorsa ya da susmuyorsa: iletişim kanallarında bir tıkanma var. Renkli tüylerini sergiliyorsa: yaratıcı ifadenin zamanı geldi, sesini duyur.', en: 'If the parrot in your dream repeats your own words — are you really hearing what you say? If it cannot speak or will not stop: there is a blockage in your communication channels. If it displays its colourful feathers: the time for creative expression has come, make your voice heard.' },
    shadow: { tr: 'Anlam olmadan tekrarlamak — başkalarının fikirlerini özümsemeden aktarmak, sahte bir bilgelik. Öte yanda: sözcükleri silah haline getirmek, gıybet ve dedikodu zinciri, sesin zehre dönüşmesi.', en: 'Repeating without meaning — conveying others\' ideas without absorbing them, a counterfeit wisdom. On the other side: turning words into weapons, a chain of gossip and slander, the voice becoming venom.' },
    whenAppears: { tr: 'İletişim sorunlarının had safhaya ulaştığı ilişkilerde, yaratıcı ifadenin bastırıldığı dönemlerde ya da başkalarının sözlerini mi yoksa kendi sesini mi taşıdığını sorguladığında.', en: 'In relationships where communication problems have reached a peak, in periods when creative expression is suppressed, or when you question whether you carry others\' words or your own voice.' },
    traditions: [
      { culture: { tr: 'Hint / Sanskrit', en: 'Indian / Sanskrit' }, meaning: { tr: 'Shuka — Vişnu\'nun elçisi papağan. Bhagavata Purana\'yı Kral Parikshit\'e aktarır. Kutsal bilginin taşıyıcısı ve öğretici ses.', en: 'Shuka — the parrot messenger of Vishnu. He conveys the Bhagavata Purana to King Parikshit. Bearer of sacred knowledge and teaching voice.' } },
      { culture: { tr: 'İslam / Sufi', en: 'Islamic / Sufi' }, meaning: { tr: 'Rumi\'nin Mesnevi\'sinde papağan aynı şehveti öğreten tacirin metaforu — gerçek özgürlük bilgiyle değil, aşkla kazanılır. Kafes dünya, papağan nefstir.', en: 'In Rumi\'s Masnavi the parrot is the metaphor of the merchant teaching the same desire — true freedom is won not with knowledge but with love. The cage is the world, the parrot is the ego-soul.' } },
      { culture: { tr: 'Amazon Yerlileri', en: 'Amazonian Indigenous' }, meaning: { tr: 'Papağan, bitki dünyasıyla insan arasındaki çevirmendir. Şamanlar papağanın sesini duyarak ormandaki değişimleri okur.', en: 'The parrot is the interpreter between the plant world and humanity. Shamans read changes in the forest by hearing the parrot\'s voice.' } },
      { culture: { tr: 'Yunan / Roma', en: 'Greek / Roman' }, meaning: { tr: 'Psittacus — Alexander\'ın keşifleriyle Yunanistan\'a giren papağan, antik dünyada fal ve kehanet kuşu sayıldı.', en: 'Psittacus — the parrot that entered Greece with Alexander\'s explorations was considered a divination and oracle bird in the ancient world.' } },
      { culture: { tr: 'Anadolu / Osmanlı', en: 'Anatolian / Ottoman' }, meaning: { tr: 'Osmanlı sarayında papağan konuşturmak sanat sayılırdı; divan edebiyatında papağan, aşk haberini taşıyan elçidir.', en: 'In the Ottoman palace, teaching a parrot to speak was considered an art; in divan literature the parrot is the messenger carrying the news of love.' } },
    ],
    myths: [
      { tr: 'Rumi\'nin Mesnevi\'sinde bir tüccarın Hindistan\'a giden arkadaşına papağanı selamlattırmasını ister. Tüccar mesajı iletir; papağanlar yere düşüp ölür. Tüccar eve döner, kendi papağanı da ölü numarası yapar. Sonra uçar gider — özgürlük, ölmesini bilmekten geçer.', en: 'In Rumi\'s Masnavi, a merchant asks a friend traveling to India to greet the parrots on his behalf. The friend delivers the message; the parrots fall and die. The merchant returns home, and his own parrot plays dead. Then it flies away — freedom passes through knowing how to die.' },
      { tr: 'Hint geleneğinde Shuka, anne karnındayken Vişnu\'nun hikâyelerini işitip doğmamayı tercih eder — dünya kirletir. On iki yıl sonra doğar ve tüm kutsal bilgiyi hafızasında taşır. Sesin hafızası, bedenin hafızasından güçlüdür.', en: 'In Indian tradition, Shuka hears the stories of Vishnu while still in the womb and chooses not to be born — the world would corrupt him. After twelve years he is born and carries all sacred knowledge in his memory. The memory of voice is stronger than the memory of the body.' },
    ],
  },

  // ─── a069 Bizon ─────────────────────────────────────────────────────────
  a069: {
    jung: { tr: '"Kutsal Bereket" ve "Topluluk Ruhu" arketipi. Bizon, Jung\'un kolektif bilinçdışında yükselen "Büyük Anne" figürünün en güçlü eril karşılığıdır — toprağın vericiliği, toplulukla paylaşımın kutsallığı. Bireyin toprakla, toplumla ve evrenin cömertliğiyle bütünleşmesini temsil eder.', en: 'The "Sacred Abundance" and "Community Spirit" archetype. The bison is the most powerful masculine counterpart of the "Great Mother" figure rising in Jung\'s collective unconscious — the generosity of the earth, the sanctity of sharing within community. It represents the individual\'s integration with earth, community, and the generosity of the universe.' },
    dream: { tr: 'Bizon rüyanda sürü halinde koşuyorsa — büyük bir güç geliyor, toprak gibi sağlam dur. Tek başınaysa ve sana bakıyorsa: topluluğuna geri dön, yalnızlık bu dönem sana hizmet etmiyor. Seninle birlikte yürüyorsa: doğru yoldasın, minnettarlığı unutma.', en: 'If bison run in a herd in your dream — great power is coming, stand firm as the earth. If it is alone and looks at you: return to your community, solitude does not serve you in this period. If it walks alongside you: you are on the right path, do not forget gratitude.' },
    shadow: { tr: 'Bereket içinde vurdumduymazlık — minnetsiz tüketim, topluluğa katkısız alma. Öte yanda: sürü zihniyeti, bireyin kolektif baskı altında ezilmesi ve kör itaat.', en: 'Indifference within abundance — ungrateful consumption, taking without contributing to the community. On the other side: herd mentality, the individual crushed under collective pressure, and blind obedience.' },
    whenAppears: { tr: 'Minnettarlıktan koptuğun dönemlerde, topluluğunla ilişkinin yeniden kurulması gerektiğinde ya da refahın kaynağını sorguladığında.', en: 'In periods when you have disconnected from gratitude, when your relationship with your community needs to be rebuilt, or when you question the source of your wellbeing.' },
    traditions: [
      { culture: { tr: 'Lakota / Siyu (Kuzey Amerika Yerlileri)', en: 'Lakota / Sioux (Native North American)' }, meaning: { tr: 'Tatanka Oyate — Bizon Halkı. Kutsal Beyaz Bufalo İneği efsanesi: Wakan Tanka\'nın mesajını getiren kutsal kadın, barış pipasını ve yaşam öğretilerini getirir.', en: 'Tatanka Oyate — the Buffalo Nation. The legend of the White Buffalo Calf Woman: the sacred woman who brings Wakan Tanka\'s message, carrying the peace pipe and life teachings.' } },
      { culture: { tr: 'Kuzey Amerika (Blackfoot)', en: 'North American (Blackfoot)' }, meaning: { tr: 'Bizon, kutsal bir antlaşmanın simgesidir — hayvan kendini verir, insan şükranla alır. Bu döngü bozulursa hem hayvan hem insan yok olur.', en: 'The bison is a symbol of a sacred covenant — the animal gives itself, the human receives with gratitude. If this cycle is broken, both animal and human are destroyed.' } },
      { culture: { tr: 'Tibet / Budizm', en: 'Tibetan / Buddhism' }, meaning: { tr: 'Yak (bizonun kutsal akrabası) — Himalaya\'da yaşamı mümkün kılan kutsal varlık. Tanrıların arabasını çektiğine inanılır.', en: 'The yak (the sacred relative of the bison) — the sacred being that makes life possible in the Himalayas. It is believed to pull the chariot of the gods.' } },
      { culture: { tr: 'Anadolu / Neolitik', en: 'Anatolian / Neolithic' }, meaning: { tr: 'Çatalhöyük\'te boğa kafatasları tapınakları süslüyor — toprağın bereketini temsil eden kutsal hayvan imgesi. Bizonun Anadolu kökenli kardeşi.', en: 'At Çatalhöyük, bull skulls adorn shrines — the image of the sacred animal representing the earth\'s abundance. The Anatolian cousin of the bison.' } },
      { culture: { tr: 'Sümer / Mezopotamya', en: 'Sumerian / Mesopotamian' }, meaning: { tr: 'Gugalanna — gökyüzü boğası. Gilgamış destanında yeraltı tanrıçası İnanna\'nın eski eşi. Toprak gücünün kozmik boyutu.', en: 'Gugalanna — the Bull of Heaven. In the Gilgamesh epic, the ancient husband of the underworld goddess Inanna. The cosmic dimension of earthly power.' } },
    ],
    myths: [
      { tr: 'Lakota söylencesinde Kutsal Beyaz Bufalo İneği iki avcıya görünür. Biri açgözlü bakışlarla bakınca toz olup uçar; öteki saygıyla eğilir. Kadın barış piposunu ve minnettarlık öğretilerini getirir. Bereket, saygıyla gelir — açgözlülükle değil.', en: 'In Lakota legend, the White Buffalo Calf Woman appears to two hunters. When one looks at her with greedy eyes he turns to dust; the other bows with reverence. The woman brings the peace pipe and the teachings of gratitude. Abundance comes with respect — not with greed.' },
      { tr: 'Kuzey Amerika düzlüklerinde milyonlarca bizon yaşardı; Yerli halklar her avdan önce dua eder, her parçasını kullanır ve hiçbir şeyi çöpe atmazlardı. Avrupalıların gelişiyle bizonlar soykırıma uğradı — ve halklar açlığa. Topluluk ile doğa arasındaki kutsal sözleşmenin ihlali, her şeyi çökertti.', en: 'Millions of bison once lived on the North American plains; Indigenous peoples prayed before each hunt, used every part, and wasted nothing. With the arrival of Europeans the bison were subjected to genocide — and the peoples to starvation. The violation of the sacred covenant between community and nature collapsed everything.' },
    ],
  },

  // ─── a070 Kanguru ────────────────────────────────────────────────────────
  a070: {
    jung: { tr: '"İleri Atılış" ve "Cesur Sıçrama" arketipi. Kanguru geriye gidemez — anatomisi bunu engeller. Bu biyo-sembolik gerçek, Jung\'un "geleceğe yönelme" ilkesini cisimleştirir: geçmişe dönüş yoktur, yalnızca ileri gidilir. Keseyi — hem korumayı hem de yeni hayatı taşımayı — aynı anda yapabilmek, olgunluğun sembolüdür.', en: 'The "Leap Forward" and "Courageous Bound" archetype. The kangaroo cannot move backward — its anatomy prevents it. This bio-symbolic truth embodies Jung\'s principle of "future-orientation": there is no return to the past, only forward movement. Being able to carry the pouch — both protection and new life — at the same time is a symbol of maturity.' },
    dream: { tr: 'Kanguru rüyanda zıplayıp gidiyorsa — geçmişe bakma, hareket et. Kesesinde yavru taşıyorsa: hem kendi hayatını hem de bir başkasının (fikir, proje, çocuk) hayatını koruyorsun. Saldırıyorsa: atılmaktan kaçındığın o karar artık seni zoruyor.', en: 'If the kangaroo leaps away in a dream — do not look back, move. If it carries a joey in its pouch: you are protecting both your own life and another\'s (an idea, a project, a child). If it attacks: that decision you have been avoiding leaping into is now pressing you.' },
    shadow: { tr: 'Sürekli sıçramak — bir şeyden diğerine geçerek hiçbirini tamamlamamak, sabırsızlık. Öte yanda: ilerlemenin zorluğu karşısında donmak, geriye gidemezken önüne de adım atamamak — varoluşsal felç.', en: 'Constantly leaping — passing from one thing to another without completing any of them, impatience. On the other side: freezing before the difficulty of progress, unable to move backward yet unable to step forward either — existential paralysis.' },
    whenAppears: { tr: 'Büyük bir değişimin eşiğinde, geçmişe bağlılığın ilerlemeni engellediği dönemde ya da hem kendin hem de bir şeyi (proje, çocuk, vizyon) taşıma sorumluluğunu üstlendiğinde.', en: 'On the threshold of a major change, in a period when attachment to the past is blocking your progress, or when you take on the responsibility of carrying both yourself and something else (a project, a child, a vision).' },
    traditions: [
      { culture: { tr: 'Avustralya Yerlileri / Aborijin', en: 'Australian Aboriginal' }, meaning: { tr: 'Kanguru, Rüya Zamanı\'nın (Dreamtime) kutsal yaratığıdır. Totem olarak onun enerjisini taşıyan klan, ileri görüşlülük ve aile koruyuculuğuyla anılır.', en: 'The kangaroo is a sacred creature of the Dreamtime. The clan that carries its energy as totem is known for foresight and protection of the family.' } },
      { culture: { tr: 'Aborijin (Batı Avustralya)', en: 'Aboriginal (Western Australia)' }, meaning: { tr: 'Kanguru derisi, törensel giysilerin en değerlisi sayılırdı. Dansçılar kanguru hareketlerini taklit ederek bereket ve ileri atılış ruhunu çağırırdı.', en: 'Kangaroo skin was considered the most precious of ceremonial garments. Dancers imitated kangaroo movements to invoke the spirit of abundance and forward momentum.' } },
      { culture: { tr: 'Avustralya (Aranda / Arrernte)', en: 'Australian (Aranda / Arrernte)' }, meaning: { tr: 'Kanguru Atası Rüya Zamanı\'nda yeryüzünü şekillendirmiştir; izlediği yollar kutsal toprak hatlarını (songlines) oluşturur.', en: 'The Kangaroo Ancestor shaped the earth during Dreamtime; the paths it travelled form the sacred land lines (songlines).' } },
      { culture: { tr: 'Çağdaş / Evrensel Sembol', en: 'Contemporary / Universal Symbol' }, meaning: { tr: 'Avustralya armasındaki kanguru — sadece ileri gidebilen hayvan. Ulusun "daima ileriye" felsefesinin simgesi.', en: 'The kangaroo on the Australian coat of arms — an animal that can only move forward. Symbol of the nation\'s philosophy of "always forward".' } },
      { culture: { tr: 'Anadolu / Halk Söylemi', en: 'Anatolian / Folk Saying' }, meaning: { tr: '"Geriye dönme, will" deyiminin cisimleşmiş hali — kanguru Anadolu\'da tanınmasa da ileri atılış cesareti "yiğit" kavramıyla örtüşür.', en: 'The embodied form of the saying "do not look back" — though the kangaroo is not native to Anatolia, the courage of leaping forward aligns with the concept of "yiğit" (the valiant).' } },
    ],
    myths: [
      { tr: 'Aborijin Rüya Zamanı\'nda Büyük Kanguru Atası kıtanın dört bir yanını zıplayarak geçti ve her ayak basışında bir nehir, her duruşunda bir dağ oluştu. Yolculuk bitmedi — hâlâ devam ediyor. Kanguru totemini taşıyan ruh bu sonsuz yolculuğun bir parçasıdır.', en: 'In the Aboriginal Dreamtime, the Great Kangaroo Ancestor leapt across the continent in every direction, and at each footfall a river formed, at each pause a mountain rose. The journey did not end — it continues still. The soul that carries the kangaroo totem is part of this endless journey.' },
      { tr: 'Arrernte söylencesinde kanguru, tanrıların çocuklara verdiği hediyeyi kesesinde taşıdı. Yıllarca zıpladı, bıkmadı, teslim olmadı. Kese her sarsıntıda sıkılaştı ama yavru zarar görmedi. Korumak ile ilerlemek — birbirini engellemez, birbirini tamamlar.', en: 'In Arrernte legend the kangaroo carried the gift the gods gave to the children in its pouch. For years it leapt, never tired, never surrendered. The pouch tightened with every jolt but the joey was unharmed. Protecting and moving forward — they do not hinder each other, they complete each other.' },
    ],
  },

  // ─── a071 Ren Geyiği ────────────────────────────────────────────────────
  a071: {
    jung: { tr: '"Şaman Yolcusu" arketipi. İki dünya arasında köprü kuran, görünür ile görünmez arasında gezinen bilinç. Ren Geyiği antleri gök ile yeri birleştirir — bu enerji, sıradan yaşamı kutsal bir yolculuğa dönüştürme çağrısıdır.', en: 'The "Shaman Traveler" archetype. A consciousness that bridges two worlds, wandering between the visible and the invisible. The reindeer\'s antlers join sky to earth — this energy is a call to transform ordinary life into a sacred journey.' },
    dream: { tr: 'Ren Geyiği rüyada — atalar seni çağırıyor, köklere dön. Karlı bir ormanda yürüyorsa: zorlu bir yolu yalnız ama rehberli geçiyorsun. Seninle konuşuyorsa: bilinçdışından gelen mesaj yakın, susarak dinle.', en: 'Reindeer in dream — the ancestors call you, return to your roots. If it walks through a snowy forest: you are crossing a difficult path alone but guided. If it speaks to you: a message from the unconscious is near, listen in silence.' },
    shadow: { tr: 'Sürekli öteki dünyalara kaçış, buradaki sorumluluklardan ruhsallık kisvesi altında sıyrılma. Köksüzlük ve aşiret bağlarının ihmal edilmesi — rehber olmak için önce yerde durabilmek gerekir.', en: 'Constant escape into other realms, evading responsibilities here under the guise of spirituality. Rootlessness and neglect of ancestral bonds — to be a guide, one must first be able to stand on the ground.' },
    whenAppears: { tr: 'Aile ve köken sorularının yoğunlaştığı dönemlerde, şamanik ya da spiritüel bir çağrı hissedildiğinde, uzun bir yolculuğun eşiğinde.', en: 'During periods when questions of family and origin intensify, when a shamanic or spiritual calling is felt, on the threshold of a long journey.' },
    traditions: [
      { culture: { tr: 'Sibirya Şamanizmi', en: 'Siberian Shamanism' }, meaning: { tr: 'Ren Geyiği şamanın ruhu olarak kabul edilir; kurban ritüellerinde şamanı öteki dünyaya taşıyan kutsal araçtır.', en: 'Reindeer is regarded as the shaman\'s spirit; in sacrifice rituals it is the sacred vehicle that carries the shaman to the other world.' } },
      { culture: { tr: 'Sami (İskandinav) Geleneği', en: 'Sámi (Scandinavian) Tradition' }, meaning: { tr: 'Ren sürüleri kutsal yaşamın merkezi sayılır; geyiğin yönü kehanet için okunur, her hayvanın bir ruhu olduğuna inanılır.', en: 'Reindeer herds are considered the centre of sacred life; the animal\'s direction is read for divination, and every reindeer is believed to have a spirit.' } },
      { culture: { tr: 'Kuzey Amerika Yerli Gelenekleri', en: 'North American Indigenous Traditions' }, meaning: { tr: 'Caribou — Büyük Yolculuğun sembolü. Göç eden sürüler mevsimin döngüsünü ve yaşamın devamlılığını temsil eder.', en: 'Caribou — symbol of the Great Journey. The migrating herds represent the cycle of seasons and the continuity of life.' } },
      { culture: { tr: 'Moğol Geleneği', en: 'Mongolian Tradition' }, meaning: { tr: 'Gök Geyiği, Tengri\'nin habercisidir; antleri yıldız haritasına benzetilir ve kozmik düzeni simgeler.', en: 'The Celestial Deer is the messenger of Tengri; its antlers are likened to a star map and symbolize the cosmic order.' } },
      { culture: { tr: 'Fin-Ugor Mitolojisi', en: 'Finno-Ugric Mythology' }, meaning: { tr: 'Ilmatar\'ın geyiği ölüm ile yaşam arasındaki sınırı korur; şamanlar onu çağırarak ruh yolculuğuna çıkar.', en: 'The deer of Ilmatar guards the boundary between death and life; shamans call upon it to embark on soul journeys.' } },
    ],
    myths: [
      { tr: 'Sibirya\'nın Evenk halkı anlatır: Zamanın başında Büyük Geyiği, güneşi her sabah boynuzlarıyla gökyüzüne taşırdı. Bir gün avcı onu vurdu — güneş düştü. Şaman, geyiğin ruhunu bulup özür diledi; geyik güneşi yerine koydu. O günden beri şamanlar "güneşi geri getiren insanlar" olarak anılır.', en: 'The Evenk people of Siberia tell: at the beginning of time, the Great Reindeer carried the sun into the sky each morning on its antlers. One day a hunter shot it — the sun fell. The shaman found the reindeer\'s spirit and asked forgiveness; the reindeer restored the sun. Since then shamans are known as "the people who bring back the sun".' },
      { tr: 'Sami geleneğinde, beyaz bir ren geyiği görülmesi ataların mesaj gönderdiğinin işaretidir. O geyiği takip eden kişi, yaşayanlar ile ölüler arasındaki nehre ulaşır; orada bir soru sormak için tek bir nefes hakkı vardır.', en: 'In Sámi tradition, seeing a white reindeer is a sign that the ancestors are sending a message. The person who follows that reindeer reaches the river between the living and the dead; there one has the right to ask a single question in a single breath.' },
    ],
  },

  // ─── a072 Kirpi ─────────────────────────────────────────────────────────
  a072: {
    jung: { tr: '"İçe Dönük Bilge" arketipi. Dışarıya diken gösteren ama içi yumuşak olan bu varlık, savunma ile kırılganlığın bir arada yaşayabileceğini öğretir. Kirpi enerjisi, sınır koymanın şiddete değil, özün korunmasına hizmet ettiğini hatırlatır.', en: 'The "Introverted Sage" archetype. This creature that shows spines outward but is soft within teaches that defense and vulnerability can coexist. Hedgehog energy reminds us that boundary-setting serves not violence but the protection of the core.' },
    dream: { tr: 'Kirpi rüyada — korunmaya ihtiyacın var, ama dikenlerin seni de hapsediyor olabilir. Diken açıyorsa: bir tehdit hissediyorsun, gerçek mi değerlendirmelisin. Top olmuş yatıyorsa: içine çekilmek seni güvende tutmuyor, açılma zamanı.', en: 'Hedgehog in dream — you need protection, but your spines may be imprisoning you too. If it raises its spines: you sense a threat, ask whether it is real. If it lies curled up: withdrawing into yourself is not keeping you safe, it is time to open up.' },
    shadow: { tr: 'Aşırı savunmacılık ve güvensizliğin kronikleşmesi. Her yakınlaşmada diken açmak, sevgiyi bile tehdit olarak algılamak — kirpi enerjisinin gölgesi, kalıcı yalnızlığa ve duygusal donukluğa yol açar.', en: 'Excessive defensiveness and the chronic calcification of distrust. Raising spines at every approach, perceiving even love as a threat — the shadow of hedgehog energy leads to permanent isolation and emotional numbness.' },
    whenAppears: { tr: 'Duygusal yaralanma sonrası kapanma dönemlerinde, sınırları öğrenme ya da sınırları çözme sürecinde, uzun bir içe dönüklüğün ardından dünyaya adım atma eşiğinde.', en: 'During periods of withdrawal after emotional wounding, in the process of learning or dissolving boundaries, on the threshold of stepping back into the world after long introversion.' },
    traditions: [
      { culture: { tr: 'Anadolu Halk Geleneği', en: 'Anatolian Folk Tradition' }, meaning: { tr: 'Kirpi, "dağın akıllısı" olarak bilinir; tıbbi bitkileri bulduğuna, yaralı insanlara gece yol gösterdiğine inanılır.', en: 'The hedgehog is known as "the wise one of the mountain"; it is believed to find medicinal plants and guide wounded people at night.' } },
      { culture: { tr: 'Mısır Mitolojisi', en: 'Egyptian Mythology' }, meaning: { tr: 'Kirpi, ölüm ve yeniden doğuşun sembolüdür; lahit kaplarına kazınmış betimlemeler ruhun korunmasına adanmıştır.', en: 'The hedgehog is a symbol of death and rebirth; depictions carved on canopic jars are dedicated to the protection of the soul.' } },
      { culture: { tr: 'İran-Zerdüşt Geleneği', en: 'Iranian-Zoroastrian Tradition' }, meaning: { tr: 'Avesta\'da kirpi kutsal sayılır; Ehriman\'ın yaratıklarına karşı dünyanın savunucusu olarak betimlenmiştir.', en: 'In the Avesta the hedgehog is considered sacred; it is described as a defender of the world against the creatures of Ahriman.' } },
      { culture: { tr: 'Kelt Geleneği', en: 'Celtic Tradition' }, meaning: { tr: 'Kirpi, yer altının habercisidir; toprağın sırlarını bilen, geceleri büyü alanlarında dolaşan varlık olarak anılır.', en: 'The hedgehog is the herald of the underworld; it is mentioned as a being that knows the secrets of the earth and wanders the magical fields at night.' } },
      { culture: { tr: 'Afrika (Hausa) Geleneği', en: 'African (Hausa) Tradition' }, meaning: { tr: 'Kirpi hikayelerde zekâ ve hayatta kalma ustasıdır; büyük hayvanları kurnazlıkla alt eden küçük ama yenilmez kahraman.', en: 'In Hausa stories the hedgehog is a master of intelligence and survival; the small but invincible hero who outwits great animals through cunning.' } },
    ],
    myths: [
      { tr: 'Eski Mısır\'da anlatılır: Kirpi, Ra\'nın güneş kayığına her gece binen ve sabah güneşin yeniden doğmasını sağlayan koruyucuydu. Dikenleri karanlığın oklarını geri yansıtır, yumuşak karnı ise sabahın ışığını taşır.', en: 'As told in ancient Egypt: the hedgehog was the guardian who boarded Ra\'s solar boat each night and ensured the sun was reborn each morning. Its spines reflect the arrows of darkness back, while its soft belly carries the light of dawn.' },
      { tr: 'Anadolu\'da anlatılan bir masalda kirpi, padişahın bahçesinden meyve çalan bir hırsızı fark eder. Padişaha söylemek için saraya gider ama kimse onu dikkate almaz. Kirpi, hırsızı kendi başına dikenlerine takarak tutar — o günden beri "küçük ama söz dinletebilen" olarak saygı görür.', en: 'In an Anatolian tale, the hedgehog notices a thief stealing fruit from the sultan\'s garden. It goes to the palace to tell the sultan, but no one heeds it. The hedgehog catches the thief alone by snagging him on its spines — from that day it is respected as "small but able to make itself heard".' },
    ],
  },

  // ─── a073 Kertenkele ─────────────────────────────────────────────────────
  a073: {
    jung: { tr: '"Rüya Görücü" arketipi. Kertenkele güneşte hareketsiz beklerken bile içi kaynar — bu enerji, görünür eylemsizlik içinde yoğun iç işlem gücünü simgeler. Bilinçdışının mesajlarını yakalamak için önce ısınmak, yani hazırlanmak gerekir.', en: 'The "Dreamer" archetype. While the lizard waits motionless in the sun its interior seethes — this energy symbolises intense inner processing within apparent stillness. To catch the messages of the unconscious, one must first warm up, that is, prepare.' },
    dream: { tr: 'Kertenkele rüyada — hızlı bir karar gerekiyor ya da hızla geri çekilmek gerekiyor. Kuyruğunu bırakıyorsa: bir parçandan vazgeç, hayatta kalmak daha önemli. Güneşte yatıyorsa: enerjini yenilemeden harekete geçme.', en: 'Lizard in dream — a swift decision is needed, or a swift retreat. If it drops its tail: let go of a part of yourself, survival matters more. If it basks in the sun: do not act before renewing your energy.' },
    shadow: { tr: 'Adaptasyonun yüzeyselleşmesi — her ortama uyum sağlayan ama hiçbirine kök atmayan kaypak kişilik. Isı peşinde koşmak, yani onay ve ilgi bağımlılığı da kertenkelenin gölgesidir.', en: 'Adaptation becoming superficial — the slippery personality that adjusts to every environment but takes root in none. Chasing warmth, meaning addiction to approval and attention, is also the shadow of the lizard.' },
    whenAppears: { tr: 'Hızlı değişen koşullarda esneklik çağrısı geldiğinde, rüyalardan gelen sinyallerin güçlendiği dönemlerde, güneşe ve yaşam enerjisine yeniden bağlanma ihtiyacında.', en: 'When the call for flexibility arises in rapidly changing conditions, during periods when signals from dreams intensify, in the need to reconnect with the sun and life energy.' },
    traditions: [
      { culture: { tr: 'Aborijin (Avustralya)', en: 'Aboriginal (Australian)' }, meaning: { tr: 'Gökkuşağı kertenkele, Rüya Zamanı\'nın koruyucusudur; toprağın altındaki su damarlarını bildiği için kurak mevsimlerde rehber kabul edilir.', en: 'The rainbow lizard is the guardian of Dreamtime; knowing the water veins beneath the earth, it is considered a guide in dry seasons.' } },
      { culture: { tr: 'Mısır Mitolojisi', en: 'Egyptian Mythology' }, meaning: { tr: 'Kertenkele hiyerogliflerinde "bol olan" anlamına gelir; bereket ve güneş ışığının taşıyıcısı olarak kapılara kazınmıştır.', en: 'In Egyptian hieroglyphs the lizard means "that which is abundant"; it is carved on doorways as a bearer of fertility and sunlight.' } },
      { culture: { tr: 'Aztek Geleneği', en: 'Aztec Tradition' }, meaning: { tr: 'Cipactli — deniz canavarı kertenkele — dünyanın yaratıldığı ilk varlıktır; hem kaos hem zemin, hem yıkım hem temel.', en: 'Cipactli — the sea-monster lizard — is the first being from which the world was created; both chaos and ground, both destruction and foundation.' } },
      { culture: { tr: 'Yunan-Roma Geleneği', en: 'Greco-Roman Tradition' }, meaning: { tr: 'Kertenkele Apollon\'un kutsal hayvanıdır; güneş tanrısının yanında uyuyarak kehanet rüyaları gördüğüne inanılır.', en: 'The lizard is the sacred animal of Apollo; it is believed to sleep beside the sun god and receive prophetic dreams.' } },
      { culture: { tr: 'Güney Afrika Zulu Geleneği', en: 'South African Zulu Tradition' }, meaning: { tr: 'Kertenkele, atalardan gelen mesajları yaşayanlara ileten ruh habercisidir; evin içine girerse şans, dışarı çıkarılırsa keder getirir.', en: 'The lizard is a spirit messenger conveying ancestral messages to the living; if it enters the house it brings luck, if driven out it brings sorrow.' } },
    ],
    myths: [
      { tr: 'Navajo geleneğinde anlatılır: Yaratılışın başında kertenkele, güneşin nasıl tutulacağını bilmeyen insanlara öğretti. "Önce onu gözlemle, sonra onunla otur, sonra ondan öğren" dedi. Bu yüzden Navajo şamanları hâlâ kertenkele pozisyonunda — yere uzanarak, güneşe dönerek — rüya alırlar.', en: 'As told in Navajo tradition: at the beginning of creation, the lizard taught humans who did not know how to receive the sun. "First observe it, then sit with it, then learn from it," it said. That is why Navajo shamans still receive dreams in the lizard position — lying on the ground, turned toward the sun.' },
      { tr: 'Eski Yunan\'da Apollon\'un tapınağında yaşayan bir kertenkele vardı. Tapınağa giren herkes ona bir soru sorardı; kertenkele uyursa "evet", kaçarsa "henüz değil" anlamına gelirdi. Delphi kahininden önce, kertenkele insanlığın ilk kehanet aracıydı.', en: 'In ancient Greece there lived a lizard in Apollo\'s temple. Everyone who entered the temple would ask it a question; if the lizard slept it meant "yes", if it fled it meant "not yet". Before the oracle of Delphi, the lizard was humanity\'s first tool of divination.' },
    ],
  },

  // ─── a074 Koç ────────────────────────────────────────────────────────────
  a074: {
    jung: { tr: '"İlahi Öncü" arketipi. Kendi başını taşla dövmekten korkmayan lider — bu enerji, dünyayı değiştirmek için önce kendi içinde yıkım-yaratım döngüsünü yaşayan bilinçtir. Koç, ateşten doğar ve ateşe döner; her yeni başlangıç bir yanmayı gerektirir.', en: 'The "Divine Pioneer" archetype. The leader who is not afraid to strike its own head against stone — this energy is a consciousness that lives the cycle of destruction-creation within itself before changing the world. The ram is born of fire and returns to fire; every new beginning requires a burning.' },
    dream: { tr: 'Koç rüyada — ilerleme zamanı, duraksama lüksün yok. Sana koşuyorsa: içindeki güç seni zorluyor, kendi potansiyelinden kaçıyorsun. Başını taşa vuruyorsa: engelin gerçek olmayabilir, sadece ısrar gerektiriyor.', en: 'Ram in dream — it is time to advance, you have no luxury of hesitation. If it charges at you: the power within is pushing you, you are fleeing your own potential. If it butts its head against stone: the obstacle may not be real, it simply requires persistence.' },
    shadow: { tr: 'Düşünmeden öne atılma ve başkalarını ezmek pahasına ilerleme. Koç enerjisinin gölgesi, ego savaşlarına dönüşen liderlik isteğidir — "ben açarım" yerini "ben geçerim" alır ve güç tahakküme kaymaya başlar.', en: 'Rushing forward without thought and advancing at the cost of trampling others. The shadow of ram energy is the desire to lead that turns into ego battles — "I will open the way" is replaced by "I will get past" and power begins to slide into domination.' },
    whenAppears: { tr: 'Yeni bir girişimin başladığı dönemlerde, liderlik rolü üstlenme ya da reddetme krizlerinde, bir kapıyı zorla açmak gerektiği anda.', en: 'During periods when a new venture begins, in crises of taking on or refusing a leadership role, at the moment when a door must be forced open.' },
    traditions: [
      { culture: { tr: 'Mezopotamya', en: 'Mesopotamia' }, meaning: { tr: 'Koç, Ea/Enki\'nin kutsal hayvanıdır; boynuzları yaratıcı bilgeliği, güçlü bedeni ise ilahi iradeyi simgeler.', en: 'The ram is the sacred animal of Ea/Enki; its horns symbolise creative wisdom and its powerful body the divine will.' } },
      { culture: { tr: 'Mısır Mitolojisi', en: 'Egyptian Mythology' }, meaning: { tr: 'Amun, koç başlı tanrı — "gizli olan" anlamına gelir. Yaratıcı güneş enerjisini ve evrensel bereket gücünü taşır.', en: 'Amun, the ram-headed god — means "the hidden one". He carries the creative solar energy and the force of universal abundance.' } },
      { culture: { tr: 'Yunan Mitolojisi', en: 'Greek Mythology' }, meaning: { tr: 'Altın Post\'un koçu, Aries burcu olarak gökyüzüne yerleştirilmiştir; ilkbaharın ve yeni başlangıçların habercisidir.', en: 'The ram of the Golden Fleece is placed in the sky as the constellation Aries; it is the herald of spring and new beginnings.' } },
      { culture: { tr: 'Anadolu (Hitit)', en: 'Anatolian (Hittite)' }, meaning: { tr: 'Fırtına tanrısı Tarhunna\'nın kurban törenlerinde koç baş tacı takar; bereketin ve ilahi ateşin taşıyıcısıdır.', en: 'In the sacrificial rites of the storm god Tarhunna the ram wears the crown; it is the bearer of fertility and divine fire.' } },
      { culture: { tr: 'İslam Geleneği', en: 'Islamic Tradition' }, meaning: { tr: 'Hz. İbrahim\'in kurban anlatısında koç, teslimiyet ve ilahi merhametin simgesidir; en yüce adanmışlığın ödülü olarak cennetten gönderilmiştir.', en: 'In the narrative of Ibrahim\'s sacrifice the ram is the symbol of submission and divine mercy; sent from paradise as the reward of supreme devotion.' } },
    ],
    myths: [
      { tr: 'Yunan mitolojisinde altın postu olan koç, Helle ile Phrixus\'u zalim üvey annelerinden kurtarmak için Poseidon tarafından gönderildi. Helle yolda denize düştü — Hellespont onun adını taşır. Phrixus\'u Kolkhis\'e götüren koç, gökyüzünde Aries olarak ebedileşti. Kurtuluş, her zaman bir kayıp içerir.', en: 'In Greek mythology the golden-fleeced ram was sent by Poseidon to rescue Helle and Phrixus from their cruel stepmother. Helle fell into the sea along the way — the Hellespont bears her name. The ram that carried Phrixus to Colchis was immortalised in the sky as Aries. Salvation always contains a loss.' },
      { tr: 'Türk-Moğol geleneklerinde anlatılır: Gökyüzünün ilk ışığı, bir koçun alnından çıkan aleve benzetilir. Bu yüzden güneşin doğduğu yön "koç yönü" olarak bilinir ve yeni kurulan çadırın kapısı o tarafa açılır.', en: 'As told in Turkic-Mongol traditions: the first light of the sky is likened to the flame that leaps from a ram\'s forehead. That is why the direction from which the sun rises is known as "the direction of the ram" and the door of a newly erected tent opens toward that quarter.' },
    ],
  },

  // ─── a075 Koi Balığı ─────────────────────────────────────────────────────
  a075: {
    jung: { tr: '"Azimli Dönüşümcü" arketipi. Koi, akıntıya karşı yüzer — bu enerji, zorluğu başarısızlığın değil büyümenin işareti olarak okuyan bilinçtir. Su içinde ateş gibi parlar; dönüşümün enerjisi ne elemental sınıra ne de zamana boyun eğer.', en: 'The "Resolute Transformer" archetype. The koi swims against the current — this energy is a consciousness that reads difficulty as a sign not of failure but of growth. It glitters like fire within water; the energy of transformation bows neither to elemental boundaries nor to time.' },
    dream: { tr: 'Koi rüyada — azmin ödüllendirileceği bir süreçtesin, bırakma. Suyun tersine yüzüyorsa: direniş doğru yoldasın demek, pes etme. Altın rengi parlıyorsa: bereket ve kabul kapıdadır, hazır ol.', en: 'Koi in dream — you are in a process where persistence will be rewarded, do not give up. If it swims against the current: resistance means you are on the right path, do not surrender. If its golden colour gleams: abundance and acceptance are at the door, be ready.' },
    shadow: { tr: 'İnatçılığın körü körüne sürdürülmesi, değişmesi gereken bir şeye tutunmak. Koi enerjisinin gölgesi, akıntıya direncin ne zaman bilgelik ne zaman ego olduğunu ayırt edememektir.', en: 'Persisting blindly in stubbornness, clinging to something that needs to change. The shadow of koi energy is the inability to discern when resistance to the current is wisdom and when it is ego.' },
    whenAppears: { tr: 'Uzun süredir çalışılan bir hedefin sonuçlanmadığı dönemlerde, vazgeçme ile sebat arasındaki kararda, bereket ve büyüme için sabır gerektiren eşiklerde.', en: 'During periods when a long-pursued goal has not yet borne fruit, at the decision between giving up and persisting, on thresholds that require patience for abundance and growth.' },
    traditions: [
      { culture: { tr: 'Çin Geleneği', en: 'Chinese Tradition' }, meaning: { tr: 'Koi — "li yu" — Sarı Nehir\'in şelalelerini aşan balık ejderhaya dönüşür; bu mit akademik başarının ve mesleki yükselişin sembolüdür.', en: 'Koi — "li yu" — the fish that surmounts the falls of the Yellow River transforms into a dragon; this myth is the symbol of academic success and professional advancement.' } },
      { culture: { tr: 'Japon Geleneği', en: 'Japanese Tradition' }, meaning: { tr: 'Koi, "nishikigoi" — samuray cesaretinin simgesi. Yakalandığında oltayı kesmez, kılıç darbesi bekler — bu soğukkanlılık erdem sayılır.', en: 'Koi, "nishikigoi" — symbol of samurai courage. When caught it does not thrash, it awaits the sword stroke — this composure is considered a virtue.' } },
      { culture: { tr: 'Kore Geleneği', en: 'Korean Tradition' }, meaning: { tr: 'Koi, han ile hüznü aşan ruhun simgesidir; uzun ömür ve ata bağlılığı için havuzlarda kutsal kabul edilir.', en: 'Koi is the symbol of the spirit that transcends han and sorrow; it is regarded as sacred in ponds for longevity and ancestral devotion.' } },
      { culture: { tr: 'Feng Shui Geleneği', en: 'Feng Shui Tradition' }, meaning: { tr: 'Dokuz koi, bolluğun zirvesidir; dokuz "nian nian you yu" — "her yıl artık" demektir. Havuzun yönü ve balık sayısı enerji akışını belirler.', en: 'Nine koi represent the peak of abundance; nine "nian nian you yu" means "ever more each year". The direction of the pond and the number of fish determine the flow of energy.' } },
      { culture: { tr: 'Budist Gelenek', en: 'Buddhist Tradition' }, meaning: { tr: 'Koi, acıdan özgürleşen ruhun simgesidir; suyun içinde özgürce yüzmek, saṃsāra\'nın akıntısına kapılmadan var olmaktır.', en: 'Koi is the symbol of the soul freed from suffering; to swim freely within the water is to exist without being swept away by the current of saṃsāra.' } },
    ],
    myths: [
      { tr: 'Çin\'in en ünlü efsanelerinden biri: Sarı Nehir\'in yukarısında, ejderha kapısı denen çağlayanlar vardır. Her bahar pek çok koi bu çağlayanları aşmaya çalışır; çoğu döner, geri çekilir. Ama her bin yılda bir, bir koi aşar. O an gökler açılır, ejderha kapısından geçen balık altın ejderhaya dönüşür ve gökyüzüne çıkar. Bu yüzden "kapıyı aşan balık" ifadesi Çincede büyük bir başarının simgesidir.', en: 'One of China\'s most celebrated legends: above the Yellow River there are rapids called the Dragon Gate. Each spring many koi attempt to ascend these rapids; most turn back, retreat. But once every thousand years, one koi succeeds. At that moment the heavens open, the fish that passes through the dragon gate transforms into a golden dragon and rises into the sky. That is why the expression "the fish that passes the gate" is in Chinese a symbol of great achievement.' },
      { tr: 'Japon anlatısında, bir samuray ölmeden önce havuzundaki en yaşlı koi\'ye son dileğini fısıldar. Koi bir kez kuyruğunu çarpar ve dalar — samurayın ailesi, o gece koi\'nin rüyalarında samurayın sesini duyar. Koi, iki dünya arasında mesaj taşıyan suya gömülü bir ruh postasıdır.', en: 'In a Japanese tale, before a samurai dies he whispers his last wish to the oldest koi in his pond. The koi slaps its tail once and dives — that night the samurai\'s family hears his voice in their dreams through the koi. The koi is a spiritual postal service embedded in water, carrying messages between two worlds.' },
    ],
  },

  // ─── a076 Bukalemun ──────────────────────────────────────────────────────
  a076: {
    jung: { tr: '"Bağlam Okuyucusu" arketipi. Bukalemun her rengi bilir çünkü hiçbir renge mahkûm değildir — bu enerji, dünyanın çoğulluğunu tehdit olarak değil bilgelik kaynağı olarak kavrayan bilinçtir. Gözler ayrı yönlere bakar, yani her şeyin iki yüzünü aynı anda görmek mümkündür.', en: 'The "Context Reader" archetype. The chameleon knows every colour because it is prisoner to none — this energy is a consciousness that grasps the plurality of the world not as a threat but as a source of wisdom. Its eyes look in separate directions, meaning it is possible to see both sides of everything simultaneously.' },
    dream: { tr: 'Bukalemun rüyada — hangi maskeyi taktığını soruyor. Renk değiştiriyorsa: ortama uyum sağlıyorsun ama kendin neredesin? Sabit duruyorsa: artık saklanmana gerek yok, gerçek rengini gösterme zamanı.', en: 'Chameleon in dream — it is asking which mask you are wearing. If it changes colour: you are adapting to your environment, but where are you yourself? If it stands still: you no longer need to hide, it is time to show your true colour.' },
    shadow: { tr: 'Kendini kaybetme pahasına uyum sağlamak. Bukalemun enerjisinin en derin gölgesi, "gerçek renk" diye bir şeyin kalmadığını hissetmektir — kimlik çözülmesi ve kameleonvari manipülasyon bunun ürünüdür.', en: 'Adapting at the cost of losing oneself. The deepest shadow of chameleon energy is the feeling that there is no such thing as a "true colour" anymore — identity dissolution and chameleonic manipulation are its products.' },
    whenAppears: { tr: 'Yeni bir ortama girişte, birden fazla kimlik arasında sıkışıldığında, gerçek benliğin ile sosyal benliğin arasındaki mesafeyi hissettiğin dönemlerde.', en: 'At entry into a new environment, when caught between multiple identities, during periods when you feel the distance between your true self and your social self.' },
    traditions: [
      { culture: { tr: 'Afrika (Yoruba) Geleneği', en: 'African (Yoruba) Tradition' }, meaning: { tr: 'Bukalemun, Obatala\'nın kutsal hayvanıdır; saflık ve çoğulluğun bir arada var olabileceğini öğretir. Renk değiştirmesi, dünyanın sonsuz katmanlarına tanıklık etmektir.', en: 'The chameleon is the sacred animal of Obatala; it teaches that purity and plurality can coexist. Its colour-changing is a witnessing of the infinite layers of the world.' } },
      { culture: { tr: 'Malagasy (Madagaskar) Geleneği', en: 'Malagasy (Madagascar) Tradition' }, meaning: { tr: 'Bukalemun, atalar ile yaşayanlar arasında habercilir; yavaş yürüyüşü hesaplı olmayı, dört bir yana bakan gözleri ise hiçbir şeyi kaçırmamayı simgeler.', en: 'The chameleon mediates between ancestors and the living; its slow gait symbolises deliberateness, and its eyes looking in all directions symbolise missing nothing.' } },
      { culture: { tr: 'Antik Yunan', en: 'Ancient Greek' }, meaning: { tr: 'Aristoteles bukalemunu renkleri içine çeken değil, kendi içindeki renkleri dışarı vuran bir varlık olarak betimler — bu, öz-yansıtmanın erken bir metaforudur.', en: 'Aristotle describes the chameleon not as a creature that absorbs colours but as one that projects inner colours outward — an early metaphor for self-reflection.' } },
      { culture: { tr: 'Hint Geleneği', en: 'Indian Tradition' }, meaning: { tr: 'Bukalemun, Maya\'nın — yanılsamanın — simgesi olarak Hindu ikonografisinde yer alır; gerçek ile görünen arasındaki perdenin habercisidir.', en: 'The chameleon appears in Hindu iconography as a symbol of Māyā — illusion; it is the herald of the veil between the real and the apparent.' } },
      { culture: { tr: 'Anadolu Halk Anlatısı', en: 'Anatolian Folk Narrative' }, meaning: { tr: 'Halk arasında "yüzü bin türlü" deyimi bukalemundan gelir; hem kötü anlamda (iki yüzlü) hem iyi anlamda (çok boyutlu) kullanılır.', en: 'The popular saying "a thousand faces" derives from the chameleon; it is used both pejoratively (two-faced) and positively (multi-dimensional).' } },
    ],
    myths: [
      { tr: 'Yoruba yaratılış anlatısında, Obatala insanları şekillendirirken bukalemunu gözlemcisi olarak yanına aldı. Bukalemun her insana bakarken renk değiştirdi — kırmızı öfkeyi, beyaz saflığı, yeşil umudu yansıttı. Obatala, "Bu hayvan insanın içini görüyor" dedi ve onu kutsal ilan etti.', en: 'In the Yoruba creation narrative, when Obatala was shaping humans he took the chameleon as his observer. As the chameleon watched each person it changed colour — red reflected anger, white purity, green hope. Obatala said, "This animal sees the interior of humans," and declared it sacred.' },
      { tr: 'Madagaskar\'da anlatılır: Tanrı Zanahary, dünyayı yarattıktan sonra bukalemunu gönderdi — "git, insanlar ölümlü mü olsun ölümsüz mü, anlaşın ve haber ver" dedi. Bukalemun yavaş yürüdü, geç döndü. Tanrı beklemekten usandı ve ölümü zaten koydu. Bukalemunun yavaşlığı, insanlığın ölümlülüğünün nedeni sayılır.', en: 'As told in Madagascar: after creating the world, God Zanahary sent the chameleon — "go, settle whether humans should be mortal or immortal, and bring word." The chameleon walked slowly and returned late. God grew weary of waiting and had already appointed death. The chameleon\'s slowness is considered the reason for human mortality.' },
    ],
  },

  // ─── a077 Porsuk ─────────────────────────────────────────────────────────
  a077: {
    jung: { tr: '"Toprak Koruyucusu" arketipi. Porsuk savaşmaktan çekinmez ama savaşı aramaz — bu enerji, neyin savunulmaya değer olduğunu bilen ve o değer için her şeyi göze alabilen kararlı bilinçtir. Toprağın altındaki kökleri bilmek, yüzeyin geçici gürültüsüne kapılmamaktır.', en: 'The "Earth Guardian" archetype. The badger does not shy from fighting but does not seek it — this energy is a resolute consciousness that knows what is worth defending and is willing to risk everything for that value. Knowing the roots beneath the earth means not being swept away by the transient noise of the surface.' },
    dream: { tr: 'Porsuk rüyada — savaşman gereken bir şey var, çekilme. Ini kazıyorsa: temelleri güçlendirme vakti, derine in. Saldırıyorsa: korktuğun şeyle yüzleş, porsuk gibi dur — geriye adım atmadan.', en: 'Badger in dream — there is something you must fight for, do not withdraw. If it digs its burrow: it is time to strengthen foundations, go deep. If it attacks: face what you fear, stand like a badger — without stepping back.' },
    shadow: { tr: 'İnatçılığın katılığa dönmesi ve değişmemek için direniş. Porsuk enerjisinin gölgesi, bir inin içinde tüm dünyaya kapanmak — koruyucu yalnızlığın hapishaneye dönüşmesi.', en: 'Stubbornness hardening into rigidity and resistance to change. The shadow of badger energy is closing off to the entire world inside a burrow — protective solitude transforming into a prison.' },
    whenAppears: { tr: 'Sınırları ihlal edildiğinde ve kararlı bir duruş gerektiğinde, topluluk veya aile için mücadele edilmesi gereken dönemlerde, köklere dönüş ve temel güçlendirme zamanlarında.', en: 'When boundaries are violated and a resolute stance is required, during periods when one must fight for community or family, in times of returning to roots and strengthening foundations.' },
    traditions: [
      { culture: { tr: 'Kelt Geleneği', en: 'Celtic Tradition' }, meaning: { tr: 'Porsuk, toprağın en kadim bilgeliğinin bekçisidir; Druitlerin sırlarını sakladığı yerin altında porsuk inlerinin bulunduğuna inanılırdı.', en: 'The badger is the guardian of the most ancient wisdom of the earth; it was believed that badger burrows lay beneath the places where Druids stored their secrets.' } },
      { culture: { tr: 'Kuzey Amerika Yerli Gelenekleri (Lakota)', en: 'North American Indigenous Traditions (Lakota)' }, meaning: { tr: 'Porsuk, şifa klanının sembolüdür; tıbbi bitkilerin köklerini bulma bilgisini taşır ve yer altının iyileştirici güçlerine aracılık eder.', en: 'The badger is the symbol of the healing clan; it carries the knowledge of finding the roots of medicinal plants and mediates the healing powers of the underground.' } },
      { culture: { tr: 'Japon Geleneği (Tanuki)', en: 'Japanese Tradition (Tanuki)' }, meaning: { tr: 'Tanuki (rakun köpeği/porsuk akrabası), şekil değiştiren trickster ve bereket ruhudur; saflık ile kurnazlığı bir arada barındırır.', en: 'Tanuki (raccoon dog/badger relative) is a shape-shifting trickster and spirit of abundance; it combines innocence and cunning.' } },
      { culture: { tr: 'İngiliz Halk Geleneği', en: 'English Folk Tradition' }, meaning: { tr: 'Porsuk, Badger\'s Moon — porsuk ayı — dedikleri sonbahar dolunayında en güçlü kabul edilir; bu gecede yapılan antlaşmalar bozulmaz sayılır.', en: 'The badger is considered most powerful at the autumn full moon they call the Badger\'s Moon; agreements made on this night are considered unbreakable.' } },
      { culture: { tr: 'Anadolu Halk İnancı', en: 'Anatolian Folk Belief' }, meaning: { tr: 'Porsuk yağının şifa gücü olduğuna inanılır; köy bilgeleri porsukla karşılaşmayı "toprağın sizi kabul ettiğinin işareti" olarak yorumlar.', en: 'The fat of the badger is believed to have healing power; village sages interpret encountering a badger as "a sign that the earth has accepted you".' } },
    ],
    myths: [
      { tr: 'Lakota anlatısında, bir zamanlar insanlar şifa bitkilerini bulmayı bilmiyordu. Porsuk Büyük Ruh\'tan şifa bilgisini istedi. Büyük Ruh, "Yerin altına in ve her kökün sesini dinle" dedi. Porsuk aylarca yer altında kaldı, her köke kulak verdi. Yeryüzüne döndüğünde, şaman oldu. O günden beri porsuk, toprağın en derin şifa sırlarını taşıyan yol göstericidir.', en: 'In a Lakota narrative, long ago humans did not know how to find healing plants. The badger asked the Great Spirit for healing knowledge. The Great Spirit said, "Go underground and listen to the voice of every root." The badger remained underground for months, lending an ear to every root. When it returned to the surface, it had become a shaman. Since that day the badger is the guide who carries the deepest healing secrets of the earth.' },
      { tr: 'İskoçya\'da anlatılır: Porsuk ve Kartal bir gün kimin daha güçlü olduğunu tartıştı. Kartal gökyüzünden hâkim olduğunu söyledi; porsuk yeraltından. "O zaman savaşalım" dedi kartal. Porsuk "Hayır" dedi, "Ben savaşmayı seçerim, savaş beni seçmez." Kartal bu sözün bilgeliğini anlayamadı. Porsuk döndü, inine girdi. Kartal hâlâ bekliyor.', en: 'As told in Scotland: the badger and the eagle argued one day about who was more powerful. The eagle said it dominated from the sky; the badger from underground. "Then let us fight," said the eagle. "No," said the badger, "I choose to fight, fight does not choose me." The eagle could not understand the wisdom of these words. The badger turned and entered its burrow. The eagle is still waiting.' },
    ],
  },

  // ─── a078 Kunduz ─────────────────────────────────────────────────────────
  a078: {
    jung: { tr: '"Yaratıcı Mimar" arketipi. Kunduz doğayı dönüştürerek dünya inşa eder — bu enerji, hayal ile eylemi birleştiren, topluluk için çalışmayı bireysel tatminden üstün tutan bilinçtir. Barajlar, tek bir el değil, kolektif iradenin eseridir.', en: 'The "Creative Architect" archetype. The beaver transforms nature to build a world — this energy is a consciousness that unites imagination and action, placing work for the community above individual satisfaction. Dams are not the work of a single hand but of collective will.' },
    dream: { tr: 'Kunduz rüyada — inşa etme, yaratma, birleştirme çağrısı. Ağaç kesiyorsa: engelini yıkarak kullanıyorsun, engel malzemeye dönüşüyor. Baraj kuruyorsa: çevrendeki akıntıları kontrol etmeyi öğreniyor, yönlendiriyorsun.', en: 'Beaver in dream — a call to build, create, unite. If it fells a tree: you are using your obstacle by dismantling it, the obstacle is becoming material. If it builds a dam: you are learning to control the currents around you, you are directing them.' },
    shadow: { tr: 'Kontrolcülük ve inşa ettiğin yapıların içine hapsolmak. Kunduz enerjisinin gölgesi, sürekli çalışma bağımlılığı ve "bitirmek" yerine "yapmaya devam etmek" ısrarıdır — baraj asla tamamlanmaz çünkü tamamlanmak duraksatır.', en: 'Controlling behaviour and being imprisoned within the structures one has built. The shadow of beaver energy is continuous workaholism and the insistence on "continuing to do" rather than "finishing" — the dam is never completed because completion means pausing.' },
    whenAppears: { tr: 'Bir projenin ya da ilişkinin temel yapısı kurulurken, topluluk inşasında liderlik üstlenildiğinde, yaratıcı azmin ve pratik uygulamanın bir araya gelmesi gerektiğinde.', en: 'While the foundational structure of a project or relationship is being built, when leadership in community-building is assumed, when creative determination and practical application need to come together.' },
    traditions: [
      { culture: { tr: 'Kuzey Amerika Yerli Gelenekleri (Algonkin)', en: 'North American Indigenous Traditions (Algonquin)' }, meaning: { tr: 'Kunduz, yaratıcı ruhun habercisidir; Büyük Kunduz Amik, dünyanın sularını şekillendiren kutsal varlıktır ve su ile kara arasındaki dengeyi korur.', en: 'The beaver is the herald of the creative spirit; the Great Beaver Amik is the sacred being that shaped the waters of the world and maintains the balance between water and land.' } },
      { culture: { tr: 'Kanada Yerli Geleneği (Haudenosaunee)', en: 'Canadian Indigenous Tradition (Haudenosaunee)' }, meaning: { tr: 'Kunduz Klanı, barışçı inşacıların klanıdır; anlaşmazlıkları çözen, topluluğu bir arada tutan mimarlar olarak saygı görür.', en: 'The Beaver Clan is the clan of peaceful builders; it is respected as the architects who resolve disputes and hold the community together.' } },
      { culture: { tr: 'Kelt Geleneği', en: 'Celtic Tradition' }, meaning: { tr: 'Dobhar-chú — su köpeği, kunduz akrabası — İrlanda mitolojisinde su ruhlarının koruyucusudur ve nehirlerin belleğini taşır.', en: 'Dobhar-chú — the water hound, kunduz kin — is the guardian of water spirits in Irish mythology and carries the memory of rivers.' } },
      { culture: { tr: 'Sibirya (Buryat) Geleneği', en: 'Siberian (Buryat) Tradition' }, meaning: { tr: 'Kunduz derisi şamanın törensel kıyafetinde kullanılır; hayvanın nehir bilgeliğini ve inşa gücünü taşıyan totem parçasıdır.', en: 'Beaver hide is used in the shaman\'s ceremonial garment; it is the totem piece carrying the animal\'s river wisdom and constructive power.' } },
      { culture: { tr: 'Anadolu Halk Geleneği', en: 'Anatolian Folk Tradition' }, meaning: { tr: 'Anadolu nehirlerinde yaşayan kunduz, "suyun ustası" olarak bilinir; köylüler onun baraj kurduğu yeri bereketli toprak sayar ve o alanlara yakın ev kurar.', en: 'The beaver living in Anatolian rivers is known as "the master of water"; villagers consider the place where it builds its dam fertile land and build homes close to those areas.' } },
    ],
    myths: [
      { tr: 'Algonkin yaratılış anlatısında, büyük tufan sonrası dünya su altındaydı. Büyük Kunduz Amik, Yaratıcı ile birlikte suların altına daldı ve çamurla ilk kara parçasını şekillendirdi. Her baraj kurduğumuzda, Amik\'in ilk eylemine saygı duyuyoruz.', en: 'In the Algonquin creation narrative, after the great flood the world was underwater. The Great Beaver Amik dived beneath the waters together with the Creator and shaped the first piece of land from mud. Every time we build a dam, we pay homage to Amik\'s first act.' },
      { tr: 'Haudenosaunee geleneğinde anlatılır: Uzun savaş dönemlerinde kunduzlar nehirden çekildi. Su azaldı, balıklar gitti, kuşlar sustı. Halk anladı ki kunduz savaştan nefret eder. Büyükler bir araya geldi, barış anlaşması imzaladı. Ertesi sabah kunduzlar geri döndü — barajları yeniden kuruldu, su aktı, yaşam başladı.', en: 'As told in Haudenosaunee tradition: during long periods of war the beavers withdrew from the river. The water diminished, the fish left, the birds fell silent. The people understood that the beaver loathes war. The elders gathered and signed a peace treaty. The next morning the beavers returned — their dams were rebuilt, water flowed, life began.' },
    ],
  },

  // ─── a079 Guguk Kuşu ─────────────────────────────────────────────────────
  a079: {
    jung: { tr: '"Zaman Bilinci" arketipi. Guguk kuşu görünmeden sesini duyurur — bu enerji, varlığını ispat etmeden etki yaratan, zamanlama bilgeliğini beden dili değil ses aracılığıyla taşıyan bilinçtir. Her sesi bir sayıdır, her sayı bir döngünün habercisidir.', en: 'The "Time Consciousness" archetype. The cuckoo makes its voice heard without being seen — this energy is a consciousness that creates impact without proving its presence, carrying the wisdom of timing not through body language but through voice. Every call is a number, every number the herald of a cycle.' },
    dream: { tr: 'Guguk kuşu rüyada — bir döngü kapanıyor ya da açılıyor, zamanlamaya dikkat et. Sesi yakından geliyorsa: karar anı yakın, hazırlan. Sesi uzaktan geliyorsa: henüz zamanı değil, bekle ve dinle.', en: 'Cuckoo in dream — a cycle is closing or opening, pay attention to timing. If its voice comes from nearby: the moment of decision is near, prepare. If its voice comes from afar: the time has not yet come, wait and listen.' },
    shadow: { tr: 'Başkasının yuvasına kurma yumurta — kendi sorumluluğunu başkasına bırakma, parazitik bağımlılık. Guguk kuşunun gölgesi, zamanlama bilgeliğinin hesapçılığa, haberciliğin manipülasyona dönüşmesidir.', en: 'Laying eggs in another\'s nest — leaving one\'s own responsibility to others, parasitic dependency. The shadow of the cuckoo is timing wisdom turning into calculation, and the herald\'s role turning into manipulation.' },
    whenAppears: { tr: 'Bir dönemin kapandığını hissedip yeni dönemin açılışını beklerken, zaman ve ritim algısının yeniden ayarlanması gerektiğinde, doğru anı bekleme sabrının sınandığı dönemlerde.', en: 'While sensing that one period has closed and awaiting the opening of a new one, when the perception of time and rhythm needs to be recalibrated, during periods when the patience of waiting for the right moment is tested.' },
    traditions: [
      { culture: { tr: 'Anadolu ve Türk Geleneği', en: 'Anatolian and Turkish Tradition' }, meaning: { tr: 'Guguk kuşunun ilk sesini duyan kişi, dileklerini sayısınca tekrarlar; o yıl ne kadar "guguk" duyulursa o kadar yıl daha yaşanacağına inanılır.', en: 'The person who hears the cuckoo\'s first call repeats their wish as many times as the count; it is believed that however many times "cuckoo" is heard that year, that many more years of life remain.' } },
      { culture: { tr: 'Slav Geleneği', en: 'Slavic Tradition' }, meaning: { tr: 'Guguk kuşu, ölülerin ruhlarını taşıyan kutsal bir varlıktır; ötüşü ölümün değil dönüşümün habercisi olarak okunur. Yaz geldiğinde geçmiş yılın ruhları onun sesiyle vedalaşır.', en: 'The cuckoo is a sacred being that carries the souls of the dead; its call is read not as a herald of death but of transformation. When summer arrives the souls of past years bid farewell through its voice.' } },
      { culture: { tr: 'Yunan-Roma Geleneği', en: 'Greco-Roman Tradition' }, meaning: { tr: 'Zeus, Hera\'yı baştan çıkarmak için guguk kuşuna dönüştü — bu mit, guguk kuşunu dönüşüm ve aşkın trickster gücüyle özdeşleştirir.', en: 'Zeus transformed into a cuckoo to seduce Hera — this myth identifies the cuckoo with the trickster power of transformation and love.' } },
      { culture: { tr: 'Japon Geleneği', en: 'Japanese Tradition' }, meaning: { tr: 'Hototogisu — Japon guguku — ölüler diyarının habercisidir; yaz geceleri onun sesi duyulduğunda atalar ziyarete gelir.', en: 'Hototogisu — the Japanese cuckoo — is the herald of the land of the dead; when its voice is heard on summer nights the ancestors come to visit.' } },
      { culture: { tr: 'İskandinav Geleneği', en: 'Scandinavian Tradition' }, meaning: { tr: 'Guguk kuşu, yılın dört yönünden birini temsil eden kutsal habercidir; ilkbaharda duyulduğunda tanrılar dünyanın döngüsünü onaylamış demektir.', en: 'The cuckoo is a sacred herald representing one of the four directions of the year; when heard in spring it means the gods have approved the cycle of the world.' } },
    ],
    myths: [
      { tr: 'Hesiodos yazan bir Yunan anlatısına göre, dünya henüz soğukken Zeus kısıtlamaları tanımayan bir güce sahip olmak istedi. Hera\'nın kucağına yumurta koymak için küçük, titreyen bir guguk kuşuna dönüştü. Hera onu ısıtmak için sardığında Zeus kendi formuna döndü. O günden beri guguk kuşu, "gücünü küçüklük içinde saklayan" varlığın simgesidir.', en: 'According to a Greek narrative cited by Hesiod, when the world was still cold Zeus wished to possess a power that acknowledged no constraints. He transformed into a small, shivering cuckoo to lay an egg in Hera\'s lap. When Hera wrapped it to warm it, Zeus returned to his own form. Since that day the cuckoo is the symbol of the being that "hides its power within smallness".' },
      { tr: 'Anadolu\'da anlatılır: Bir zamanlar guguk kuşu tüm yıl boyunca şarkı söylerdi. Ama insanlar onun sesini duyunca işi bırakır, dinlemeye dalar, zamanı unuturlardı. Tanrı, "Bu öyle olmaz" dedi ve guguk kuşuna yalnızca ilkbahar ile yazın ötme izni verdi. Guguk kuşu kabul etti — çünkü nadir olan değerlidir, her an ötülürse sesi anlamsızlaşır.', en: 'As told in Anatolia: once upon a time the cuckoo sang throughout the whole year. But whenever people heard its voice they would stop working, fall into listening, forget time. God said, "This will not do," and gave the cuckoo permission to call only in spring and summer. The cuckoo accepted — because what is rare is precious; if it called at every moment its voice would lose meaning.' },
    ],
  },

  // ─── a080 Saksağan ──────────────────────────────────────────────────────
  a080: {
    jung: { tr: '"İkili Doğa Bilgesi" arketipi. Saksağan siyah ile beyazı bedeninde taşır — bu enerji, zıtlıkları sentezleyen, her şeyin iki yüzünü bir arada gören, trickster ile bilge arasında gidip gelen bilinçtir. Parlak nesneleri toplamak, dünyayı anlama açlığının simgesidir.', en: 'The "Dual Nature Sage" archetype. The magpie carries black and white in its body — this energy is a consciousness that synthesises opposites, sees both sides of everything simultaneously, and moves between trickster and sage. Collecting shiny objects is the symbol of a hunger to understand the world.' },
    dream: { tr: 'Saksağan rüyada — bir haber geliyor ya da gönderilmesi gereken bir mesaj var. Tek saksağan görülürse: beklenmedik bir değişim, uyanık kal. Çift saksağan: bir ilişkide denge kuruldu ya da kurulacak.', en: 'Magpie in dream — news is coming, or there is a message that needs to be sent. If a single magpie is seen: an unexpected change, stay alert. Two magpies: balance has been or will be established in a relationship.' },
    shadow: { tr: 'Parlak olan her şeye kapılmak — derinliksiz merak ve dikkat dağınıklığı. Saksağan enerjisinin gölgesi, bilgi toplarken bilgelik üretememek ve başkasının değerlisine sahip çıkma eğilimidir — hoarding ve ödünç kimlikler.', en: 'Being swept away by everything that glitters — superficial curiosity and scattered attention. The shadow of magpie energy is collecting information while failing to produce wisdom, and the tendency to claim what is valuable to others — hoarding and borrowed identities.' },
    whenAppears: { tr: 'Önemli bir haberin beklediği ya da verilmesi gereken dönemlerde, zıt güçleri bir arada tutmayı öğrenme sürecinde, zekânın ve gözlem yetisinin ön plana çıkması gereken anlarda.', en: 'During periods when important news is awaited or must be delivered, in the process of learning to hold opposing forces together, at moments when intelligence and the power of observation need to come to the fore.' },
    traditions: [
      { culture: { tr: 'Çin Geleneği', en: 'Chinese Tradition' }, meaning: { tr: 'Saksağan "xi que" — mutlu kuş. İki saksağan beraber görülürse "çift mutluluk" (双喜) işaretidir; düğünlerde ve kutlamalarda iyiye yorulur.', en: 'The magpie "xi que" — the happy bird. Two magpies seen together are a sign of "double happiness" (双喜); it is read as a good omen at weddings and celebrations.' } },
      { culture: { tr: 'Kore Geleneği', en: 'Korean Tradition' }, meaning: { tr: 'Saksağan, Kore\'nin ulusal kuşudur; iyilik, cesaret ve sevincin simgesidir. Sabah saksağan görülürse misafir geleceğine inanılır.', en: 'The magpie is the national bird of Korea; it is the symbol of goodness, courage, and joy. If a magpie is seen in the morning it is believed that a guest will arrive.' } },
      { culture: { tr: 'İngiliz ve İskoç Halk Geleneği', en: 'English and Scottish Folk Tradition' }, meaning: { tr: '"Bir saksağan keder, iki saksağan sevinç" — saksağan sayısını kehanet için sayan bu gelenek yüzyıllardır sürmektedir. Her sayı farklı bir kaderi işaret eder.', en: '"One for sorrow, two for joy" — the tradition of counting the number of magpies for divination has continued for centuries. Each count points to a different fate.' } },
      { culture: { tr: 'Sibirya Şaman Geleneği', en: 'Siberian Shamanic Tradition' }, meaning: { tr: 'Saksağan, şamanın ruhlar dünyasındaki habercisidir; iki dünya arasında mektup taşır ve şamanın gittiği yerlerin haritasını bilir.', en: 'The magpie is the shaman\'s messenger in the spirit world; it carries letters between two worlds and knows the map of the places the shaman travels.' } },
      { culture: { tr: 'Anadolu Halk İnancı', en: 'Anatolian Folk Belief' }, meaning: { tr: 'Saksağan eve konarsa yakın zamanda misafir gelir ya da bir haber ulaşır. Bir dala konup gitmeden bekliyorsa "söylemesi gereken bir şey var" denir — sessizce dinlenir.', en: 'If a magpie perches on a house, a guest will arrive or news will reach soon. If it perches on a branch and waits without leaving, it is said "it has something to say" — one listens in silence.' } },
    ],
    myths: [
      { tr: 'Kore\'nin Gyeonu ile Jiknyeo efsanesinde, iki âşık Samanyolu\'nun iki yakasına ayrılmıştır. Yılda yalnızca bir gece — Tanabata\'da — buluşabilirler. Bu geceye ulaşmak için tüm saksağanlar birleşerek gökyüzünde köprü kurar: kanatları birbirine geçmiş binlerce saksağan, iki yıldız âşığı birleştirir. Sabah saksağanların başı dazlak görülürse, o gece köprü kurduklarının işaretidir.', en: 'In the Korean legend of Gyeonwoo and Jiknyeo, two lovers are separated on opposite sides of the Milky Way. Only one night a year — on Tanabata — can they meet. To reach this night, all the magpies unite to build a bridge in the sky: thousands of magpies with wings interlocked unite the two star-crossed lovers. If magpies are seen with bare heads in the morning, it is a sign that they built the bridge that night.' },
      { tr: 'Çin\'de anlatılır: Saksağan bir gün güneşe uçmaya karar verdi. "Seni bulacağım ve en parlak nesneyi yanına koyacağım" dedi. Aylarca uçtu, güneşe ulaşamadı. Dönerken gördü ki dünya zaten güneşle doluydu — her damlada, her yaprakta, her gözde. O günden beri saksağan yalnızca parlayan şeyleri değil, parlakın içinde gizlenmiş derin şeyleri de taşır.', en: 'As told in China: one day the magpie decided to fly to the sun. "I will find you and place the shiniest object beside you," it said. It flew for months and could not reach the sun. On its return it saw that the world was already full of sunlight — in every drop, every leaf, every eye. Since that day the magpie carries not only shining things but also the deep things hidden within the shine.' },
    ],
  },

  // ─── a081 Simurg ────────────────────────────────────────────────────────
  a081: {
    jung: { tr: '"Kolektif Benlik" arketipi. Simurg, bireysel egonun erimesiyle ortaya çıkan evrensel farkındalığın simgesidir. Jung\'un "bütünleşme" kavramını en yüce noktasına taşır — 30 kuş aynaya baktığında gördüğü tek varlık, ayrılığın illüzyon olduğunu fısıldar.', en: '"Collective Self" archetype. The Simurgh represents the universal awareness that emerges when individual ego dissolves. It carries Jung\'s concept of "individuation" to its highest peak — when 30 birds look in the mirror and see one being, it whispers that separation is illusion.' },
    dream: { tr: 'Simurg rüyada — kolektife ait bir hakikati aramaktasın. Kanatlarını görüyorsan: bilgelik sende zaten var, aramayı bırak. Çok kuş olarak uçuyorsan: topluluğunla bütünleşme zamanı gelmiş.', en: 'Simurgh in dream — you are seeking a truth that belongs to the collective. If you see its wings: the wisdom already resides in you, stop searching. If you fly as many birds: the time has come to merge with your community.' },
    shadow: { tr: 'Aşkınlık adına yalnızlığa çekilme. "Ben herkeste varım" düşüncesi, somut ilişkilerden kaçışın mistik örtüsü olabilir. Evrensel sevgiden bahsedip yakınlarını görmezden gelmek.', en: 'Withdrawing into solitude in the name of transcendence. The thought "I exist in everyone" can become a mystical veil over escape from concrete relationships. Speaking of universal love while ignoring those close to you.' },
    whenAppears: { tr: 'Bir topluluğa ait olmak ya da tam bağımsızlık arasında kaldığında; "ben kimim" sorusunun kalabalığın içinde kaybolduğu dönemlerde.', en: 'When you are caught between belonging to a community and complete independence; in periods when the question "who am I" is lost within the crowd.' },
    traditions: [
      { culture: { tr: 'Sufi-İran', en: 'Sufi-Persian' }, meaning: { tr: 'Feridüddin Attar\'ın Mantıku\'t-Tayr\'ında 30 kuş Simurg\'u arar; sonunda ayna karşısında kendilerinin Simurg olduğunu görürler.', en: 'In Attar\'s Conference of the Birds, 30 birds seek the Simurgh; before the mirror they finally realize they themselves are the Simurgh.' } },
      { culture: { tr: 'Zerdüşt', en: 'Zoroastrian' }, meaning: { tr: 'Saena kuşu — Hayat Ağacı\'nın tepesinde yuvalanan, tüm bitkilerin tohumlarını dağıtan kutsal koruyucu.', en: 'The Saena bird — sacred guardian nesting atop the Tree of Life, scattering seeds of all plants across the world.' } },
      { culture: { tr: 'Şahnâme', en: 'Shahnameh' }, meaning: { tr: 'Rüstem\'in babası Zal\'ı büyüten Simurg, bilgeliğini ve tüyünü insanlığa armağan eder; ihtiyaç anında yakılacak bir tüydür o.', en: 'The Simurgh who raised Zal, father of Rostam, gifts its wisdom and a feather to humanity — a feather to be burned in the moment of need.' } },
      { culture: { tr: 'Türk Destanları', en: 'Turkic Epics' }, meaning: { tr: 'Anka ya da Zümrüdüanka olarak bilinir — "Yeşil Anka" — ulaşılamaz dağlarda yaşayan, yiğitleri sınayan dönüşüm kuşu.', en: 'Known as Anka or Zümrüdüanka — "Emerald Phoenix" — the bird of transformation dwelling in unreachable mountains, testing the worthy.' } },
      { culture: { tr: 'Hint', en: 'Indian' }, meaning: { tr: 'Garuda ile Simurg paralel koşar — her ikisi de güneş enerjisini taşır, tanrısal bilgiyi insana aktarır.', en: 'Garuda runs parallel to the Simurgh — both carry solar energy, both transmit divine knowledge to humanity.' } },
    ],
    myths: [
      { tr: 'Attar\'ın Kuş Konferansı\'nda 30 kuş, yedi vadiden geçerek Simurg\'un dağına ulaşır: Talep, Aşk, Marifet, Kanaat, Tevhid, Hayret ve Yokluk. Her vadide bir kuş düşer. Kalanlar aynaya baktığında tek bir varlık görür — hem kendileri hem Simurg. Ayrılık hiç olmamıştır.', en: 'In Attar\'s Conference of the Birds, 30 birds cross seven valleys to reach the Simurgh\'s mountain: Quest, Love, Knowledge, Contentment, Unity, Wonder, and Annihilation. In each valley a bird falls. When the remaining look into the mirror they see a single being — both themselves and the Simurgh. Separation never existed.' },
      { tr: 'Şahnâme\'de Zal, doğumundan itibaren Simurg\'un yuvasında büyür. Rüstem yaralı düştüğünde babası Simurg\'un tüyünü yakar — kuş gelir, deva verir ve der ki: "Ben hem sizi hem sizin acınızı bilirim, çünkü ben sizin içinizdeki bilgeliktim."', en: 'In the Shahnameh, Zal grows up in the Simurgh\'s nest from birth. When Rostam falls wounded, his father burns the Simurgh\'s feather — the bird arrives, brings remedy and says: "I know both you and your pain, for I was the wisdom within you."' },
    ],
  },

  // ─── a082 Garuda ────────────────────────────────────────────────────────
  a082: {
    jung: { tr: '"İlahi Araç" arketipi. Garuda, egonun ilahi iradenin hizmetine girdiği anı simgeler — artık bireysel istek değil, evrensel düzen taşınır. Jung\'un "numinous" deneyimi: benliğin büyük bir güç tarafından seçildiği o titreşimli an.', en: '"Divine Vehicle" archetype. Garuda symbolizes the moment the ego enters the service of divine will — it no longer carries individual desire but universal order. Jung\'s "numinous" experience: that trembling moment when the self is chosen by a greater power.' },
    dream: { tr: 'Garuda rüyada — bir misyon üstlenme zamanı gelmiştir. Kanatlarını açıyorsa: engellerden üstünsün, yüksek bir amacın seni taşıyor. Yılanla savaşıyorsa: bilinçdışındaki zehri dönüştürme süreci başlamış.', en: 'Garuda in dream — the time has come to take on a mission. If it spreads wings: you are above obstacles, a higher purpose carries you. If it battles a serpent: the process of transforming the poison in the unconscious has begun.' },
    shadow: { tr: '"Tanrı adına" öfke ve yargı. Garuda\'nın ateşi yanlış yöne döndüğünde, kişi kendini kutsal bir savaşçı sanıp başkalarını yok etmeye kalkar. Ego, ilahiliği kendi gücüne sarıp onu araçsallaştırır.', en: 'Anger and judgment "in the name of God." When Garuda\'s fire turns the wrong way, a person fancies themselves a holy warrior and sets out to destroy others. The ego wraps divinity around its own power and instrumentalizes it.' },
    whenAppears: { tr: 'Büyük bir haksızlıkla yüz yüze geldiğinde ya da uzun süredir kaçındığın bir görevi nihayet üstlenmek zorunda kaldığında.', en: 'When you face a great injustice or when you are finally compelled to take on a duty you have long been avoiding.' },
    traditions: [
      { culture: { tr: 'Hindu', en: 'Hindu' }, meaning: { tr: 'Vişnu\'nun vahana\'sı — ilahi düzenin taşıyıcısı. Nagaraja\'nın, yılanların efendisinin ezeli düşmanı; zehri arındırır.', en: 'Vahana of Vishnu — carrier of divine order. Eternal enemy of Nagaraja, lord of serpents; it purifies venom.' } },
      { culture: { tr: 'Budist', en: 'Buddhist' }, meaning: { tr: 'Sekiz büyük varlıktan biri. Bilgelik ve merhameti simgeler; naga\'ları (yılanları) farkındalıkla ehlileştirir.', en: 'One of the eight great beings. Symbolizes wisdom and compassion; tames the nagas (serpents) with mindfulness.' } },
      { culture: { tr: 'Endonezya', en: 'Indonesian' }, meaning: { tr: 'Garuda, Endonezya\'nın ulusal amblemi — birlik, güç ve bağımsızlık ruhu. Pancasila ilkelerini kanatlarında taşır.', en: 'Garuda is Indonesia\'s national emblem — the spirit of unity, strength, and independence. It bears the Pancasila principles on its wings.' } },
      { culture: { tr: 'Tayland-Khmer', en: 'Thai-Khmer' }, meaning: { tr: 'Kraliyet gücünün sembolü. Kral Garuda\'nın üzerinde tahtına oturur — ilahi düzenin yeryüzündeki yansıması.', en: 'Symbol of royal power. The king sits on his throne atop Garuda — the earthly reflection of divine order.' } },
      { culture: { tr: 'Japon', en: 'Japanese' }, meaning: { tr: 'Karura — Budist koruyucu dört tanrısından biri. Ağzından alev çıkar, naga\'ları yer; negatif enerjiyi dönüştürür.', en: 'Karura — one of the four Buddhist guardian deities. Flames burst from its mouth, it devours nagas; it transforms negative energy.' } },
    ],
    myths: [
      { tr: 'Hindu mitiyle Garuda, annesini köle eden yılanlardan kurtarmak için amritu, ölümsüzlük iksirini çalar. Vişnu\'nun karşısına çıkar; tanrı onun cesaretine o denli hayran kalır ki onu tahtının karşısına kondurmak yerine kendi aracı yapar. Böylece Garuda hem özgürlüğü hem sonsuzluğu kazanır — ama iktidar değil, hizmet yoluyla.', en: 'In Hindu myth, Garuda steals the amrita, the elixir of immortality, to free his mother enslaved by serpents. He stands before Vishnu; the god is so awed by his courage that instead of punishing him he makes him his vehicle. Thus Garuda wins both freedom and eternity — not through power, but through service.' },
      { tr: 'Bir Japon efsanesine göre Karura gökyüzünde ağlar — çünkü yalnızca naga yiyebilir ama onları yemek onu da acıya sürükler. Bir Budist aziz yaklaşır ve sorar: "Neden ağlıyorsun?" Karura der ki: "Hem öldürüyorum hem de acı çekiyorum." Aziz cevaplar: "Bu farkındalık, seni Budha\'ya yaklaştıran şeydir."', en: 'According to a Japanese legend, Karura weeps in the sky — for it can only eat nagas, but eating them fills it with sorrow. A Buddhist saint approaches and asks: "Why do you weep?" Karura says: "I both kill and suffer." The saint replies: "This awareness is what brings you closer to Buddha."' },
    ],
  },

  // ─── a083 Keçi ──────────────────────────────────────────────────────────
  a083: {
    jung: { tr: '"Yaratıcı Özgürlük" ve "İçgüdüsel Bilgelik" arketipi. Keçi, egonun katı yapılarını aşıp dağın sarp kayalıklarında — yani sınırın tam kenarında — denge bulan bilinçdışı yaratıcılığı simgeler. Pan ile özdeşleştirilen bu enerji, medeniyetin bastırdığı doğal yaşam sevincini geri çağırır.', en: '"Creative Freedom" and "Instinctual Wisdom" archetype. The goat symbolizes the unconscious creativity that transcends the ego\'s rigid structures and finds balance on the steep cliffs of the mountain — right at the edge of the limit. This energy, identified with Pan, recalls the natural joy of life suppressed by civilization.' },
    dream: { tr: 'Keçi rüyada — imkânsız görünen bir yolda ilerleyebilirsin. Kayalıkta tırmanıyorsa: kendi özgün yolunu bul, kimsenin geçmediği yerden geç. Düşüyorsa: yaratıcı cesaretini korkuya kurban ediyorsun.', en: 'Goat in dream — you can move forward on a path that seems impossible. If it climbs cliffs: find your own unique path, pass where no one has gone. If it falls: you are sacrificing your creative courage to fear.' },
    shadow: { tr: 'İnatçılık ve sürüye katılmama. Keçinin bağımsızlık enerjisi sapkınlaştığında, kişi işbirliğini tamamen reddeder, her çiti yıkar ama hiçbir bahçe kurmaz. Özgürlük, sorumsuzluğun kılığına bürünür.', en: 'Stubbornness and refusal to join the herd. When the goat\'s independence energy turns perverse, the person completely rejects cooperation, breaks every fence but builds no garden. Freedom disguises itself as irresponsibility.' },
    whenAppears: { tr: '"Bu yol benim için değil" dediğin anda ama korkudan geri çekildiğinde; yaratıcı bir proje için alışılmadık bir yol aramak zorunda kaldığında.', en: 'At the moment you say "this path is not for me" but retreat out of fear; when you are compelled to seek an unconventional path for a creative project.' },
    traditions: [
      { culture: { tr: 'Yunan', en: 'Greek' }, meaning: { tr: 'Pan — yarı keçi, yarı insan tanrı. Doğanın, verimliliğin ve serbest müziğin tanrısı. Panik kelimesi ondan gelir — derin ormanlarda duyulan ilkel korku sesi.', en: 'Pan — half-goat, half-human god. God of nature, fertility, and free music. The word panic comes from him — the primal sound of terror heard in deep forests.' } },
      { culture: { tr: 'İskandinav', en: 'Norse' }, meaning: { tr: 'Tanngrisnir ve Tanngnjóstr — Thor\'un keçileri. Her gece yenir, her sabah dirilirler. Yeniden doğuş ve sonsuz besin kaynağı.', en: 'Tanngrisnir and Tanngnjóstr — Thor\'s goats. Eaten every night, resurrected every morning. Rebirth and the inexhaustible source of nourishment.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Onikilik takvimin sekizinci hayvanı. Keçi yılı; sanat, zarafet, sezgi ve sürüden farklı düşünme enerjisini taşır.', en: 'The eighth animal of the twelve-year cycle. The Year of the Goat carries the energy of art, grace, intuition, and thinking differently from the herd.' } },
      { culture: { tr: 'Anadolu', en: 'Anatolian' }, meaning: { tr: 'Kıl keçisi Anadolu\'nun dört mevsim yoldaşı — süt, yün, deri, et verir. "Keçi gibi inat" deyimi hem zorluk hem direnciyle büyük saygı taşır.', en: 'The Angora goat is Anatolia\'s companion across four seasons — giving milk, wool, leather, meat. The saying "stubborn as a goat" carries deep respect for both its difficulty and its resilience.' } },
      { culture: { tr: 'Batı Afrika', en: 'West African' }, meaning: { tr: 'Yoruba geleneğinde Eşu\'nun keçisi — tanrılar ve insanlar arasındaki mesajcı, sınırları aşan, sürpriz getiren varlık.', en: 'In Yoruba tradition, Eshu\'s goat — the messenger between gods and humans, crossing boundaries, bringing surprises.' } },
    ],
    myths: [
      { tr: 'Pan bir gün nehir kıyısında uyuyan Syrinx\'e âşık olur. Syrinx kaçar, nehre ulaşınca su perilerine dönüşmesini diler. Pan ellerini uzattığında kamışları kavrar — ve kamışın iniltisini duyunca o sesi müziğe dönüştürür. Böylece Pan flütü doğar: kaybedilen güzellik, yaratıcılığa dönüşür.', en: 'One day Pan falls in love with Syrinx sleeping by the river. Syrinx flees, and upon reaching the river prays to be transformed by the water nymphs. When Pan reaches out he grasps reeds — and hearing the moan of the reed he transforms that sound into music. Thus the Pan flute is born: lost beauty becomes creativity.' },
      { tr: 'Thor\'un keçilerini bir gece bir çiftçi ailesi yemiştir. Sabah Thor kemikleri toplar, büyüsüyle keçileri diriltir — ama biri aksıyor. Bir kemik kırılmıştır. Thor öfkesini bastırır, çiftçi ailesini affeder ve keçinin bacağındaki izin "bağışlama" gücünü hatırlatır.', en: 'One night a farmer\'s family has eaten Thor\'s goats. In the morning Thor gathers the bones, resurrects the goats with his magic — but one limps. A bone was broken. Thor suppresses his anger, forgives the farmer\'s family, and the mark on the goat\'s leg becomes a reminder of the power of "forgiveness."' },
    ],
  },

  // ─── a084 İbis ──────────────────────────────────────────────────────────
  a084: {
    jung: { tr: '"İlahi Aracı" ve "Hermeneut" arketipi. İbis, bilinçdışının gizemli dil katmanlarına nüfuz eden, bu katmanları yazıya, sembole, anlama dönüştüren zihinsel ilkeyi simgeler. Thoth enerjisi — ham deneyimi kutsal anlama çeviren tercüman.', en: '"Divine Mediator" and "Hermeneutic" archetype. The ibis symbolizes the mental principle that penetrates the mysterious language layers of the unconscious and transforms them into writing, symbol, and meaning. The Thoth energy — the translator who turns raw experience into sacred sense.' },
    dream: { tr: 'İbis rüyada — bir mesajı doğru okuman gerekmektedir. Yazı yazıyorsa: içindeki bilgeliği dışa vurma zamanı. Ayakta ve hareketsiz duruyorsa: acele etme, doğru kelimeleri bulmak için sabret.', en: 'Ibis in dream — you need to read a message correctly. If it writes: the time has come to externalize the wisdom within. If it stands still and motionless: do not rush, be patient to find the right words.' },
    shadow: { tr: 'Entelektüel kibir ve bilginin tekelleştirilmesi. İbis enerjisi karanlığa döndüğünde, kişi bilgiyi güç olarak kullanır, paylaşmaz, anlaşılmaz dilde konuşarak diğerlerini küçümser. Kutsal bilgi, ego aracına dönüşür.', en: 'Intellectual arrogance and the monopolization of knowledge. When ibis energy turns dark, the person uses knowledge as power, does not share it, and belittles others by speaking in incomprehensible language. Sacred knowledge becomes a tool of the ego.' },
    whenAppears: { tr: 'Yazmak, öğretmek ya da bir gerçeği ifade etmek için doğru kelimeler aradığında; hayatının büyük bir bölümünü anlamlandırmaya çalıştığın dönemlerde.', en: 'When you search for the right words to write, teach, or express a truth; in periods when you are trying to make sense of a large chapter of your life.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Thoth\'un kutsal hayvanı. Tanrı Thoth ibis başlıdır — bilgelik, ay, yazı, matematik ve ölüler kitabının yazıcısı.', en: 'The sacred animal of Thoth. The god Thoth has an ibis head — scribe of wisdom, the moon, writing, mathematics, and the Book of the Dead.' } },
      { culture: { tr: 'Antik Yunan', en: 'Ancient Greek' }, meaning: { tr: 'Yunanlılar ibisi Hermes\'le ilişkilendirdi — tanrılar arası mesajcı, ölüler âleminin rehberi, sözün ve anlamın efendisi.', en: 'The Greeks associated the ibis with Hermes — messenger between gods, guide of the underworld, master of word and meaning.' } },
      { culture: { tr: 'Roma', en: 'Roman' }, meaning: { tr: 'Nil\'in kutsal koruyucusu. İbis yılanları yer, salgını önler — beden sağlığı ve zihin temizliği bir arada.', en: 'Sacred guardian of the Nile. The ibis eats serpents, prevents plague — bodily health and mental clarity combined.' } },
      { culture: { tr: 'Batı Afrika', en: 'West African' }, meaning: { tr: 'Bazı Vodou geleneklerinde ibis tüyleri kehanet ritüellerinde kullanılır — bilgelik ve ilahi iletişimin simgesi.', en: 'In some Vodou traditions ibis feathers are used in divination rituals — a symbol of wisdom and divine communication.' } },
      { culture: { tr: 'Japon', en: 'Japanese' }, meaning: { tr: 'Toki — Japonya\'nın neredeyse nesli tükenen kutsal kuşu. Narinlikle, zarafetle, koruma gerektiren nadir bilgelik olarak yeniden canlandırıldı.', en: 'Toki — Japan\'s nearly extinct sacred bird. Revived as a symbol of rarity, grace, and wisdom that requires protection.' } },
    ],
    myths: [
      { tr: 'Mısır mitinde Thoth, Ra ile Ay arasında oynanan bir oyunda Ay\'dan beş ek gün kazanır — böylece Nut\'un çocukları, Osiris, İsis, Set, Nephthys ve Horus yeryüzüne gelebilir. Thoth yalnızca bir bilge değildir; zamanı, çözülmez görünen düğümleri çözen bilgeliğidir.', en: 'In Egyptian myth, Thoth wins five extra days from the Moon in a game played between Ra and the Moon — allowing Nut\'s children, Osiris, Isis, Set, Nephthys, and Horus, to come into the world. Thoth is not merely a sage; he is the wisdom that unravels time and seemingly impossible knots.' },
      { tr: 'Osiris öldürüldükten sonra İsis parçalanmış bedenini arar. Her şeyi kaydeden Thoth\'tur — kayıp parçaları, söylenmesi gereken büyü sözlerini, ölümden dönüşün şifresini yazar. Kutsal bilgelik, yas içinde bile kalemine devam eder.', en: 'After Osiris is killed, Isis searches for his dismembered body. It is Thoth who records everything — the missing pieces, the magic words that must be spoken, the cipher of the return from death. Sacred wisdom continues writing even within grief.' },
    ],
  },

  // ─── a085 İskarabe ──────────────────────────────────────────────────────
  a085: {
    jung: { tr: '"Yeniden Doğuş" ve "Dönüşüm" arketipi. İskarabe, Jung\'un meşhur eserinde sinkoronisiteyle ilişkilendirilir — rasyonel aklın tıkandığı yerde doğanın simgesel cevabıdır. Gübre topunda yeni güneşi yuvarlayan bu küçük varlık, en karanlık maddeden kutsal yaratımın mümkün olduğunu gösterir.', en: '"Rebirth" and "Transformation" archetype. The scarab is associated with synchronicity in Jung\'s famous work — it is nature\'s symbolic answer where the rational mind reaches a dead end. This small being rolling the new sun in a dung ball shows that sacred creation from the darkest matter is possible.' },
    dream: { tr: 'İskarabe rüyada — köklü bir dönüşüm başlamak üzeredir. Güneşe doğru yuvarlıyorsa: içinden geçtiğin zor süreç seni aydınlatacak. Çoğalıyorsa: küçük ama sürekli adımlar büyük değişimi getirir.', en: 'Scarab in dream — a fundamental transformation is about to begin. If it rolls toward the sun: the difficult process you are passing through will illuminate you. If they multiply: small but continuous steps bring great change.' },
    shadow: { tr: 'Kirli olanı kutsallaştırma takıntısı. İskarabe enerjisi sapkınlaştığında, kişi her çukuru "dönüşüm fırsatı" diye sahiplenir ve asıl temizlenme işini süresiz erteler. Gübre içinde kalmayı maneviyatla örtmek.', en: 'The obsession with sanctifying what is filthy. When scarab energy turns perverse, the person claims every pit as a "transformation opportunity" and indefinitely postpones the actual work of cleansing. Covering remaining in dung with spirituality.' },
    whenAppears: { tr: 'En altta hissettiğinde, utanç ya da başarısızlık içindeyken; anlamsız görünen bir sürecin ortasında anlam aradığında.', en: 'When you feel at rock bottom, inside shame or failure; when you search for meaning in the middle of a process that seems meaningless.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Khepri — doğan güneşin tanrısı, skarabeus başlı. Her sabah güneşi ufuktan yukarı iter. "Kheper" = "olmak", "var olmak", "dönüşmek".', en: 'Khepri — god of the rising sun, scarab-headed. Every morning he pushes the sun up from the horizon. "Kheper" = "to be," "to exist," "to transform."' } },
      { culture: { tr: 'Mısır Muskası', en: 'Egyptian Amulet' }, meaning: { tr: 'Kalp skarabeusu — ölünün mumyasının üstüne konur. Ruhun yargılanması sırasında kalbi aleyhine tanıklık etmemesi için dua yazılıdır.', en: 'Heart scarab — placed over the mummy of the deceased. A prayer is inscribed so the heart does not testify against the soul at judgment.' } },
      { culture: { tr: 'Jung Psikolojisi', en: 'Jungian Psychology' }, meaning: { tr: 'Jung\'un meşhur vakasında bir hasta Altın Skarabeus rüyasını anlatırken pencereye bir skarabeus böceği çarpar — sinkonisitenin simgesi olur.', en: 'In Jung\'s famous case, while a patient recounts a dream of the Golden Scarab, a scarab beetle strikes the window — it becomes the symbol of synchronicity.' } },
      { culture: { tr: 'Roma', en: 'Roman' }, meaning: { tr: 'Mısır kültünün yayılmasıyla Roma\'ya taşınan skarabeus muskası, uğur, yeniden doğuş ve koruma sembolü olarak kullanıldı.', en: 'Carried to Rome with the spread of Egyptian cult, the scarab amulet was used as a symbol of luck, rebirth, and protection.' } },
      { culture: { tr: 'Modern Sembolizm', en: 'Modern Symbolism' }, meaning: { tr: 'İskarabe günümüzde atık ve dönüşümün simgesi olarak çevre etiğinde yeniden anlam kazanıyor — hiçbir şey ziyan olmaz, her şey dönüşür.', en: 'Today the scarab is regaining meaning in environmental ethics as a symbol of waste and transformation — nothing is wasted, everything transforms.' } },
    ],
    myths: [
      { tr: 'Mısır kozmolojisinde dünya her gece Nun\'un ilk sularına — yokluğa — döner. Khepri, sabahın ilk ışığında güneş topunu ufuktan iter ve "ben bugün de varım" der. İskarabenin gübre topunda yuvarlayıp gömdüğü yumurtalar, karanlık topraktan patlayan larvalardır — yaratım, çürümeden doğar.', en: 'In Egyptian cosmology the world returns each night to the primordial waters of Nun — to nothingness. Khepri, at the first light of morning, pushes the sun ball up from the horizon and says "I exist again today." The eggs the scarab rolls in its dung ball and buries are larvae that burst from dark earth — creation is born from decay.' },
      { tr: 'Jung\'un bir hastası rüyasında ona altın bir skarabeus böceği uzatır. Aynı anda, terapi odasının penceresine gerçek bir skarabeus böceği çarpar. Jung pencereyi açar, böceği içeri alır ve hastaya verir. O an, hastanın yıllarca dirençle koruduğu rasyonalizmi çözülmeye başlar. İçeriden gelen simge, dışarıdan bir sesle yankılanmıştır.', en: 'A patient of Jung\'s extends a golden scarab beetle to him in a dream. At the very same moment, a real scarab beetle strikes the window of the therapy room. Jung opens the window, takes the beetle inside, and hands it to the patient. At that moment, the rationalism the patient had guarded with resistance for years begins to dissolve. The symbol from within has echoed with a voice from without.' },
    ],
  },

  // ─── a086 Piton ─────────────────────────────────────────────────────────
  a086: {
    jung: { tr: '"Ata Ruhu" ve "Chthonic Ana" arketipi. Piton, toprağın derinliklerinden gelen, ata bilgeliğini ve kolektif belleği taşıyan bilinçdışı güçleri simgeler. Jung\'un "Büyük Ana" figürünün en eski, en köklü biçimi — hem besleyen hem yutan, hem koruyan hem dönüştüren.', en: '"Ancestral Spirit" and "Chthonic Mother" archetype. The python symbolizes the unconscious forces coming from the depths of earth, carrying ancestral wisdom and collective memory. The oldest, most rooted form of Jung\'s "Great Mother" figure — both nourishing and engulfing, both protecting and transforming.' },
    dream: { tr: 'Piton rüyada — ata sesleri konuşuyor. Sarıyorsa ama boğmuyorsa: köklerinle bütünleş, geçmişin seni taşıyor. Boğuyorsa: ailenin ya da geleneğin baskısından nefes alamıyorsun.', en: 'Python in dream — ancestral voices are speaking. If it coils but does not constrict: integrate with your roots, the past carries you. If it constricts: you cannot breathe under the pressure of family or tradition.' },
    shadow: { tr: 'Özgürlüğü kıstıran gelenekçilik. Piton\'un toprak enerjisi sapkınlaştığında, atalar adına baskı, yenilik karşıtlığı ve "böyle gördük böyle yaparız" katılığı devreye girer. Kök, kanat olacak yerde pranga olur.', en: 'Traditionalism that constricts freedom. When python\'s earth energy turns perverse, pressure in the name of ancestors, opposition to innovation, and the rigidity of "we saw it this way, we do it this way" take over. The root becomes a shackle where it should become a wing.' },
    whenAppears: { tr: 'Aile mirası ya da kültürel köklerle yüzleşmen gerektiğinde; bir döngünün kapandığını ve yenisine geçiş için derin bir arınma gerektiğini hissettiğinde.', en: 'When you need to face your family heritage or cultural roots; when you sense that a cycle is closing and deep purification is needed to transition to the next.' },
    traditions: [
      { culture: { tr: 'Yunan', en: 'Greek' }, meaning: { tr: 'Python — Delphi kehanet merkezinin koruyucusu. Gaia\'nın oğlu, toprağın sesi. Apollon onu öldürür ama onun adını taşır: Pythia, yer altından konuşur.', en: 'Python — guardian of the Delphic oracle center. Son of Gaia, voice of the earth. Apollo slays it but bears its name: the Pythia speaks from underground.' } },
      { culture: { tr: 'Batı Afrika — Dahomey', en: 'West African — Dahomey' }, meaning: { tr: 'Ayida-Weddo ve Damballa — Vodou\'nun gökkuşağı yılanı çifti. Toprak ve gökyüzünü, ölümlü ve ölümsüzü birleştirir.', en: 'Ayida-Weddo and Damballa — the Vodou rainbow serpent couple. Uniting earth and sky, mortal and immortal.' } },
      { culture: { tr: 'Avustralya Aborijin', en: 'Australian Aboriginal' }, meaning: { tr: 'Gökkuşağı Yılanı — yaratılış miti. Yer altından çıkıp nehirleri, dağları, yaşam biçimlerini şekillendirir. Hem yaratıcı hem yıkıcı, hem ata hem tanrı.', en: 'Rainbow Serpent — creation myth. Rising from underground it shapes rivers, mountains, and ways of life. Both creator and destroyer, both ancestor and god.' } },
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Apophis — Ra\'nın geceleyin geçtiği yolun tehlikesi. Ama Mehen yılanı Ra\'yı korur — aynı enerji hem tehdit hem kalkan olabilir.', en: 'Apophis — the danger on the path Ra traverses at night. But the serpent Mehen protects Ra — the same energy can be both threat and shield.' } },
      { culture: { tr: 'Zulu', en: 'Zulu' }, meaning: { tr: 'İnhlwathi — büyük piton, ataların ruhu. Ata mezarı yakınında görülmesi, koruyucu bir mesajın geldiğini gösterir.', en: 'Inhlwathi — the great python, spirit of the ancestors. Being seen near an ancestral burial site signals that a protective message has arrived.' } },
    ],
    myths: [
      { tr: 'Apollon Delphi\'ye geldiğinde orası Python\'un egemenliğindedir — toprağın, bilinçdışının, ham kehanetin krallığı. Apollon Python\'u öldürür ve mabedi kurar. Ama kehanetin ruhu kaybolmaz: Pythia, Python\'un nefesinin çıktığı yarıktan yükselen buharı içerek kehanet söyler. Öldürülen güç, taşıyıcı değişince de konuşmaya devam eder.', en: 'When Apollo arrives at Delphi it is under the sovereignty of Python — the kingdom of earth, the unconscious, raw prophecy. Apollo slays Python and builds the temple. But the spirit of prophecy does not vanish: the Pythia speaks prophecy breathing the vapors rising from the fissure where Python\'s breath emerged. The slain power continues to speak even as the carrier changes.' },
      { tr: 'Zulu geleneğinde bir savaşçı, pitonun köy yakınında göründüğünü söyler. Köylüler korkar, onu öldürmek ister. Yaşlı şaman durur: "Bu Python, dedenin ruhudur. Sizi uyarıyor." O gece köy ateş tehlikesinden kurtulur. Piton ertesi sabah kaybolmuştur; ama onun gittiği yöne bir su kaynağı bulunur.', en: 'In Zulu tradition a warrior reports a python seen near the village. The villagers are afraid and want to kill it. The elder shaman stops them: "This python is the spirit of your grandfather. It is warning you." That night the village is saved from the danger of fire. By morning the python has gone; but in the direction it left, a water source is found.' },
    ],
  },

  // ─── a087 Albatros ──────────────────────────────────────────────────────
  a087: {
    jung: { tr: '"Sonsuz Yolcu" ve "Rüzgâr Gezgini" arketipi. Albatros, hedef olmaksızın yolun kendisi olan, varışa değil yolculuğa teslim olmuş bilinçdışı özgürlük dürtüsünü simgeler. Jung\'un "individuasyon" yolculuğunu en isabetli imgeleyen hayvan — yıllarca okyanusta, kıyıya değmeden uçar.', en: '"Eternal Wanderer" and "Wind Traveler" archetype. The albatross symbolizes the unconscious impulse of freedom that is the path itself without destination, surrendered not to arrival but to the journey. The animal that most aptly images Jung\'s "individuation" journey — it flies for years over the ocean, never touching shore.' },
    dream: { tr: 'Albatros rüyada — uzun ve yorucu bir yolculuğun tam ortasındasın. Süzülüyorsa: çaba değil teslim, rüzgâra bırak kendini. Yorgunsa ve alçak uçuyorsa: dinlenme vakti; güç toplamadan ilerleyemezsin.', en: 'Albatross in dream — you are right in the middle of a long and exhausting journey. If it glides: not effort but surrender, release yourself to the wind. If it is weary and flying low: time to rest; you cannot move forward without gathering strength.' },
    shadow: { tr: 'Köksüzlük ve yüzeysel özgürlük. Albatros enerjisi sapkınlaştığında, kişi hiçbir yere konmaz, hiçbir şeyle kök salmaz — derinliği olmayan bir gezginliğe sığınır. Bağ kurmaktan kaçınmak "özgürlük" diye sunulur.', en: 'Rootlessness and superficial freedom. When albatross energy turns perverse, the person lands nowhere, roots in nothing — takes refuge in a wandering that has no depth. Avoidance of forming bonds is presented as "freedom."' },
    whenAppears: { tr: 'Uzun bir süreç ya da ilişkinin ortasında tükendiğinde; hayatının büyük bir bölümünün anlamını sorguladığında.', en: 'When you are exhausted in the middle of a long process or relationship; when you question the meaning of a large portion of your life.' },
    traditions: [
      { culture: { tr: 'Denizci Geleneği', en: 'Sailor Tradition' }, meaning: { tr: 'Albatros, denizde ölen denizcilerin ruhunu taşır — öldürülmesi büyük uğursuzluk getirir. Coleridge\'in Eski Denizci\'sinde bu inanç trajik olarak işlenir.', en: 'The albatross carries the souls of sailors who died at sea — killing one brings great misfortune. This belief is tragically explored in Coleridge\'s Rime of the Ancient Mariner.' } },
      { culture: { tr: 'Polinesya', en: 'Polynesian' }, meaning: { tr: 'Büyük kanatla uçan kuşlar, deniz yolcularına yön gösterir. Albatros varlığı, karaya yaklaşıldığını ya da güvenli suyun işaretini verir.', en: 'Birds flying with great wings guide ocean voyagers. The presence of the albatross signals that land is near or marks safe water.' } },
      { culture: { tr: 'İngiliz Romantizmi', en: 'English Romanticism' }, meaning: { tr: 'Coleridge — "Eski Denizci\'nin Türküsü": Bir denizci albatrosu öldürür; lanet başlar. Doğa ile insanlık arasındaki ahdin ihlali, yalnızlık ve sürgünü getirir.', en: 'Coleridge — "The Rime of the Ancient Mariner": A sailor kills an albatross; the curse begins. Violation of the covenant between nature and humanity brings solitude and exile.' } },
      { culture: { tr: 'Maori', en: 'Māori' }, meaning: { tr: 'Toroa — dev albatros. Tangaroa\'nın, deniz tanrısının temsilcisi. Okyanusun sınırsızlığını ve atalar ruhunu taşır.', en: 'Toroa — the great albatross. Representative of Tangaroa, god of the sea. Carries the boundlessness of the ocean and the spirit of ancestors.' } },
      { culture: { tr: 'Bilimsel Gözlem', en: 'Scientific Observation' }, meaning: { tr: 'Albatros, rüzgâr olmadan hareket etmez — "dinamik süzülme" denen teknikle, sıfır kas enerjisiyle binlerce kilometre kat eder. Doğanın mükemmel verimliliği.', en: 'The albatross does not move without wind — using a technique called "dynamic soaring," it covers thousands of kilometers with zero muscular energy. Nature\'s perfect efficiency.' } },
    ],
    myths: [
      { tr: 'Coleridge\'in şiirinde Eski Denizci, yolculuklarında kendisine eşlik eden albatrosu hiç sebep vermeksizin öldürür. Mürettebat önce kızar, sonra fırtınanın durmasıyla denizciye hak verir. Ama denizci lanetlenmiştir: tüm arkadaşları ölür, o yaşar — boynunda albatrosu ile. Lanet, ancak başka canlıları kalp dolusu sevdiğinde çözülür. Suç değil sevememe; arınma değil sevinçle sevmek.', en: 'In Coleridge\'s poem the Ancient Mariner kills the albatross that accompanied him on his voyages for no reason. The crew first grows angry, then vindicates the sailor when the storm stops. But the mariner is cursed: all his companions die, he lives — with the albatross around his neck. The curse is lifted only when he loves other creatures with a full heart. Not the crime but the inability to love; not purification but loving with joy.' },
      { tr: 'Polinesya yolculuk mitlerinde büyük kanatçılar, bir adadan ötekine giden kanoculara eşlik eder. Bir efsaneye göre bir denizci kaybolmuş ve üç gün yön bulamazken, ufukta beliren tek albatros onu kıyıya götürür. Denizci döndüğünde albatrosun gözünde babasının bakışını gördüğünü anlatır.', en: 'In Polynesian voyage myths, great-winged birds accompany canoe paddlers from one island to the next. According to one legend, a sailor who is lost and cannot find direction for three days is led to shore by a single albatross appearing on the horizon. When the sailor returns he says he saw his father\'s gaze in the albatross\'s eye.' },
    ],
  },

  // ─── a088 Flamingo ──────────────────────────────────────────────────────
  a088: {
    jung: { tr: '"Zarafet" ve "Topluluk Dengesi" arketipi. Flamingo, bireyselliği yok etmeden topluluğun ritminde bütünleşen, hem estetik hem sosyal bilinci simgeler. Jung\'un "persona" ile "gerçek benlik" arasındaki ince denge — toplulukla dans ederken kendini kaybetmemek.', en: '"Grace" and "Community Balance" archetype. The flamingo symbolizes both aesthetic and social consciousness that integrates into the rhythm of community without erasing individuality. The fine balance between Jung\'s "persona" and "true self" — not losing oneself while dancing with the community.' },
    dream: { tr: 'Flamingo rüyada — topluluk içindeki yerine dair mesajlar var. Pembe toplu dans ediyorsa: topluluğuna katıl, uyum gücünü küçümseme. Tek başına solgunsa: kendini bastırarak uyum sağlamaya çalışıyorsun.', en: 'Flamingo in dream — there are messages about your place within community. If they dance pink together: join your community, do not underestimate the power of harmony. If alone and faded: you are trying to conform by suppressing yourself.' },
    shadow: { tr: '"Hep birlikte" baskısı ve farklılığın yok edilmesi. Flamingo enerjisi sapkınlaştığında, topluluk adına bireysel ses bastırılır. "Herkes böyle" çoğulculuğu, gerçek dönüşümü engeller. Pembe görünmek zorunlu olur.', en: 'The pressure of "all together" and the erasure of difference. When flamingo energy turns perverse, the individual voice is suppressed in the name of community. The pluralism of "everyone does so" blocks genuine transformation. Appearing pink becomes compulsory.' },
    whenAppears: { tr: 'Bir gruba ait olup olmama sorusunu yaşarken; kendini göstermek ile uyum arasında sıkışıp kaldığında.', en: 'While living the question of whether to belong to a group; when you are caught between showing yourself and conforming.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Ra\'nın erken biçimi flamingo olarak tasvir edilmiştir. Kızıl-pembe rengi, doğan güneşin alevini simgeler — gün başlangıcının kuşu.', en: 'An early form of Ra was depicted as a flamingo. Its red-pink color symbolizes the flame of the rising sun — the bird of the day\'s beginning.' } },
      { culture: { tr: 'Aztek', en: 'Aztec' }, meaning: { tr: 'Quetzal\'ın pembe kardeşi olarak görülen flamingo, adak törenlerinde soyluluğu ve güneşin yeryüzündeki yansımasını simgeler.', en: 'Seen as the pink sibling of the quetzal, the flamingo symbolizes nobility and the earth\'s reflection of the sun in offering ceremonies.' } },
      { culture: { tr: 'Hint', en: 'Indian' }, meaning: { tr: 'Hans — ruhsal saflığın kuşu. Beyaz veya pembe rengiyle maddi kirlilikten arınmış zihin halini simgeler; bilge kişi "hansa" olarak anılır.', en: 'Hans — the bird of spiritual purity. With its white or pink color it symbolizes a mental state purified of material impurity; a wise person is called "hansa."' } },
      { culture: { tr: 'Karayip', en: 'Caribbean' }, meaning: { tr: 'Bahamalar\'ın ulusal kuşu. Lagün sularının pembeye boyandığı manzara, cömertliğin ve bolluğun imgesidir.', en: 'National bird of the Bahamas. The landscape of lagoon waters dyed pink is an image of generosity and abundance.' } },
      { culture: { tr: 'Modern Sembolizm', en: 'Modern Symbolism' }, meaning: { tr: 'Flamingo, 1950\'lerden itibaren pop kültürde eğlence, zarafet ve anti-konformizmin ironik simgesi olmuştur — toplu uyumun içinde bireysel estetik jest.', en: 'Since the 1950s the flamingo has become an ironic symbol of amusement, grace, and anti-conformism in pop culture — an individual aesthetic gesture within collective conformity.' } },
    ],
    myths: [
      { tr: 'Mısır mitinde Ra\'nın ilk biçimi, kılıçbaltası gaga taşıyan pembe bir kuştu. Nun\'un ilk sularından yükseldiğinde, kanadını çırpması güneşin ilk ışıklarını yarattı. O zamandan beri flamingo her şafakta o ilk anı hatırlar ve rengini güneşe borçlu olduğunu bilir.', en: 'In Egyptian myth Ra\'s first form was a pink bird bearing a scimitar beak. When it rose from the primordial waters of Nun, its wing beat created the first rays of sunlight. Since then the flamingo remembers that first moment at every dawn and knows it owes its color to the sun.' },
      { tr: 'Bir Karayip efsanesine göre flamingolar eski bir göçün kaybolan halkının ruhlarıdır. Denizde boğulanlar, günbatımının rengine boyanmış kuşlara dönüşür. Toplu dans ettiklerinde atalarını anarlar; tek kaldıklarında o kayboluşun acısını taşırlar. Bu yüzden flamingo hiçbir zaman tam yalnız kalmak istemez.', en: 'According to a Caribbean legend, flamingos are the souls of a lost people from an ancient migration. Those who drowned at sea transform into birds dyed in the color of sunset. When they dance together they honor their ancestors; when alone they carry the pain of that disappearance. This is why the flamingo never wishes to be completely alone.' },
    ],
  },

  // ─── a089 Manta Vatoz ───────────────────────────────────────────────────
  a089: {
    jung: { tr: '"Derinlik Yolcusu" ve "Özgür Ruh" arketipi. Manta vatoz, bilinçdışının en derin, en karanlık sularında akıntıya direnmeden süzülme becerisini simgeler. Jung\'un "okyanusal duygu" kavramıyla örtüşür — sınırların eridiği, benliğin evrensele açıldığı o geniş su altı sessizliği.', en: '"Depth Traveler" and "Free Spirit" archetype. The manta ray symbolizes the ability to glide without resisting the current in the deepest, darkest waters of the unconscious. It overlaps with Jung\'s concept of "oceanic feeling" — that vast underwater silence where boundaries dissolve and the self opens to the universal.' },
    dream: { tr: 'Manta vatoz rüyada — derin duygusal sularda bir yolculuk var. Kanatlarını açıp yavaş süzülüyorsa: teslim ol, akışa bırak kendini, mücadele etme. Suyun yüzeyine çıkıp atlıyorsa: bilinçdışından bir gerçek yüzeye vurmak üzere.', en: 'Manta ray in dream — there is a journey in deep emotional waters. If it opens wings and glides slowly: surrender, release yourself to the flow, do not struggle. If it breaches the surface and leaps: a truth from the unconscious is about to surface.' },
    shadow: { tr: 'Derinliğe kaçış ve gerçeklikten kopuş. Manta enerjisi sapkınlaştığında, kişi yüzeyde yaşamı reddeder ve sürekli "daha derin" bir anlam arar — gündelik sorumluluktan, ilişkilerden ve bedensellikten kaçış mistik bir kılık giyer.', en: 'Escape into depth and disconnection from reality. When manta energy turns perverse, the person rejects life on the surface and constantly seeks a "deeper" meaning — escape from everyday responsibility, relationships, and embodiment wears a mystical disguise.' },
    whenAppears: { tr: 'Duygusal bir konuyu bastırıp bastırmadığını sorguladığında; hayatın büyük akışına kendini bırakmakla kontrol arasında kaldığında.', en: 'When you question whether you are suppressing an emotional subject; when you are caught between surrendering to the great flow of life and maintaining control.' },
    traditions: [
      { culture: { tr: 'Polinesya', en: 'Polynesian' }, meaning: { tr: 'Manta vatoz, Tangaroa\'nın — deniz tanrısının — elçisi. Deniz yolculuklarında görülmesi iyi hava ve güvenli geçişin işareti.', en: 'The manta ray is the messenger of Tangaroa — god of the sea. Sighting one during ocean voyages is a sign of good weather and safe passage.' } },
      { culture: { tr: 'Meksika-Pasifik', en: 'Mexican-Pacific' }, meaning: { tr: 'Mantanın kanatlarını açık uçuşu, okyanusun "uçan kardeşi" olarak görülür. Balıkçılar mantayı selamlayarak okyanus ruhunu onurlandırır.', en: 'The manta\'s open-winged flight is seen as the ocean\'s "flying sibling." Fishermen greet the manta to honor the ocean spirit.' } },
      { culture: { tr: 'Endonezya', en: 'Indonesian' }, meaning: { tr: 'Komodo adaları çevresinde manta, ata ruhunu taşıdığına inanılan kutsal hayvan. Zarar vermek yasaktır; onunla yüzmek kutsama sayılır.', en: 'Around the Komodo islands, the manta is a sacred animal believed to carry ancestral spirit. Harming one is forbidden; swimming with one is considered a blessing.' } },
      { culture: { tr: 'Modern Okyanografi', en: 'Modern Oceanography' }, meaning: { tr: 'Manta vatozun beyninin oransal büyüklüğü, balıklar arasında en yüksek olanlardan biridir. Ayna testinde kendini tanıyan nadir canlılardandır — derin zekânın simgesi.', en: 'The proportional brain size of the manta ray is among the highest of any fish. It is one of the rare creatures that recognizes itself in the mirror test — a symbol of deep intelligence.' } },
      { culture: { tr: 'Japon', en: 'Japanese' }, meaning: { tr: 'Okinawa balıkçı geleneklerinde manta "denizin hâkimi" olarak adlandırılır. Rüyada görülmesi, bir yolculuğun ya da büyük bir kararın eşiğinde olunduğunu gösterir.', en: 'In Okinawa fishing traditions the manta is called "sovereign of the sea." Seeing one in dream signals that one stands on the threshold of a journey or major decision.' } },
    ],
    myths: [
      { tr: 'Polinesya deniz mitolojisinde Tangaroa bir gün okyanusun dibine iner ve orada hiçbir ışık olmadan yaşayan varlıkları bulur. En büyüğü, kanatlarını okyanusun tabanına açmış bir Manta vatozdur. Tangaroa sorar: "Işıksız nasıl yaşarsın?" Manta cevaplar: "Işık arama, dalga ol." O günden beri manta, karanlık sulardaki bilgeliğin simgesidir.', en: 'In Polynesian sea mythology, Tangaroa one day descends to the ocean\'s floor and finds beings living there without any light. The greatest of them is a Manta ray with wings spread across the ocean floor. Tangaroa asks: "How do you live without light?" The manta answers: "Do not seek light, be the wave." From that day the manta has been the symbol of wisdom in dark waters.' },
      { tr: 'Bir Meksika balıkçı hikâyesinde genç bir denizci büyük fırtınada kaybolur. Üç gün sonra kıyıya döner ve dev bir manta vatozun sırtında denizi geçtiğini anlatır. Kimse inanmaz. Ama sonraki yıl aynı manta, bu kez bir başka kayık içindeki çocuğu güvene taşır. Bazı şeyler inanılmak için değil, yaşanmak için vardır.', en: 'In a Mexican fisherman\'s story, a young sailor is lost in a great storm. Three days later he returns to shore and tells of crossing the sea on the back of a giant manta ray. No one believes him. But the following year the same manta carries a child in another stranded boat to safety. Some things exist not to be believed, but to be lived.' },
    ],
  },

  // ─── a090 Yele Kurdu ────────────────────────────────────────────────────
  a090: {
    jung: { tr: '"Yalnız Kahraman" ve "Köprü Kurucu" arketipi. Yele kurdu, ne tam sürüye ne tam yabana ait olan, bu araf konumuyla iki dünyanın arasındaki geçişi mümkün kılan enerjiyi simgeler. Jung\'un "individue" figürü — toplumdan ayrışmadan özgünleşen, sınır koruyucu.', en: '"Solitary Hero" and "Bridge Builder" archetype. The maned wolf symbolizes the energy that belongs neither fully to the pack nor fully to the wild, and through this liminal position makes passage between two worlds possible. Jung\'s "individual" figure — becoming authentic without separating from society, the boundary guardian.' },
    dream: { tr: 'Yele kurdu rüyada — ait olmama hissini taşıyorsun ama bu yalnızlık güçtür. Koşuyorsa ve yalnızsa: özgün yolunda devam et, sürü seni yavaşlatır. Sana bakıyorsa ve gözleri parlıyorsa: kendi özgünlüğünü görme vakti geldi.', en: 'Maned wolf in dream — you carry the feeling of not belonging but this solitude is strength. If it runs and is alone: continue on your authentic path, the pack will slow you down. If it looks at you and its eyes gleam: the time has come to see your own uniqueness.' },
    shadow: { tr: 'Cronizm ve anlaşılamamışlık saplantısı. Yele kurdunun "ne sürü ne yabani" enerjisi sapkınlaştığında, kişi hiçbir yere ait olmama acısını kronik yalnızlık ve başkalarını anlayamama biçiminde yaşar. "Kimse beni anlamaz" anlatısı, gerçek bağ kurmanın önüne geçer.', en: 'Chronicism and obsession with being misunderstood. When the maned wolf\'s "neither pack nor wild" energy turns perverse, the person experiences the pain of belonging nowhere as chronic loneliness and inability to understand others. The narrative "no one understands me" blocks the formation of genuine bonds.' },
    whenAppears: { tr: 'Hiçbir kategoriye uymadığını fark ettiğinde; özgün bir yol açmak zorunda olduğunu bildiğin ama yalnızlığından korktuğun anlarda.', en: 'When you realize you fit no category; in moments when you know you must open an original path but fear your solitude.' },
    traditions: [
      { culture: { tr: 'Brezilya', en: 'Brazilian' }, meaning: { tr: 'Guará — Cerrado\'nun sembolü, sınır hayvanı. Ne kurt ne tilki. Brezilya halk inanışında hem şifacı hem tehlikeli, hem ormancı hem savanacı.', en: 'Guará — symbol of the Cerrado, the border animal. Neither wolf nor fox. In Brazilian folk belief, both healer and dangerous, both forest dweller and savanna creature.' } },
      { culture: { tr: 'Guaraní Yerli Kültürü', en: 'Guaraní Indigenous Culture' }, meaning: { tr: 'Yele kurdu, ruhların taşıyıcısı. Ormanlıktan savana geçerken ata ruhlarına eşlik eder. Görülmesi, dönüşümün habercisi sayılır.', en: 'The maned wolf is a carrier of spirits. It accompanies ancestral spirits in passing from forest to savanna. Being sighted is considered a herald of transformation.' } },
      { culture: { tr: 'Bilimsel Gözlem', en: 'Scientific Observation' }, meaning: { tr: '"Tek tür cins" — Chrysocyon brachyurus. Ne Canis ailesinde ne başka bir grupta. Evrimsel yalnızlık; en yakın akrabasından 6 milyon yıl önce ayrılmış.', en: '"Single species genus" — Chrysocyon brachyurus. Neither in the Canis family nor in any other group. Evolutionary solitude; separated from its nearest relative 6 million years ago.' } },
      { culture: { tr: 'Modern Koruma Etiği', en: 'Modern Conservation Ethics' }, meaning: { tr: 'Yele kurdu, biyoçeşitlilik göstergesi — Cerrado ekosistemi sağlıklıysa o orada. Kayboluşu tüm ekosistemin krizi demektir; köprü olmadan iki taraf da çöker.', en: 'The maned wolf is a biodiversity indicator — if the Cerrado ecosystem is healthy, it is there. Its disappearance means crisis for the entire ecosystem; without the bridge both sides collapse.' } },
      { culture: { tr: 'Şaman Geleneği — Güney Amerika', en: 'Shamanic Tradition — South America' }, meaning: { tr: 'Yele kurdu şamanın yol hayvanı. Sınır geçişlerinde, iki dünya arasındaki geçişlerde şamana rehberlik eden köprü varlığı.', en: 'The maned wolf is the shaman\'s path animal. The bridge being that guides the shaman through border crossings, in transitions between two worlds.' } },
    ],
    myths: [
      { tr: 'Guaraní geleneğinde yele kurdu, yaratılışın tamamlanmamış bir parçasıdır. Tanrı Ñamandú her hayvanı bir kategoriye koyarken, yele kurdunu tam yaratmayı unutur. Ama bu "unutuluş" onu özgür kılar: ne sürüde ne tümüyle yalnız, ne ormanda ne savanada — iki dünyanın tüm bilgisini taşır ve bu yüzden şifacıdır.', en: 'In Guaraní tradition the maned wolf is an uncompleted piece of creation. While the god Ñamandú places every animal into a category, he forgets to finish creating the maned wolf. But this "forgetting" sets it free: neither in the pack nor entirely alone, neither in forest nor savanna — it carries the full knowledge of two worlds and for this reason it is a healer.' },
      { tr: 'Bir Brezilya efsanesine göre Cerrado\'nun ruhları bir gün toplanır ve en büyük tehlikeyi konuşur. Ormandan savanaya geçen yangın her şeyi yakacaktır. Küçük hayvanlar panikler, büyük hayvanlar kaçar. Yalnızca yele kurdu, iki bölgeyi de bilen tek varlık olarak, bir su yolu keşfeder ve iki halkı birbirine bağlar. Yangın geçer; yele kurdu ne bir tarafın ne ötekinin kahramanıdır — yalnızca köprüdür.', en: 'According to a Brazilian legend, the spirits of the Cerrado gather one day and speak of the greatest danger. A fire crossing from forest to savanna will burn everything. Small animals panic, large animals flee. Only the maned wolf, as the single being who knows both regions, discovers a waterway and connects the two peoples to each other. The fire passes; the maned wolf is neither the hero of one side nor the other — it is simply the bridge.' },
    ],
  },

  // ─── a091 Ateş Kuşu ─────────────────────────────────────────────────────
  a091: {
    jung: { tr: '"Arzu ve İlham" arketipi. İçteki yaratıcı ateşin kişileşmiş hâli — bastırıldığında söner, serbest bırakıldığında dünyayı aydınlatır. Ateş Kuşu, ruhun en canlı anını simgeler: peşinden koşmayı hak ettiğin o şeyin kendisi.', en: '"Desire and Inspiration" archetype. The personified form of the inner creative fire — when suppressed it dims, when released it illuminates the world. The Firebird embodies the most vivid moment of the soul: the very thing you deserve to pursue.' },
    dream: { tr: 'Ateş Kuşu rüyada — içindeki bir arzunun artık susturulamayacağının işareti. Uzaklaşıyorsa: onu kovalamaktan vazgeçiyorsun; yaklaşıyorsa: ilham kapına gelmiş, kapıyı açmak sana kalmış.', en: 'The Firebird in dream — a sign that a desire within you can no longer be silenced. If it flies away: you are giving up the chase; if it approaches: inspiration has come to your door, opening it is up to you.' },
    shadow: { tr: 'Ateşin yıkıcı yüzü: arzu bir tutkuya değil, bir saplantıya dönüştüğünde her şeyi yakar. Başkalarının enerjisini tüketmek ya da kendi hayalinde kaybolup somut adım atmamak — Ateş Kuşu\'nun gölgesidir.', en: 'The destructive face of fire: when desire turns not into passion but obsession, it burns everything. Consuming others\' energy or losing oneself in one\'s own dream without taking concrete steps — these are the shadows of the Firebird.' },
    whenAppears: { tr: 'Yıllardır ertelediğin bir hayalin kapısında durduğunda, ya da bir tutkuyu "bana göre değil" diyerek içine gömdüğünde.', en: 'When you stand at the door of a dream you have postponed for years, or when you bury a passion inside yourself saying "it\'s not for me".' },
    traditions: [
      { culture: { tr: 'Slav Mitolojisi', en: 'Slavic Mythology' }, meaning: { tr: 'Zhar-Ptitsa — tüyleri şans ve lanet getiren, yakalanması imkânsız ışık kuşu.', en: 'Zhar-Ptitsa — the luminous bird whose feathers bring fortune and curse alike, impossible to capture.' } },
      { culture: { tr: 'Japon', en: 'Japanese' }, meaning: { tr: 'Hō-ō (Feniks) — dürüstlük ve refahın habercisi; yalnızca erdemli bir hükümdar döneminde görünür.', en: 'Hō-ō (Phoenix) — herald of virtue and prosperity; seen only in the reign of a righteous ruler.' } },
      { culture: { tr: 'Türk-Altay Şamanizmi', en: 'Turkic-Altaic Shamanism' }, meaning: { tr: 'Alev ruhlu kuş — şamanın gökyüzü yolculuğunda rehberi; ilham ruhunun dışa vurumu.', en: 'The flame-souled bird — guide of the shaman\'s celestial journey; the outward expression of the spirit of inspiration.' } },
      { culture: { tr: 'Hint', en: 'Indian' }, meaning: { tr: 'Garuda\'nın ateş formu — tanrısal gücün ve yaratıcı enerjinin taşıyıcısı.', en: 'The fire form of Garuda — carrier of divine power and creative energy.' } },
      { culture: { tr: 'İran Mitolojisi', en: 'Iranian Mythology' }, meaning: { tr: 'Hüma kuşu — başının üzerinden geçtiği kişiyi tahta çıkaran, hükümdarlık kaderini ateşleyen kuş.', en: 'The Huma bird — the bird that crowns whoever passes beneath its shadow, igniting the destiny of kingship.' } },
    ],
    myths: [
      { tr: 'Rus masalında Ivan Çareviç, Ateş Kuşu\'nun düşürdüğü bir tüyü bulur. Babası onu getirmesini ister — bu yolculuk onu dünyanın ucuna götürür, imkânsız görevler verilir. Her seferinde tüyü bırakmayı düşünür ama içindeki o küçük ışık onu ileri iter. Kuşu yakalar; ama artık kuş değil, kendi cesareti ödüldür.', en: 'In a Russian tale, Ivan Tsarevich finds a feather dropped by the Firebird. His father bids him bring the bird — the journey takes him to the ends of the earth, impossible tasks are set before him. Each time he thinks of abandoning the feather, yet that small inner light pushes him forward. He captures the bird; but by then, the prize is not the bird — it is his own courage.' },
      { tr: 'Anadolu ozanları Ateş Kuşu\'nu içteki ilham sesine benzetir: "Onu bir kez görürsen artık sıradan hayata dönemezsin." Görmek bile insanı dönüştürür; çünkü arzu, onu taşıyan kişinin bizzat kendisidir.', en: 'Anatolian bards liken the Firebird to the voice of inner inspiration: "Once you have seen it, you can no longer return to an ordinary life." Even the seeing transforms a person; for desire is none other than the one who carries it.' },
    ],
  },

  // ─── a092 Deve Kuşu ──────────────────────────────────────────────────────
  a092: {
    jung: { tr: '"Gerçekle Yüzleşme" arketipi. Deve Kuşu\'nun başını kuma gömmesi bir efsanedir — gerçekte en hızlı kaçan değil, en sert koşan o\'dur. Psikolojik olarak: topraktan güç alan, gerçeği ne kadar ağır olursa olsun taşıma kapasitesini simgeler.', en: '"Confronting Reality" archetype. The ostrich burying its head in the sand is a myth — in truth it is not the fastest to flee, but the hardest to run. Psychologically: it embodies drawing power from the earth, the capacity to carry truth no matter how heavy.' },
    dream: { tr: 'Deve Kuşu rüyada — kaçınmakta olduğun bir gerçeğin varlığına işaret eder. Koşuyorsa: yüzleşme zamanı gelmiş, hız senin yanındadır; bekliyor ya da duruyorsa: saklamaya çalıştığın şey zaten görünüyor.', en: 'The ostrich in dream — points to the presence of a truth you are avoiding. If it runs: the time for confrontation has come, speed is on your side; if it stands still or waits: what you try to hide is already visible.' },
    shadow: { tr: '"Baş kuma gömme" sendromu — sorunları görmezden gelerek büyümelerine izin vermek. Deve Kuşu gölgesindeki kişi kriz çıkmadan önce işaret fişeklerini fark etmeyi reddeder; toprak gücünü savunmaya değil inkâra kullanır.', en: 'The "head in the sand" syndrome — ignoring problems and allowing them to grow. The person in ostrich\'s shadow refuses to notice the warning signals before a crisis erupts; uses the power of earth not for defense but for denial.' },
    whenAppears: { tr: 'Uzun süredir görmezden geldiğin bir durumun artık kaçınılmaz hale geldiği anlarda; gerçeği söylemenin ya da duymanın tam sırası olduğunda.', en: 'At the moments when a situation you have long ignored becomes unavoidable; when it is exactly time to speak or hear the truth.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Deve Kuşu tüyü Ma\'at\'ın sembolüydü — ölçekte ruha karşı tartılırdı; eşit ağırlıkta olan ruh arınmış sayılırdı.', en: 'The ostrich feather was the symbol of Ma\'at — weighed against the soul on the scales; the soul balanced by it was deemed pure.' } },
      { culture: { tr: 'Afrika (Maasai)', en: 'African (Maasai)' }, meaning: { tr: 'Deve Kuşu yumurtası doğurganlık ve uzun ömür armağanı olarak kabul edilir; büyük törenlerde sunulur.', en: 'The ostrich egg is regarded as a gift of fertility and long life; offered at great ceremonies.' } },
      { culture: { tr: 'Arap Kültürü', en: 'Arab Culture' }, meaning: { tr: '"Devekuşu aklı" deyimi kararlılıkla hareket etmek yerine bekleyip seyretmeyi anlatır — ama deve kuşu aslında en hızlı kara kuşudur.', en: 'The expression "ostrich mind" describes watching and waiting instead of acting decisively — yet the ostrich is in fact the fastest of all land birds.' } },
      { culture: { tr: 'Roma', en: 'Roman' }, meaning: { tr: 'Romalılar deve kuşunu dayanıklılığın simgesi olarak ziyafetlerde sunardı; sindiremeyeceği hiçbir şey yok denirdi.', en: 'Romans offered ostrich at feasts as a symbol of endurance; it was said there was nothing it could not digest.' } },
      { culture: { tr: 'Hristiyanlık (Orta Çağ)', en: 'Christianity (Medieval)' }, meaning: { tr: 'Ortaçağ ressamları deve kuşunu terk edilmiş yumurtasıyla çizerdi — insanın ilahi ilgiyi unutması metaforu.', en: 'Medieval painters depicted the ostrich with its abandoned egg — a metaphor for humanity forgetting divine attention.' } },
    ],
    myths: [
      { tr: 'Afrika\'nın bir efsanesine göre deve kuşu eskiden uçabilirdi. Ama bir gün gökyüzünden yere bir çocuğun ağlamasını duydu, indi ve bir daha çıkamadı. Toprak onu tuttu — çünkü merhametle yere inen, artık toprağın gücünü taşır.', en: 'According to an African legend the ostrich could once fly. But one day it heard a child crying from the earth below, descended, and could never rise again. The earth held it — for one who descends with compassion henceforth carries the power of the earth.' },
    ],
  },

  // ─── a093 Kilin ──────────────────────────────────────────────────────────
  a093: {
    jung: { tr: '"Kutsal Nadir" arketipi. Kilin varlığı bile bir lütuf sayılır; Jung\'un "numinous" kavramını cisimleştirir — karşılaşıldığında akıl susar, yalnızca hayret konuşur. Dürüstlüğün ve içsel erdeminun dışa vurumudur: görünmez olmak için değil, yalnızca hazır olanların görebileceği şekilde var olmak.', en: '"Sacred Rarity" archetype. Even the existence of the qilin is considered a grace; it embodies Jung\'s concept of the "numinous" — when encountered, reason falls silent, only wonder speaks. It is the outward form of honesty and inner virtue: not to be invisible, but to exist in a way that only those who are ready can perceive.' },
    dream: { tr: 'Kilin rüyada — olağanüstü bir dönemin eşiğindesin ya da hayatına kutsal bir varlık giriyor. Uzaktan görüyorsan: erdem kazanmaya henüz başlıyorsun; yanına geliyorsa: ruhun olgunlaşmış, saf olanı çekmeye hazır.', en: 'The qilin in dream — you stand on the threshold of an extraordinary period, or a sacred presence is entering your life. If you see it from afar: you are just beginning to earn virtue; if it approaches: your spirit has matured, ready to attract what is pure.' },
    shadow: { tr: 'Nadirliği bir kibire dönüştürmek: "Ben seçilmişim, sıradan insanlar beni anlayamaz" yanılgısı. Kilin gölgesi, erdemi performansa çeviren kişide yaşar — gösteriş için dürüst olan, dürüstlüğünü kaybetmiş demektir.', en: 'Turning rarity into arrogance: the delusion of "I am chosen, ordinary people cannot understand me." The shadow of the qilin lives in the one who turns virtue into performance — one who is honest for show has already lost their honesty.' },
    whenAppears: { tr: 'Uzun bir arayıştan sonra gerçek bir bilginin ya da eşin hayatına girdiğinde; sahici erdem ile gösterişli erdemin arasını ayırt etmen gereken anlarda.', en: 'When a truly wise person or soulmate enters your life after a long search; at the moments you must distinguish genuine virtue from its performance.' },
    traditions: [
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Kilin — Dört Kutsal Hayvan\'dan biri; yalnızca erdemli bir hükümdarın saltanatında belirir, ot bile çiğnemez.', en: 'The Qilin — one of the Four Sacred Creatures; appears only in the reign of a virtuous ruler, and does not even trample grass.' } },
      { culture: { tr: 'Japon', en: 'Japanese' }, meaning: { tr: 'Kirin — uzun ömür, bereket ve iyi yönetimin simgesi; görülmesi bir kehanet gibi yorumlanır.', en: 'Kirin — symbol of longevity, abundance, and good governance; its sighting is interpreted as a prophecy.' } },
      { culture: { tr: 'Kore', en: 'Korean' }, meaning: { tr: 'Girin — efsanevi adaletli liderlerin doğumunu müjdeleyen kutsal varlık.', en: 'Girin — the sacred being that heralds the birth of legendarily just leaders.' } },
      { culture: { tr: 'Vietnam', en: 'Vietnamese' }, meaning: { tr: 'Kỳ lân — halk şenliklerinde saf niyetin ve bereketin dansçısı olarak kutlanır.', en: 'Kỳ lân — celebrated in folk festivals as the dancer of pure intention and abundance.' } },
      { culture: { tr: 'Türk-Çin İpek Yolu Kültürü', en: 'Turkic-Chinese Silk Road Culture' }, meaning: { tr: 'Kilin imgesi İpek Yolu kervanlarında uğur sembolü olarak taşınırdı — ticaretin dürüstlüğünün koruyucusu.', en: 'The image of the qilin was carried by Silk Road caravans as a talisman of good fortune — guardian of honesty in trade.' } },
    ],
    myths: [
      { tr: 'Konfüçyüs\'ün annesi, doğumdan önce kilinle karşılaştığını ve hayvanın ona bir jade tablet bıraktığını söyler. Üzerinde "Sui\'nin oğlu, taht devrildiğinde kristal gibi bir kral olacak" yazıyordu. Konfüçyüs dünyaya geldi; ama kral olmadı — bilgeliğiyle bütün bir medeniyetin tahtını kurdu.', en: 'Confucius\'s mother says that before his birth she encountered a qilin, and the creature left her a jade tablet. On it was written: "Son of Sui, when the throne falls, he shall be a king of crystal." Confucius was born; but he became no king — with his wisdom he built the throne of an entire civilization.' },
    ],
  },

  // ─── a094 Su Aygırı ──────────────────────────────────────────────────────
  a094: {
    jung: { tr: '"Dişil Güç ve Doğum" arketipi. Su Aygırı, Büyük Ana\'nın su altındaki yüzüdür — hem besleyici hem sınır koyan, hem doğuran hem koruyandır. Sular üzerindeki egemenliği, dişil bilincin bilinçdışı derinliklerini yönetme kapasitesini temsil eder.', en: '"Feminine Power and Birth" archetype. The hippo is the submerged face of the Great Mother — both nourishing and boundary-setting, both birth-giving and protective. Its sovereignty over the waters represents the feminine mind\'s capacity to govern the depths of the unconscious.' },
    dream: { tr: 'Su Aygırı rüyada — ana karnındaki bir yaratıcılık ya da proje; ya da sınırlarının çiğnendiğinin işareti. Saldırıyorsa: güç alanın ihlal edilmiş, kendini savunma zamanı; suda sessizce duruyorsa: derinlerde bir şey olgunlaşıyor.', en: 'The hippo in dream — a creativity or project still in the womb; or a sign that your boundaries are being violated. If attacking: your power field has been breached, time to defend yourself; if standing silently in water: something is ripening in the depths.' },
    shadow: { tr: 'Su Aygırı\'nın gölgesi: koruma içgüdüsünün bir tahakküme dönüşmesi. Sevdiklerini "koruma" adına boğmak, kendi sularını o kadar sahiplenmek ki başkası nefes alamaz hale gelir — aşırı sahiplenme ve kontrol ihtiyacı.', en: 'The hippo\'s shadow: the protective instinct transforming into domination. Smothering loved ones in the name of "protection," claiming one\'s own waters so completely that others cannot breathe — excessive possessiveness and the need for control.' },
    whenAppears: { tr: 'Bir şeyi ya da birini koruma güdüsünün zirveye çıktığı anlarda; annelik, doğurganlık ya da yaratıcılık temalarının hayatına hâkim olduğu dönemlerde.', en: 'At the moments when the drive to protect something or someone reaches its peak; during periods when themes of motherhood, fertility, or creativity dominate your life.' },
    traditions: [
      { culture: { tr: 'Mısır', en: 'Egyptian' }, meaning: { tr: 'Taweret — hamile kadınların ve doğumun koruyucu tanrıçası; su aygırı başlı, aslan pençeli, timsah kuyruklu.', en: 'Taweret — guardian goddess of pregnant women and childbirth; with a hippo head, lion claws, and a crocodile tail.' } },
      { culture: { tr: 'Mısır (Set)', en: 'Egyptian (Set)' }, meaning: { tr: 'Set bazen su aygırı formunda tasvir edilir — Nil\'deki kaotik gücün ve fırtınanın cisimleşmesi.', en: 'Set is sometimes depicted in hippo form — the embodiment of chaotic power and storm in the Nile.' } },
      { culture: { tr: 'Yunan', en: 'Greek' }, meaning: { tr: 'Hippopotamos — "nehir atı"; Yunanlar onu Nil\'in efendisi olarak hayranlıkla tanımladı.', en: 'Hippopotamos — "river horse"; the Greeks described it with admiration as the master of the Nile.' } },
      { culture: { tr: 'Afrika (Batı Afrika Halkları)', en: 'African (West African Peoples)' }, meaning: { tr: 'Su Aygırı, nehirlerin ve yağmurun ruhudur; ona saygı göstermek sular üzerinde güvenlik sağlar.', en: 'The hippo is the spirit of rivers and rain; showing it respect ensures safety on the waters.' } },
      { culture: { tr: 'İncil (Eyüp Kitabı)', en: 'Biblical (Book of Job)' }, meaning: { tr: 'Behemot — Tanrı\'nın en büyük yaratığı; gücün ve yeryüzü kuvvetinin simgesi.', en: 'Behemoth — God\'s greatest creature; symbol of power and earthly might.' } },
    ],
    myths: [
      { tr: 'Mısır\'ın doğum odalarında Taweret heykeli hep vardı. Doğum yaparken ağrılar dayanılmaz olduğunda kadınlar ona seslenirdi: "Su Ana, ellerini uzat." Nil\'in derinliklerinden güç çektiğine inanılırdı — su nasıl her şeyi doğurursa, Taweret de her doğumda anaya su aygırının direncini verirdi.', en: 'The statue of Taweret was always present in Egyptian birthing rooms. When the pain of labor became unbearable, women would call to her: "Water Mother, extend your hands." She was believed to draw power from the depths of the Nile — just as water gives birth to everything, so Taweret gave every laboring mother the resilience of the hippo.' },
    ],
  },

  // ─── a095 Anakonda ───────────────────────────────────────────────────────
  a095: {
    jung: { tr: '"Kozmik Yılan ve Su Bilgeliği" arketipi. Anakonda, Uroboros\'un Amazon teki — başını yutan yılan değil, suyu saran yılan. Bilinçdışının en ilkel katmanını, dönüşümün sessiz ve yavaş ama kaçınılmaz doğasını simgeler. Bir şeyi kavradığında bırakmaz; kavrama gücü, neye sarıldığının bilincinde olmayı gerektirir.', en: '"Cosmic Serpent and Water Wisdom" archetype. The anaconda is the Amazon\'s Uroboros — not the serpent swallowing its tail, but the serpent embracing the water. It embodies the most primal layer of the unconscious, the silent and slow yet inevitable nature of transformation. When it grasps something it does not let go; the power of grasping requires awareness of what one holds.' },
    dream: { tr: 'Anakonda rüyada — psikenin derinliklerinden bir dönüşüm mesajı. Sarıyorsa: hayatındaki bir durum seni dönüştürüyor, direnmek değil teslim olmak gerekiyor; suda kayboluyorsa: bilinçaltın bir sırrı yutmuş, hazır olduğunda yüzeyine çıkacak.', en: 'The anaconda in dream — a message of transformation from the depths of the psyche. If it coils around you: a situation in your life is transforming you, not resistance but surrender is needed; if it disappears into water: your unconscious has swallowed a secret, it will surface when you are ready.' },
    shadow: { tr: 'Boğma enerjisi: kontrolü ele geçirmek için etrafındakileri yavaş yavaş sıkıştırmak. Anakonda gölgesindeki kişi sevgi adına özgürlüğü söndürür; sahip olduğu her şeyi o kadar sıkı sarar ki içindeki yaşam kımıldayamaz hale gelir.', en: 'The smothering energy: slowly tightening around those nearby to seize control. The person in anaconda\'s shadow extinguishes freedom in the name of love; wraps everything they possess so tightly that the life within can no longer stir.' },
    whenAppears: { tr: 'Derin bir dönüşüm geçirmekte olduğun ve buna direnmekten vazgeçmen gereken dönemlerde; ya da bilinçdışının bir mesajını artık görmezden gelemeyeceğin anlarda.', en: 'During periods of deep transformation when you must cease resisting it; or at moments when you can no longer ignore a message from your unconscious.' },
    traditions: [
      { culture: { tr: 'Amazon Yerlileri (Desana)', en: 'Amazon Peoples (Desana)' }, meaning: { tr: 'Büyük Yılan Anaconda — nehirlerin atası; dünyanın yaratılışında suyu taşıyan omurga.', en: 'The Great Serpent Anaconda — ancestor of rivers; the spine that carried the waters at the creation of the world.' } },
      { culture: { tr: 'Amazon Yerlileri (Yawalpiti)', en: 'Amazon Peoples (Yawalpiti)' }, meaning: { tr: 'Şamanlar anacondayla özdeşleşerek sular altına iner, ölülerin ruhlarıyla konuşur ve şifa getirir.', en: 'Shamans identify with the anaconda to descend beneath the waters, speak with the souls of the dead, and bring healing.' } },
      { culture: { tr: 'Hint', en: 'Indian' }, meaning: { tr: 'Naga yılanları — suların koruyucuları; anakondayla akraba imge, doğurganlık ve dönüşümün simgesi.', en: 'Naga serpents — guardians of the waters; a kindred image to the anaconda, symbol of fertility and transformation.' } },
      { culture: { tr: 'Afrika (Yoruba)', en: 'African (Yoruba)' }, meaning: { tr: 'Oshumare — gökkuşağı yılanı; yaşam döngüsünü, suyu ve dönüşümü yöneten ilahi güç.', en: 'Oshumare — the rainbow serpent; the divine power governing the life cycle, water, and transformation.' } },
      { culture: { tr: 'Avustralya Aborijin', en: 'Australian Aboriginal' }, meaning: { tr: 'Gökkuşağı Yılanı Yurlunggur — su kaynaklarının ve yaratılışın efendisi; totem ve dönüşümün babası.', en: 'Rainbow Serpent Yurlunggur — master of water sources and creation; totem and father of transformation.' } },
    ],
    myths: [
      { tr: 'Amazon şamanları ayahuasca seremonilerinde büyük yılanın geldiğini anlatır: "O seni yuttu mu, dünyayı içinden görürsün." Yutulmak ölüm değil, derinleşmedir. Yılanın karnında dünyanın sırrı saklıdır; oraya giren kişi geri döndüğünde başkadır — kelimenin tam anlamıyla.', en: 'Amazon shamans tell of the great serpent\'s coming in ayahuasca ceremonies: "Once it swallows you, you see the world from inside." Being swallowed is not death, but deepening. The secret of the world is held within the serpent\'s belly; whoever enters it returns as another — in the fullest sense of the word.' },
    ],
  },

  // ─── a096 Tukan ──────────────────────────────────────────────────────────
  a096: {
    jung: { tr: '"Yaratıcı İfade ve Tropik Bilgelik" arketipi. Tukan\'ın devasa, renkli gagası orantısız görünür — ama bu orantısızlık onun gücüdür. Psikolojik olarak: kendi sesini, renklerini ve ifade biçimini aşırı bulmaktan korkmamak demektir. Gaga ne kadar büyükse, söylenecek söz o kadar cesur.', en: '"Creative Expression and Tropical Wisdom" archetype. The toucan\'s enormous, colorful beak appears disproportionate — but this disproportion is its power. Psychologically: it means not being afraid of finding one\'s own voice, colors, and manner of expression excessive. The larger the beak, the bolder the word to be spoken.' },
    dream: { tr: 'Tukan rüyada — ifade etmek isteyip susturduğun bir şeyin sesi yükseliyor. Gagasını açıyorsa: artık konuşma zamanı; renkleri parlıyorsa: özgün olduğun zaman doğru yoldayısındır.', en: 'The toucan in dream — the voice of something you wished to express but silenced is rising. If it opens its beak: it is time to speak at last; if its colors shine: you are on the right path when you are authentic.' },
    shadow: { tr: 'Görünür olmak için her rengi kullanmak — derinliksiz parlaklık. Tukan gölgesi, özgünlük yerine sansasyon arayan kişide belirir; söylemin içeriği değil, rengi öne çıkar. Gösteriş bilgeliğin yerini aldığında tukan susar.', en: 'Using every color just to be visible — brightness without depth. The toucan\'s shadow appears in the person seeking sensation rather than authenticity; it is not the content of speech that comes forward, but the color. When show replaces wisdom, the toucan falls silent.' },
    whenAppears: { tr: 'Yaratıcı sesini bulmak ya da var olan sesini daha özgürce kullanmak üzere olduğunda; renkli, alışılmadık bir ifade biçiminin sana kapı araladığı anlarda.', en: 'When you are about to find your creative voice or use your existing voice more freely; at moments when a colorful, unconventional mode of expression opens a door for you.' },
    traditions: [
      { culture: { tr: 'Maya', en: 'Mayan' }, meaning: { tr: 'Tukan gagası şamanların baş süslemesinde kullanılırdı — öteki âlemlerle konuşmanın sembolü.', en: 'Toucan beaks were used in shamanic headdresses — a symbol of speaking with other realms.' } },
      { culture: { tr: 'Amazon Yerlileri (Kayapó)', en: 'Amazon Peoples (Kayapó)' }, meaning: { tr: 'Tukan tüyleri ritüel giysisinin parçasıdır; ruh dünyasına gidişin renkli rehberi sayılır.', en: 'Toucan feathers are part of ritual dress; considered the colorful guide for journeys to the spirit world.' } },
      { culture: { tr: 'Aztekler', en: 'Aztec' }, meaning: { tr: 'Quetzalcoatl\'ın tropik kuşları arasında tukan da vardır — ilahi iletişimin ve güneşin renkleriyle bezenmiş haberci.', en: 'Among Quetzalcoatl\'s tropical birds the toucan is also counted — a messenger adorned with the colors of divine communication and the sun.' } },
      { culture: { tr: 'Brezilya Halk Kültürü', en: 'Brazilian Folk Culture' }, meaning: { tr: 'Tukan sesi yağmurun habercisi sayılır — doğanın döngüsünde değişimin müjdecisi.', en: 'The toucan\'s call is considered a harbinger of rain — the herald of change in nature\'s cycle.' } },
      { culture: { tr: 'Kolombiya Yerli Kültürleri', en: 'Colombian Indigenous Cultures' }, meaning: { tr: 'Renkli gagası güneşin ve bereketin simgesi; topluluk törenlerinde neşeyi ve şükrü temsil eder.', en: 'Its colorful beak is a symbol of the sun and abundance; in community ceremonies it represents joy and gratitude.' } },
    ],
    myths: [
      { tr: 'Amazon\'un bir efsanesine göre ilk insanlar gri ve sessizdi. Tukan tanrıdan renk istedi: "Dünyayı güzel yapacak sesin ve rengin tek kaynağı benim" dedi. Tanrı güldü ve her renge bir anlam verdi — sarı cesareti, mavi huzuru, kırmızı tutkuyu. Tukan hem bunları taşır hem söyler; bu yüzden söylediğimiz her renkli söz bir tutukun hediyesidir.', en: 'According to an Amazon legend, the first humans were grey and silent. The toucan asked the god for color: "I am the sole source of the voice and color that will make the world beautiful," it said. The god laughed and gave each color a meaning — yellow for courage, blue for peace, red for passion. The toucan both carries and speaks them; thus every colorful word we utter is a gift of the toucan.' },
    ],
  },

  // ─── a097 Dingo ──────────────────────────────────────────────────────────
  a097: {
    jung: { tr: '"Ehlileşmemiş Özgürlük" arketipi. Dingo ne tam evcil köpektir ne de tam yaban hayvanı — bu arada oluş onun özüdür. Psikolojik olarak: medeniyetin kalıplarına tam sığmayan, ama vahşeti de seçmeyen bilinç hâlini simgeler. İçgüdüyle aklın tam sınırında yaşamak.', en: '"Untamed Freedom" archetype. The dingo is neither a fully domesticated dog nor a purely wild animal — this in-between state is its essence. Psychologically: it embodies the state of consciousness that does not fully fit civilization\'s molds, yet does not choose savagery either. Living precisely on the border of instinct and reason.' },
    dream: { tr: 'Dingo rüyada — ehlileştirilemeyen bir parçanın sesi. Yalnız koşuyorsa: özgürlük ihtiyacın çığlık atıyor; seni izliyorsa: içgüdülerine kulak vermelisin, aklın onları bastırmaya çalışıyor olabilir.', en: 'The dingo in dream — the voice of an untameable part. If running alone: your need for freedom is crying out; if watching you: you should listen to your instincts, your mind may be trying to suppress them.' },
    shadow: { tr: 'Ehlileşmemeyi bir erdem sanmak: bağlanmaktan, sorumluluktan, topluluğun kurallarından kaçmak için "özgürlük" söylemini kullanmak. Dingo gölgesi, her çitin dışına çıkar ama hiçbir yuvada kalmaz — sonsuz bir arayış, sonsuz bir yalnızlık.', en: 'Mistaking untameability for virtue: using the discourse of "freedom" to flee attachment, responsibility, the community\'s rules. The dingo\'s shadow leaps outside every fence but stays in no home — an endless search, an endless solitude.' },
    whenAppears: { tr: 'Toplumsal beklentilerle içsel özgürlük ihtiyacın arasında sıkıştığında; ya da saf içgüdüne güvenmen gerektiği ama aklının onu bastırdığı anlarda.', en: 'When you are caught between social expectations and your inner need for freedom; or at moments when you need to trust your pure instinct but your mind is suppressing it.' },
    traditions: [
      { culture: { tr: 'Avustralya Aborijin', en: 'Australian Aboriginal' }, meaning: { tr: 'Dingo Rüya Zamanı\'nın parçasıdır — atalardan gelen yabani ruhun toprağa bağlı özgür hâlidir.', en: 'The dingo is part of the Dreamtime — the earthbound free form of the wild spirit inherited from the ancestors.' } },
      { culture: { tr: 'Avustralya Aborijin (Toas)', en: 'Australian Aboriginal (Toas)' }, meaning: { tr: 'Dingo, seyahat ve yön işaretlerinde; bir yerin ruhunu ve yolun nasıl izleneceğini anlatmak için kullanılır.', en: 'The dingo appears in travel and direction markers; used to tell of a place\'s spirit and how a path is to be followed.' } },
      { culture: { tr: 'Sömürge Dönemi Avustralya', en: 'Colonial Australia' }, meaning: { tr: 'Avrupalı yerleşimciler dingoyu tehdit olarak gördü; bu yüzden uzun çitler inşa edildi. Ama dingo çitleri aştı — özgürlük duvarlardan büyüktür.', en: 'European settlers saw the dingo as a threat; long fences were built as a result. But the dingo crossed the fences — freedom is greater than walls.' } },
      { culture: { tr: 'Modern Avustralya Kültürü', en: 'Modern Australian Culture' }, meaning: { tr: 'Dingo ulusal bir sembol olarak tartışmalıdır — ehlileştirilemeyen, ne içeride ne dışarıda tam yerini bulan bir kimlik imgesi.', en: 'The dingo is a contested national symbol — an image of identity that cannot be domesticated, fully at home neither inside nor outside.' } },
      { culture: { tr: 'Güneydoğu Asya Kökeni', en: 'Southeast Asian Origin' }, meaning: { tr: 'Araştırmalar dingoyu Güneydoğu Asya\'dan gelen ilk denizci halkların köpeğiyle ilişkilendirir — kıtalar arası bir göçün izini taşır.', en: 'Research connects the dingo to the dogs of the first seafaring peoples arriving from Southeast Asia — it carries the trace of an intercontinental migration.' } },
    ],
    myths: [
      { tr: 'Aborijin anlatılarında Dingo, Rüya Zamanı\'nda Büyük Ata\'nın habercisiydi. Ne köyde ne ormanda kalmayı seçti; sınırda yaşadı. Bu yüzden o sınırı geçen her insan için yol arkadaşı oldu. Onu evcilleştirmeye çalışan kayboldu; onunla birlikte koşmayı öğrenen ise hem doğayı hem kendini buldu.', en: 'In Aboriginal stories, in the Dreamtime the Dingo was the messenger of the Great Ancestor. It chose to remain neither in the village nor in the forest; it lived on the border. For this reason it became the traveling companion of every person who crossed that boundary. Those who tried to domesticate it were lost; those who learned to run alongside it found both nature and themselves.' },
    ],
  },

  // ─── a098 Platipus ───────────────────────────────────────────────────────
  a098: {
    jung: { tr: '"Sınıflandırılamaz Güzellik" arketipi. Platipus hem memeliydi hem yumurtluyordu, hem memeli hem kuş özelliği taşıyordu — bilim onu gördüğünde sahte sandı. Bu, psikede kategorilerin dışında kalan her şeyi temsil eder: kendini tanımlamakta zorlandığın, ama gerçek olan benliğin.', en: '"Unclassifiable Beauty" archetype. The platypus was both mammal and egg-layer, carrying features of both mammal and bird — when science first saw it, they thought it a hoax. This represents in the psyche everything that falls outside categories: the self you struggle to define, yet which is real.' },
    dream: { tr: 'Platipus rüyada — kendini bir kategoriye sığdırma baskısından kurtulma zamanı. Suda yüzüyorsa: bilinçdışın zıtlıkları bütünleştiriyor; seni izliyorsa: benzersizliğin artık görünür olmak istiyor.', en: 'The platypus in dream — time to free yourself from the pressure of fitting into a category. If swimming in water: your unconscious is integrating opposites; if watching you: your uniqueness wishes to become visible now.' },
    shadow: { tr: '"Ben kategoriye sığmıyorum" söylemini bir sorumsuzluk kalkanına dönüştürmek. Platipus gölgesi, her sistemi reddeder ama kendi sistemini de kuramaz; zıtlığı entegre etmek yerine onların arasında kaybolur.', en: 'Turning the discourse of "I don\'t fit into a category" into a shield of irresponsibility. The platypus shadow rejects every system but cannot build its own either; instead of integrating opposites it becomes lost between them.' },
    whenAppears: { tr: 'Kendini toplumun ya da ailenin beklentilerine sığdıramadığını hissettiğinde; ya da zıt özelliklerini bir bütünde harmanlama fırsatının doğduğu dönemlerde.', en: 'When you feel you cannot fit into society\'s or family\'s expectations; or during periods when the opportunity arises to blend your opposing qualities into a whole.' },
    traditions: [
      { culture: { tr: 'Avustralya Aborijin (Wiradjuri)', en: 'Australian Aboriginal (Wiradjuri)' }, meaning: { tr: 'Platipus (Bilarr), hem su hem toprak dünyasına ait olduğu için iki âlem arasında arabuluculuk yapar.', en: 'The platypus (Bilarr), belonging to both the water and land worlds, mediates between the two realms.' } },
      { culture: { tr: 'Avustralya Aborijin (Dreamtime)', en: 'Australian Aboriginal (Dreamtime)' }, meaning: { tr: 'Platipus, Rüya Zamanı\'nda bir tartışmadan doğdu: hayvanlar birbirini dışlarken platipus hepsinin özelliklerini aldı. Ata onun için dedi ki: "Sen hepsindensin."', en: 'In the Dreamtime the platypus was born from a dispute: while animals excluded one another, the platypus took on the features of all. The Ancestor said of it: "You belong to all of them."' } },
      { culture: { tr: 'Batı Bilimi (18. yy)', en: 'Western Science (18th c.)' }, meaning: { tr: 'İlk platipus örneği İngiltere\'ye ulaştığında doğa bilimciler sahte olduğunu iddia etti — gerçek, tanımların dışına çıktığında inkâr edilir.', en: 'When the first platypus specimen reached England, naturalists claimed it was a fake — reality is denied when it exceeds definitions.' } },
      { culture: { tr: 'Modern Ekoloji', en: 'Modern Ecology' }, meaning: { tr: 'Platipus elektroresepsiyon yeteneğiyle sualtında görmeden avlanır — altıncı hissin, sezginin biyolojik karşılığı.', en: 'The platypus hunts underwater without seeing using electroreception — the biological counterpart of sixth sense, of intuition.' } },
      { culture: { tr: 'Çağdaş Spiritüelite', en: 'Contemporary Spirituality' }, meaning: { tr: 'Platipus totem hayvanı olarak "ben kendimim" mesajını verir — başkasının kategorisinde var olmak yerine kendi bütünlüğünde yaşamak.', en: 'As a totem animal the platypus gives the message "I am myself" — living in one\'s own wholeness rather than existing within another\'s category.' } },
    ],
    myths: [
      { tr: 'Aborijin anlatısında su faresi ile ördek arasında uzun bir tartışma vardır: ikisi de platipusu kendi türünden sayar. Platipus onları dinler, sonra suya dalar. Derinliklerde Büyük Ata ona şunu söyler: "Tartışmalarını dinle ama adlarına inanma. Sen suyla toprak arasındaki sırrın kendisisin."', en: 'In an Aboriginal story there is a long dispute between the water rat and the duck: each counts the platypus as its own kind. The platypus listens to them, then dives into the water. In the depths the Great Ancestor says to it: "Listen to their arguments but do not believe their names. You are the secret itself between water and earth."' },
    ],
  },

  // ─── a099 Dalgıç Kuşu ────────────────────────────────────────────────────
  a099: {
    jung: { tr: '"Bilinçaltı Sesi ve İçsel Çığlık" arketipi. Dalgıç kuşunun çığlığı, psikede bastırılmış duyguların yüzeye çıkma anını simgeler — hem rüyanın hem gözyaşının hem de öfkenin sesidir. Jung\'un "gölge"sinin su yüzeyinde yankılanan yankısıdır.', en: '"Voice of the Unconscious and Inner Cry" archetype. The loon\'s cry symbolizes the moment repressed emotions surface in the psyche — it is the voice of both the dream, and the tear, and the rage. It is the echo of Jung\'s "shadow" reverberating on the surface of water.' },
    dream: { tr: 'Dalgıç Kuşu rüyada — bilinçaltından gelen bir mesaj artık duyulabilir seviyeye çıktı. Çığlık atıyorsa: uzun süredir bastırdığın bir duygunun serbest bırakılması gerekiyor; suya dalıyorsa: cevabı derinlerde ara, yüzeyde değil.', en: 'The loon in dream — a message from the unconscious has now risen to an audible level. If crying out: an emotion long suppressed needs to be released; if diving: seek the answer in the depths, not on the surface.' },
    shadow: { tr: 'Çığlığı duymayı reddetmek ya da sonsuz çığlık. Dalgıç Kuşu gölgesinde ya içini tamamen susturmak — duygusal donukluk — ya da durdurulamayan bir iç ses: sonsuz bir hüzün, giderilemeyen bir yalnızlık hissi vardır.', en: 'Refusing to hear the cry, or the endless cry. In the loon\'s shadow there is either completely silencing the inner voice — emotional numbness — or an unstoppable inner sound: an endless sorrow, an irremedable sense of loneliness.' },
    whenAppears: { tr: 'İçindeki bir sesin artık duyulması gerektiği anlarda; ya da yalnızlık ve derinlik temalarının seni en güçlü biçimde sardığı dönemlerde.', en: 'At moments when an inner voice must now be heard; or during periods when themes of solitude and depth surround you most powerfully.' },
    traditions: [
      { culture: { tr: 'Yerli Kuzey Amerika (Anishinaabe)', en: 'Native North America (Anishinaabe)' }, meaning: { tr: 'Dalgıç Kuşu rüya rehberidir — sesi bilinçaltının kapısını açar, su şamanının yoldaşıdır.', en: 'The loon is a dream guide — its voice opens the door of the unconscious, it is the companion of the water shaman.' } },
      { culture: { tr: 'Kuzey Amerika Yerlileri (Cree)', en: 'North American Indigenous (Cree)' }, meaning: { tr: 'Dalgıç Kuşu\'nun çığlığı, kaybedilen sevdiklerin ruhu olarak yorumlanır — yas ve bağ arasındaki köprü.', en: 'The loon\'s cry is interpreted as the spirit of lost loved ones — the bridge between grief and connection.' } },
      { culture: { tr: 'İskandinav', en: 'Scandinavian' }, meaning: { tr: 'Dalgıç Kuşu kuzey göllerinin sesi; fırtına öncesi çığlığı denizcileri uyarır, değişimin habercisidir.', en: 'The loon is the voice of northern lakes; its cry before a storm warns sailors, it is the herald of change.' } },
      { culture: { tr: 'İnuit', en: 'Inuit' }, meaning: { tr: 'Dalgıç Kuşu körlerin gözlerini açtığına inanılır — ruhsal görüşü restore eden kutsal varlık.', en: 'The loon is believed to restore sight to the blind — the sacred being that restores spiritual vision.' } },
      { culture: { tr: 'Kanada Ulusal Sembolizmi', en: 'Canadian National Symbolism' }, meaning: { tr: 'Kanada\'nın bir dolarlık sikkesinde yaşayan "loonie" — ulusal kimliğin derinlik ve sessizlik içindeki yankısı.', en: 'Living on Canada\'s one-dollar coin as the "loonie" — the echo of national identity within depth and silence.' } },
    ],
    myths: [
      { tr: 'İnuit efsanesinde kör bir yaşlı adam Dalgıç Kuşu\'ndan iyileşmesini diler. Kuş onu suyun altına üç kez götürür. Her seferinde bir ışık daha açılır gözlerinde. Üçüncüde yüzeye çıkar ve tüm dünyayı görür — hem dışarıdaki hem içindeki. Dalgıç Kuşu\'nun hediyesi sadece görme değil, derinliğe bakabilmedir.', en: 'In an Inuit legend a blind old man prays to the Loon for healing. The bird takes him underwater three times. Each time another light opens in his eyes. On the third he surfaces and sees the entire world — both outside and within. The Loon\'s gift is not sight alone, but the ability to look into the depths.' },
    ],
  },

  // ─── a100 Beyaz Geyik ────────────────────────────────────────────────────
  a100: {
    jung: { tr: '"İlahi Çağrı ve Kutsal Belirti" arketipi. Beyaz Geyik, psikede nadiren görülen ama görüldüğünde her şeyi değiştiren anlara karşılık gelir — aşkınlık deneyimi. Kişinin kendi kaderine çağrıldığı o eşik anı; tam anlamıyla bir "numinos" tezahürüdür, kutsal olanın sıradan içinde görünmesidir.', en: '"Divine Call and Sacred Sign" archetype. The White Deer corresponds to the rarely seen moments in the psyche that change everything when they appear — the transcendence experience. That threshold moment when one is called to one\'s own destiny; it is a true "numinous" manifestation, the appearance of the sacred within the ordinary.' },
    dream: { tr: 'Beyaz Geyik rüyada — olağanüstü bir çağrının, bir dönüm noktasının eşiğindesin. Dur bakıyorsa: henüz hazır mısın sorusunu soruyor; kaçıyorsa: çağrıyı duyuyorsun ama henüz kabul etmiyorsun; seni takip ediyorsa: kaçış yok, bu sefer yüzleşmek zorundasın.', en: 'The White Deer in dream — you stand on the threshold of an extraordinary call, a turning point. If it stands and gazes: it asks whether you are yet ready; if it flees: you hear the call but have not yet accepted it; if it follows you: there is no escape, this time you must face it.' },
    shadow: { tr: '"İşaret bekleme" tuzağı: her beyaz geyiği beklerken sıradan anda sunulan lütfu görmemek. Beyaz Geyik gölgesi, olağanüstü olanı öyle özler ki sıradan anın kutsallığına kör olur — mucize arar, yanıbaşındaki yaşamı kaçırır.', en: 'The "waiting for a sign" trap: while waiting for every white deer, failing to see the grace offered in the ordinary moment. The White Deer\'s shadow longs so deeply for the extraordinary that it goes blind to the sacredness of the ordinary instant — it searches for a miracle and misses the life right beside it.' },
    whenAppears: { tr: 'Hayatının gerçek yönünü bulman gereken dönüm noktalarında; ya da sıradan bir anın içinde kutsal olanı fark ettiğin o nadiren gelen anlarda.', en: 'At the turning points where you must find the true direction of your life; or at those rarely arriving moments when you perceive the sacred within an ordinary instant.' },
    traditions: [
      { culture: { tr: 'Kelt Mitolojisi', en: 'Celtic Mythology' }, meaning: { tr: 'Beyaz Geyik Öteki Dünya\'nın habercisidir — onu kovalayan kahraman, ölümlü dünyadan kutsal aleme geçer.', en: 'The White Deer is the herald of the Otherworld — the hero who chases it crosses from the mortal world to the sacred realm.' } },
      { culture: { tr: 'Arthurian Efsaneleri', en: 'Arthurian Legends' }, meaning: { tr: 'Beyaz Geyik Graal arayışının tetikleyicisidir — şövalyeler onu yakalamanın imkânsız olduğunu bilir ama peşinden gitmek zorunludur.', en: 'The White Deer triggers the Grail quest — the knights know catching it is impossible but following it is compulsory.' } },
      { culture: { tr: 'Çin', en: 'Chinese' }, meaning: { tr: 'Beyaz Geyik uzun ömrün ve bilgeliğin sembolüdür; Shou tanrısının yanında dururdu.', en: 'The white deer is a symbol of longevity and wisdom; it stood beside the god Shou.' } },
      { culture: { tr: 'Kore', en: 'Korean' }, meaning: { tr: 'Beyaz Geyik efsanevi yöneticilerin ya da bilgelerin doğumunu müjdeleyen kutsal belirti olarak görülür.', en: 'The white deer is seen as a sacred sign heralding the birth of legendary rulers or sages.' } },
      { culture: { tr: 'Yerli Kuzey Amerika (Lakota)', en: 'Native North America (Lakota)' }, meaning: { tr: 'Beyaz Bufalo Kadını\'nın dönüşümünde olduğu gibi, beyaz hayvan genellikle ilahi mesajın taşıyıcısıdır; dönüşüm ve barışın simgesi.', en: 'As with the transformation of White Buffalo Woman, the white animal is generally the carrier of divine message; a symbol of transformation and peace.' } },
    ],
    myths: [
      { tr: 'Kelt efsanesinde genç bir avcı ormanda Beyaz Geyik\'in izini sürer. Tam oklarını çekeceği anda geyik dönüp ona bakar — gözleri insan gözü gibidir. Avcı yayını bırakır. Geyik onu gece boyu ormanın içine götürür; sabah çıktığında avcı, köyün çoktandır kaybettiği şifacı bilgeye ulaşmıştır. Beyaz Geyik yakalanmaz; o yalnızca yolu gösterir.', en: 'In a Celtic legend a young hunter tracks the White Deer through the forest. Just as he is about to loose his arrow, the deer turns and looks at him — its eyes are like human eyes. The hunter lets fall his bow. The deer leads him through the forest all night; when he emerges at dawn, the hunter has reached the healing sage the village had long since lost. The White Deer is not caught; it only shows the way.' },
      { tr: 'Anadolu\'da beyaz hayvan görümü her zaman bir işaret sayılmıştır. Halk arasında "Beyaz geyik gördüm" demek, "Hayatımda bir şey değişecek" demektir. Sufiler bunu Hakk\'ın kalbine doğru çekiş olarak yorumlar: hayvan kaçar, sen koşarsın — ama varış yeri geyiğin yurdu değil, kendi kalbinin derinliğidir.', en: 'In Anatolia a vision of a white animal has always been considered a sign. Among the people, to say "I saw a white deer" is to say "something in my life will change." Sufis interpret this as the pull toward the heart of the Divine: the animal flees, you run — but the destination is not the deer\'s home, it is the depth of your own heart.' },
    ],
  },

};

export function getAnimalLore(id: string): AnimalLore | undefined {
  return ANIMAL_LORE[id];
}
